import customtkinter as ctk

import tkinter as _tk_mod
_orig_report_cb = _tk_mod.Tk.report_callback_exception
def _silent_ctk_errors(self, exc, val, tb):
    msg = str(val)
    if any(x in msg for x in ('check_dpi_scaling','click_animation','_draw_engine')):
        return
    _orig_report_cb(self, exc, val, tb)
_tk_mod.Tk.report_callback_exception = _silent_ctk_errors

# ══ СИСТЕМА ЛОГУВАННЯ ПОМИЛОК ══
import logging as _logging
import os as _os

def _get_log_path():
    try:
        base = _os.path.dirname(_os.path.abspath(__file__))
        log_dir = _os.path.normpath(_os.path.join(base, '..', '..', 'data'))
        _os.makedirs(log_dir, exist_ok=True)
        return _os.path.join(log_dir, 'hotel_errors.log')
    except Exception:
        return _os.path.join(_os.path.expanduser('~'), 'hotel_errors.log')

_log_path = _get_log_path()
_logger = _logging.getLogger('hotel')
if not _logger.handlers:
    _fh = _logging.FileHandler(_log_path, encoding='utf-8')
    _fh.setFormatter(_logging.Formatter('%(asctime)s [%(levelname)s] %(message)s', '%Y-%m-%d %H:%M:%S'))
    _logger.addHandler(_fh)
    _logger.setLevel(_logging.DEBUG)

def log_error(msg, exc=None):
    """Записати помилку в лог."""
    if exc:
        _logger.error(f"{msg}: {exc}", exc_info=True)
    else:
        _logger.error(msg)

def log_info(msg):
    _logger.info(msg)

# Перехоплювати всі необроблені виключення
import sys as _sys
_orig_excepthook = _sys.excepthook
def _global_excepthook(exc_type, exc_val, exc_tb):
    import traceback as _tb
    msg = ''.join(_tb.format_exception(exc_type, exc_val, exc_tb))
    _logger.critical(f"НЕОБРОБЛЕНА ПОМИЛКА:\n{msg}")
    _orig_excepthook(exc_type, exc_val, exc_tb)
_sys.excepthook = _global_excepthook

