# ══════════════════════════════════════════════════════════════════════════════
# OFFLINE-FIRST МЕНЕДЖЕР СИНХРОНІЗАЦІЇ
# ══════════════════════════════════════════════════════════════════════════════
# Архітектура:
#   • Всі записи (INSERT/UPDATE) спочатку зберігаються у локальний SQLite (pending_ops)
#   • Фоновий потік кожні SYNC_INTERVAL секунд намагається скинути їх у PostgreSQL
#   • При відкритті зміни — ПОВНА синхронізація PG → SQLite (download)
#   • При закритті зміни — ОБОВ'ЯЗКОВА синхронізація SQLite → PG (upload), блокуюча
#   • При недоступності PG — робота продовжується локально, всі операції в черзі
# ══════════════════════════════════════════════════════════════════════════════

import sqlite3 as _sq3
import threading as _thr
import time as _time_mod
import queue as _queue_mod
import traceback as _tb_mod

APP_VERSION = "1.0.0"  # Версія — змінюйте при кожному оновленні
SYNC_INTERVAL = 60    # секунд між автосинхронізаціями


class OfflineSyncManager:
    """
    Менеджер offline-first синхронізації між локальним SQLite і PostgreSQL.

    Ключові методи:
        is_online()          → True якщо PG доступний
        queue_op(sql, args)  → поставити операцію в чергу (завжди успішно)
        flush_to_pg()        → вивантажити чергу в PG (блокуючий)
        pull_from_pg()       → завантажити все з PG в SQLite (блокуючий)
        start()              → запустити фоновий потік автосинхронізації
        stop()               → зупинити фоновий потік
    """

    _instance = None

    def __new__(cls):
        if cls._instance is None:
            cls._instance = super().__new__(cls)
            cls._instance._initialized = False
        return cls._instance

    def __init__(self):
        if self._initialized:
            return
        self._initialized = True
        self._lock = _thr.Lock()
        self._stop_evt = _thr.Event()
        self._thread = None
        self._online = False
        self._last_check = 0.0
        self._last_sync = 0.0
        self._on_status_change = None   # callback(online: bool)
        self._db_path = _os.path.join(
            _os.path.normpath(_os.path.join(
                _os.path.dirname(_os.path.abspath(__file__)), '..', '..', 'data'
            )),
            'offline_sync.db'
        )
        # Ініціалізація SQLite у фоновому потоці — не блокує старт UI
        _thr.Thread(target=self._deferred_init, daemon=True).start()

    # ── Відкладена ініціалізація (щоб не блокувати старт UI) ─────────────────
    def _deferred_init(self):
        """Виконується у фоновому потоці — ініціалізує SQLite без блокування UI."""
        try:
            _os.makedirs(_os.path.dirname(self._db_path), exist_ok=True)
            self._init_local_db()
        except Exception as _e:
            _logging.getLogger('hotel').error(f"OfflineSync: deferred_init error: {_e}")

    # ── Ініціалізація локальної БД ────────────────────────────────────────────
    def _init_local_db(self):
        """Створює таблиці у SQLite якщо ще не існують."""
        try:
            with _sq3.connect(self._db_path, timeout=10) as c:
                c.executescript("""
                    CREATE TABLE IF NOT EXISTS pending_ops (
                        id        INTEGER PRIMARY KEY AUTOINCREMENT,
                        sql_text  TEXT    NOT NULL,
                        sql_args  TEXT    NOT NULL DEFAULT '[]',
                        created_at TEXT   NOT NULL DEFAULT (datetime('now','localtime')),
                        attempts  INTEGER NOT NULL DEFAULT 0,
                        last_error TEXT   DEFAULT NULL
                    );
                    CREATE TABLE IF NOT EXISTS sync_log (
                        id         INTEGER PRIMARY KEY AUTOINCREMENT,
                        event      TEXT NOT NULL,
                        details    TEXT DEFAULT '',
                        ts         TEXT NOT NULL DEFAULT (datetime('now','localtime'))
                    );
                    CREATE TABLE IF NOT EXISTS sync_state (
                        key   TEXT PRIMARY KEY,
                        value TEXT
                    );
                """)
        except Exception as _e:
            _logging.getLogger('hotel').error(f"OfflineSync: init_local_db error: {_e}")

    # ── Перевірка з'єднання з PG ─────────────────────────────────────────────
    def check_online(self) -> bool:
        """Перевіряє чи є з'єднання з PostgreSQL (з кешуванням на 5с)."""
        now = _time_mod.monotonic()
        if now - self._last_check < 5:
            return self._online
        self._last_check = now
        try:
            import json as _jco, socket as _sockco
            _cfg_co = {}
            try:
                _p_co = _os.path.normpath(_os.path.join(
                    _os.path.dirname(_os.path.abspath(__file__)),
                    '..', '..', 'config', 'db.json'))
                with open(_p_co) as _fco: _cfg_co = _jco.load(_fco)
            except Exception: pass
            host_co = str(_cfg_co.get('host', 'localhost')).strip()
            port_co = int(_cfg_co.get('port', 5432))
            with _sockco.create_connection((host_co, port_co), timeout=3): pass
            import psycopg2 as _pg2co
            _c2 = _pg2co.connect(host=host_co, port=port_co,
                dbname=_cfg_co.get('dbname', _cfg_co.get('database', 'hotel')),
                user=_cfg_co.get('user', 'hotel'), password=_cfg_co.get('password', ''),
                connect_timeout=4)
            _c2.close()
            was_online = self._online
            self._online = True
            if not was_online and self._on_status_change:
                try: self._on_status_change(True)
                except Exception: pass
        except Exception:
            was_online = self._online
            self._online = False
            if was_online and self._on_status_change:
                try: self._on_status_change(False)
                except Exception: pass
        return self._online

    def is_online(self) -> bool:
        return self._online

    # ── Черга операцій ────────────────────────────────────────────────────────
    def queue_op(self, sql_text: str, sql_args: tuple = ()):
        """
        Додає SQL-операцію (INSERT/UPDATE/DELETE) до локальної черги.
        Завжди повертає True — запис до SQLite завжди доступний.
        """
        import json as _j
        try:
            with _sq3.connect(self._db_path, timeout=10) as c:
                c.execute(
                    "INSERT INTO pending_ops (sql_text, sql_args) VALUES (?, ?)",
                    (sql_text, _j.dumps(list(sql_args), default=str))
                )
            return True
        except Exception as _e:
            _logging.getLogger('hotel').error(f"OfflineSync: queue_op error: {_e}")
            return False

    def pending_count(self) -> int:
        """Кількість операцій в черзі."""
        try:
            with _sq3.connect(self._db_path, timeout=5) as c:
                r = c.execute("SELECT COUNT(*) FROM pending_ops").fetchone()
                return r[0] if r else 0
        except Exception:
            return 0

    # ── Вивантаження в PG ─────────────────────────────────────────────────────
    def flush_to_pg(self, on_progress=None) -> dict:
        """
        Вивантажує всі операції з черги в PostgreSQL.
        on_progress(done, total) — callback для UI progressbar.
        Повертає {'ok': N, 'fail': N, 'total': N}.
        Блокуючий — викликати з фонового потоку або before закриття зміни.
        """
        import json as _j
        result = {'ok': 0, 'fail': 0, 'total': 0}
        if not self.check_online():
            self._log('flush_skipped', 'PG недоступний')
            return result
        try:
            with _sq3.connect(self._db_path, timeout=15) as local_c:
                rows = local_c.execute(
                    "SELECT id, sql_text, sql_args FROM pending_ops ORDER BY id ASC"
                ).fetchall()
                result['total'] = len(rows)
                if not rows:
                    # Черга порожня — оновлюємо час синхронізації і виходимо
                    self._last_sync = _time_mod.monotonic()
                    self._log('flush_ok', 'ok=0 fail=0 total=0 (черга порожня)')
                    return result
                from app.utils.db import get_conn as _gc
                with _gc() as pg_c:
                    for i, (row_id, sql_text, sql_args_json) in enumerate(rows):
                        try:
                            args = tuple(_j.loads(sql_args_json))
                            # Конвертуємо %s → %s (psycopg2), ? → %s (якщо це SQLite-стиль)
                            pg_sql = sql_text.replace('?', '%s')
                            with pg_c.cursor() as _cur:
                                _cur.execute(pg_sql, args)
                            pg_c.commit()
                            local_c.execute("DELETE FROM pending_ops WHERE id=?", (row_id,))
                            local_c.commit()
                            result['ok'] += 1
                        except Exception as _row_err:
                            pg_c.rollback()
                            local_c.execute(
                                "UPDATE pending_ops SET attempts=attempts+1, last_error=? WHERE id=?",
                                (str(_row_err)[:500], row_id)
                            )
                            local_c.commit()
                            result['fail'] += 1
                        if on_progress:
                            try: on_progress(i + 1, result['total'])
                            except Exception: pass
            self._last_sync = _time_mod.monotonic()
            self._log('flush_ok', f"ok={result['ok']} fail={result['fail']} total={result['total']}")
            # Після успішного flush — оновити full_sync кешу
            if result['ok'] > 0:
                try:
                    from app.utils.db_cache import _cache_instance as _ci
                    if _ci:
                        _thr.Thread(target=_ci.full_sync, daemon=True).start()
                except Exception:
                    pass
        except Exception as _e:
            self._log('flush_error', str(_e))
            _logging.getLogger('hotel').error(f"OfflineSync: flush_to_pg error: {_e}")
        return result

    # ── Завантаження з PG ─────────────────────────────────────────────────────
    def pull_from_pg(self) -> bool:
        """
        Повна завантаження даних PG → локальний SQLite кеш.
        Викликається при відкритті зміни.
        Повертає True якщо успішно.
        """
        if not self.check_online():
            self._log('pull_skipped', 'PG недоступний')
            return False
        try:
            from app.utils.db_cache import _cache_instance as _ci
            if _ci and hasattr(_ci, 'full_sync'):
                _ci.full_sync()
                self._log('pull_ok', 'full_sync виконано')
                return True
            elif _install_db_cache:
                _install_db_cache()
                self._log('pull_ok', 'install_cache виконано')
                return True
        except Exception as _e:
            self._log('pull_error', str(_e))
            _logging.getLogger('hotel').error(f"OfflineSync: pull_from_pg error: {_e}")
        return False

    # ── Синхронізація при відкритті зміни ────────────────────────────────────
    def on_shift_open(self, shift_id=None):
        """
        Викликається при відкритті зміни.
        1) Завантажує актуальні дані з PG в локальний кеш.
        2) Якщо є незавершені операції в черзі — намагається їх відправити.
        """
        def _task():
            _logging.getLogger('hotel').info(f"[OfflineSync] on_shift_open shift_id={shift_id}")
            # Спочатку — скинути накопичені офлайн-операції
            pending = self.pending_count()
            if pending > 0:
                _logging.getLogger('hotel').info(f"[OfflineSync] Є {pending} пend. операцій — flush перед pull")
                self.flush_to_pg()
            # Потім — завантажити актуальний стан з PG
            self.pull_from_pg()
            self._save_state('last_pull', _time_mod.strftime('%Y-%m-%d %H:%M:%S'))
        _thr.Thread(target=_task, daemon=True).start()

    # ── Синхронізація при закритті зміни ─────────────────────────────────────
    def on_shift_close(self, parent_widget=None) -> bool:
        """
        Викликається при закритті зміни (Z-звіт).
        ОБОВ'ЯЗКОВА синхронізація — блокуюча, з UI-прогресом.
        Повертає True якщо всі операції вивантажено успішно.
        """
        pending = self.pending_count()
        if pending == 0 and self.is_online():
            self._log('shift_close_sync', 'Черга порожня, PG доступний — sync OK')
            return True

        if not self.check_online():
            # PG недоступний — показуємо попередження, але не блокуємо закриття
            _logging.getLogger('hotel').warning("[OfflineSync] PG недоступний при закритті зміни!")
            try:
                from tkinter import messagebox as _mb
                _mb.showwarning(
                    "⚠️  Увага! Немає зв'язку з сервером",
                    f"Сервер недоступний.\n"
                    f"Операцій в черзі: {pending}\n\n"
                    "Дані збережені локально.\n"
                    "При наступному підключенні вони будуть автоматично вивантажені."
                )
            except Exception:
                pass
            return False

        # Є pending + є з'єднання — обов'язковий flush з прогресом
        _result = {'ok': 0, 'fail': 0}

        def _do_flush():
            res = self.flush_to_pg()
            _result.update(res)

        t = _thr.Thread(target=_do_flush, daemon=True)
        t.start()
        t.join(timeout=30)  # чекаємо до 30 секунд

        if _result['fail'] > 0:
            try:
                from tkinter import messagebox as _mb
                _mb.showwarning(
                    "⚠️  Синхронізація",
                    f"Вивантажено: {_result['ok']} операцій\n"
                    f"Помилок: {_result['fail']}\n\n"
                    "Невивантажені операції залишились в черзі.\n"
                    "Спробуйте знову або зверніться до адміністратора."
                )
            except Exception:
                pass
            return False

        self._log('shift_close_sync', f"Успішно flush {_result['ok']} операцій")
        return True

    # ── Автоматична фонова синхронізація ─────────────────────────────────────
    def start(self):
        """Запускає фоновий потік автосинхронізації."""
        if self._thread and self._thread.is_alive():
            return
        self._stop_evt.clear()
        self._thread = _thr.Thread(target=self._bg_loop, daemon=True, name='OfflineSyncBG')
        self._thread.start()
        _logging.getLogger('hotel').info("[OfflineSync] Фоновий потік запущено")

    def stop(self):
        self._stop_evt.set()

    def _bg_loop(self):
        """Фоновий цикл: перевірка онлайн + синхронізація кожні SYNC_INTERVAL сек."""
        while not self._stop_evt.is_set():
            try:
                online = self.check_online()
                if online:
                    pending = self.pending_count()
                    now = _time_mod.monotonic()
                    time_to_sync = (now - self._last_sync) >= SYNC_INTERVAL

                    if pending > 0:
                        # Є незавантажені операції → вивантажити в PG
                        _logging.getLogger('hotel').info(
                            f"[OfflineSync] Авто-flush: {pending} операцій")
                        self.flush_to_pg()
                    elif time_to_sync:
                        # Черга порожня, але час планової синхронізації →
                        # завантажити свіжі дані PG → SQLite (full_sync)
                        try:
                            from app.utils.db_cache import _cache_instance as _ci
                            if _ci and hasattr(_ci, 'full_sync'):
                                _logging.getLogger('hotel').info("[OfflineSync] Планова full_sync PG→SQLite")
                                _ci.full_sync()
                                self._last_sync = _time_mod.monotonic()
                                self._log('full_sync', 'авто-синхронізація PG→SQLite')
                            else:
                                self._last_sync = _time_mod.monotonic()
                                self._log('flush_ok', 'кеш недоступний')
                        except Exception as _se:
                            _logging.getLogger('hotel').error(f"[OfflineSync] full_sync error: {_se}")
            except Exception as _e:
                _logging.getLogger('hotel').error(f"[OfflineSync] bg_loop error: {_e}")
            self._stop_evt.wait(timeout=15)  # перевірка кожні 15 сек

    # ── Допоміжні ─────────────────────────────────────────────────────────────
    def _log(self, event: str, details: str = ''):
        try:
            with _sq3.connect(self._db_path, timeout=5) as c:
                c.execute("INSERT INTO sync_log (event, details) VALUES (?, ?)", (event, details))
        except Exception:
            pass

    def _save_state(self, key: str, value: str):
        try:
            with _sq3.connect(self._db_path, timeout=5) as c:
                c.execute("INSERT OR REPLACE INTO sync_state (key, value) VALUES (?, ?)", (key, value))
        except Exception:
            pass

    def get_state(self, key: str, default=None):
        try:
            with _sq3.connect(self._db_path, timeout=5) as c:
                r = c.execute("SELECT value FROM sync_state WHERE key=?", (key,)).fetchone()
                return r[0] if r else default
        except Exception:
            return default

    def get_sync_log(self, limit=50) -> list:
        """Повертає останні записи лога синхронізації."""
        try:
            with _sq3.connect(self._db_path, timeout=5) as c:
                rows = c.execute(
                    "SELECT ts, event, details FROM sync_log ORDER BY id DESC LIMIT ?",
                    (limit,)
                ).fetchall()
                return [{'ts': r[0], 'event': r[1], 'details': r[2]} for r in rows]
        except Exception:
            return []

    def get_pending_ops(self, limit=100) -> list:
        """Повертає операції в черзі (для відображення в UI)."""
        try:
            with _sq3.connect(self._db_path, timeout=5) as c:
                rows = c.execute(
                    "SELECT id, created_at, sql_text, attempts, last_error FROM pending_ops ORDER BY id DESC LIMIT ?",
                    (limit,)
                ).fetchall()
                return [{'id': r[0], 'ts': r[1], 'sql': r[2][:80], 'attempts': r[3], 'error': r[4]} for r in rows]
        except Exception:
            return []


# Глобальний єдиний екземпляр
_sync_mgr = OfflineSyncManager()


def get_sync_manager() -> OfflineSyncManager:
    """Повертає глобальний екземпляр менеджера синхронізації."""
    return _sync_mgr


