# ЖУРНАЛ ПРИБИРАНЬ — PostgreSQL (з fallback на JSON)
# ══════════════════════════════════════════════════════
def _ensure_cleaning_log_table():
    """Створює таблицю cleaning_log якщо не існує."""
    try:
        from app.utils.db import get_conn
        with get_conn() as conn:
            with conn.cursor() as cur:
                cur.execute("""
                    CREATE TABLE IF NOT EXISTS cleaning_log (
                        id SERIAL PRIMARY KEY,
                        room TEXT NOT NULL DEFAULT '',
                        cleaner TEXT NOT NULL DEFAULT '',
                        started TEXT NOT NULL DEFAULT '',
                        finished TEXT NOT NULL DEFAULT '',
                        new_status TEXT NOT NULL DEFAULT '',
                        note TEXT NOT NULL DEFAULT '',
                        logged_at TEXT NOT NULL DEFAULT ''
                    )
                """)
            conn.commit()
        return True
    except Exception:
        return False

def _cl_load():
    """Читає всі записи журналу прибирань з PostgreSQL, fallback → JSON."""
    try:
        from app.utils.db import get_conn
        with get_conn() as conn:
            with conn.cursor() as cur:
                cur.execute("SELECT room,cleaner,started,finished,new_status,note,logged_at FROM cleaning_log ORDER BY id ASC")
                rows = cur.fetchall()
        keys = ('room','cleaner','started','finished','new_status','note','logged_at')
        log = [dict(zip(keys, r)) for r in rows]
        if log:
            return log
    except Exception:
        pass
    # fallback: JSON
    try:
        import json as _j, os as _o
        fp = _o.path.join(get_data_dir(), 'cleaning_log.json')
        with open(fp, encoding='utf-8') as f: return _j.load(f)
    except Exception:
        return []

def _cl_append(entry: dict):
    """Додає один запис у PostgreSQL, fallback → JSON."""
    _ensure_cleaning_log_table()
    try:
        from app.utils.db import get_conn
        with get_conn() as conn:
            with conn.cursor() as cur:
                cur.execute(
                    "INSERT INTO cleaning_log (room,cleaner,started,finished,new_status,note,logged_at) VALUES (%s,%s,%s,%s,%s,%s,%s)",
                    (str(entry.get('room','')), str(entry.get('cleaner','')),
                     str(entry.get('started','')), str(entry.get('finished','')),
                     str(entry.get('new_status','')), str(entry.get('note','')),
                     str(entry.get('logged_at','')))
                )
            conn.commit()
        return True
    except Exception:
        pass
    # fallback: JSON
    try:
        import json as _j, os as _o
        fp = _o.path.join(get_data_dir(), 'cleaning_log.json')
        try:
            with open(fp, encoding='utf-8') as f: log = _j.load(f)
        except Exception: log = []
        log.append(entry)
        with open(fp, 'w', encoding='utf-8') as f: _j.dump(log, f, ensure_ascii=False, indent=2)
    except Exception: pass
    return False

def _cl_update(idx_in_list: int, all_entries: list, updated: dict):
    """Оновлює один запис. idx_in_list — індекс у списку повернутому _cl_load()."""
    _ensure_cleaning_log_table()
    try:
        from app.utils.db import get_conn
        # Знаходимо id рядка в БД за позицією (ORDER BY id)
        with get_conn() as conn:
            with conn.cursor() as cur:
                cur.execute("SELECT id FROM cleaning_log ORDER BY id ASC")
                ids = [r[0] for r in cur.fetchall()]
            if idx_in_list < len(ids):
                row_id = ids[idx_in_list]
                with conn.cursor() as cur:
                    cur.execute(
                        "UPDATE cleaning_log SET room=%s,cleaner=%s,started=%s,finished=%s,new_status=%s,note=%s,logged_at=%s WHERE id=%s",
                        (str(updated.get('room','')), str(updated.get('cleaner','')),
                         str(updated.get('started','')), str(updated.get('finished','')),
                         str(updated.get('new_status','')), str(updated.get('note','')),
                         str(updated.get('logged_at','')), row_id)
                    )
                conn.commit()
                return True
    except Exception:
        pass
    return False

def _cl_clear():
    """Очищає весь журнал."""
    try:
        from app.utils.db import get_conn
        with get_conn() as conn:
            with conn.cursor() as cur:
                cur.execute("DELETE FROM cleaning_log")
            conn.commit()
    except Exception: pass
    try:
        import json as _j, os as _o
        fp = _o.path.join(get_data_dir(), 'cleaning_log.json')
        with open(fp,'w',encoding='utf-8') as f: _j.dump([],f)
    except Exception: pass

def _cl_save_all(log: list):
    """Перезаписує весь журнал (для міграції та дедуплікації)."""
    try:
        from app.utils.db import get_conn
        with get_conn() as conn:
            with conn.cursor() as cur:
                cur.execute("DELETE FROM cleaning_log")
                cur.executemany(
                    "INSERT INTO cleaning_log (room,cleaner,started,finished,new_status,note,logged_at) VALUES (%s,%s,%s,%s,%s,%s,%s)",
                    [(str(e.get('room','')), str(e.get('cleaner','')),
                      str(e.get('started','')), str(e.get('finished','')),
                      str(e.get('new_status','')), str(e.get('note','')),
                      str(e.get('logged_at',''))) for e in log]
                )
            conn.commit()
        return True
    except Exception: pass
    return False

def get_data_dir():
    """Повертає абсолютний шлях до папки data/ проекту. Завжди однаковий."""
    import os, sys
    # PyInstaller dist збірка: шукаємо data/ поруч з exe або в _internal/
    if getattr(sys, 'frozen', False):
        exe_dir = os.path.dirname(sys.executable)
        # Перевіряємо варіанти де може бути hotel_local_cache.db
        for candidate in [
            os.path.join(exe_dir, '_internal', 'data'),
            os.path.join(exe_dir, 'data'),
        ]:
            if os.path.exists(candidate):
                return candidate
        # Якщо не знайшли — створюємо поруч з exe
        d = os.path.join(exe_dir, 'data')
        os.makedirs(d, exist_ok=True)
        return d
    # Dev-режим: hotel2/app/ui/main_window.py → hotel2/data/
    base = os.path.dirname(os.path.abspath(__file__))
    d = os.path.normpath(os.path.join(base, '..', '..', 'data'))
    os.makedirs(d, exist_ok=True)
    return d

