def _get_app_settings_path():
    try:
        return os.path.join(get_data_dir(), 'app_settings.json')
    except Exception:
        return os.path.join(os.path.expanduser('~'), 'hotel_app_settings.json')

def _load_app_settings():
    """Читає app_settings.json з папки data/."""
    try:
        p = _get_app_settings_path()
        if _os.path.exists(p):
            with open(p, encoding='utf-8') as _asf:
                return json.load(_asf)
    except Exception:
        pass
    return {}

def _save_app_settings(updates: dict):
    """Зберігає ключі з updates у app_settings.json (merge, не перезаписує)."""
    try:
        p = _get_app_settings_path()
        cur = _load_app_settings()
        cur.update(updates)
        with open(p, 'w', encoding='utf-8') as _asf:
            json.dump(cur, _asf, ensure_ascii=False, indent=2)
    except Exception as _e:
        _logger.warning(f"_save_app_settings: {_e}")

# ── Прибиральниці: in-memory cache + PostgreSQL + local json fallback ──
_cleaners_cache = None          # in-memory cache
_cleaners_cache_ts = 0.0        # timestamp останнього завантаження

def _get_cleaners_db():
    """Читає прибиральниць з кешу (60с), потім БД, потім файл — без зависань."""
    import time, json as _jcls, os
    global _cleaners_cache, _cleaners_cache_ts
    now = time.monotonic()
    # Якщо кеш свіжий (< 60 секунд) — повертаємо одразу без запиту до БД
    if _cleaners_cache is not None and (now - _cleaners_cache_ts) < 60:
        return list(_cleaners_cache)
    # Спроба прочитати з БД з коротким timeout
    try:
        from app.utils.db import get_conn as _gcl
        with _gcl() as _ccl:
            _ccl.set_session(autocommit=False)
            with _ccl.cursor() as _curcl:
                _curcl.execute("""
                    CREATE TABLE IF NOT EXISTS hotel_settings
                    (key TEXT PRIMARY KEY, value TEXT)
                """)
                _ccl.commit()
                _curcl.execute("SELECT value FROM hotel_settings WHERE key='cleaners'")
                row = _curcl.fetchone()
                if row:
                    result = _jcls.loads(row[0]) or []
                    _cleaners_cache = result
                    _cleaners_cache_ts = now
                    return list(result)
    except Exception: pass
    # Fallback: local json (без мережі)
    try:
        with open(os.path.join(get_data_dir(),'cleaners.json'),encoding='utf-8') as _fp:
            result = _jcls.load(_fp)
            if result:
                # Авто-синхронізація: якщо в БД пусто — записуємо туди
                import threading as _thr_sync
                def _auto_sync():
                    try:
                        from app.utils.db import get_conn as _gcs
                        with _gcs() as _ccs:
                            with _ccs.cursor() as _curs:
                                _curs.execute("SELECT value FROM hotel_settings WHERE key='cleaners'")
                                row_s = _curs.fetchone()
                                if not row_s:
                                    import json as _jss
                                    val_s = _jss.dumps(result, ensure_ascii=False)
                                    _curs.execute("""INSERT INTO hotel_settings(key,value) VALUES('cleaners',%s)
                                        ON CONFLICT(key) DO NOTHING""", (val_s,))
                            _ccs.commit()
                    except Exception: pass
                _thr_sync.Thread(target=_auto_sync, daemon=True).start()
            _cleaners_cache = result
            _cleaners_cache_ts = now
            return list(result)
    except Exception: pass
    return list(_cleaners_cache) if _cleaners_cache is not None else []

def _save_cleaners_db(cleaners_list):
    """Зберігає прибиральниць в БД + локально + оновлює кеш."""
    import json as _jcls3, os, time
    global _cleaners_cache, _cleaners_cache_ts
    # Оновити кеш одразу — UI не підвисне
    _cleaners_cache = list(cleaners_list)
    _cleaners_cache_ts = time.monotonic()
    # Зберегти локально (швидко)
    try:
        with open(os.path.join(get_data_dir(),'cleaners.json'),'w',encoding='utf-8') as _fp2:
            _jcls3.dump(cleaners_list, _fp2, ensure_ascii=False, indent=2)
    except Exception: pass
    # Зберегти в БД у фоні — не блокуємо UI
    import threading
    def _db_save():
        try:
            from app.utils.db import get_conn as _gcl2
            with _gcl2() as _ccl2:
                with _ccl2.cursor() as _curcl2:
                    _curcl2.execute("""
                        CREATE TABLE IF NOT EXISTS hotel_settings
                        (key TEXT PRIMARY KEY, value TEXT)
                    """)
                    # Merge: read existing from DB, combine with new list (unique names)
                    _curcl2.execute("SELECT value FROM hotel_settings WHERE key='cleaners'")
                    _row_m = _curcl2.fetchone()
                    if _row_m:
                        try:
                            _existing = _jcls3.loads(_row_m[0]) or []
                        except Exception: _existing = []
                        # Union: new list wins order, add any DB-only names at end
                        _merged = list(cleaners_list)
                        for _n in _existing:
                            if _n and _n not in _merged:
                                _merged.append(_n)
                    else:
                        _merged = list(cleaners_list)
                    val = _jcls3.dumps(_merged, ensure_ascii=False)
                    _curcl2.execute("""
                        INSERT INTO hotel_settings(key,value) VALUES('cleaners',%s)
                        ON CONFLICT(key) DO UPDATE SET value=EXCLUDED.value
                    """, (val,))
                _ccl2.commit()
        except Exception: pass
    threading.Thread(target=_db_save, daemon=True).start()

