def get_session_start():
    """Повертає datetime початку поточної зміни або None.
    Читає opened_at з БД щоб .exe і Python показували однаковий час зміни.
    """
    import os, json, datetime as _dt
    try:
        from app.utils.db import query
        shift_id = get_current_shift_id()
        if shift_id:
            row = query("SELECT opened_at FROM shifts WHERE id=%s", (shift_id,), fetch='one')
            if row and row.get('opened_at'):
                oa = row['opened_at']
                # Якщо psycopg2 повернув aware datetime — конвертуємо в Київ
                if hasattr(oa, 'tzinfo') and oa.tzinfo is not None:
                    return oa.astimezone(_kyiv_tz()).replace(tzinfo=None)
                if isinstance(oa, str):
                    try:
                        oa_aware = _dt.datetime.fromisoformat(oa.replace(' ', 'T'))
                        if oa_aware.tzinfo is not None:
                            return oa_aware.astimezone(_kyiv_tz()).replace(tzinfo=None)
                        return oa_aware
                    except Exception:
                        return _dt.datetime.fromisoformat(oa.replace(' ','T').split('+')[0].split('.')[0])
                return oa
    except Exception:
        pass
    # Fallback — session.json
    try:
        sfile = os.path.join(get_data_dir(), 'session.json')
        with open(sfile, encoding='utf-8') as f:
            s = json.load(f)
        return _dt.datetime.fromisoformat(s['login_dt'])
    except Exception:
        pass
    return None

def _kyiv_tz():
    """Повертає часовий пояс Київ. Працює на Windows без tzdata."""
    try:
        from zoneinfo import ZoneInfo
        return ZoneInfo('Europe/Kyiv')
    except Exception:
        pass
    try:
        import pytz
        return pytz.timezone('Europe/Kyiv')
    except Exception:
        pass
    # Fallback: UTC+2 (зима) / UTC+3 (літо) — вибираємо UTC+2 як безпечний мінімум
    import datetime
    return datetime.timezone(datetime.timedelta(hours=2))

def get_current_shift_id():
    """Повертає shift_id поточної відкритої зміни.
    Пріоритет: зміна поточного юзера з БД → будь-яка відкрита зміна з БД → session.json.
    ВИПРАВЛЕННЯ: якщо юзер admin/manager і не має власної зміни — повертає
    будь-яку відкриту зміну БД (не чекає поки session.json оновиться bg-потоком).
    """
    import os, json
    # 1. Спробуємо отримати з БД — найточніший варіант
    try:
        from app.utils.db import query
        username = None
        try:
            sfile = os.path.join(get_data_dir(), 'session.json')
            with open(sfile, encoding='utf-8') as f:
                username = json.load(f).get('user')
        except Exception:
            pass
        if username:
            row = query(
                "SELECT id FROM shifts WHERE username=%s AND status='open' ORDER BY id DESC LIMIT 1",
                (username,), fetch='one')
        else:
            row = query(
                "SELECT id FROM shifts WHERE status='open' ORDER BY id DESC LIMIT 1",
                fetch='one')
        if row and row.get('id'):
            # Синхронізуємо session.json щоб наступного разу було актуально
            try:
                sfile = os.path.join(get_data_dir(), 'session.json')
                with open(sfile, encoding='utf-8') as f:
                    s = json.load(f)
                if s.get('shift_id') != row['id']:
                    s['shift_id'] = row['id']
                    with open(sfile, 'w', encoding='utf-8') as f:
                        json.dump(s, f, ensure_ascii=False, indent=2)
            except Exception:
                pass
            return row['id']
        # ── ВИПРАВЛЕННЯ: username є але зміни по ньому немає (admin/manager) ──
        # Не чекаємо session.json — одразу беремо будь-яку відкриту зміну з БД
        if username:
            row_any = query(
                "SELECT id FROM shifts WHERE status='open' ORDER BY id DESC LIMIT 1",
                fetch='one')
            if row_any and row_any.get('id'):
                # Синхронізуємо session.json
                try:
                    sfile = os.path.join(get_data_dir(), 'session.json')
                    with open(sfile, encoding='utf-8') as f:
                        s = json.load(f)
                    s['shift_id'] = row_any['id']
                    with open(sfile, 'w', encoding='utf-8') as f:
                        json.dump(s, f, ensure_ascii=False, indent=2)
                except Exception:
                    pass
                return row_any['id']
    except Exception:
        pass
    # 2. Fallback — session.json
    try:
        sfile = os.path.join(get_data_dir(), 'session.json')
        with open(sfile, encoding='utf-8') as f:
            s = json.load(f)
        return s.get('shift_id')
    except Exception:
        return None

def _cleanup_stale_shifts():
    """Закриває всі відкриті зміни КРІМ останньої — щоб в БД була тільки одна активна."""
    try:
        from app.utils.db import get_conn as _gcCL
        with _gcCL() as _cCL:
            with _cCL.cursor() as _curCL:
                # Знайти ID останньої відкритої зміни
                _curCL.execute("SELECT id FROM shifts WHERE status='open' ORDER BY id DESC LIMIT 1")
                _latest = _curCL.fetchone()
                if _latest:
                    # Закрити всі СТАРІШІ відкриті зміни
                    _curCL.execute(
                        "UPDATE shifts SET closed_at=NOW(), status='closed' "
                        "WHERE status='open' AND id < %s",
                        (_latest[0],))
                    closed = _curCL.rowcount
                    if closed > 0:
                        print(f"[shifts] Закрито {closed} застарілих змін, активна: #{_latest[0]}")
            _cCL.commit()
    except Exception as e:
        print(f"[shifts] cleanup error: {e}")

def _ensure_shifts_table():
    """Створює таблицю shifts і колонку payments.shift_id якщо немає."""
    from app.utils.db import query
    try:
        query("""CREATE TABLE IF NOT EXISTS shifts (
            id SERIAL PRIMARY KEY,
            username VARCHAR(100),
            full_name VARCHAR(200),
            opened_at TIMESTAMPTZ DEFAULT NOW(),
            closed_at TIMESTAMPTZ,
            status VARCHAR(20) DEFAULT 'open',
            opening_cash NUMERIC(10,2) DEFAULT 0,
            opening_deposits NUMERIC(10,2) DEFAULT 0
        )""", fetch=None)
        query("ALTER TABLE shifts ADD COLUMN IF NOT EXISTS opening_cash NUMERIC(10,2) DEFAULT 0", fetch=None)
        query("ALTER TABLE shifts ADD COLUMN IF NOT EXISTS opening_deposits NUMERIC(10,2) DEFAULT 0", fetch=None)
        query("ALTER TABLE payments ADD COLUMN IF NOT EXISTS shift_id INTEGER", fetch=None)
        query("""CREATE TABLE IF NOT EXISTS cash_transfers (
            id SERIAL PRIMARY KEY,
            shift_id INTEGER,
            amount NUMERIC(10,2) NOT NULL,
            reason TEXT NOT NULL,
            created_at TIMESTAMPTZ DEFAULT NOW(),
            username VARCHAR(100)
        )""", fetch=None)
    except Exception as e:
        print(f"shifts table ensure: {e}")

def save_session_start(user=None, force_new=False):
    """Зберігає початок зміни.
    
    ВИПРАВЛЕННЯ: Якщо користувач повторно входить ТОГО ЖЕ ДНЯ і Z-звіт
    ще не робився — зберігається СТАРИЙ login_dt, щоб каса не обнулялась.
    force_new=True використовується лише при закритті зміни (Z-звіт).
    """
    import os, json, datetime as _dt
    _ensure_shifts_table()
    from app.utils.db import query
    sfile = os.path.join(get_data_dir(), 'session.json')
    try:
        with open(sfile, encoding='utf-8') as f:
            s = json.load(f)
    except Exception:
        s = {}

    username = ''
    full_name = ''
    role = ''
    if user:
        full_name = user.get('full_name', '')
        username  = user.get('username') or full_name
        role      = user.get('role', '')
        s['full_name'] = full_name
        s['user']      = username
        s['role']      = role
    elif s.get('user'):
        username  = s.get('user', '')
        full_name = s.get('full_name', '')
        role      = s.get('role', '')

    now = _dt.datetime.now()

    # ── КЛЮЧОВА ЛОГІКА ──────────────────────────────────────────────────────
    # Адміністратор/менеджер — НІКОЛИ не створює нову зміну.
    # Підхоплює ID ЄДИНОЇ поточної відкритої зміни (рецепціоніста).
    if role in ('admin', 'manager') and not force_new:
        try:
            from app.utils.db import get_conn as _gcA
            with _gcA() as _cA:
                with _cA.cursor() as _curA:
                    _curA.execute(
                        "SELECT id FROM shifts WHERE status='open' ORDER BY id DESC LIMIT 1")
                    row_a = _curA.fetchone()
                    if row_a:
                        s['shift_id'] = row_a[0]
        except Exception:
            pass
        import json as _json_adm
        with open(sfile, 'w', encoding='utf-8') as f:
            _json_adm.dump(s, f, ensure_ascii=False, indent=2)
        return
    # ────────────────────────────────────────────────────────────────────────

    # Рецепціоніст: зміна продовжується якщо той самий юзер і не force_new
    existing_dt_str = s.get('login_dt', '')
    existing_user   = s.get('user', '')
    keep_existing = False
    if not force_new and existing_dt_str and username == existing_user:
        try:
            _dt.datetime.fromisoformat(existing_dt_str)
            # Перевірити чи справді зміна ще відкрита в БД
            row_chk = query(
                "SELECT id FROM shifts WHERE username=%s AND status='open' ORDER BY id DESC LIMIT 1",
                (username,), fetch='one')
            keep_existing = bool(row_chk)
        except Exception:
            pass

    if keep_existing:
        print(f"[session] Вхід {username} — зміна продовжується з {existing_dt_str}")
    else:
        # Нова зміна (після Z-звіту або перший вхід)
        s['login_dt'] = now.isoformat()
        s['login_at'] = now.strftime('%d.%m.%Y %H:%M:%S')
        try:
            query("UPDATE shifts SET closed_at=NOW(), status='closed' WHERE username=%s AND status='open'",
                  (username,), fetch=None)
        except Exception:
            pass
        # Запитати початковий залишок при відкритті нової зміни
        _opening_cash = 0.0
        _opening_deposits = 0.0
        try:
            # Отримати суму незакритих залогів з попередньої зміни
            _prev_deposits_row = query(
                "SELECT COALESCE(SUM(CASE WHEN note LIKE 'Залог%%' AND amount>0 THEN amount END),0)"
                " - COALESCE(ABS(SUM(CASE WHEN note LIKE 'Повернення залогу%%' THEN amount END)),0)"
                " AS dep_balance FROM payments",
                fetch='one')
            _prev_dep = float(_prev_deposits_row[0] if _prev_deposits_row else 0)
        except Exception:
            _prev_dep = 0.0

        try:
            import tkinter as _tk2
            import customtkinter as _ctk2
            _dlg = _ctk2.CTkToplevel()
            _dlg.title("📋 Відкриття зміни")
            _dlg.geometry("420x320")
            _dlg.grab_set()
            _dlg.attributes('-topmost', True)
            _dlg.configure(fg_color=C['bg'])
            _dlg.resizable(False, False)

            _f = _ctk2.CTkFrame(_dlg, fg_color=C['card'], corner_radius=12)
            _f.pack(fill='both', expand=True, padx=15, pady=15)

            _ctk2.CTkLabel(_f, text="💼  Відкриття нової зміни",
                           font=('Segoe UI', 15, 'bold'),
                           text_color=C['green']).pack(anchor='w', padx=15, pady=(15,5))
            _ctk2.CTkLabel(_f, text=f"Касир: {full_name}",
                           font=('Segoe UI', 11),
                           text_color=C['text2']).pack(anchor='w', padx=15, pady=(0,12))

            # Готівковий залишок
            _rf1 = _ctk2.CTkFrame(_f, fg_color=C['card2'], corner_radius=8); _rf1.pack(fill='x', padx=12, pady=4)
            _ctk2.CTkLabel(_rf1, text="💵 Готівковий залишок в касі:", font=('Segoe UI',12),
                           text_color=C['text']).pack(side='left', padx=10, pady=10)
            _e_cash = _ctk2.CTkEntry(_rf1, width=110, font=('Segoe UI',12)); _e_cash.pack(side='right', padx=10)
            _e_cash.insert(0, "0")

            # Залоги від попередньої зміни
            _rf2 = _ctk2.CTkFrame(_f, fg_color=C['card2'], corner_radius=8); _rf2.pack(fill='x', padx=12, pady=4)
            _ctk2.CTkLabel(_rf2, text=f"🔒 Залоги (передано від попередньої):", font=('Segoe UI',12),
                           text_color=C['text']).pack(side='left', padx=10, pady=10)
            _e_dep = _ctk2.CTkEntry(_rf2, width=110, font=('Segoe UI',12)); _e_dep.pack(side='right', padx=10)
            _e_dep.insert(0, str(int(_prev_dep)) if _prev_dep > 0 else "0")

            if _prev_dep > 0:
                _ctk2.CTkLabel(_f, text=f"ℹ️ Розрахунковий залог від попередньої зміни: {_prev_dep:.0f}₴",
                               font=('Segoe UI', 10), text_color=C['yellow']).pack(anchor='w', padx=15, pady=(2,0))

            _result = [False]
            def _confirm():
                nonlocal _opening_cash, _opening_deposits
                try: _opening_cash = float(_e_cash.get() or 0)
                except: _opening_cash = 0.0
                try: _opening_deposits = float(_e_dep.get() or 0)
                except: _opening_deposits = 0.0
                _result[0] = True
                _dlg.destroy()

            def _skip():
                _result[0] = True
                _dlg.destroy()

            _bf = _ctk2.CTkFrame(_f, fg_color='transparent'); _bf.pack(fill='x', padx=12, pady=12)
            _ctk2.CTkButton(_bf, text="✅ Відкрити зміну", command=_confirm,
                            fg_color=C['green'], font=('Segoe UI',12,'bold'), height=40).pack(side='left', padx=(0,6), fill='x', expand=True)
            _ctk2.CTkButton(_bf, text="⏭ Пропустити", command=_skip,
                            fg_color=C['card2'], font=('Segoe UI',11), height=40).pack(side='left', fill='x', expand=True)

            _dlg.wait_window()
        except Exception as _de:
            print(f"shift open dialog error: {_de}")

        try:
            from app.utils.db import get_conn as _gcS
            with _gcS() as _cS:
                with _cS.cursor() as _curS:
                    _curS.execute(
                        "INSERT INTO shifts (username, full_name, opened_at, status, opening_cash, opening_deposits) "
                        "VALUES (%s, %s, NOW(), 'open', %s, %s) RETURNING id",
                        (username, full_name, _opening_cash, _opening_deposits))
                    row = _curS.fetchone()
                    if row:
                        s['shift_id'] = row[0]
                _cS.commit()
        except Exception as e:
            print(f"shift create error: {e}")
    # ────────────────────────────────────────────────────────────────────────

    with open(sfile, 'w', encoding='utf-8') as f:
        json.dump(s, f, ensure_ascii=False, indent=2)

def _suppress_tk_errors():
    """Придушує попередження 'invalid command name' від CustomTkinter на Linux."""
    import tkinter as _tk
    _orig_report = getattr(_tk.Tk, 'report_callback_exception', None)
    def _safe_report(self, exc, val, tb):
        import traceback
        msg = str(val)
        if 'invalid command name' in msg:
            return  # тихо ігноруємо
        if _orig_report:
            _orig_report(self, exc, val, tb)
        else:
            traceback.print_exception(exc, val, tb)
    _tk.Tk.report_callback_exception = _safe_report

_suppress_tk_errors()

