# ══════════════════════════════════════════════════════
# CHECKBOX РРО — інтеграція
# ══════════════════════════════════════════════════════

_CHECKBOX_CFG = {
    'enabled': False,
    'login': '',
    'password': '',
    'cashier_pin': '',
    'cash_register_id': '',
    'token': '',           # кешований JWT токен
    'shift_id': '',        # поточна зміна
}

def _cbx_load():
    import json, os
    cfg = os.path.join(os.path.dirname(os.path.abspath(__file__)), 'checkbox_cfg.json')
    if os.path.exists(cfg):
        try: _CHECKBOX_CFG.update(json.load(open(cfg, encoding='utf-8')))
        except Exception: pass

def _cbx_save():
    import json, os
    cfg = os.path.join(os.path.dirname(os.path.abspath(__file__)), 'checkbox_cfg.json')
    try: json.dump(_CHECKBOX_CFG, open(cfg,'w',encoding='utf-8'), ensure_ascii=False, indent=2)
    except Exception: pass

_cbx_load()

CBX_URL = 'https://api.checkbox.ua/api/v1'

def _cbx_headers():
    h = {'Content-Type': 'application/json', 'X-Client-Name': 'HotelPMS', 'X-Client-Version': '1.0'}
    if _CHECKBOX_CFG.get('token'):
        h['Authorization'] = f"Bearer {_CHECKBOX_CFG['token']}"
    return h

def _cbx_request(method, path, data=None):
    import urllib.request, json
    url = CBX_URL + path
    body = json.dumps(data).encode('utf-8') if data else None
    req = urllib.request.Request(url, data=body, headers=_cbx_headers(), method=method)
    try:
        with urllib.request.urlopen(req, timeout=5) as r:
            return json.loads(r.read().decode('utf-8'))
    except urllib.error.HTTPError as e:
        err = e.read().decode('utf-8', errors='replace')
        try: msg = json.loads(err).get('message', err)
        except Exception: msg = err
        raise RuntimeError(f"Checkbox {e.code}: {msg}")

def cbx_login():
    """Авторизація касира — отримати JWT токен."""
    resp = _cbx_request('POST', '/cashier/signin', {
        'login': _CHECKBOX_CFG['login'],
        'password': _CHECKBOX_CFG['password'],
    })
    _CHECKBOX_CFG['token'] = resp['access_token']
    _cbx_save()
    return resp['access_token']

def cbx_open_shift():
    """Відкрити зміну."""
    if not _CHECKBOX_CFG.get('token'):
        cbx_login()
    resp = _cbx_request('POST', '/shifts/open', {
        'cashier_pin': _CHECKBOX_CFG['cashier_pin'],
    })
    _CHECKBOX_CFG['shift_id'] = resp.get('id','')
    _cbx_save()
    return resp

def cbx_close_shift():
    """Закрити зміну."""
    if not _CHECKBOX_CFG.get('token'):
        cbx_login()
    resp = _cbx_request('POST', '/shifts/close')
    _CHECKBOX_CFG['shift_id'] = ''
    _cbx_save()
    return resp

def cbx_get_shift():
    """Отримати поточну зміну."""
    if not _CHECKBOX_CFG.get('token'):
        cbx_login()
    return _cbx_request('GET', '/shifts/opened')

def cbx_create_receipt(amount: float, payment_type: str, description: str,
                        guest_name: str = '', phone: str = '') -> dict:
    """
    Пробити фіскальний чек.
    payment_type: 'CASH' або 'CARD'
    amount: сума в гривнях
    """
    if not _CHECKBOX_CFG.get('token'):
        cbx_login()

    # Перевіряємо відкриту зміну
    if not _CHECKBOX_CFG.get('shift_id'):
        try:
            sh = cbx_get_shift()
            _CHECKBOX_CFG['shift_id'] = sh.get('id','')
        except Exception:
            cbx_open_shift()

    amount_coins = int(round(amount * 100))  # Checkbox приймає копійки

    payload = {
        'goods': [{
            'good': {
                'code': 'hotel_service',
                'name': description[:128],
                'price': amount_coins,
            },
            'quantity': 1000,  # 1.000 одиниці
        }],
        'payments': [{
            'type': payment_type,  # 'CASH' або 'CARD'
            'value': amount_coins,
        }],
    }
    if guest_name:
        payload['header'] = f"Гість: {guest_name}"
    if phone:
        payload['delivery'] = {'phone': phone}

    resp = _cbx_request('POST', '/receipts/sell', payload)
    return resp

import threading

def cbx_auto_receipt(amount: float, payment_type: str, description: str, 
                     guest_name: str = '', phone: str = ''):
    """Пробити чек у фоновому потоці, щоб інтерфейс не тормозив."""
    if not _CHECKBOX_CFG.get('enabled'):
        return None

    def _threaded_task():
        try:
            # Сам запит до API (може тривати 5-10 секунд)
            resp = cbx_create_receipt(amount, payment_type, description, guest_name, phone)
            receipt_id = resp.get('id','')
            url = f"https://check.checkbox.ua/{receipt_id}"
            log_info(f"[Checkbox] Чек успішно створено: {url}")
        except Exception as e:
            log_error("Помилка Checkbox", e)
            import tkinter as _tkroot
            _roots = _tkroot._default_root  # noqa
            try:
                if _roots is not None and _roots.winfo_exists():
                    _roots.after(0, lambda msg=str(e): messagebox.showwarning(
                        "⚠️ Checkbox РРО",
                        f"Не вдалося пробити чек:\n{msg}"
                    ))
            except Exception:
                pass

    # Запускаємо в окремому потоці
    threading.Thread(target=_threaded_task, daemon=True).start()


def cbx_ask_and_receipt(amount: float, payment_type: str, description: str,
                         guest_name: str = '', phone: str = ''):
    """При готівці — запитати чи друкувати фіскальний чек. При картці — одразу."""
    if not _CHECKBOX_CFG.get('enabled'):
        return None
    if payment_type == 'CASH':
        # Запитати користувача
        answer = messagebox.askyesno(
            "🧾 Фіскальний чек",
            f"Пробити фіскальний чек на суму {amount:.0f}₴?\n({description})",
            icon='question'
        )
        if not answer:
            return None
    return cbx_auto_receipt(amount, payment_type, description, guest_name, phone)

# ── Налаштування POS-принтера (зберігаємо між сесіями) ─────────────────
_POS_SETTINGS = {'enabled': True, 'port': '127.0.0.1', 'baudrate': 9101, 'type': 'direct'}

def _load_pos_settings():
    import json, os
    cfg = os.path.join(os.path.dirname(os.path.abspath(__file__)), 'pos_printer.json')
    if os.path.exists(cfg):
        try:
            _POS_SETTINGS.update(json.load(open(cfg, encoding='utf-8')))
        except Exception: pass

def _save_pos_settings():
    import json, os
    cfg = os.path.join(os.path.dirname(os.path.abspath(__file__)), 'pos_printer.json')
    try: json.dump(_POS_SETTINGS, open(cfg,'w',encoding='utf-8'), ensure_ascii=False, indent=2)
    except Exception: pass

_load_pos_settings()


def _print_pos(text):
    """Відправити текст на POS термо-принтер."""
    import subprocess, os, tempfile
    lines = text.encode('cp1251', errors='replace')

    # ESC/POS команди
    ESC = b'\x1b'
    INIT    = ESC + b'@'          # ініціалізація
    BOLD_ON = ESC + b'E\x01'
    BOLD_OFF= ESC + b'E\x00'
    CENTER  = ESC + b'a\x01'
    LEFT    = ESC + b'a\x00'
    CUT     = b'\x1d' + b'V\x41\x03'  # часткове відрізання

    typ = _POS_SETTINGS.get('type','serial')

    if typ == 'usb_raw':
        # Windows: пряме відправлення на USB принтер через ім'я
        port = _POS_SETTINGS.get('port','USB001')
        try:
            import win32print
            h = win32print.OpenPrinter(port)
            try:
                j = win32print.StartDocPrinter(h, 1, ("Receipt", None, "RAW"))
                win32print.StartPagePrinter(h)
                win32print.WritePrinter(h, INIT + lines + b'\n\n\n' + CUT)
                win32print.EndPagePrinter(h)
                win32print.EndDocPrinter(h)
            finally:
                win32print.ClosePrinter(h)
            return True
        except ImportError:
            # без win32print — через copy команду
            tmp = tempfile.mktemp(suffix='.bin')
            with open(tmp,'wb') as f: f.write(INIT + lines + b'\n\n\n' + CUT)
            subprocess.run(f'copy /b "{tmp}" "{port}"', shell=True)
            os.unlink(tmp)
            return True

    elif typ == 'serial':
        import serial as _serial
        port = _POS_SETTINGS.get('port','COM1')
        baud = int(_POS_SETTINGS.get('baudrate', 9600))
        try:
            with _serial.Serial(port, baud, timeout=3) as s:
                s.write(INIT + lines + b'\n\n\n' + CUT)
            return True
        except Exception as e:
            raise RuntimeError(f"COM-порт {port}: {e}")

    elif typ == 'network':
        import socket
        host = _POS_SETTINGS.get('port','192.168.1.100')
        tport= int(_POS_SETTINGS.get('baudrate', 9100))
        try:
            with socket.create_connection((host, tport), timeout=5) as s:
                s.sendall(INIT + lines + b'\n\n\n' + CUT)
            return True
        except Exception as e:
            raise RuntimeError(f"Мережа {host}:{tport}: {e}")

    elif typ == 'lp':
        # Linux: lp команда
        tmp = tempfile.mktemp(suffix='.bin')
        with open(tmp,'wb') as f: f.write(INIT + lines + b'\n\n\n' + CUT)
        port = _POS_SETTINGS.get('port','')
        cmd = ['lp', '-d', port, '-o', 'raw', tmp] if port else ['lp', '-o', 'raw', tmp]
        subprocess.run(cmd)
        os.unlink(tmp)
        return True

    elif typ == 'direct':
        # Прямий друк на локальний принтер (exe запускається локально)
        import os, subprocess, tempfile, datetime
        fname_d = os.path.join(tempfile.gettempdir(),
            f"receipt_{datetime.datetime.now().strftime('%Y%m%d_%H%M%S')}.txt")
        with open(fname_d, 'w', encoding='utf-8') as _f:
            _f.write(text)
        errors = []
        printed = False

        # Метод 1: PowerShell Out-Printer (найнадійніший без pywin32)
        try:
            ps = f'Get-Content -Encoding UTF8 -Path \"{fname_d}\" | Out-Printer'
            r = subprocess.run(
                ['powershell', '-WindowStyle', 'Hidden', '-NoProfile', '-Command', ps],
                timeout=20, capture_output=True
            )
            if r.returncode == 0:
                printed = True
            else:
                errors.append(f"PS: {r.stderr.decode(errors='replace').strip()[:100]}")
        except Exception as e:
            errors.append(f"PS: {e}")

        # Метод 2: notepad /p (друкує і закриває)
        if not printed:
            try:
                r2 = subprocess.run(
                    ['notepad.exe', '/p', fname_d],
                    timeout=15, capture_output=True
                )
                printed = True  # notepad /p не повертає помилку навіть якщо принтер не знайдено
            except Exception as e:
                errors.append(f"notepad: {e}")

        if printed:
            return True
        else:
            raise RuntimeError("\n".join(errors) or "Невідома помилка друку")

    elif typ == 'tcp_server':
        # Підключення до локального print_server.py на ПК користувача
        import socket as _sock
        host = _POS_SETTINGS.get('port', '127.0.0.1')
        tport = int(_POS_SETTINGS.get('baudrate', 9101))
        raw = text.encode('utf-8')
        size = len(raw).to_bytes(4, 'big')
        try:
            with _sock.create_connection((host, tport), timeout=5) as s:
                s.sendall(size + raw)
                resp = s.recv(3)
            if resp == b'OK':
                return True
            raise RuntimeError(f"Сервер відповів: {resp}")
        except Exception as e:
            raise RuntimeError(f"Print-сервер {host}:{tport} — {e}")

    return False


