def _win_print_file(fname, text):
    """Друк на локальному принтері — app працює локально (PyInstaller exe)."""
    import os, subprocess, tempfile

    if os.name != 'nt':
        try: subprocess.Popen(['lp', fname])
        except Exception: pass
        return

    printed = False

    # Метод 1: win32print — найнадійніший, прямий RAW друк
    try:
        import win32print, win32ui, win32con
        from win32 import win32api
        pname = win32print.GetDefaultPrinter()
        # Друк через win32api.ShellExecute — відкриває і друкує без вікна
        win32api.ShellExecute(0, "print", fname, None, ".", 0)
        printed = True
    except ImportError:
        pass
    except Exception as e:
        print(f"[win32api err] {e}")

    # Метод 2: PowerShell Out-Printer (тихий режим)
    if not printed:
        try:
            ps = f'Get-Content -Path "{fname}" | Out-Printer'
            r = subprocess.run(
                ['powershell', '-WindowStyle', 'Hidden', '-NoProfile', '-Command', ps],
                timeout=15, capture_output=True
            )
            if r.returncode == 0:
                printed = True
            else:
                print(f"[PS] {r.stderr.decode(errors='replace')}")
        except Exception as e:
            print(f"[PS err] {e}")

    # Метод 3: cmd print (вбудований в Windows)
    if not printed:
        try:
            subprocess.run(f'print "{fname}"', shell=True, timeout=10)
            printed = True
        except Exception as e:
            print(f"[cmd print err] {e}")

    if not printed:
        # Fallback — відкрити у блокноті
        try: subprocess.Popen(['notepad.exe', fname])
        except Exception: pass
        messagebox.showinfo('📄',
            f'Відкрийте файл і надрукуйте вручну (Ctrl+P):\n{fname}')


def print_text(title, lines):
    """Завжди показує вікно-перегляд чеку з кнопками Роздрукувати / Відміна."""
    import datetime, os, tempfile
    now = datetime.datetime.now().strftime('%d.%m.%Y %H:%M:%S')
    _W = 52
    _HOTEL = (
        f"{'='*_W}\n"
        f"  Готель 'Королівська Бочка'\n"
        f"  вул. Івана Гонти, 68\n"
        f"  тел: +38097-558-27-27\n"
        f"{'='*_W}\n"
        f"{title:^{_W}}\n"
        f"{'='*_W}\n"
        f"{now:^{_W}}\n"
        f"{'='*_W}\n"
    )
    text = _HOTEL
    for line in lines:
        text += line + '\n'
    text += '='*_W + '\n'

    # Зберегти у файл
    fname = os.path.join(tempfile.gettempdir(),
        f"receipt_{datetime.datetime.now().strftime('%Y%m%d_%H%M%S')}.txt")
    with open(fname, 'w', encoding='utf-8') as f:
        f.write(text)

    # ── Вікно перегляду чеку — завжди показується ──
    win = ctk.CTkToplevel()
    win.title(f"🧾  {title}")
    win.configure(fg_color=C['bg'])
    win.attributes('-topmost', True)
    try:
        sw = win.winfo_screenwidth(); sh = win.winfo_screenheight()
        win.geometry(f"540x640+{(sw-540)//2}+{(sh-640)//2}")
    except Exception:
        win.geometry('540x640')
    win.lift(); win.focus_force()

    # Заголовок
    hdr = ctk.CTkFrame(win, fg_color=C['card'], corner_radius=0)
    hdr.pack(fill='x')
    lbl(hdr, f"🧾  {title}", 14, True, C['accent']).pack(side='left', padx=16, pady=10)

    # Тіло чеку
    tb = ctk.CTkTextbox(win, font=('Courier New', 11), fg_color=C['card'],
                        text_color=C['text'], wrap='none', corner_radius=8)
    tb.pack(fill='both', expand=True, padx=15, pady=(10, 5))
    tb.insert('end', text)
    tb.configure(state='disabled')

    # Підказка
    hint_text = "💡 POS-принтер: натисніть «Роздрукувати»" if _POS_SETTINGS.get('enabled') else "💡 Натисніть «Роздрукувати» → Ctrl+P у блокноті"
    lbl(win, hint_text, 10, color=C['text2']).pack(pady=(0, 4))

    # Кнопки
    bf = ctk.CTkFrame(win, fg_color='transparent')
    bf.pack(fill='x', padx=15, pady=(0, 14))

    def do_print():
        if _POS_SETTINGS.get('enabled'):
            def _pos_thread():
                try:
                    _print_pos(text)
                    import tkinter as _tkr
                    root = _tkr._default_root
                    if root is not None:
                        try:
                            root.after(0, lambda: messagebox.showinfo('✅', 'Надруковано на POS-принтері!'))
                        except Exception: pass
                except Exception as ex:
                    import tkinter as _tkr
                    root = _tkr._default_root
                    try:
                        if root is not None and root.winfo_exists():
                            root.after(0, lambda msg=str(ex): messagebox.showerror(
                                "🖨 POS помилка", f"Не вдалося надрукувати:\n{msg}"))
                    except Exception: pass
            threading.Thread(target=_pos_thread, daemon=True).start()
            win.destroy()
        else:
            _win_print_file(fname, text)
            win.destroy()

    def do_cancel():
        win.destroy()

    btn(bf, '🖨  Роздрукувати', do_print, C['green'], 200, height=40).pack(side='left', padx=4)
    btn(bf, '✖  Відміна', do_cancel, C['red'], 140, height=40).pack(side='right', padx=4)

    # Закрити по Escape
    win.bind('<Escape>', lambda e: do_cancel())

def bind_mousewheel(widget):
    """Прив'язати скрол колесом миші — глобально через bind_all."""
    def _scroll(event):
        try:
            w = event.widget
            while w:
                if isinstance(w, ctk.CTkScrollableFrame):
                    try: w._parent_canvas.yview_scroll(int(-1*(event.delta/120)), 'units')
                    except Exception: pass
                    return
                try: w = w.master
                except Exception: break
        except Exception: pass
    try:
        widget.bind_all('<MouseWheel>', _scroll, add='+')
    except Exception:
        pass


def _dlg_remove_topmost(w):
    """Знімає topmost з вікна якщо воно ще існує."""
    try:
        if w.winfo_exists():
            w.attributes('-topmost', False)
    except Exception:
        pass

# ── Глобальний кеш геометрій вікон (назва → "WxH") ────────────────────────────
# Зберігається у JSON-файлі між перезапусками програми.
import json as _json_geom

def _get_geom_path():
    try:
        base = _os.path.normpath(_os.path.join(
            _os.path.dirname(_os.path.abspath(__file__)), '..', '..', 'data'))
        _os.makedirs(base, exist_ok=True)
        return _os.path.join(base, 'window_sizes.json')
    except Exception:
        return _os.path.join(_os.path.expanduser('~'), 'hotel_window_sizes.json')

def _load_geom_cache():
    try:
        p = _get_geom_path()
        if _os.path.exists(p):
            with open(p, 'r', encoding='utf-8') as _f:
                return _json_geom.load(_f)
    except Exception:
        pass
    return {}

# ── Глобальний конфіг логіки (logic_config.json) ───────────────────────────
def _get_logic_cfg():
    """Повертає поточний конфіг логіки (з кешем на 30 сек)."""
    import time as _time
    _now = _time.time()
    if hasattr(_get_logic_cfg, '_cache') and _now - _get_logic_cfg._ts < 30:
        return _get_logic_cfg._cache
    import json as _jlg
    default = {
        "cash": {
            "deposit_notes":      ["Залог при заселенні", "Залог при бронюванні", "deposit:"],
            "refund_notes":       ["Повернення залогу"],
            "deposit_any":        ["Залог", "deposit"],
            "advance_notes":      ["Аванс"],
            "service_notes":      ["Послуга:", "Додаткові послуги"],
            "exclude_from_total": ["Залог", "deposit", "Повернення"]
        },
        "categories": {
            "bani":    ["бан", "saun", "[tariff:hour]"],
            "besidky": ["бесід", "альтанк"]
        },
        "restaurant": {
            "excluded_categories":  ["штрафи", "бані", "бесідки"],
            "unlimited_categories": ["до_кави", "кава-чай", "кава_чай", "кава", "чай", "coffee", "tea"]
        }
    }
    try:
        base = _os.path.normpath(_os.path.join(
            _os.path.dirname(_os.path.abspath(__file__)), '..', '..', 'data'))
        p2 = _os.path.join(base, 'logic_config.json')
        if _os.path.exists(p2):
            with open(p2, 'r', encoding='utf-8') as _f2:
                saved = _jlg.load(_f2)
            for section, vals in default.items():
                if section not in saved:
                    saved[section] = vals
                elif isinstance(vals, dict):
                    for k, v in vals.items():
                        if k not in saved[section]:
                            saved[section][k] = v
            default = saved
    except Exception:
        pass
    _get_logic_cfg._cache = default
    _get_logic_cfg._ts = _now
    return default

_DLG_GEOM_CACHE: dict = _load_geom_cache()

def _dlg_save_geom(win, key):
    """Зберігає розмір вікна у кеш і JSON при кожній зміні."""
    try:
        geom = win.geometry()          # "WxH+X+Y"
        size_part = geom.split('+')[0]  # тільки "WxH"
        if 'x' in size_part:
            ww, wh = (int(v) for v in size_part.split('x'))
            if ww > 100 and wh > 100:  # ігноруємо нульові/мінімальні значення
                if _DLG_GEOM_CACHE.get(key) == size_part:
                    return  # не перезаписувати якщо не змінилось
                _DLG_GEOM_CACHE[key] = size_part
                try:
                    with open(_get_geom_path(), 'w', encoding='utf-8') as _f:
                        _json_geom.dump(_DLG_GEOM_CACHE, _f, ensure_ascii=False, indent=2)
                except Exception:
                    pass
    except Exception:
        pass

def dlg_win(parent, title, size="500x400", modal=True):
    w = ctk.CTkToplevel(parent)
    w.title(title)
    w.configure(fg_color=C['bg'])
    # Ключ кешу — очищений заголовок (без емодзі та спецсимволів для надійності)
    _cache_key = title.strip()
    try:
        # Якщо є збережений розмір — використовуємо його
        saved = _DLG_GEOM_CACHE.get(_cache_key)
        if saved and 'x' in saved:
            ww, wh = (int(v) for v in saved.split('x'))
        else:
            ww, wh = (int(x) for x in size.split('x'))
        root = parent.winfo_toplevel()
        root.update_idletasks()
        sw = root.winfo_screenwidth()
        sh = root.winfo_screenheight()
        # Підігнати розмір під екран з відступом 40px
        ww = min(ww, sw - 40)
        wh = min(wh, sh - 40)
        rx = root.winfo_rootx()
        ry = root.winfo_rooty()
        rw = root.winfo_width()
        rh = root.winfo_height()
        x = rx + (rw - ww) // 2
        y = ry + (rh - wh) // 2
        x = max(0, min(x, sw - ww))
        y = max(0, min(y, sh - wh))
        w.geometry(f"{ww}x{wh}+{x}+{y}")
        w.transient(root)
        w.resizable(True, True)
        w.minsize(min(ww, 300), min(wh, 200))
        # Зберігати розмір при кожній зміні вікна
        w.bind('<Configure>', lambda e, _k=_cache_key, _w=w: _dlg_save_geom(_w, _k))
    except Exception:
        w.geometry(size)
    try:
        w.attributes('-topmost', True)
        w.lift(); w.focus_force()
        # Знімаємо topmost через 200мс — вікно вже видно, не треба блокувати
        w.after(200, lambda: _dlg_remove_topmost(w))
    except Exception:
        w.lift(); w.focus_force()
    return w

def _center_window(win, w, h, parent=None):
    """Центрує вікно та підганяє розмір під екран."""
    try:
        root = parent.winfo_toplevel() if parent else win
        root.update_idletasks()
        sw = root.winfo_screenwidth()
        sh = root.winfo_screenheight()
        w = min(w, sw - 40)
        h = min(h, sh - 40)
        if parent:
            rx = root.winfo_rootx(); ry = root.winfo_rooty()
            rw = root.winfo_width(); rh = root.winfo_height()
            x = rx + (rw - w) // 2
            y = ry + (rh - h) // 2
        else:
            x = (sw - w) // 2; y = (sh - h) // 2
        x = max(0, min(x, sw - w))
        y = max(0, min(y, sh - h))
        win.geometry(f"{w}x{h}+{x}+{y}")
        win.resizable(True, True)
        win.minsize(min(w, 400), min(h, 300))
    except Exception:
        win.geometry(f"{w}x{h}")

def row_frm(parent):
    f = ctk.CTkFrame(parent, fg_color='transparent')
    f.pack(fill='x', padx=12, pady=3)
    return f

def field_row(parent, label_text, entry_widget=None, width=140):
    f = row_frm(parent)
    ctk.CTkLabel(f, text=label_text, font=('Segoe UI',11),
                 text_color=C['text2'], width=width, anchor='w').pack(side='left')
    if entry_widget:
        entry_widget.pack(side='left')
    return f

