def _relogin(root_win):
    """Закрити поточну сесію і показати вікно авторизації."""
    try:
        root_win.destroy()
    except Exception:
        pass
    try:
        setup = SetupWindow()
        setup.mainloop()
        if getattr(setup, 'user', None):
            app = HotelApp(setup.user)
            app.mainloop()
    except Exception:
        pass

def _pg_direct_test(cfg: dict) -> tuple:
    """Тест підключення до PostgreSQL НАПРЯМУ через psycopg2."""
    import socket as _sock_t
    try:
        import psycopg2 as _pg
    except ImportError:
        try:
            import importlib as _il, sys as _sys_t
            if 'app.utils.db' in _sys_t.modules:
                _il.reload(_sys_t.modules['app.utils.db'])
            from app.utils.db import test_connection as _tc
            return _tc()
        except Exception as _fe:
            return False, f"psycopg2 недоступний: {_fe}"
    try:
        host = str(cfg.get('host', 'localhost')).strip()
        port = int(cfg.get('port', 5432))
        try:
            with _sock_t.create_connection((host, port), timeout=3): pass
        except (_sock_t.timeout, OSError) as _se:
            return False, f"Немає зв'язку з {host}:{port} ({_se})"
        _c = _pg.connect(host=host, port=port,
            dbname=cfg.get('dbname', cfg.get('database', 'hotel')),
            user=cfg.get('user', 'hotel'), password=cfg.get('password', ''),
            connect_timeout=5)
        _c.close()
        return True, "OK"
    except Exception as _e:
        return False, str(_e)


class SetupWindow(ctk.CTk):
    def __init__(self):
        super().__init__()
        self.title("Готель Королівська Бочка")
        def _silent(exc, val, tb):
            if any(x in str(val) for x in ('check_dpi_scaling','click_animation','update','_draw_engine')):
                return
            import traceback; traceback.print_exception(exc, val, tb)
        self.report_callback_exception = _silent
        self.configure(fg_color=C['bg'])
        self.resizable(True, True)
        self.user = None
        apply_style()
        self._build()
        self.update_idletasks()
        sw, sh = self.winfo_screenwidth(), self.winfo_screenheight()
        w, h = min(520, sw - 40), min(620, sh - 40)
        x = (sw - w) // 2; y = (sh - h) // 2
        self.geometry(f"{w}x{h}+{x}+{y}")
        self.minsize(400, 480)

    def _build(self):
        # Прокручуваний контейнер
        scroll = ctk.CTkScrollableFrame(self, fg_color=C['bg'])
        scroll.pack(fill='both', expand=True)

        hdr = card(scroll); hdr.pack(fill='x', padx=25, pady=(20,8))
        lbl(hdr,"🏨 Готель Королівська Бочка",26,True,C['accent']).pack(pady=(15,3))
        lbl(hdr,"Система управління готелем",12,color=C['text2']).pack(pady=(0,15))

        db = card(scroll); db.pack(fill='x', padx=25, pady=5)
        lbl(db,"⚙️  База даних",13,True).pack(anchor='w', padx=12, pady=(10,6))
        cfg = self._load_cfg()
        self.dbf = {}
        for label_text, key in [("Host",'host'),("Port",'port'),("Database",'dbname'),("User",'user'),("Password",'password')]:
            f = row_frm(db)
            ctk.CTkLabel(f,text=label_text,font=('Segoe UI',11),text_color=C['text2'],width=90,anchor='w').pack(side='left')
            e = ent(f, w=300, show='*' if key=='password' else None)
            e.insert(0, str(cfg.get(key,''))); e.pack(side='left')
            self.dbf[key] = e
        bf = ctk.CTkFrame(db, fg_color='transparent'); bf.pack(fill='x', padx=12, pady=(6,12))
        btn(bf,"🔗 Тест",self._test,C['green'],100).pack(side='left',padx=(0,6))
        btn(bf,"💾 Зберегти",self._save_cfg,C['card2'],120).pack(side='left')
        self.db_lbl = lbl(bf,"",11,color=C['green']); self.db_lbl.pack(side='left',padx=10)

        lg = card(scroll); lg.pack(fill='x', padx=25, pady=5)
        lbl(lg,"🔐  Вхід",13,True).pack(anchor='w', padx=12, pady=(10,6))
        f1=row_frm(lg); ctk.CTkLabel(f1,text="Логін",font=('Segoe UI',11),text_color=C['text2'],width=80,anchor='w').pack(side='left')
        self.e_user=ent(f1,w=310); self.e_user.pack(side='left')
        f2=row_frm(lg); ctk.CTkLabel(f2,text="Пароль",font=('Segoe UI',11),text_color=C['text2'],width=80,anchor='w').pack(side='left')
        self.e_pass=ent(f2,w=310,show='*'); self.e_pass.pack(side='left')
        # ── Галочка "Запам'ятати логін" ──
        self._remember_var = tk.BooleanVar(value=False)
        chk_row = ctk.CTkFrame(lg, fg_color='transparent'); chk_row.pack(anchor='w', padx=12, pady=(2,4))
        ctk.CTkCheckBox(chk_row, text="Запам'ятати логін", variable=self._remember_var,
                        font=('Segoe UI',11), text_color=C['text2'],
                        fg_color=C['accent'], hover_color=C['accent']).pack(side='left')
        # ── Підвантажити збережений логін ──
        _lc = self._load_login_cache()
        if _lc.get('remember'):
            self.e_user.insert(0, _lc.get('username',''))
            self.e_pass.insert(0, _lc.get('password',''))
            self._remember_var.set(True)
        btn(lg,"▶  Увійти",self._login,height=42).pack(fill='x',padx=12,pady=(6,15))
        self.e_pass.bind('<Return>', lambda e: self._login())
        # Відступ знизу щоб кнопка не обрізалась
        ctk.CTkFrame(scroll, fg_color='transparent', height=20).pack()

    def _load_login_cache(self):
        try:
            p = os.path.normpath(os.path.join(os.path.dirname(os.path.abspath(__file__)),'..','..','config','login_cache.json'))
            with open(p) as f: return json.load(f)
        except: return {}

    def _save_login_cache(self, username, password, remember):
        p = os.path.normpath(os.path.join(os.path.dirname(os.path.abspath(__file__)),'..','..','config','login_cache.json'))
        os.makedirs(os.path.dirname(p), exist_ok=True)
        data = {'username': username, 'password': password, 'remember': remember} if remember else {'remember': False}
        with open(p, 'w') as f: json.dump(data, f)

    def _save_user_profile_cache(self, user_dict):
        """Зберігає профіль користувача в SQLite для офлайн-авторизації."""
        try:
            import sqlite3 as _sq3c, json as _jc
            db_path = _sync_mgr._db_path
            with _sq3c.connect(db_path, timeout=5) as _c:
                _c.execute("""CREATE TABLE IF NOT EXISTS user_cache (
                    username TEXT PRIMARY KEY,
                    password TEXT,
                    user_json TEXT,
                    updated_at TEXT DEFAULT (datetime('now','localtime'))
                )""")
                _c.execute("""INSERT OR REPLACE INTO user_cache (username, password, user_json)
                              VALUES (?, ?, ?)""",
                           (user_dict.get('username',''),
                            user_dict.get('password',''),
                            _jc.dumps({k: str(v) for k, v in user_dict.items() if v is not None})))
        except Exception as _e:
            log_error("_save_user_profile_cache", _e)

    def _get_user_from_cache(self, username, password):
        """Авторизація з локального SQLite-кешу коли PG недоступний."""
        try:
            import sqlite3 as _sq3c, json as _jc
            db_path = _sync_mgr._db_path
            with _sq3c.connect(db_path, timeout=5) as _c:
                _c.execute("CREATE TABLE IF NOT EXISTS user_cache (username TEXT PRIMARY KEY, password TEXT, user_json TEXT, updated_at TEXT)")
                row = _c.execute(
                    "SELECT user_json FROM user_cache WHERE username=? AND password=?",
                    (username, password)
                ).fetchone()
                if row:
                    return _jc.loads(row[0])
        except Exception as _e:
            log_error("_get_user_from_cache", _e)
        return None

    def _load_cfg(self):
        try:
            p = os.path.normpath(os.path.join(os.path.dirname(os.path.abspath(__file__)),'..','..','config','db.json'))
            with open(p) as f: return json.load(f)
        except: return {'host':'localhost','port':5432,'dbname':'hotel','user':'hotel','password':'hotel'}

    def _save_cfg(self):
        cfg = {k:(int(v.get()) if k=='port' else v.get()) for k,v in self.dbf.items()}
        p = os.path.normpath(os.path.join(os.path.dirname(os.path.abspath(__file__)),'..','..','config','db.json'))
        os.makedirs(os.path.dirname(p), exist_ok=True)
        with open(p,'w') as f: json.dump(cfg,f,indent=4)

    def _test(self):
        self._save_cfg()
        cfg = {k: (int(v.get()) if k == 'port' else v.get()) for k, v in self.dbf.items()}
        ok, msg = _pg_direct_test(cfg)
        try:
            _sync_mgr._last_check = 0.0
            _sync_mgr._online = ok
        except Exception: pass
        self.db_lbl.configure(text="✓ OK" if ok else f"✗ {msg[:50]}",
            text_color=C['green'] if ok else C['red'])

    def _login(self):
        self._save_cfg()
        username = self.e_user.get().strip()
        password = self.e_pass.get().strip()
        _is_offline_login = False
        try:
            from app.utils.db import query, get_conn as _gcL
            # Перевірити чи PG доступний
            _pg_ok = _sync_mgr.check_online()
            if not _pg_ok:
                # ── ОФЛАЙН: авторизація з кешу ──
                u = self._get_user_from_cache(username, password)
                if not u:
                    messagebox.showerror("Сервер недоступний",
                        "Сервер БД офлайн.\nДля офлайн-режиму потрібно хоча б раз увійти при активному сервері.\nПеревірте підключення.")
                    return
                _is_offline_login = True
                # Показати попередження про офлайн-режим
                messagebox.showwarning("⚠️ Офлайн-режим",
                    "Сервер БД недоступний. Всі зміни зберігаються локально та синхронізуються при відновленні зв'язку.")
            else:
                u = query("SELECT * FROM users WHERE username=%s AND password=%s AND active=TRUE",
                          (username, password), fetch='one')
            if not u:
                messagebox.showerror("Помилка","Невірний логін або пароль"); return

            role = u.get('role','')
            username = u.get('username','')

            # Зберегти логін якщо увімкнена галочка
            try:
                remember = self._remember_var.get()
                self._save_login_cache(self.e_user.get().strip(), self.e_pass.get().strip(), remember)
            except Exception: pass
            # Зберегти профіль для офлайн-авторизації (якщо є зв'язок)
            if not _is_offline_login:
                try: self._save_user_profile_cache(u)
                except Exception: pass

            # Адміністратор/менеджер — може зайти завжди, не створює нову зміну
            if role in ('admin','manager'):
                self.user = u
                self.destroy()
                return

            # Рецепціоніст — перевірка відкритої зміни
            try:
                with _gcL() as _cL:
                    with _cL.cursor() as _curL:
                        _curL.execute(
                            "SELECT id, username, full_name, opened_at FROM shifts "
                            "WHERE status='open' ORDER BY id DESC LIMIT 1"
                        )
                        colsL = [d[0] for d in _curL.description]
                        rowL  = _curL.fetchone()
                        open_shift = dict(zip(colsL, rowL)) if rowL else None
            except Exception:
                open_shift = None

            if open_shift:
                owner = open_shift.get('username','')
                if owner == username:
                    # Це його зміна — продовжуємо
                    self.user = u; self.destroy()
                else:
                    # Чужа незакрита зміна
                    opened = open_shift.get('opened_at','')
                    owner_name = open_shift.get('full_name') or owner
                    shift_id_open = open_shift.get('id')
                    msg = ("Є відкрита зміна:\n"
                           "Касир: " + str(owner_name) + "\n"
                           "Відкрита: " + str(opened) + "\n\n"
                           "Попросіть " + str(owner_name) + " закрити зміну (Z-звіт)\n"
                           "або зверніться до адміністратора.")
                    # Адмін/менеджер може примусово закрити чужу зміну
                    if role in ('admin', 'manager'):
                        force = messagebox.askyesno(
                            "Зміна не закрита",
                            msg + "\n\nВи — адміністратор. Примусово закрити цю зміну?",
                            icon='warning'
                        )
                        if force:
                            try:
                                from app.utils.db import get_conn as _gc_f
                                with _gc_f() as _conn_f:
                                    with _conn_f.cursor() as _cur_f:
                                        if shift_id_open:
                                            _cur_f.execute(
                                                "UPDATE shifts SET closed_at=NOW(), status='closed' WHERE id=%s",
                                                (shift_id_open,)
                                            )
                                        else:
                                            _cur_f.execute(
                                                "UPDATE shifts SET closed_at=NOW(), status='closed' WHERE status='open'"
                                            )
                                    _conn_f.commit()
                                messagebox.showinfo("✅ Зміну закрито",
                                    f"Зміну касира {owner_name} примусово закрито.\nМожна входити.")
                                self.user = u; self.destroy()
                            except Exception as _fe:
                                messagebox.showerror("Помилка", f"Не вдалося закрити зміну:\n{_fe}")
                    else:
                        messagebox.showerror("Зміна не закрита", msg)
            else:
                # Немає відкритої зміни — входимо і створюємо нову
                self.user = u; self.destroy()
        except Exception as e:
            messagebox.showerror("Помилка БД", f"{e}")

# ══════════════════════════════════════════════════════
class HotelApp(ctk.CTk):
    def _quit(self):
        try:
            import sys
            self.after_cancel_all() if hasattr(self,'after_cancel_all') else None
        except Exception:
            pass
        try:
            self.eval('destroy .')
        except Exception:
            pass
        import sys; sys.exit(0)

    def __init__(self, user):
        super().__init__()
        self.user = user
        # Придушити помилки від CTk внутрішніх after() при знищенні віджетів
        # Це нешкідливо — виникає коли після pack_forget/destroy ще є заплановані after()
        _CTK_NOISE = (
            'check_dpi_scaling', 'click_animation', 'update',
            '_draw_engine', 'invalid command name', 'after script',
        )
        def _silent_callback_error(exc, val, tb):
            msg = str(val)
            if any(x in msg for x in _CTK_NOISE):
                return  # ігнорувати CTk internal помилки — не виводити в консоль
            import traceback
            traceback.print_exception(exc, val, tb)
        self.report_callback_exception = _silent_callback_error

        # Також перехопити Tcl-рівневі "invalid command name NNNN..." помилки
        import sys
        if sys.stderr is not None:
            _orig_stderr_write = sys.stderr.write
            def _filtered_stderr(msg):
                if 'invalid command name' in msg and 'after' in msg:
                    return
                if any(x in msg for x in ('check_dpi_scaling', 'click_animation', '_draw_engine')):
                    return
                _orig_stderr_write(msg)
            sys.stderr.write = _filtered_stderr
        self.configure(fg_color=C['bg'])
        self.title(f"🏨 Готель Королівська Бочка — {user['full_name']}")
        apply_style()
        self.minsize(900, 600)
        self.resizable(True, True)
        self.protocol("WM_DELETE_WINDOW", self._on_close)
        self.after(10, self._maximize_window)

        # ── UI будується ПЕРШИМ — вікно зʼявляється миттєво ──────────────────
        self._skeleton_frame = None
        self._build()

        # ── Ініціалізація БД у фоні — не блокує рендер ───────────────────────
        # _save_session_start + _ensure_rooms_status виконують 7+ запитів до БД
        # (включно з ALTER TABLE). При повільному зʼєднанні (>200ms) це давало
        # чорний екран на кілька секунд ПЕРЕД тим як вікно взагалі намалювалось.
        import threading as _thr_init
        def _bg_init():
            # 0. Мігрувати SQLite схему ПЕРШИМ — ще до install_cache,
            #    щоб перша синхронізація не давала WARNING про deposit_amount
            try: self._migrate_sqlite_cache()
            except Exception as _ei: log_error("bg_init: sqlite_migrate", _ei)
            # 1. Підключити кеш — патчить query(), далі читання йдуть з SQLite
            if _install_db_cache is not None:
                try: _install_db_cache()
                except Exception as _ei: log_error("bg_init: db_cache", _ei)
            # 1b. Патч logic.get_rooms — при офлайні повертає дані з SQLite кешу
            try:
                import app.modules.logic as _logic_mod
                _orig_get_rooms = _logic_mod.get_rooms
                def _get_rooms_with_sqlite_fallback():
                    try:
                        result = _orig_get_rooms() or []
                        if result:
                            return result
                    except Exception:
                        pass
                    # Fallback → SQLite
                    return _get_rooms_from_sqlite() or []
                _logic_mod.get_rooms = _get_rooms_with_sqlite_fallback
            except Exception as _ep:
                log_error("bg_init: patch get_rooms", _ep)
            # 2. Міграція PostgreSQL БД + сесія
            try: self._save_session_start()
            except Exception as _ei: log_error("bg_init: session", _ei)
            try: _cleanup_stale_shifts()
            except Exception: pass
            # 3. Тестовий режим — автоочистка даних після входу
            try: self._test_mode_cleanup_on_login()
            except Exception as _ei: log_error("bg_init: test_mode_cleanup", _ei)
            # 4. Запустити менеджер offline-синхронізації
            try:
                _sync_mgr.start()
                # При відкритті зміни — завантажити актуальні дані з PG
                shift_id = get_current_shift_id()
                _sync_mgr.on_shift_open(shift_id)
                log_info(f"[OfflineSync] Менеджер запущено, shift_id={shift_id}")
            except Exception as _ei:
                log_error("bg_init: offline_sync", _ei)
        _thr_init.Thread(target=_bg_init, daemon=True).start()

    def _save_session_start(self):
        save_session_start(self.user)
        self._ensure_rooms_status()

    def _on_sync_status_change(self, online: bool):
        """Callback при зміні статусу синхронізації (викликається з фонового потоку)."""
        try:
            if self.winfo_exists():
                self.after(0, self._update_sync_badge)
        except Exception:
            pass
        # При відновленні зв'язку — автоматично вивантажити офлайн-зміни в PG
        if online:
            import threading as _thr_sync
            def _auto_flush():
                try:
                    pending = _sync_mgr.pending_count()
                    if pending > 0:
                        log_info(f"[OfflineSync] Відновлено зв'язок, вивантажую {pending} операцій у PG...")
                        result = _sync_mgr.flush_to_pg()
                        log_info(f"[OfflineSync] Flush: ok={result['ok']} fail={result['fail']}")
                        if result['ok'] > 0:
                            # Оновити UI після синхронізації
                            try:
                                if self.winfo_exists():
                                    self.after(0, lambda: self._notify_sync_done(result))
                            except Exception: pass
                except Exception as _fe:
                    log_error("auto_flush", _fe)
            _thr_sync.Thread(target=_auto_flush, daemon=True).start()

    def _notify_sync_done(self, result):
        """Сповіщення після успішного auto-flush."""
        try:
            pending_left = _sync_mgr.pending_count()
            msg = f"✅ Зв'язок відновлено. Синхронізовано {result['ok']} операцій."
            if result['fail'] > 0:
                msg += f"\n⚠️ Не вдалось: {result['fail']} (буде повтор)."
            if pending_left == 0:
                log_info(msg)
                # Тихе сповіщення через badge
                self._update_sync_badge()
        except Exception:
            pass

    def _run_update(self, src_path):
        """Копіює src_path у всі цільові файли (ті самі що в ручному оновленні) і перезапускає."""
        import os as _ou, shutil as _shu, sys as _syu, subprocess as _spu
        import tkinter.messagebox as _mbu

        # Перевіряємо що файл справжній Python-скрипт
        try:
            with open(src_path, 'r', encoding='utf-8', errors='ignore') as _tf:
                _head = _tf.read(500)
            if 'import' not in _head and 'def ' not in _head and 'class ' not in _head:
                _mbu.showerror("Помилка оновлення", "Завантажений файл не є Python-скриптом.")
                return
        except Exception as _ve:
            _mbu.showerror("Помилка", "Не вдалось перевірити файл: " + str(_ve)); return

        # Ті самі цільові шляхи що й у ручному оновленні
        def _get_targets():
            _ts = []
            FIXED = [
                'C:\\hotel2\\app\\ui\\main_window.py',
                'C:\\hotel2\\dist\\HotelPMS\\app\\ui\\main_window.py',
            ]
            for fw in FIXED:
                _n = _ou.path.normpath(fw)
                if _n not in _ts: _ts.append(_n)
            _cur = _ou.path.abspath(__file__)
            if _cur not in _ts: _ts.append(_cur)
            _base = _cur
            for _ in range(6):
                _base = _ou.path.dirname(_base)
                for _extra in [
                    _ou.path.join(_base, 'dist', 'HotelPMS', 'app', 'ui', 'main_window.py'),
                    _ou.path.join(_base, 'dist', 'HotelPMS', '_internal', 'app', 'ui', 'main_window.py'),
                ]:
                    _nrm = _ou.path.normpath(_extra)
                    if _nrm not in _ts and _ou.path.exists(_nrm): _ts.append(_nrm)
            return _ts

        _targets = _get_targets()
        _ts_str = "\n".join("  " + chr(8226) + " " + t for t in _targets)
        _sz = _ou.path.getsize(src_path) // 1024

        if not _mbu.askyesno("Замінити файл програми?",
            "Звідки: main_window.py  (" + str(_sz) + " КБ)\n\nКуди:\n" + _ts_str +
            "\n\nФайл буде замінено і програма перезапуститься автоматично.\n"
            "Збірка EXE НЕ потрібна " + chr(8212) + " просто перезапуск."):
            return

        _errors = []; _ok = 0
        for _tgt in _targets:
            try:
                _ou.makedirs(_ou.path.dirname(_tgt), exist_ok=True)
                if _ou.path.exists(_tgt): _shu.copy2(_tgt, _tgt + '.bak')
                _shu.copy2(src_path, _tgt); _ok += 1
            except Exception as _ce:
                _errors.append(_ou.path.basename(_tgt) + ": " + str(_ce))

        if _errors and _ok == 0:
            _mbu.showerror("Помилка", "Не вдалось скопіювати:\n" + "\n".join(_errors)); return
        if _errors:
            _mbu.showwarning("Частково", "Оновлено " + str(_ok) + " файлів.\n" + "\n".join(_errors))

        try:
            if getattr(_syu, 'frozen', False):
                _spu.Popen([_syu.executable] + _syu.argv[1:])
            else:
                _spu.Popen([_syu.executable] + _syu.argv)
            self.after(500, self.destroy)
        except Exception:
            _mbu.showinfo("Оновлено", "Оновлено " + str(_ok) + " файлів.\nПерезапустіть програму вручну.")


    def _check_mega_update_bg(self):
        """Фонова перевірка оновлень на MEGA при запуску."""
        import threading as _thr_mu
        def _bg():
            try:
                import urllib.request as _ur2, re as _re2, os as _os_mu, sys as _sys_mu
                # Читаємо збережене посилання або дефолтне
                try:
                    _upd_cfg = _load_app_settings()
                    MEGA = _upd_cfg.get('update_url', '') or "https://mega.nz/file/hg8nQQrD#sSav2kaJjhuQH6un01zrtWoqjyGq6L-vBrVRTbq7jH0"
                except Exception:
                    MEGA = "https://mega.nz/file/hg8nQQrD#sSav2kaJjhuQH6un01zrtWoqjyGq6L-vBrVRTbq7jH0"
                # Конвертуємо Google Drive/Dropbox у прямі посилання
                import re as _reu2
                m_gd = _reu2.search(r'drive\.google\.com/file/d/([a-zA-Z0-9_-]+)', MEGA)
                if m_gd:
                    MEGA = f"https://drive.google.com/uc?export=download&id={m_gd.group(1)}"
                elif 'dropbox.com' in MEGA:
                    MEGA = _reu2.sub(r'[?&]dl=0', '', MEGA).rstrip('?') + ('&' if '?' in MEGA else '?') + 'dl=1'
                req = _ur2.Request(MEGA, headers={"User-Agent": "Mozilla/5.0"})
                with _ur2.urlopen(req, timeout=10) as resp:
                    raw = resp.read()
                # Якщо отримали py-файл — порівнюємо розміри
                if b'def ' in raw[:2000] or b'import ' in raw[:2000]:
                    html = ""; sm_size = len(raw)
                else:
                    html = raw.decode("utf-8", errors="ignore"); sm_size = 0
                sm = _re2.search(r'"s"\s*:\s*(\d+)', html)
                if not sm and not sm_size: return
                remote_size = sm_size if sm_size else int(sm.group(1))
                if getattr(_sys_mu, "frozen", False):
                    _cur = _os_mu.path.join(_os_mu.path.dirname(_sys_mu.executable), "app", "ui", "main_window.py")
                else:
                    _cur = _os_mu.path.abspath(__file__)
                cur_size = _os_mu.path.getsize(_cur) if _os_mu.path.exists(_cur) else 0

                # Порівнюємо: спочатку по версії (якщо є), потім по розміру
                has_update = False
                update_info = ""
                try:
                    import re as _rver
                    # Шукаємо версію в завантаженому файлі
                    remote_ver = None
                    if sm_size and raw:
                        vm = _rver.search(rb'APP_VERSION[^=]*=[^"]*"([^"]+)"', raw)
                        if vm: remote_ver = vm.group(1).decode('utf-8', errors='ignore')
                    # Шукаємо версію в поточному файлі
                    cur_ver = None
                    try:
                        if _os_mu.path.exists(_cur):
                            with open(_cur, 'rb') as _cf:
                                _ch = _cf.read(4000)
                            cvm = _rver.search(rb'APP_VERSION[^=]*=[^"]*"([^"]+)"', _ch)
                            if cvm: cur_ver = cvm.group(1).decode('utf-8', errors='ignore')
                    except Exception: pass

                    if remote_ver and cur_ver and remote_ver != cur_ver:
                        has_update = True
                        update_info = f"v{cur_ver} → v{remote_ver}"
                    elif remote_size > 0 and remote_size != cur_size:
                        has_update = True
                        update_info = f"{cur_size//1024} КБ → {remote_size//1024} КБ"
                except Exception:
                    if remote_size > 0 and remote_size != cur_size:
                        has_update = True
                        update_info = f"{cur_size//1024} КБ → {remote_size//1024} КБ"

                if has_update:
                    def _show_banner(info=update_info, dl_url=MEGA, dl_raw=raw if sm_size else None):
                        try:
                            if hasattr(self, "_upd_banner"):
                                try: self._upd_banner.destroy()
                                except Exception: pass
                            self._upd_banner = ctk.CTkFrame(self, fg_color="#1a3a1a", height=42)
                            self._upd_banner.place(relx=0.5, y=2, anchor="n", relwidth=0.75)
                            tk.Label(self._upd_banner,
                                text=f"  🆕 Доступне оновлення програми ({info})  ",
                                font=("Segoe UI", 11), fg="#aaffaa", bg="#1a3a1a").pack(side="left", padx=10, pady=8)

                            def _do_install_now():
                                """Встановити зараз — без переходу в налаштування."""
                                import threading as _thi, os as _osi, tempfile as _tmpi
                                try: self._upd_banner.place_forget()
                                except Exception: pass

                                # Якщо файл вже є в пам'яті (завантажили раніше)
                                if dl_raw and len(dl_raw) > 10000:
                                    _tmp = _os_mu.path.join(_tmpi.gettempdir(), 'main_window_update.py')
                                    with open(_tmp, 'wb') as _tf: _tf.write(dl_raw)
                                    self._run_update(_tmp)
                                    return

                                # Інакше — завантажуємо і встановлюємо
                                _prog = ctk.CTkToplevel(self)
                                _prog.title("Оновлення")
                                _prog.geometry("380x110")
                                _prog.configure(fg_color=C['bg'])
                                _prog.grab_set()
                                _lbl_p = lbl(_prog, "⬇️ Завантаження оновлення...", 12)
                                _lbl_p.pack(pady=(20,8))
                                _bar = ctk.CTkProgressBar(_prog, width=320)
                                _bar.pack(pady=4); _bar.set(0); _bar.start()

                                def _dl_bg():
                                    try:
                                        import urllib.request as _ur_i
                                        opener = _ur_i.build_opener(_ur_i.HTTPCookieProcessor())
                                        req_i = _ur_i.Request(dl_url, headers={"User-Agent":"Mozilla/5.0"})
                                        with opener.open(req_i, timeout=30) as _r:
                                            _data = _r.read()
                                        _tmp = _os_mu.path.join(_tmpi.gettempdir(), 'main_window_update.py')
                                        with open(_tmp, 'wb') as _tf: _tf.write(_data)
                                        def _done():
                                            try: _prog.destroy()
                                            except Exception: pass
                                            self._run_update(_tmp)
                                        self.after(0, _done)
                                    except Exception as _de:
                                        def _err():
                                            try: _bar.stop(); _lbl_p.configure(text=f"❌ Помилка: {_de}")
                                            except Exception: pass
                                        self.after(0, _err)
                                _thi.Thread(target=_dl_bg, daemon=True).start()

                            ctk.CTkButton(self._upd_banner, text="⬇️ Встановити зараз",
                                command=_do_install_now,
                                fg_color="#27ae60", hover_color="#1e8449",
                                font=("Segoe UI", 11, "bold"), height=28, width=180).pack(side="left", padx=4)
                            ctk.CTkButton(self._upd_banner, text="Пізніше",
                                command=lambda: self._show_frame("settings"),
                                fg_color="#444", hover_color="#555",
                                font=("Segoe UI", 10), height=28, width=90).pack(side="left", padx=2)
                            ctk.CTkButton(self._upd_banner, text="✕",
                                command=lambda: self._upd_banner.place_forget(),
                                fg_color="transparent", hover_color="#333",
                                font=("Segoe UI", 11), height=28, width=30).pack(side="right", padx=4)
                        except Exception: pass
                    try: self.after(0, _show_banner)
                    except Exception: pass
            except Exception: pass
        _thr_mu.Thread(target=_bg, daemon=True).start()

    def _update_sync_badge(self):
        """Оновлює індикатор синхронізації в сайдбарі."""
        try:
            if not self.winfo_exists():
                return
            online = _sync_mgr.is_online()
            pending = _sync_mgr.pending_count()
            if online and pending == 0:
                self._sync_dot.configure(text_color=C['green'])
                self._sync_lbl.configure(text=" ☁ Синхронізовано", text_color=C['text2'])
                self._sync_count_lbl.configure(text="")
                self._sync_badge.configure(fg_color=C['card2'])
            elif online and pending > 0:
                self._sync_dot.configure(text_color=C['yellow'])
                self._sync_lbl.configure(text=" ☁ Вивантаження...", text_color=C['yellow'])
                self._sync_count_lbl.configure(text=f"{pending} оп.")
                self._sync_badge.configure(fg_color='#2a2500')
            else:
                self._sync_dot.configure(text_color=C['red'])
                self._sync_lbl.configure(text=" ☁ Офлайн-режим", text_color=C['red'])
                self._sync_count_lbl.configure(
                    text=f"{pending} оп. в черзі" if pending > 0 else "", text_color=C['yellow'])
                self._sync_badge.configure(fg_color='#2e1414')
            # Повторне оновлення через 15 секунд
            if getattr(self, '_db_check_running', False):
                self.after(15000, self._update_sync_badge)
        except Exception:
            pass

    def _test_mode_cleanup_on_login(self):
        """Fallback ТІЛЬКИ якщо програма аварійно завершилась під час тест-режиму.
        При звичайному перелогіні — НЕ чіпаємо тест-режим, він має зберігатись.
        Аварійне завершення визначаємо за наявністю спеціального lock-файлу."""
        import tempfile as _tmpf
        _lock_path = _os.path.join(_os.path.dirname(_get_app_settings_path()), '_hotel_running.lock')
        s = _load_app_settings()
        if s.get('test_mode_active') and s.get('test_mode_started_at'):
            # Перевіряємо: якщо lock-файл НЕ існує — це аварійний restart, скидаємо флаг
            # Якщо існує — це нормальний перелогін, режим залишаємо активним
            if not _os.path.exists(_lock_path):
                log_info("[TEST MODE] Виявлено аварійне завершення під час тест-режиму — скидаємо флаг (дані очистить адмін вручну)")
                _save_app_settings({'test_mode_active': False, 'test_mode_started_at': None})
            else:
                log_info("[TEST MODE] Перелогін під час тест-режиму — режим залишається активним")
        # Створюємо lock-файл — він видаляється при нормальному завершенні програми
        try:
            with open(_lock_path, 'w') as _lf:
                import datetime as _dtlk
                _lf.write(str(_dtlk.datetime.now()))
        except Exception:
            pass

    def refresh_test_banner(self):
        """Оновлює банер тест-режиму в сайдбарі. Викликається зі SettingsFrame."""
        try:
            s = _load_app_settings()
            active = s.get('test_mode_active', False)
            since  = s.get('test_mode_started_at', '')[:16]
            if active:
                self._test_banner.configure(fg_color='#7c3a00')
                self._test_banner_lbl.configure(
                    text=f"🧪 ТЕСТОВИЙ РЕЖИМ\nз {since}",
                    text_color='#ffcc44')
                self._test_banner.pack(fill='x', padx=0, pady=0)
            else:
                self._test_banner.pack_forget()
        except Exception:
            pass

    def _ensure_rooms_status(self):
        """Міграція: status/deposit на rooms; видаляє CHECK constraint на services."""
        from app.utils.db import query
        try: query("ALTER TABLE rooms ADD COLUMN IF NOT EXISTS status VARCHAR(20) DEFAULT 'free'", fetch=None)
        except Exception: pass
        try: query("UPDATE rooms SET status='free' WHERE status IS NULL", fetch=None)
        except Exception: pass
        try: query("ALTER TABLE rooms ADD COLUMN IF NOT EXISTS deposit_amount NUMERIC(10,2) DEFAULT 0", fetch=None)
        except Exception: pass
        # Видалити обмеження CHECK яке забороняє нові категорії (бані, бесідки, штрафи)
        try: query("ALTER TABLE services DROP CONSTRAINT IF EXISTS services_category_check", fetch=None)
        except Exception: pass
        try: query("ALTER TABLE services DROP CONSTRAINT IF EXISTS services_cat_check", fetch=None)
        except Exception: pass
        try: query("ALTER TABLE services ALTER COLUMN category TYPE VARCHAR(100)", fetch=None)
        except Exception: pass
        # ── ВИПРАВЛЕННЯ: Міграція локального SQLite-кешу ────────────────────
        # Якщо основна БД вже має deposit_amount, а локальний SQLite — ні,
        # кеш виводить WARNING при кожній синхронізації. Виправляємо тут.
        self._migrate_sqlite_cache()

    def _migrate_sqlite_cache(self):
        """Додає відсутні колонки до локального SQLite кешу щоб прибрати WARNING-и.
        ВАЖЛИВО: викликається ДО _install_db_cache() щоб перша синхронізація вже
        мала правильну схему і не генерувала WARNING-и.
        """
        try:
            import sqlite3 as _sq
        except ImportError:
            # sqlite3 відсутній (Python з Microsoft Store) — кеш недоступний взагалі
            import logging as _l
            _l.getLogger('hotel').warning(
                "sqlite3 не знайдено — локальний кеш вимкнено. "
                "Встановіть Python з https://www.python.org/downloads/ "
                "з галочкою 'tcl/tk and IDLE'."
            )
            return

        # Шукаємо шлях до SQLite файлу
        db_path = None
        try:
            from app.utils.db_cache import _cache_instance as _ci
            db_path = getattr(_ci, '_db_path', None) or getattr(_ci, 'db_path', None)
        except Exception:
            pass
        if not db_path:
            db_path = os.path.join(get_data_dir(), 'hotel_local_cache.db')

        if not db_path or not os.path.exists(str(db_path)):
            return

        # Всі ALTER TABLE що можуть бути відсутні в старому кеші
        _migrations = [
            "ALTER TABLE rooms ADD COLUMN deposit_amount REAL DEFAULT 0",
            "ALTER TABLE rooms ADD COLUMN status TEXT DEFAULT 'free'",
            "ALTER TABLE bookings ADD COLUMN deposit_amount REAL DEFAULT 0",
            "ALTER TABLE bookings ADD COLUMN deposit_paid INTEGER DEFAULT 0",
            "ALTER TABLE bookings ADD COLUMN notes TEXT DEFAULT ''",
            "ALTER TABLE services ADD COLUMN quantity REAL DEFAULT 0",
            "ALTER TABLE services ADD COLUMN stock REAL DEFAULT 0",
        ]
        try:
            with _sq.connect(str(db_path)) as _sc:
                for _sql in _migrations:
                    try: _sc.execute(_sql)
                    except Exception: pass  # вже існує — OK
                _sc.commit()
        except Exception:
            pass

    def _maximize_window(self):
        try:
            self.state('zoomed')          # Windows
        except Exception:
            try:
                self.attributes('-zoomed', True)  # Linux/GTK
            except Exception:
                sw = self.winfo_screenwidth()
                sh = self.winfo_screenheight()
                self.geometry(f"{sw}x{sh}+0+0")

    def _on_close(self):
        self._db_check_running = False
        try:
            _sync_mgr.stop()
        except Exception:
            pass
        # Видаляємо lock-файл при нормальному завершенні
        try:
            _lock_path = _os.path.join(_os.path.dirname(_get_app_settings_path()), '_hotel_running.lock')
            if _os.path.exists(_lock_path):
                _os.remove(_lock_path)
        except Exception:
            pass
        import sys; sys.exit(0)

    def _check_db_status(self):
        """Перевіряє підключення до БД і оновлює індикатор-бейдж у сайдбарі."""
        if not getattr(self, '_db_check_running', False):
            return
        import threading, time as _time
        
        # 🔧 ВИПРАВЛЕННЯ: Добавити флаг для вимкнення ping якщо він вішає
        _ping_timeout_count = getattr(self, '_ping_timeout_count', 0)
        if _ping_timeout_count > 2:
            # Якщо ping вішав більше 2 разів - вимкнемо його
            self._db_lbl.configure(text=" 🗄 БД: ping вимкнено", text_color=C['yellow'])
            return
        
        def _ping():
            try:
                from app.utils.db import get_conn
                t0 = _time.perf_counter()
                # 🔧 ВИПРАВЛЕННЯ: Додати timeout щоб уникнути зависання
                try:
                    import socket
                    socket.setdefaulttimeout(2)  # 2 секунди timeout для всіх операцій
                except Exception:
                    pass
                
                with get_conn() as _c:
                    with _c.cursor() as _cur:
                        _cur.execute("SELECT 1")
                ms = int((_time.perf_counter() - t0) * 1000)
                self._ping_timeout_count = 0  # Reset лічильник успішних ping
                return True, ms
            except Exception as e:
                #記錄timeout
                self._ping_timeout_count = _ping_timeout_count + 1
                return False, 0
        
        def _run():
            ok, ms = _ping()
            def _update_ui():
                try:
                    if not self.winfo_exists(): return
                    if ok:
                        clr = C['green'] if ms < 50 else C['yellow'] if ms < 200 else C['red']
                        self._db_dot.configure(text_color=clr)
                        self._db_lbl.configure(text=" 🗄 БД: підключено", text_color=C['green'])
                        self._db_ping_lbl.configure(text=f"{ms}ms", text_color=clr)
                        try: self._db_badge.configure(fg_color='#162416')
                        except Exception: pass
                    else:
                        self._db_dot.configure(text_color=C['red'])
                        self._db_lbl.configure(text=" 🗄 БД: немає зв'язку", text_color=C['red'])
                        self._db_ping_lbl.configure(text="✗", text_color=C['red'])
                        try: self._db_badge.configure(fg_color='#2e1414')
                        except Exception: pass
                    if getattr(self, '_db_check_running', False):
                        self.after(10000, self._check_db_status)
                except Exception:
                    pass
            try:
                if self.winfo_exists():
                    self.after(0, _update_ui)
            except Exception:
                pass
        # 🔧 ВИПРАВЛЕННЯ: Запустити ping в окремому потоці з daemon=True для автоматичного завершення
        threading.Thread(target=_run, daemon=True).start()

