        btn(sb_top,"🚪 Вийти",self._quit,C['red'],190,height=34).pack(padx=10,pady=(2,12))

        # ── Банер тестового режиму (прихований якщо режим вимкнено) ──
        self._test_banner = ctk.CTkFrame(sb_top, fg_color='#7c3a00', corner_radius=0)
