# SEARCHABLE DROPDOWN — пошукове поле зі списком (заміна CTkOptionMenu)
# ══════════════════════════════════════════════════════
class SearchableDropdown(tk.Frame):
    """Текстове поле з автодоповненням + скролований список."""
    def __init__(self, parent, values=None, width=230, fg_color=None, **kw):
        bg = fg_color or C['card2']
        super().__init__(parent, bg=bg, **kw)
        self._all_values = list(values or [])
        self._filtered   = list(self._all_values)
        self._popup      = None
        self._listbox    = None
        self._var        = tk.StringVar()
        self._selected   = tk.StringVar()

        # Текстовий рядок пошуку
        self._entry = ctk.CTkEntry(self, textvariable=self._var,
                                   width=width, fg_color=C['card2'],
                                   border_color=C['border'], text_color=C['text'],
                                   placeholder_text="🔍 Пошук...")
        self._entry.pack(side='left')
        self._var.trace_add('write', self._on_type)
        self._entry.bind('<FocusIn>',  self._open_popup)
        self._entry.bind('<Escape>',   lambda e: self._close_popup())
        self._entry.bind('<Return>',   self._pick_first)
        self._entry.bind('<Down>',     self._focus_list)
        self._entry.bind('<FocusOut>', lambda e: self.after(150, self._close_popup))

    # ── public API ────────────────────────────────────
    def get(self):
        return self._selected.get()

    def set_values(self, values):
        self._all_values = list(values)
        self._filtered   = list(values)
        self._close_popup()

    def set(self, value):
        self._selected.set(value)
        self._var.set(value)

    # ── internal ──────────────────────────────────────
    def _on_type(self, *_):
        q = self._var.get().lower()
        self._filtered = [v for v in self._all_values if q in v.lower()] if q else list(self._all_values)
        if self._popup and self._listbox:
            self._listbox.delete(0, 'end')
            for v in self._filtered: self._listbox.insert('end', v)
        else:
            self._open_popup()

    def _open_popup(self, event=None):
        if self._popup:
            try:
                if self._popup.winfo_exists():
                    return  # вже відкрито
            except Exception:
                pass
            self._popup = None

        # Розміри та позиція ПІСЛЯ рендеру
        self.update_idletasks()
        x = self._entry.winfo_rootx()
        y = self._entry.winfo_rooty() + self._entry.winfo_height() + 2
        w = max(self._entry.winfo_width(), 200)
        row_h = 24
        rows  = min(max(len(self._filtered), 3), 12)
        h     = rows * row_h + 6

        # Не виходити за межі екрану
        try:
            sw = self.winfo_screenwidth()
            sh = self.winfo_screenheight()
            if x + w > sw: x = sw - w - 4
            if y + h > sh: y = self._entry.winfo_rooty() - h - 2  # відкрити вгору
        except Exception: pass

        self._popup = tk.Toplevel(self)
        self._popup.overrideredirect(True)
        self._popup.configure(bg=C['card2'])
        self._popup.geometry(f"{w}x{h}+{x}+{y}")
        # Завжди зверху вікна програми
        try:
            root = self.winfo_toplevel()
            self._popup.transient(root)
        except Exception: pass
        self._popup.attributes('-topmost', True)
        self._popup.lift()

        frm = tk.Frame(self._popup, bg=C['card2']); frm.pack(fill='both', expand=True)
        sb  = tk.Scrollbar(frm, orient='vertical', bg=C['card2'], troughcolor=C['bg'])
        sb.pack(side='right', fill='y')
        self._listbox = tk.Listbox(frm, yscrollcommand=sb.set,
                                   bg=C['card2'], fg=C['text'],
                                   selectbackground=C['accent'], selectforeground='white',
                                   activestyle='none', relief='flat', bd=0,
                                   font=('Segoe UI', 11), height=rows)
        self._listbox.pack(side='left', fill='both', expand=True)
        sb.config(command=self._listbox.yview)
        for v in self._filtered: self._listbox.insert('end', v)
        if self._listbox.size() > 0: self._listbox.selection_set(0)
        self._listbox.bind('<<ListboxSelect>>', self._on_select)
        self._listbox.bind('<MouseWheel>', lambda e: self._listbox.yview_scroll(int(-1*(e.delta/120)),'units'))
        self._listbox.bind('<Escape>',     lambda e: self._close_popup())
        self._listbox.bind('<Return>',     lambda e: self._on_select())
        self._listbox.bind('<FocusOut>',   lambda e: self.after(200, self._safe_close))
        self._popup.bind('<FocusOut>',     lambda e: self.after(200, self._safe_close))

    def _safe_close(self):
        """Закриває popup тільки якщо фокус більше не всередині."""
        try:
            focused = self.focus_get()
            if focused in (self._entry._entry if hasattr(self._entry,'_entry') else None,
                           self._listbox, self._popup):
                return
        except Exception: pass
        self._close_popup()

    def _close_popup(self):
        if self._popup:
            try: self._popup.destroy()
            except: pass
            self._popup = None; self._listbox = None

    def _on_select(self, event=None):
        if not self._listbox: return
        sel = self._listbox.curselection()
        if sel:
            val = self._listbox.get(sel[0])
            self._selected.set(val)
            self._var.set(val)
        self._close_popup()

    def _pick_first(self, event=None):
        if self._filtered:
            self._selected.set(self._filtered[0])
            self._var.set(self._filtered[0])
        self._close_popup()

    def _focus_list(self, event=None):
        if self._listbox:
            self._listbox.focus_set()
            if self._listbox.size(): self._listbox.selection_set(0)


