def _svcs_by_cat(cat_keys):
    """Послуги з services де category IN cat_keys."""
    if not cat_keys: return []
    from app.utils.db import get_conn as _gc_sb
    try:
        with _gc_sb() as _c:
            with _c.cursor() as _cur:
                ph=','.join(['%s']*len(cat_keys))
                _cur.execute(f"SELECT id,name,price,unit FROM services WHERE category IN ({ph}) AND active=true ORDER BY name",tuple(cat_keys))
                return [dict(zip([d[0] for d in _cur.description],r)) for r in _cur.fetchall()]
    except Exception: return []

# ══ Глобальний кеш кімнат — щоб не дублювати DB-запит при кожному переключенні ═
import time as _time_mod
_ROOMS_CACHE     = []    # список rooms
_ROOMS_CACHE_TS  = 0.0   # час останнього оновлення
_ROOMS_CACHE_TTL = 15.0  # секунди до примусового оновлення

def _invalidate_rooms_cache():
    """Примусово інвалідує кеш кімнат (викликати після зміни статусу)."""
    global _ROOMS_CACHE_TS
    _ROOMS_CACHE_TS = 0.0

def _get_sqlite_db_path():
    """Знаходить шлях до hotel_local_cache.db — перевіряє кілька можливих місць."""
    import os, sys
    candidates = []
    # 1. Шлях через get_data_dir() (dev і частина dist збірок)
    try:
        candidates.append(os.path.join(get_data_dir(), 'hotel_local_cache.db'))
    except Exception:
        pass
    # 2. _internal/data/ — PyInstaller --onedir збірка
    try:
        if hasattr(sys, '_MEIPASS'):
            candidates.append(os.path.join(sys._MEIPASS, 'data', 'hotel_local_cache.db'))
        # Також поруч з exe
        exe_dir = os.path.dirname(sys.executable)
        candidates.append(os.path.join(exe_dir, 'data', 'hotel_local_cache.db'))
        candidates.append(os.path.join(exe_dir, '_internal', 'data', 'hotel_local_cache.db'))
    except Exception:
        pass
    # 3. config/db_cache.py зберігає за path з config
    try:
        import json
        for cfg_dir in [
            os.path.join(os.path.dirname(os.path.abspath(__file__)), '..', '..', 'config'),
            os.path.join(os.path.dirname(sys.executable), 'config'),
            os.path.join(os.path.dirname(sys.executable), '_internal', 'config'),
        ]:
            cfg_path = os.path.normpath(os.path.join(cfg_dir, 'db.json'))
            if os.path.exists(cfg_path):
                with open(cfg_path, encoding='utf-8') as _f:
                    _cfg = json.load(_f)
                if _cfg.get('sqlite_path'):
                    candidates.append(_cfg['sqlite_path'])
    except Exception:
        pass
    for c in candidates:
        try:
            if os.path.exists(c):
                return c
        except Exception:
            pass
    return None

def _get_rooms_from_sqlite():
    """Читає кімнати з локального SQLite кешу при офлайні, з cat_name через JOIN."""
    try:
        import sqlite3 as _sq3loc
        _db = _get_sqlite_db_path()
        if not _db:
            return []
        with _sq3loc.connect(_db, timeout=5) as _sc:
            _sc.row_factory = _sq3loc.Row
            try:
                rows = _sc.execute("""
                    SELECT r.*,
                           COALESCE(rc.name, '') as cat_name,
                           COALESCE(rc.base_price, r.price_per_day, 0) as price_per_day
                    FROM rooms r
                    LEFT JOIN room_categories rc ON rc.id = r.category_id
                    ORDER BY CAST(r.number AS INTEGER), r.number
                """).fetchall()
            except Exception:
                rows = _sc.execute(
                    "SELECT *, COALESCE(category,'') as cat_name FROM rooms ORDER BY number"
                ).fetchall()
            result = []
            for r in rows:
                d = dict(r)
                if not d.get('cat_name'):
                    d['cat_name'] = d.get('category', '') or ''
                result.append(d)
            return result
    except Exception:
        return []

def _sqlite_select(sql, params=()):
    """Виконує SELECT у локальному SQLite кеші (для офлайн-fallback)."""
    try:
        import sqlite3 as _sq3loc
        _db = _get_sqlite_db_path()
        if not _db:
            return []
        with _sq3loc.connect(_db, timeout=5) as _sc:
            _sc.row_factory = _sq3loc.Row
            _sql2 = sql.replace('%s', '?')
            return [dict(r) for r in _sc.execute(_sql2, params).fetchall()]
    except Exception:
        return []

def _get_rooms_cached(force=False):
    """Повертає список кімнат з кешу (max 15с) або свіжі з БД, або SQLite при офлайні."""
    global _ROOMS_CACHE, _ROOMS_CACHE_TS
    now = _time_mod.perf_counter()
    if not force and _ROOMS_CACHE and (now - _ROOMS_CACHE_TS) < _ROOMS_CACHE_TTL:
        return list(_ROOMS_CACHE)
    try:
        from app.modules.logic import get_rooms
        rooms = get_rooms() or []
        if rooms:
            _ROOMS_CACHE    = rooms
            _ROOMS_CACHE_TS = _time_mod.perf_counter()
            return list(rooms)
        raise Exception("empty result")
    except Exception:
        # PG недоступний — in-memory кеш або SQLite
        if _ROOMS_CACHE:
            return list(_ROOMS_CACHE)
        sqlite_rooms = _get_rooms_from_sqlite()
        if sqlite_rooms:
            _ROOMS_CACHE    = sqlite_rooms
            _ROOMS_CACHE_TS = _time_mod.perf_counter()
        return list(_ROOMS_CACHE)

def _sqlite_bookings(status=None, search=None, limit=500):
    """Читає бронювання з SQLite кешу з усіма потрібними полями."""
    try:
        where = []
        params = []
        if status:
            if isinstance(status, (list, tuple)):
                ph = ','.join('?' * len(status))
                where.append(f"b.status IN ({ph})")
                params.extend(status)
            else:
                where.append("b.status = ?")
                params.append(status)
        if search:
            where.append("(g.name LIKE ? OR r.number LIKE ?)")
            params += [f'%{search}%', f'%{search}%']
        wclause = ('WHERE ' + ' AND '.join(where)) if where else ''
        sql = f"""
            SELECT b.id, b.room_id, b.guest_id, b.status,
                   b.check_in, b.check_out,
                   COALESCE(b.total_amount, 0) as total_amount,
                   COALESCE(b.price_per_day, 0) as price_per_day,
                   COALESCE(b.notes, '') as notes,
                   COALESCE(b.deposit_amount, 0) as deposit_amount,
                   r.number as room_number,
                   COALESCE(r.category, '') as room_category,
                   COALESCE(g.name, '') as guest_name,
                   COALESCE(g.phone, '') as guest_phone,
                   COALESCE(g.email, '') as guest_email
            FROM bookings b
            LEFT JOIN rooms r ON r.id = b.room_id
            LEFT JOIN guests g ON g.id = b.guest_id
            {wclause}
            ORDER BY b.id DESC
            LIMIT {limit}
        """
        rows = _sqlite_select(sql, tuple(params))
        # Конвертуємо дати і числа
        from datetime import date as _dt_date
        for r in rows:
            for fld in ('total_amount', 'price_per_day', 'deposit_amount'):
                try: r[fld] = float(r[fld] or 0)
                except Exception: r[fld] = 0.0
            for fld in ('check_in', 'check_out'):
                if r.get(fld) and isinstance(r[fld], str):
                    try: r[fld] = _dt_date.fromisoformat(r[fld][:10])
                    except Exception: pass
        return rows
    except Exception:
        return []

def _sqlite_payments_for_bookings(booking_ids):
    """Читає платежі для списку booking_id з SQLite."""
    if not booking_ids:
        return {}
    try:
        ph = ','.join('?' * len(booking_ids))
        rows = _sqlite_select(
            f"SELECT booking_id, amount, note, method, created_at "
            f"FROM payments WHERE booking_id IN ({ph})",
            tuple(int(i) for i in booking_ids))
        result = {}
        for r in rows:
            k = int(r['booking_id'])
            if k not in result:
                result[k] = []
            r['amount'] = float(r.get('amount') or 0)
            result[k].append(r)
        return result
    except Exception:
        return {}

def _sqlite_rooms_with_status():
    """Читає кімнати з SQLite з поточним статусом (враховує бронювання)."""
    try:
        from datetime import date as _dt_date
        today = str(_dt_date.today())
        rooms = _sqlite_select("SELECT * FROM rooms ORDER BY number")
        if not rooms:
            return []
        # Заселені
        ci = {int(r['room_id']) for r in _sqlite_select(
            "SELECT DISTINCT room_id FROM bookings WHERE status='checkedin'")}
        # Підтверджені (заїзд сьогодні або після)
        cf = {int(r['room_id']) for r in _sqlite_select(
            "SELECT DISTINCT room_id FROM bookings WHERE status='confirmed' AND check_out >= ?",
            (today,))}
        for r in rooms:
            rid = int(r.get('id', 0))
            st = r.get('status', 'free') or 'free'
            if rid in ci:
                r['status'] = 'checkedin'
            elif rid in cf:
                r['status'] = 'confirmed'
            elif st not in ('cleaning', 'repair', 'blocked'):
                r['status'] = 'free'
            try: r['price_per_day'] = float(r.get('price_per_day') or 0)
            except Exception: r['price_per_day'] = 0.0
        return rooms
    except Exception:
        return []

class DashboardFrame(tk.Frame):
    def __init__(self, parent, user):
        super().__init__(parent, bg=C['bg'])
        self.user = user
        self._loading = False
        self._build_skeleton()
        # Запускаємо завантаження через 300мс — достатньо щоб UI намалювався
        # _bg_init працює у фоні паралельно, _get_rooms_cached() має fallback
        self.after(300, self._load_data_async)

    def _build_skeleton(self):
        """Будує статичну частину UI одразу, без запитів до БД."""
        today = date.today()
        self._stat_card_lbls  = {}   # 'free' → (num_label, title_label)
        self._tile_refs        = {}   # room_id → (cell_frame, num_label, st_label)
        self._arr_tree         = None
        self._dep_tree         = None
        self._first_render     = True  # перший раз будуємо сітку, далі оновлюємо

        self._hdr = tk.Frame(self, bg=C['bg']); self._hdr.pack(fill='x', padx=20, pady=(15,8))
        lbl(self._hdr, f"🏠  Дашборд — {today.strftime('%d.%m.%Y')}", 22, True).pack(side='left')
        self._shift_lbl = lbl(self._hdr, f"👤 {self.user.get('full_name','')}", 11, color=C['text2'])
        self._shift_lbl.pack(side='left', padx=15)
        refresh_btn(self._hdr, self._load_data_async, side='right', padx=8)

        # ── Банер "Готівка в касі / Залоги в касі" (як у Касі) ──
        self._cash_banner = ctk.CTkFrame(self, fg_color=C['card2'], corner_radius=12)
        self._cash_banner.pack(fill='x', padx=20, pady=(0, 6))
        _cb = tk.Frame(self._cash_banner, bg=C['card2']); _cb.pack(fill='x', padx=16, pady=10)
        lbl(_cb, "💵  Готівка:", 13, True, C['text']).pack(side='left')
        self._dash_cash_lbl = lbl(_cb, "—", 22, True, C['green'])
        self._dash_cash_lbl.pack(side='left', padx=(8, 18))
        tk.Frame(_cb, bg=C['text2'], width=1, height=36).pack(side='left', fill='y', padx=(0, 18))
        lbl(_cb, "💳  Картка:", 13, True, C['text']).pack(side='left')
        self._dash_card_lbl = lbl(_cb, "—", 22, True, C['accent'])
        self._dash_card_lbl.pack(side='left', padx=(8, 18))
        tk.Frame(_cb, bg=C['text2'], width=1, height=36).pack(side='left', fill='y', padx=(0, 18))
        lbl(_cb, "🏦  Переказ:", 13, True, C['text']).pack(side='left')
        self._dash_transfer_lbl = lbl(_cb, "—", 22, True, '#9b59b6')
        self._dash_transfer_lbl.pack(side='left', padx=(8, 18))
        tk.Frame(_cb, bg=C['text2'], width=1, height=36).pack(side='left', fill='y', padx=(0, 18))
        lbl(_cb, "🔒  Залоги:", 13, True, C['text']).pack(side='left')
        self._dash_dep_lbl = lbl(_cb, "—", 22, True, '#e67e22')
        self._dash_dep_lbl.pack(side='left', padx=(8, 8))

        # ── Банер тестового режиму (відображається якщо режим активний) ──
        self._test_mode_dash_banner = None
        def _check_test_mode_dash():
            try:
                _tms = _load_app_settings()
                if _tms.get('test_mode_active'):
                    _since = str(_tms.get('test_mode_started_at', ''))[:16]
                    if self._test_mode_dash_banner is None:
                        _tb = ctk.CTkFrame(self, fg_color='#3d2600', corner_radius=8)
                        _tb.pack(fill='x', padx=20, pady=(0, 4))
                        self._test_mode_dash_banner = _tb
                        _tbrow = tk.Frame(_tb, bg='#3d2600'); _tbrow.pack(fill='x', padx=12, pady=7)
                        lbl(_tbrow, f"🧪  ТЕСТОВИЙ РЕЖИМ активний з {_since}", 12, True, C['yellow']).pack(side='left')
                        lbl(_tbrow, "   Всі дані тестові — не реальні", 11, color=C['text2']).pack(side='left')
            except Exception:
                pass
        self.after(200, _check_test_mode_dash)

        # Статистичні картки — будуємо одразу з placeholder-ами
        self._st = tk.Frame(self, bg=C['bg']); self._st.pack(fill='x', padx=20, pady=5)
        self._loading_lbl = lbl(self._st, "⏳ Завантаження даних...", 13, color=C['text2'])
        self._loading_lbl.pack(pady=10)

        lbl(self, "🗺️  Статус номерів", 15, True).pack(anchor='w', padx=20, pady=(12,4))
        # ── Placeholder для банера прострочених — прямо над сіткою плиток ──
        self._overdue_banner_frame = tk.Frame(self, bg=C['bg'])
        self._overdue_banner_frame.pack(fill='x', padx=20, pady=(0, 4))
        self._overdue_banner = None
        self._scroll_outer = tk.Frame(self, bg=C['bg'])
        self._scroll_outer.pack(fill='both', expand=True, padx=20, pady=0)
        # Запустити авто-оновлення кожні 30 секунд
        self._schedule_auto_refresh()

    def _schedule_auto_refresh(self):
        """Авто-оновлення: тільки дані, без перемальовування."""
        try:
            if self.winfo_exists():
                self.after(30000, self._auto_refresh_tick)
        except Exception:
            pass

    def _auto_refresh_tick(self):
        try:
            if not self.winfo_exists(): return
            if not self._loading and self._first_render is False:
                self._load_data_async()
            self.after(30000, self._auto_refresh_tick)
        except Exception:
            pass

    def _load_data_async(self):
        """Запускає завантаження даних у фоновому потоці."""
        import threading
        if self._loading:
            return
        self._loading = True
        threading.Thread(target=self._fetch_and_render, daemon=True).start()

    def _fetch_and_render(self):
        """Виконується у фоновому потоці: запити до БД, потім оновлює UI через after()."""
        try:
            from app.utils.db import query as _q
            today = date.today()
            rooms = _get_rooms_cached() or []
            arr   = []
            dep   = []

            try:
                # Статуси номерів — завжди з БД напряму (не кеш) для актуальності
                try:
                    from app.utils.db import get_conn as _get_conn2
                    with _get_conn2() as _dc:
                        with _dc.cursor() as _dcur:
                            _dcur.execute("SELECT id, status FROM rooms")
                            _cols = [d[0] for d in _dcur.description]
                            db_statuses = {row[0]: row[1] for row in _dcur.fetchall()}
                            _dcur.execute(
                                "SELECT DISTINCT room_id FROM bookings WHERE status='confirmed' AND check_out >= %s",
                                (today,))
                            confirmed_room_ids = {row[0] for row in _dcur.fetchall()}
                            _dcur.execute(
                                "SELECT DISTINCT room_id FROM bookings WHERE status='checkedin'")
                            checkedin_room_ids = {row[0] for row in _dcur.fetchall()}
                except Exception:
                    # PG недоступний — читаємо з локального SQLite кешу
                    _sq_rooms = _sqlite_select("SELECT id, status FROM rooms")
                    db_statuses = {int(r['id']): r['status'] for r in _sq_rooms}
                    _sq_conf = _sqlite_select(
                        "SELECT DISTINCT room_id FROM bookings WHERE status='confirmed' AND check_out >= ?",
                        (str(today),))
                    confirmed_room_ids = {int(r['room_id']) for r in _sq_conf}
                    _sq_ci = _sqlite_select(
                        "SELECT DISTINCT room_id FROM bookings WHERE status='checkedin'")
                    checkedin_room_ids = {int(r['room_id']) for r in _sq_ci}
                for r in rooms:
                    rid_r = int(r.get('id'))  # кеш дає рядок, psycopg2 — int
                    if rid_r in checkedin_room_ids:
                        r['status'] = 'checkedin'
                    elif rid_r in confirmed_room_ids:
                        r['status'] = 'confirmed'
                    elif rid_r in db_statuses and db_statuses[rid_r] not in ('free',):
                        r['status'] = db_statuses[rid_r]
                    elif rid_r not in checkedin_room_ids and rid_r not in confirmed_room_ids:
                        if db_statuses.get(rid_r) in ('cleaning', 'repair', 'blocked'):
                            r['status'] = db_statuses[rid_r]
                        elif r.get('status') not in ('cleaning', 'repair', 'blocked', 'occupied'):
                            r['status'] = db_statuses.get(rid_r, 'free') or 'free'
            except Exception as _sync_err:
                log_error("Dashboard: помилка синхронізації статусів", _sync_err)

            shift_start_dt = get_session_start()
            import datetime as _dt2
            if shift_start_dt:
                if shift_start_dt.date() == _dt2.date.today():
                    shift_label = f"з {shift_start_dt.strftime('%H:%M')}"
                else:
                    shift_label = f"з {shift_start_dt.strftime('%d.%m %H:%M')}"
            else:
                shift_label = "—"

            # ── Беремо дані З КАСИ по shift_id (та сама логіка що CashboxFrame) ──
            shift_paid = 0.0
            shift_dep  = 0.0
            try:
                from app.utils.db import get_conn as _gc_dash
                _sid = get_current_shift_id()
                if _sid:
                    with _gc_dash() as _dc2:
                        with _dc2.cursor() as _cur2:
                            _cur2.execute(
                                "SELECT COALESCE(opening_cash,0), COALESCE(opening_deposits,0) FROM shifts WHERE id=%s",
                                (_sid,))
                            _op = _cur2.fetchone() or (0, 0)
                            _op_cash = float(_op[0] or 0)
                            _op_dep  = float(_op[1] or 0)

                            _cur2.execute("""SELECT
                                COALESCE(SUM(CASE WHEN method='cash' AND amount>0
                                    AND (note IS NULL OR (
                                        note NOT LIKE 'Залог%%' AND note NOT LIKE 'deposit%%'
                                        AND note NOT LIKE 'Повернення%%'))
                                    THEN amount END), 0),
                                -- Повернення готівки БЕЗ залогів (залог повертається з депозитного залишку)
                                COALESCE(ABS(SUM(CASE WHEN method='cash' AND amount<0
                                    AND (note IS NULL OR (
                                        note NOT LIKE 'Повернення залогу%%'
                                        AND note NOT LIKE 'deposit_returned%%'))
                                    THEN amount END)), 0),
                                COALESCE(SUM(CASE WHEN amount>0
                                    AND (note LIKE 'Залог%%' OR note LIKE 'deposit%%')
                                    THEN amount END), 0),
                                -- Повернення залогів (лише залогові від'ємні)
                                COALESCE(ABS(SUM(CASE WHEN amount<0
                                    AND (note LIKE 'Повернення залогу%%' OR note LIKE 'deposit_returned%%')
                                    THEN amount END)), 0),
                                COALESCE(SUM(CASE WHEN method='card' AND amount>0
                                    AND (note IS NULL OR (
                                        note NOT LIKE 'Залог%%' AND note NOT LIKE 'deposit%%'
                                        AND note NOT LIKE 'Повернення%%'))
                                    THEN amount END), 0),
                                COALESCE(SUM(CASE WHEN method IN ('transfer','online') AND amount>0
                                    AND (note IS NULL OR (
                                        note NOT LIKE 'Залог%%' AND note NOT LIKE 'deposit%%'
                                        AND note NOT LIKE 'Повернення%%'))
                                    THEN amount END), 0)
                                FROM payments WHERE shift_id=%s""", (_sid,))
                            _p = _cur2.fetchone() or (0, 0, 0, 0, 0, 0)

                            _cur2.execute(
                                "SELECT COALESCE(SUM(amount),0) FROM cash_transfers WHERE shift_id=%s",
                                (_sid,))
                            _tr = (_cur2.fetchone() or (0,))[0] or 0

                            # Готівка = відкриття + оплати готівкою (БЕЗ залогів) − повернення − переміщення
                            shift_paid = _op_cash + float(_p[0] or 0) - float(_p[1] or 0) - float(_tr)
                            # Залоги — окремо
                            shift_dep  = max(_op_dep + float(_p[2] or 0) - float(_p[3] or 0), 0)
                            shift_card     = float(_p[4] or 0)
                            shift_transfer = float(_p[5] or 0)
            except Exception as _cash_err:
                log_error("Dashboard: помилка запиту каси", _cash_err)
                shift_paid = 0.0
                shift_dep  = 0.0
                shift_card = 0.0
                shift_transfer = 0.0

            # ── Прострочені виїзди та виїзди сьогодні ──────────────────────
            overdue_bookings = []
            def _calc_days_late(rows):
                for _row in rows:
                    try:
                        _co = _row.get('check_out')
                        if _co is None: _row['days_late'] = 0; continue
                        if hasattr(_co, 'date'): _co = _co.date()
                        elif isinstance(_co, str):
                            import datetime as _dtp
                            _co = _dtp.date.fromisoformat(_co[:10])
                        _row['days_late'] = (today - _co).days
                    except Exception:
                        _row['days_late'] = 0
                return rows
            try:
                from app.utils.db import get_conn as _gc_ov
                with _gc_ov() as _ovc:
                    with _ovc.cursor() as _ovcur:
                        _ovcur.execute("""
                            SELECT b.id, r.number as room_number,
                                   COALESCE(g.name, '') as guest_name, b.check_in, b.check_out
                            FROM bookings b
                            JOIN rooms r ON r.id = b.room_id
                            LEFT JOIN guests g ON g.id = b.guest_id
                            WHERE b.status = 'checkedin'
                              AND b.check_out <= %s
                            ORDER BY b.check_out ASC
                        """, (today,))
                        _cols_ov = [d[0] for d in _ovcur.description]
                        _rows_ov = [dict(zip(_cols_ov, row)) for row in _ovcur.fetchall()]
                        overdue_bookings = _calc_days_late(_rows_ov)
                        log_info(f"Dashboard overdue: знайдено {len(overdue_bookings)} записів для today={today}")
            except Exception as _ov_err:
                log_error("Dashboard: помилка запиту прострочених виїздів", _ov_err)
                # Fallback → SQLite кеш
                try:
                    _fb = _sqlite_select(
                        """SELECT b.id, r.number as room_number,
                           COALESCE(g.name,'') as guest_name, b.check_in, b.check_out
                           FROM bookings b JOIN rooms r ON r.id=b.room_id
                           LEFT JOIN guests g ON g.id=b.guest_id
                           WHERE b.status='checkedin' AND b.check_out <= ?
                           ORDER BY b.check_out ASC""", (str(today),))
                    overdue_bookings = _calc_days_late(_fb)
                    log_info(f"Dashboard overdue SQLite fallback: {len(overdue_bookings)} записів")
                except Exception as _fb_err:
                    log_error("Dashboard: SQLite fallback overdue теж не вдався", _fb_err)

            # ── Заїзди і виїзди сьогодні (з SQLite якщо PG недоступний) ──
            if not arr:
                try:
                    arr = _sqlite_select(
                        """SELECT b.id, r.number as room_number,
                           COALESCE(g.name,'') as guest_name, b.check_in, b.check_out
                           FROM bookings b JOIN rooms r ON r.id=b.room_id
                           LEFT JOIN guests g ON g.id=b.guest_id
                           WHERE b.status='confirmed' AND b.check_in=?""", (str(today),))
                except Exception:
                    arr = []
            if not dep:
                try:
                    dep = _sqlite_select(
                        """SELECT b.id, r.number as room_number,
                           COALESCE(g.name,'') as guest_name, b.check_in, b.check_out
                           FROM bookings b JOIN rooms r ON r.id=b.room_id
                           LEFT JOIN guests g ON g.id=b.guest_id
                           WHERE b.status='checkedin' AND b.check_out=?""", (str(today),))
                except Exception:
                    dep = []

            try:
                if self.winfo_exists():
                    self.after(0, lambda: self._render_data(rooms, arr, dep, shift_label, shift_paid, shift_dep, today, overdue_bookings, shift_card, shift_transfer))
            except Exception:
                pass
        except Exception as e:
            log_error("Dashboard: помилка завантаження даних", e)
            try:
                if self.winfo_exists():
                    self.after(0, lambda: self._render_error(str(e)))
            except Exception:
                pass
        finally:
            self._loading = False

    def _render_error(self, msg):
        try:
            self._loading_lbl.configure(text=f"❌ Помилка: {msg}", text_color=C['red'])
        except Exception:
            pass

    def _render_data(self, rooms, arr, dep, shift_label, shift_paid, shift_dep, today, overdue_bookings=None, shift_card=0.0, shift_transfer=0.0):
        """Оновлює UI: при першому виклику будує, далі тільки оновлює дані."""
        try:
            self._shift_lbl.configure(text=f"👤 {self.user.get('full_name','')}  |  Зміна {shift_label}")
        except Exception:
            pass

        free_r      = sum(1 for r in rooms if r['status']=='free')
        occ_r       = sum(1 for r in rooms if r['status'] in ('occupied','checkedin'))
        confirmed_r = sum(1 for r in rooms if r['status'] in ('confirmed','booked'))
        clean       = sum(1 for r in rooms if r['status']=='cleaning')
        repair      = sum(1 for r in rooms if r['status']=='repair')
        stat_items = [
            ("total",    "🛏 Всього",        len(rooms),           C['accent']),
            ("free",     "✅ Вільних",       free_r,               C['green']),
            ("occ",      "🔴 Зайнятих",     occ_r,                C['red']),
            ("conf",     "📋 Заброньовано",  confirmed_r,          C['accent']),
            ("clean",    "🧹 Прибирання",   clean,                C['yellow']),
            ("repair",   "🔧 Ремонт",       repair,               C['gray']),
            ("arr",      "📥 Заїздів",      len(arr),             '#9b59b6'),
            ("dep",      "📤 Виїздів",      len(dep),             '#1abc9c'),
        ]

        # Оновлюємо банер готівки/залогів/картки/переказу
        try:
            _cash_color = C['green'] if shift_paid >= 0 else C['red']
            self._dash_cash_lbl.configure(text=f"{shift_paid:.0f}₴", text_color=_cash_color)
            self._dash_card_lbl.configure(text=f"{shift_card:.0f}₴")
            self._dash_transfer_lbl.configure(text=f"{shift_transfer:.0f}₴")
            self._dash_dep_lbl.configure(text=f"{shift_dep:.0f}₴")
        except Exception:
            pass

        # ── Зберігаємо overdue_list для використання після побудови плиток ──
        self._overdue_list = overdue_bookings or []


        if self._first_render:
            # ── Перший раз: будуємо картки і сітку ──
            try:
                self._loading_lbl.destroy()
            except Exception:
                pass
            ncols = len(stat_items)
            for col in range(ncols): self._st.columnconfigure(col, weight=1)
            for idx, (key, title, val, color) in enumerate(stat_items):
                c = ctk.CTkFrame(self._st, fg_color=color, corner_radius=12)
                c.grid(row=0, column=idx, padx=3, pady=3, sticky='nsew', ipady=0)
                # Звичайна картка — розпірки для центрування по висоті
                tk.Frame(c, bg=color, height=10).pack()
                num_l = lbl(c, str(val), 14, True, 'white'); num_l.pack(pady=(0,1))
                lbl(c, title, 8, color='white').pack()
                tk.Frame(c, bg=color, height=10).pack()
                self._stat_card_lbls[key] = num_l

            # Сітка номерів — на весь екран без зовнішнього скролу
            self._main_canvas = None  # не використовується більше
            self._inner = tk.Frame(self._scroll_outer, bg=C['bg'])
            self._inner.pack(fill='both', expand=True)

            COLS = 12
            rows_count = (len(rooms) - 1) // COLS + 1 if rooms else 1
            # Висота: всі рядки видимі без обмеження
            TILE_H = 60

            rg_outer = tk.Frame(self._inner, bg=C['card'], bd=0)
            rg_outer.pack(fill='both', expand=True, pady=(0,8))

            # Горизонтальна прокрутка (якщо більше 12 колонок)
            h_scroll = tk.Scrollbar(rg_outer, orient='horizontal', bg=C['card2'])
            h_scroll.pack(side='bottom', fill='x')
            # Вертикальна прокрутка (якщо більше MAX_ROWS_VISIBLE рядків)
            v_scroll_g = tk.Scrollbar(rg_outer, orient='vertical', bg=C['card2'])
            v_scroll_g.pack(side='right', fill='y')

            self._grid_canvas = tk.Canvas(rg_outer, bg=C['card'], highlightthickness=0,
                                    xscrollcommand=h_scroll.set,
                                    yscrollcommand=v_scroll_g.set)
            self._grid_canvas.pack(side='top', fill='both', expand=True)
            h_scroll.config(command=self._grid_canvas.xview)
            v_scroll_g.config(command=self._grid_canvas.yview)

            self._rf = tk.Frame(self._grid_canvas, bg=C['card'])
            self._rf_win_id = self._grid_canvas.create_window((0,0), window=self._rf, anchor='nw')

            self._tile_refs = {}
            # Налаштовуємо рівну вагу всіх колонок — плитки розтягуються рівномірно
            for ci in range(COLS):
                self._rf.columnconfigure(ci, weight=1, minsize=90)
            # Словник: room_number → overdue info для швидкого пошуку
            _overdue_by_room = {str(b.get('room_number','')): b for b in self._overdue_list}
            for i, r in enumerate(rooms):
                rid = int(r.get('id', i))
                color = STATUS_COLOR.get(r['status'], C['gray'])
                row_i, col_i = i//COLS, i%COLS
                cell = tk.Frame(self._rf, bg=color)
                cell.grid(row=row_i, column=col_i, padx=3, pady=3, sticky='nsew')
                num_l = tk.Label(cell, text=f"№{r['number']}", bg=color, fg='white',
                         font=('Segoe UI',10,'bold'), padx=6, pady=6)
                num_l.pack()
                st_l  = tk.Label(cell, text=STATUS_UA.get(r['status'],''), bg=color, fg='white',
                         font=('Segoe UI',8), padx=4, pady=2)
                st_l.pack()
                self._tile_refs[rid] = (cell, num_l, st_l)
                # ── Бейдж прострочення прямо на плитці ──
                _ov_info = _overdue_by_room.get(str(r.get('number','')))
                if _ov_info:
                    _dl = _ov_info.get('days_late', 0)
                    _badge_bg = '#cc0000' if _dl > 0 else '#cc8800'
                    _badge_txt = f"!+{_dl}д" if _dl > 0 else "!сьогодні"
                    _badge = tk.Label(cell, text=_badge_txt, bg=_badge_bg, fg='white',
                                      font=('Segoe UI', 7, 'bold'), padx=2)
                    _badge.place(relx=1.0, rely=0.0, anchor='ne', x=-1, y=1)

            def _on_rf_configure(e):
                self._grid_canvas.configure(scrollregion=self._grid_canvas.bbox('all'))
                # Переміщуємо overlay вище всіх плиток при зміні розміру
                if hasattr(self, '_overdue_tile_overlay') and self._overdue_tile_overlay:
                    try: self._overdue_tile_overlay.lift()
                    except Exception: pass
            self._rf.bind('<Configure>', _on_rf_configure)

            def _on_canvas_resize(e):
                # Розтягуємо _rf на повну ширину canvas
                self._grid_canvas.itemconfig(self._rf_win_id, width=e.width)
            self._grid_canvas.bind('<Configure>', _on_canvas_resize)

            # ── Overlay-банер над сіткою плиток (після побудови _rf) ────────
            def _build_tile_overlay():
                try:
                    if hasattr(self, '_overdue_tile_overlay') and self._overdue_tile_overlay:
                        try: self._overdue_tile_overlay.place_forget()
                        except Exception: pass
                    overdue = self._overdue_list
                    if not overdue: return
                    strictly = [b for b in overdue if b.get('days_late', 0) > 0]
                    today_co = [b for b in overdue if b.get('days_late', 0) == 0]
                    _bg  = '#3d0000' if strictly else '#3d2c00'
                    _fg  = '#ff4444' if strictly else '#ffcc00'
                    _ico = '🚨' if strictly else '⚠️'
                    _msg = (f"{_ico} {len(strictly)} прострочених виїздів — Виселити або Продовжити"
                            if strictly else
                            f"⚠️ Виїзд сьогодні: {len(today_co)} номерів — Виселити або Продовжити")

                    ov = tk.Frame(self._grid_canvas, bg=_bg,
                                  highlightbackground=_fg, highlightthickness=2)
                    # place поверх canvas зверху зліва з правого відступу
                    ov.place(relx=0.0, rely=0.0, anchor='nw', relwidth=1.0, y=0)
                    self._overdue_tile_overlay = ov

                    hf = tk.Frame(ov, bg=_bg); hf.pack(fill='x', padx=8, pady=(5, 3))
                    tk.Label(hf, text=_msg, bg=_bg, fg=_fg,
                             font=('Segoe UI', 10, 'bold')).pack(side='left')
                    tk.Button(hf, text='✕', bg=_bg, fg='#888888',
                              relief='flat', bd=0, cursor='hand2',
                              font=('Segoe UI', 10),
                              command=lambda: ov.place_forget()).pack(side='right')

                    cf = tk.Frame(ov, bg=_bg); cf.pack(fill='x', padx=8, pady=(0, 5))
                    for b in overdue[:12]:
                        d  = b.get('days_late', 0)
                        bc = '#cc0000' if d > 0 else '#cc8800'
                        bt = f"+{d} дн." if d > 0 else "виїзд"
                        nm = (b.get('guest_name') or '—').split()[0]
                        ch = tk.Frame(cf, bg=bc, padx=4, pady=2)
                        ch.pack(side='left', padx=2, pady=1)
                        tk.Label(ch, text=f"№{b.get('room_number','?')} {nm} {bt}",
                                 bg=bc, fg='white', font=('Segoe UI', 8, 'bold')).pack()
                    if len(overdue) > 12:
                        tk.Label(cf, text=f"  +{len(overdue)-12} ще",
                                 bg=_bg, fg='#888888', font=('Segoe UI', 8)).pack(side='left', padx=3)
                    ov.lift()
                except Exception as _ove:
                    log_error("Dashboard: tile overlay", _ove)
            self.after(100, _build_tile_overlay)

            # Колесо миші: Shift+колесо = горизонталь, просто колесо = вертикаль у сітці
            def _grid_scroll_v(e):
                self._grid_canvas.yview_scroll(int(-1*(e.delta/120)), 'units')
            def _grid_scroll_h(e):
                self._grid_canvas.xview_scroll(int(-1*(e.delta/120)), 'units')
            self._grid_canvas.bind('<MouseWheel>', _grid_scroll_v)
            self._grid_canvas.bind('<Shift-MouseWheel>', _grid_scroll_h)
            self._rf.bind('<MouseWheel>', _grid_scroll_v)
            self._rf.bind('<Shift-MouseWheel>', _grid_scroll_h)

            self._first_render = False

        else:
            # ── Наступні виклики: лише оновлюємо дані ──
            for key, title, val, color in stat_items:
                if key in self._stat_card_lbls:
                    try: self._stat_card_lbls[key].configure(text=str(val))
                    except Exception: pass
            # Оновлюємо плитки номерів
            _overdue_by_room2 = {str(b.get('room_number','')): b for b in self._overdue_list}
            for r in rooms:
                rid = int(r.get('id', 0))
                if rid in self._tile_refs:
                    cell, num_l, st_l = self._tile_refs[rid]
                    new_color = STATUS_COLOR.get(r['status'], C['gray'])
                    try:
                        cell.configure(bg=new_color)
                        num_l.configure(bg=new_color)
                        st_l.configure(bg=new_color, text=STATUS_UA.get(r['status'],''))
                        # Оновлюємо/видаляємо бейдж прострочення
                        for _w in cell.winfo_children():
                            if isinstance(_w, tk.Label) and getattr(_w, '_is_overdue_badge', False):
                                _w.destroy()
                        _ov2 = _overdue_by_room2.get(str(r.get('number','')))
                        if _ov2:
                            _dl2 = _ov2.get('days_late', 0)
                            _bb2 = '#cc0000' if _dl2 > 0 else '#cc8800'
                            _bt2 = f"!+{_dl2}д" if _dl2 > 0 else "!сьогодні"
                            _b2  = tk.Label(cell, text=_bt2, bg=_bb2, fg='white',
                                            font=('Segoe UI', 7, 'bold'), padx=2)
                            _b2._is_overdue_badge = True
                            _b2.place(relx=1.0, rely=0.0, anchor='ne', x=-1, y=1)
                    except Exception: pass
            # Оновлюємо overlay
            if hasattr(self, '_overdue_tile_overlay'):
                try:
                    if self._overdue_tile_overlay:
                        self._overdue_tile_overlay.place_forget()
                    self._overdue_tile_overlay = None
                except Exception: pass
            def _rebuild_overlay():
                try:
                    overdue = self._overdue_list
                    if not overdue: return
                    if not hasattr(self, '_grid_canvas') or not self._grid_canvas.winfo_exists(): return
                    strictly = [b for b in overdue if b.get('days_late', 0) > 0]
                    today_co = [b for b in overdue if b.get('days_late', 0) == 0]
                    _bg  = '#3d0000' if strictly else '#3d2c00'
                    _fg  = '#ff4444' if strictly else '#ffcc00'
                    _ico = '🚨' if strictly else '⚠️'
                    _msg = (f"{_ico} {len(strictly)} прострочених виїздів — Виселити або Продовжити"
                            if strictly else
                            f"⚠️ Виїзд сьогодні: {len(today_co)} номерів — Виселити або Продовжити")
                    ov = tk.Frame(self._grid_canvas, bg=_bg,
                                  highlightbackground=_fg, highlightthickness=2)
                    ov.place(relx=0.0, rely=0.0, anchor='nw', relwidth=1.0, y=0)
                    self._overdue_tile_overlay = ov
                    hf = tk.Frame(ov, bg=_bg); hf.pack(fill='x', padx=8, pady=(5, 3))
                    tk.Label(hf, text=_msg, bg=_bg, fg=_fg,
                             font=('Segoe UI', 10, 'bold')).pack(side='left')
                    tk.Button(hf, text='✕', bg=_bg, fg='#888888',
                              relief='flat', bd=0, cursor='hand2',
                              font=('Segoe UI', 10),
                              command=lambda: ov.place_forget()).pack(side='right')
                    cf = tk.Frame(ov, bg=_bg); cf.pack(fill='x', padx=8, pady=(0, 5))
                    for b in overdue[:12]:
                        d  = b.get('days_late', 0)
                        bc = '#cc0000' if d > 0 else '#cc8800'
                        bt = f"+{d} дн." if d > 0 else "виїзд"
                        nm = (b.get('guest_name') or '—').split()[0]
                        ch = tk.Frame(cf, bg=bc, padx=4, pady=2)
                        ch.pack(side='left', padx=2, pady=1)
                        tk.Label(ch, text=f"№{b.get('room_number','?')} {nm} {bt}",
                                 bg=bc, fg='white', font=('Segoe UI', 8, 'bold')).pack()
                    if len(overdue) > 12:
                        tk.Label(cf, text=f"  +{len(overdue)-12} ще",
                                 bg=_bg, fg='#888888', font=('Segoe UI', 8)).pack(side='left', padx=3)
                    ov.lift()
                except Exception: pass
            self.after(50, _rebuild_overlay)

    def _rebuild(self):
        """Оновлює лише дані — скелет UI зберігається."""
        self._loading = False
        self._load_data_async()

