def _CleaningFrame_seed_cleaners():
    """Якщо в БД немає жодної прибиральниці — додає список за замовчуванням."""
    try:
        existing = _get_cleaners_db()
        if existing:
            return  # вже є
        default_cleaners = ['Таня', 'Оля', 'Надя', 'Люда', 'Галя']
        _save_cleaners_db(default_cleaners)
    except Exception:
        pass


def _CleaningFrame_seed_log_from_rooms():
    """Синхронізує журнал — додає записи для кімнат зі статусом cleaning яких ще немає в незавершених записах."""
    import datetime as _dt_seed
    try:
        existing = _cl_load()
        # Кімнати що вже є в журналі як незавершені (finished порожній)
        in_log = {e['room'] for e in existing if not e.get('finished', '').strip()}
        from app.utils.db import get_conn as _gc_seed
        with _gc_seed() as _c_seed:
            with _c_seed.cursor() as _cur_seed:
                _cur_seed.execute(
                    "SELECT number FROM rooms WHERE status='cleaning' ORDER BY number"
                )
                cleaning_rooms = [str(r[0]) for r in _cur_seed.fetchall()]
        # Додаємо тільки ті кімнати яких немає в журналі
        missing = [r for r in cleaning_rooms if r not in in_log]
        if not missing:
            return
        now_str = _dt_seed.datetime.now().strftime('%d.%m.%Y %H:%M')
        now_ts  = _dt_seed.datetime.now().strftime('%d.%m.%Y %H:%M:%S')
        for room_num in missing:
            _cl_append({
                'room':       room_num,
                'cleaner':    '—',
                'started':    now_str,
                'finished':   '',
                'new_status': 'cleaning',
                'note':       'Авто-запис: кімната в статусі "Прибирання"',
                'logged_at':  now_ts,
            })
    except Exception:
        pass


class CleaningFrame(tk.Frame):
    """Окрема вкладка — журнал прибирань."""
    def __init__(self, parent, user):
        super().__init__(parent, bg=C['bg'])
        self.user=user
        self._stat_lbls = {}  # посилання на stat label-и
        lbl(self,'⏳ Завантаження...', 14, color=C['text2']).pack(pady=60)
        self.after(30, self._build)

    def _build(self):
        try:
            for w in self.winfo_children(): w.destroy()
        except Exception: pass
        import os, json

        tb=ctk.CTkFrame(self,fg_color=C['card']); tb.pack(fill='x',padx=15,pady=(15,5))
        lbl(tb,"🧹  Журнал прибирань",18,True).pack(side='left',padx=15,pady=12)
        refresh_btn(tb, self._rebuild, side='right', padx=10, pady=10)
        btn(tb,"📊 Звіт",self._cleaners_report_dlg,C['green'],120).pack(side='right',padx=4,pady=10)
        btn(tb,"✏️ Статус номера",self._change_status_dlg,C['accent'],160).pack(side='right',padx=4,pady=10)
        btn(tb,"🧹 Нове прибирання",self._cleaning_dlg,C['yellow'],170).pack(side='right',padx=4,pady=10)

        # ── Авто-додавання прибиральниць якщо список порожній ──────────────
        _CleaningFrame_seed_cleaners()
        # ── Авто-запис кімнат зі статусом 'cleaning' якщо журнал порожній ──
        _CleaningFrame_seed_log_from_rooms()
        # Статистика — також враховуємо номери зі статусом 'cleaning' у БД
        log = _cl_load()
        # Дедуплікація авто-записів: якщо є реальний запис для кімнати сьогодні — видаляємо авто-дублікати
        today_str_b = date.today().strftime('%d.%m.%Y')
        real_today_b = {e.get('room') for e in log
                        if e.get('logged_at', '').startswith(today_str_b)
                        and e.get('note') != 'Авто-статус з БД'}
        log = [e for e in log
               if not (e.get('note') == 'Авто-статус з БД'
                       and e.get('logged_at', '').startswith(today_str_b)
                       and e.get('room') in real_today_b)]
        today_log = [e for e in log if e.get('logged_at', '').startswith(today_str_b)]

        self._stat_frame=tk.Frame(self,bg=C['bg']); self._stat_frame.pack(fill='x',padx=15,pady=5)
        stat_data = [
            ('all',   "📋 Всього записів",  str(len(log)),                                           C['accent']),
            ('today', "🧹 Сьогодні",        str(len(today_log)),                                     C['yellow']),
            ('free',  "✅ Вільний після",   str(sum(1 for e in log if e.get('new_status')=='free')), C['green']),
            ('repair',"🔧 Ремонт після",    str(sum(1 for e in log if e.get('new_status')=='repair')),C['gray']),
        ]
        for i,(key,lt,val,color) in enumerate(stat_data):
            self._stat_frame.columnconfigure(i,weight=1)
            c=ctk.CTkFrame(self._stat_frame,fg_color=color,corner_radius=12)
            c.grid(row=0,column=i,padx=5,pady=5,sticky='ew',ipady=10)
            val_lbl=lbl(c,val,22,True,'white'); val_lbl.pack(pady=(8,2))
            lbl(c,lt,10,color='white').pack(pady=(0,8))
            self._stat_lbls[key]=val_lbl

        # Фільтр
        ff=ctk.CTkFrame(self,fg_color=C['card']); ff.pack(fill='x',padx=15,pady=3)
        lbl(ff,"Показати:",11,color=C['text2']).pack(side='left',padx=(10,5),pady=8)
        self._filter_var=ctk.StringVar(value='Всі')
        ctk.CTkOptionMenu(ff,values=['Всі','Сьогодні','Вільний','Прибирання','Ремонт'],
            variable=self._filter_var,width=140,fg_color=C['card2'],button_color=C['accent'],
            command=lambda v:self._load_log()).pack(side='left',padx=4)
        btn(ff,"🗑 Очистити журнал",self._clear_log,C['red'],160).pack(side='right',padx=10,pady=8)

        # Таблиця
        main=tk.Frame(self,bg=C['bg']); main.pack(fill='both',expand=True,padx=15,pady=5)
        ff2,self.clean_t=mktree(main,('room','cleaner','started','finished','status','note'),
                                20,[70,160,130,130,110,200])
        for c,h in zip(('room','cleaner','started','finished','status','note'),
                       ['Кімн.','Прибиральник','Початок','Кінець','Статус після','Нотатка']):
            self.clean_t.heading(c,text=h)
        ff2.pack(fill='both',expand=True)
        self.clean_t.bind('<Double-1>', self._edit_log_row)
        self._log=log
        self._load_log()

    def _load_log(self):
        if not hasattr(self,'clean_t'): return
        self.clean_t.delete(*self.clean_t.get_children())
        fv=self._filter_var.get() if hasattr(self,'_filter_var') else 'Всі'
        today_prefix=date.today().strftime('%d.%m.%Y')
        status_map={'free':'✅ Вільний','cleaning':'🧹 Прибирання',
                    'repair':'🔧 Ремонт','blocked':'🔒 Заблокований'}
        for e in reversed(self._log):
            ns=e.get('new_status','')
            if fv=='Сьогодні' and not e.get('logged_at','').startswith(today_prefix): continue
            if fv=='Вільний' and ns!='free': continue
            if fv=='Прибирання' and ns!='cleaning': continue
            if fv=='Ремонт' and ns!='repair': continue
            self.clean_t.insert('','end',values=(
                e.get('room',''), e.get('cleaner',''),
                e.get('started',''), e.get('finished',''),
                status_map.get(ns,ns), e.get('note','')))

    def _clear_log(self):
        import os, json
        if not messagebox.askyesno("Очистити?","Видалити весь журнал прибирань?"): return
        _cl_clear()
        self._rebuild()

    def _get_cleaners(self):
        """Читає список прибиральниць з БД."""
        return _get_cleaners_db()

    def _save_cleaners(self, lst):
        _save_cleaners_db(lst)

    def _manage_cleaners_dlg(self):
        """Діалог управління списком прибиральниць."""
        import json
        cleaners = self._get_cleaners()
        win = dlg_win(self, "👤 Прибиральниці", "400x420")
        main = tk.Frame(win, bg=C['bg']); main.pack(fill='both',expand=True,padx=12,pady=12)
        hdr = card(main); hdr.pack(fill='x',pady=(0,8))
        lbl(hdr,"👤  Список прибиральниць",14,True).pack(anchor='w',padx=12,pady=(10,4))
        lbl(hdr,"Ці імена будуть у списку при реєстрації прибирання",
            10,color=C['text2']).pack(anchor='w',padx=12,pady=(0,10))
        lf = card(main); lf.pack(fill='both',expand=True,pady=(0,8))
        lb = tk.Listbox(lf, bg=C['card2'], fg=C['text'], font=('Segoe UI',12),
                        selectbackground=C['accent'], relief='flat',
                        highlightthickness=0, bd=0)
        lb.pack(fill='both',expand=True,padx=8,pady=8)
        for c in cleaners: lb.insert('end', c)
        af = tk.Frame(main, bg=C['bg']); af.pack(fill='x',pady=(0,8))
        e_new = ent(af, "Ім'я нової прибиральниці", w=220); e_new.pack(side='left',padx=(0,6))
        def add():
            name = e_new.get().strip()
            if not name or name == "Ім'я нової прибиральниці": return
            if name not in cleaners:
                cleaners.append(name)
                lb.insert('end', name)
                self._save_cleaners(cleaners)
            e_new.delete(0,'end')
        def remove():
            sel = lb.curselection()
            if not sel: return
            name = lb.get(sel[0])
            if name in cleaners: cleaners.remove(name)
            lb.delete(sel[0])
            self._save_cleaners(cleaners)
        btn(af,"➕ Додати",add,C['green'],100).pack(side='left',padx=(0,4))
        btn(af,"🗑 Видалити",remove,C['red'],110).pack(side='left')
        btn(main,"✖ Закрити",win.destroy,C['card2'],380,height=38).pack(pady=(0,4))

    def _change_status_dlg(self):
        """Швидка зміна статусу номера з журналу прибирань."""
        from app.utils.db import get_conn as _gc3, query
        import json as _j3, datetime as _dt3
        # Показуємо всі номери зі статусом cleaning/repair/blocked/occupied
        try:
            with _gc3() as _c3:
                with _c3.cursor() as _cur3:
                    _cur3.execute("""SELECT r.id, r.number, r.status, COALESCE(rc.name,'') as cat_name
                        FROM rooms r LEFT JOIN room_categories rc ON r.category_id=rc.id
                        WHERE r.status IN ('cleaning','repair','blocked','occupied','free')
                        ORDER BY r.number""")
                    cols3 = [d[0] for d in _cur3.description]
                    all_rooms = [dict(zip(cols3,row)) for row in _cur3.fetchall()]
        except Exception: all_rooms = []

        win = dlg_win(self, "✏️ Змінити статус номера", "480x540")
        scroll = ctk.CTkScrollableFrame(win, fg_color=C['bg'])
        scroll.pack(fill='both', expand=True, padx=10, pady=10)

        hdr = card(scroll); hdr.pack(fill='x', pady=5)
        lbl(hdr, "✏️  Змінити статус номера", 15, True, C['accent']).pack(anchor='w', padx=12, pady=(10,4))

        f1 = card(scroll); f1.pack(fill='x', pady=4)
        lbl(f1, "🛏 Номер:", 12, True).pack(anchor='w', padx=12, pady=(8,3))
        # Filter to show cleaning rooms first
        cleaning_rooms = [r for r in all_rooms if r['status']=='cleaning']
        priority = cleaning_rooms + [r for r in all_rooms if r['status']!='cleaning']
        room_labels3 = [f"№{r['number']} — {r['cat_name']} [{STATUS_UA.get(r['status'],r['status'])}]" for r in priority]
        rid_by_lbl3 = {room_labels3[i]: priority[i]['id'] for i in range(len(priority))}
        room_var3 = ctk.StringVar(value=room_labels3[0] if room_labels3 else '—')
        ctk.CTkOptionMenu(f1, values=room_labels3 or ['—'], variable=room_var3,
                          width=430, fg_color=C['card2'], button_color=C['accent']).pack(padx=12, pady=(0,10))

        f2 = card(scroll); f2.pack(fill='x', pady=4)
        lbl(f2, "📌 Новий статус:", 12, True).pack(anchor='w', padx=12, pady=(8,3))
        sv3 = ctk.StringVar(value='free')
        sf3 = ctk.CTkFrame(f2, fg_color='transparent'); sf3.pack(fill='x', padx=12, pady=(0,10))
        for val,label_text,clr in [
            ('free',     '✅ Вільний',      C['green']),
            ('cleaning', '🧹 Прибирається', C['yellow']),
            ('repair',   '🔧 Ремонт',       C['gray']),
            ('blocked',  '🔒 Заблокований', C['gray']),
        ]:
            ctk.CTkRadioButton(sf3, text=label_text, variable=sv3, value=val,
                               fg_color=clr, text_color=C['text'],
                               font=('Segoe UI',11)).pack(side='left', padx=6)

        # Прибиральниця (для запису в журнал)
        f3 = card(scroll); f3.pack(fill='x', pady=4)
        lbl(f3, "👤 Прибиральниця:", 12, True).pack(anchor='w', padx=12, pady=(8,3))
        _cl5 = _get_cleaners_db()
        cl_opts5 = _cl5 if _cl5 else ['—']
        cl_var5 = ctk.StringVar(value=cl_opts5[0])
        ctk.CTkOptionMenu(f3, values=cl_opts5, variable=cl_var5,
                          width=430, fg_color=C['card2'], button_color=C['accent']).pack(padx=12, pady=(0,6))
        lbl(f3, "або вручну:", 10, color=C['text2']).pack(anchor='w', padx=12)
        e_cl5 = ent(f3, "Ім'я", w=430); e_cl5.pack(padx=12, pady=(2,10))

        f4 = card(scroll); f4.pack(fill='x', pady=4)
        lbl(f4, "📝 Нотатка:", 12, True).pack(anchor='w', padx=12, pady=(8,3))
        e_note5 = ent(f4, "Що зроблено...", w=430); e_note5.pack(padx=12, pady=(0,10))

        def save5():
            lbl5 = room_var3.get()
            rid5 = rid_by_lbl3.get(lbl5)
            if not rid5: messagebox.showerror("","Оберіть номер"); return
            new_st5 = sv3.get()
            try:
                query("UPDATE rooms SET status=%s WHERE id=%s", (new_st5, rid5), fetch=None)
            except Exception as ex: messagebox.showerror("Помилка БД", str(ex)); return
            # Записати в журнал
            cleaner5 = e_cl5.get().strip()
            if not cleaner5 or cleaner5=="Ім'я": cleaner5=cl_var5.get().strip()
            if cleaner5=='—': cleaner5=''
            _now5 = _dt3.datetime.now().strftime('%d.%m.%Y %H:%M')
            _room_num = lbl5.split('—')[0].replace('№','').strip() if '—' in lbl5 else lbl5
            _cl_append({'room': _room_num, 'cleaner': cleaner5,
                        'started': _now5, 'finished': _now5,
                        'new_status': new_st5, 'note': e_note5.get().strip(),
                        'logged_at': _dt3.datetime.now().strftime('%d.%m.%Y %H:%M:%S')})
            messagebox.showinfo("✅", f"Статус номера оновлено → {STATUS_UA.get(new_st5,new_st5)}")
            win.destroy(); self._rebuild()

        bf5 = ctk.CTkFrame(scroll, fg_color='transparent'); bf5.pack(fill='x', pady=10)
        btn(bf5,"💾 Зберегти",save5,C['green'],200,height=42).pack(side='left',padx=5)
        btn(bf5,"✖ Скасувати",win.destroy,C['red'],140,height=42).pack(side='left',padx=5)

    def _cleaning_dlg(self):
        from app.modules.logic import get_rooms
        from app.utils.db import query
        import os, json, datetime as _dt
        rooms = get_rooms() or []
        # Будуємо map по id кімнати для надійності
        room_list = [(r['id'], f"№{r['number']} — {r.get('cat_name','')} ({STATUS_UA.get(r.get('status',''),'')})", r)
                     for r in rooms]
        room_labels = [x[1] for x in room_list]
        id_by_label = {x[1]: x[0] for x in room_list}
        r_by_id     = {x[0]: x[2] for x in room_list}

        # Список прибиральниць
        cleaners = self._get_cleaners()
        cleaner_options = cleaners + ['— ввести вручну —'] if cleaners else ['— ввести вручну —']

        win = dlg_win(self, "🧹 Прибирання", "500x560")
        main_f = tk.Frame(win, bg=C['bg']); main_f.pack(fill='both',expand=True)
