        hdr=card(scroll); hdr.pack(fill='x',pady=5)
        lbl(hdr,"🧹  Реєстрація прибирання",15,True,C['yellow']).pack(anchor='w',padx=12,pady=(10,4))

        # Вибір номера
        f1=card(scroll); f1.pack(fill='x',pady=4)
