    def _load_room_deposits(self):
        """Завантажує єдиний залог для номерів (перший знайдений != 0, або 0)."""
        if not hasattr(self,'_dep_e'): return
        try:
            from app.utils.db import get_conn as _gcD
            _EXCL=['бесідк','беседк','альтанк','gazebo','баня','бані','sauna','лазня']
            with _gcD() as _c:
                with _c.cursor() as _cur:
                    _cur.execute("""SELECT COALESCE(r.deposit_amount,0) as dep,
                                          COALESCE(c.name,r.cat_name,'') as cat
                                   FROM rooms r LEFT JOIN categories c ON r.category_id=c.id
                                   ORDER BY dep DESC LIMIT 1""")
                    row=_cur.fetchone()
                    dep=float(row[0]) if row else 0.0
        except Exception: dep=0.0
        self._dep_e.delete(0,'end'); self._dep_e.insert(0,str(int(dep)) if dep else "0")

    def _on_dep_sel(self,e): pass  # не використовується в новому UI

    def _save_room_deposit(self):
        try: amount=float(self._dep_e.get().strip())
        except: messagebox.showerror("","Введіть числове значення"); return
        _EXCL=['бесідк','беседк','альтанк','gazebo','баня','бані','sauna','лазня']
        try:
            from app.utils.db import get_conn as _gcSD
            with _gcSD() as _c:
                with _c.cursor() as _cur:
                    # Застосувати до всіх номерів (НЕ бань і НЕ бесідок)
                    _cur.execute("""UPDATE rooms SET deposit_amount=%s
                                    WHERE id IN (
                                        SELECT r.id FROM rooms r
                                        LEFT JOIN categories c ON r.category_id=c.id
                                        WHERE NOT (
                                            lower(COALESCE(c.name,r.cat_name,'')) LIKE ANY(ARRAY[
                                                '%бесідк%','%беседк%','%альтанк%','%gazebo%',
                                                '%баня%','%бані%','%sauna%','%лазня%'
                                            ])
                                        )
                                    )""", (amount,))
                _c.commit()
            self._load_room_deposits()
            messagebox.showinfo("✅", f"Залог {amount:.0f}₴ встановлено для всіх номерів")
        except Exception as ex: messagebox.showerror("Помилка",str(ex))

    def _deposit_room_dlg(self):
        """Швидкий діалог налаштування залогів — один залог на тип."""
        _EXCL_SAUNA   = ['баня','бані','sauna','лазня']
        _EXCL_GAZEBO  = ['бесідк','беседк','альтанк','gazebo']
        def _get_cat_dep(excl_kws):
            try:
                from app.utils.db import get_conn as _gcT
                with _gcT() as _c:
                    with _c.cursor() as _cur:
                        _cur.execute("""SELECT COALESCE(r.deposit_amount,0) as dep,
                                               COALESCE(c.name,r.cat_name,'') as cat
                                        FROM rooms r LEFT JOIN categories c ON r.category_id=c.id
                                        WHERE lower(COALESCE(c.name,r.cat_name,'')) LIKE ANY(%s)
                                        ORDER BY dep DESC LIMIT 1""",
                                     ([f'%{k}%' for k in excl_kws],))
                        row=_cur.fetchone()
                        return float(row[0]) if row else 0.0
            except Exception: return 0.0
        def _get_rooms_dep():
            try:
                from app.utils.db import get_conn as _gcT
                with _gcT() as _c:
                    with _c.cursor() as _cur:
                        _cur.execute("""SELECT COALESCE(r.deposit_amount,0) as dep
                                        FROM rooms r LEFT JOIN categories c ON r.category_id=c.id
                                        WHERE NOT lower(COALESCE(c.name,r.cat_name,'')) LIKE ANY(%s)
                                        ORDER BY dep DESC LIMIT 1""",
                                     (['%бесідк%','%беседк%','%альтанк%','%gazebo%',
                                       '%баня%','%бані%','%sauna%','%лазня%'],))
                        row=_cur.fetchone()
                        return float(row[0]) if row else 0.0
            except Exception: return 0.0

        dep_rooms  = _get_rooms_dep()
        dep_sauna  = _get_cat_dep(_EXCL_SAUNA)
        dep_gazebo = _get_cat_dep(_EXCL_GAZEBO)

        win=dlg_win(self,"💛 Залоги","380x380")
        sc=ctk.CTkScrollableFrame(win,fg_color=C['bg']); sc.pack(fill='both',expand=True,padx=10,pady=10)

        hdr=card(sc); hdr.pack(fill='x',pady=5)
        lbl(hdr,"💛  Залоги",16,True,C['yellow']).pack(padx=12,pady=(10,3))
        lbl(hdr,"Один залог на кожен тип — підставляється при заселенні.",10,color=C['text2']).pack(padx=12,pady=(0,10))

        entries={}
        for label, key, cur_dep, sql_pat in [
            ("🏨 Номери",   'rooms',   dep_rooms,  None),
            ("🔥 Бані",     'sauna',   dep_sauna,  _EXCL_SAUNA),
            ("⛺ Бесідки",  'gazebo',  dep_gazebo, _EXCL_GAZEBO),
        ]:
            c_=card(sc); c_.pack(fill='x',pady=4)
            lbl(c_,label,13,True).pack(anchor='w',padx=12,pady=(8,3))
            rf=tk.Frame(c_,bg=C['card']); rf.pack(fill='x',padx=12,pady=(0,10))
            lbl(rf,"Залог:",11,color=C['text2']).pack(side='left')
            e=ent(rf,str(int(cur_dep)) if cur_dep else "0",w=110); e.pack(side='left',padx=8)
            lbl(rf,"₴",11,color=C['text2']).pack(side='left')
            entries[key]=(e,sql_pat)

        def _save_all():
            try:
                from app.utils.db import get_conn as _gcSA
                with _gcSA() as _c3:
                    with _c3.cursor() as _cur3:
                        # Номери
                        amt_r=float(entries['rooms'][0].get().strip() or 0)
                        _cur3.execute("""UPDATE rooms SET deposit_amount=%s WHERE id IN (
                            SELECT r.id FROM rooms r LEFT JOIN categories c ON r.category_id=c.id
                            WHERE NOT lower(COALESCE(c.name,r.cat_name,'')) LIKE ANY(%s))""",
                            (amt_r,['%бесідк%','%беседк%','%альтанк%','%gazebo%',
                                    '%баня%','%бані%','%sauna%','%лазня%']))
                        # Бані
                        amt_s=float(entries['sauna'][0].get().strip() or 0)
                        _cur3.execute("""UPDATE rooms SET deposit_amount=%s WHERE id IN (
                            SELECT r.id FROM rooms r LEFT JOIN categories c ON r.category_id=c.id
                            WHERE lower(COALESCE(c.name,r.cat_name,'')) LIKE ANY(%s))""",
                            (amt_s,['%баня%','%бані%','%sauna%','%лазня%']))
                        # Бесідки
                        amt_g=float(entries['gazebo'][0].get().strip() or 0)
                        _cur3.execute("""UPDATE rooms SET deposit_amount=%s WHERE id IN (
                            SELECT r.id FROM rooms r LEFT JOIN categories c ON r.category_id=c.id
                            WHERE lower(COALESCE(c.name,r.cat_name,'')) LIKE ANY(%s))""",
                            (amt_g,['%бесідк%','%беседк%','%альтанк%','%gazebo%']))
                    _c3.commit()
                self._load_room_deposits()
                messagebox.showinfo("✅",
                    f"Збережено:\n🏨 Номери: {amt_r:.0f}₴\n🔥 Бані: {amt_s:.0f}₴\n⛺ Бесідки: {amt_g:.0f}₴")
                win.destroy()
            except Exception as ex: messagebox.showerror("Помилка",str(ex))

        bf=tk.Frame(win,bg=C['bg']); bf.pack(fill='x',padx=10,pady=8)
        btn(bf,"💾 Зберегти",_save_all,C['green'],150,height=40).pack(side='left',padx=8)
        btn(bf,"✖ Закрити",win.destroy,C['card2'],100,height=40).pack(side='left')

