    def _load_room_fines(self):
        if not hasattr(self,'fines_t'): return
        self.fines_t.delete(*self.fines_t.get_children())
        try:
            from app.utils.db import get_conn as _gcF
            with _gcF() as _cf2:
                with _cf2.cursor() as _curf:
                    _curf.execute("SELECT id,room_number,reason,COALESCE(amount,0),TO_CHAR(created_at AT TIME ZONE 'Europe/Kyiv','DD.MM HH24:MI') FROM room_fines ORDER BY created_at DESC LIMIT 100")
                    rows=_curf.fetchall()
        except Exception: rows=[]
        for r in rows:
            self.fines_t.insert('','end',iid=str(r[0]),values=(r[1],r[2],f"{float(r[3]):.0f}₴",r[4]))

    def _del_fine(self):
        sel=self.fines_t.selection()
        if not sel: messagebox.showwarning("","Оберіть штраф"); return
        if not messagebox.askyesno("Видалити?","Видалити цей штраф?"): return
        try:
            from app.utils.db import get_conn as _gcDF
            with _gcDF() as _cdf:
                with _cdf.cursor() as _cur: _cur.execute("DELETE FROM room_fines WHERE id=%s",(int(sel[0]),))
                _cdf.commit()
            self._load_room_fines()
        except Exception as ex: messagebox.showerror("Помилка",str(ex))

