    try:
        from app.utils.db import query as _q
        # Шукаємо ціну по cat_name напряму в room_categories
        for _tbl in ('room_categories','categories','room_types','category'):
            try:
                row_p = _q(f"SELECT base_price FROM {_tbl} WHERE name=%s LIMIT 1",
                           (room.get('cat_name',''),), fetch='one')
                if row_p and float(row_p.get('base_price') or 0) > 0:
                    default_price = float(row_p['base_price']); break
            except Exception: continue
        # Якщо не знайшли — через JOIN по id
        if default_price == 0:
            for _tbl in ('room_categories','categories','room_types','category'):
                for _fk in ('category_id','cat_id','room_category_id'):
                    try:
                        row_p = _q(f"SELECT c.base_price FROM rooms r JOIN {_tbl} c ON r.{_fk}=c.id WHERE r.id=%s",
                                   (room['id'],), fetch='one')
                        if row_p and float(row_p.get('base_price') or 0) > 0:
                            default_price = float(row_p['base_price']); break
                    except Exception: continue
                if default_price > 0: break
    except Exception: pass
    # Запасний 1 — напряму з таблиці rooms
    if default_price == 0:
        try:
            row_r = _q("SELECT base_price FROM rooms WHERE id=%s", (room['id'],), fetch='one')
            if row_r and float(row_r.get('base_price') or 0) > 0:
                default_price = float(row_r['base_price'])
        except Exception: pass
    # Запасний 2 — з полів об'єкта room
    if default_price == 0:
        for _key in ('base_price','price','price_per_day','cat_price','cost'):
            _v = room.get(_key)
            if _v:
                try:
                    if float(_v) > 0: default_price = float(_v); break
                except: pass

    pf = tk.Frame(p_card, bg=C['card']); pf.pack(fill='x', padx=12, pady=(0,6))

    lbl(pf,"Ціна/ніч:",12).grid(row=0,column=0,sticky='w',pady=4)
    lbl(pf, f"{default_price:.0f} ₴/ніч", 12, True, C['accent']).grid(row=0,column=1,sticky='w',padx=15,pady=4)

    lbl(pf,"Сума за номер:",12).grid(row=1,column=0,sticky='w',pady=4)
    lbl_total = lbl(pf, "", 13, True, C['green']); lbl_total.grid(row=1,column=1,padx=15,pady=4,sticky='w')
    def _update_total(*a):
        try:
            ci = date.fromisoformat(e_in.get().strip())
            co = date.fromisoformat(e_out.get().strip())
            n = max((co-ci).days, 1)
            base = default_price * n
            try:
                svc_total = sum(float(sv.get('total', 0)) for sv in _get_room_svcs())
            except (NameError, Exception):
                svc_total = 0.0
            grand = base + svc_total
            svc_str = f" + {svc_total:.0f}₴ послуги" if svc_total > 0 else ""
            lbl_total.configure(text=f"{grand:.0f}₴  ({n} ніч × {default_price:.0f}₴{svc_str})")
        except: lbl_total.configure(text="?")
    _update_total()
    e_in.bind('<FocusOut>', _update_total); e_out.bind('<FocusOut>', _update_total)

    lbl(pf,"Залог:",12).grid(row=2,column=0,sticky='w',pady=4)
    dep_row = tk.Frame(pf, bg=C['card']); dep_row.grid(row=2,column=1,sticky='w',pady=4)
    # Автоматично підтягуємо залог з налаштувань кімнати
    _dep_default = 0
    try:
        _dep_default = int(float(room.get('deposit_amount') or 0))
    except Exception:
        pass
    if _dep_default == 0:
        try:
            _dep_row = query("SELECT COALESCE(deposit_amount,0) FROM rooms WHERE id=%s", (room['id'],), fetch='one')
            if _dep_row: _dep_default = int(float(_dep_row[0]))
        except Exception:
            pass
    e_dep = ent(dep_row, str(_dep_default) if _dep_default else "0", w=100)
    if _dep_default:
        e_dep.delete(0, 'end'); e_dep.insert(0, str(_dep_default))
    e_dep.pack(side='left',padx=(0,4))
    lbl(dep_row,"₴",11,color=C['text2']).pack(side='left')
    e_dep.bind('<KeyRelease>', _update_total)

    lbl(pf,"Оплата:",12).grid(row=3,column=0,sticky='w',pady=4)
    meth_var = ctk.StringVar(value='cash')
    mf = tk.Frame(pf, bg=C['card']); mf.grid(row=3,column=1,sticky='w',pady=4)
    for val,label_text,clr in [('cash','💵 Готівка',C['green']),
                                ('card','💳 Картка',C['accent']),
                                ('transfer','🏦 Переказ','#9b59b6')]:
        ctk.CTkRadioButton(mf,text=label_text,variable=meth_var,value=val,
                           fg_color=clr,text_color=C['text'],
                           font=('Segoe UI',11)).pack(side='left',padx=6)

    lbl(pf,"Нотатка:",12).grid(row=4,column=0,sticky='w',pady=4)
    e_note = ent(pf, "", w=300); e_note.grid(row=4,column=1,padx=(15,0),pady=4,sticky='w')

    # ── Додаткові послуги ───────────────────────────────────────────────
    _get_room_svcs = _build_services_block(sc, ['restaurant','minibar','other'],
                                           "🛎 Додаткові послуги до номера",
                                           on_change=_update_total)

    # ── Штраф ────────────────────────────────────────────────────────────
    fine_f = card(sc); fine_f.pack(fill='x', padx=12, pady=5)
    lbl(fine_f,"⚠️  Штраф (необов'язково)",13,True).pack(anchor='w',padx=12,pady=(10,4))
    lbl(fine_f,"Якщо потрібно одразу нарахувати штраф при заселенні",10,color=C['text2']).pack(anchor='w',padx=12,pady=(0,4))
    fine_row=tk.Frame(fine_f,bg=C['card']); fine_row.pack(fill='x',padx=12,pady=(0,10))
    fine_svcs_room=_svcs_by_cat(['штрафи'])
    fine_reason_opts_r=([s['name'] for s in fine_svcs_room] if fine_svcs_room else
        ["Пошкодження майна","Куріння","Пізній виїзд","Втрата ключа","Інше"])
    fine_reason_var_r=ctk.StringVar(value=fine_reason_opts_r[0])
    ctk.CTkOptionMenu(fine_row,values=fine_reason_opts_r,variable=fine_reason_var_r,width=220,
                      fg_color=C['card2'],button_color=C['red'],font=('Segoe UI',10)).pack(side='left',padx=(0,6))
    e_fine_r=ent(fine_row,"0",w=70); e_fine_r.pack(side='left',padx=(0,3))
    lbl(fine_row,"₴",10).pack(side='left')

    def do_checkin():
        from app.modules.logic import update_booking_status
        name  = e_name.get().strip()
        phone = e_phone.get().strip()
        pseries = e_pass_series.get().strip()
        pnum    = e_pass_num.get().strip()
        if not name:  messagebox.showerror("","Введіть ім'я гостя"); return
        if not phone: messagebox.showerror("","Введіть телефон"); return
        try:
            ci = date.fromisoformat(e_in.get().strip())
            co = date.fromisoformat(e_out.get().strip())
            if co <= ci: raise ValueError
        except: messagebox.showerror("","Невірні дати"); return
        price = default_price
        nights = (co - ci).days
        total  = price * nights
        try: dep = float(e_dep.get() or 0)
        except: dep = 0.0

        # Створити/знайти гостя
        passport_info = f"{pseries} {pnum}".strip()
        g = query("SELECT id FROM guests WHERE phone=%s", (phone,), fetch='one')
        if g:
            gid = g['id']
            query("UPDATE guests SET name=%s WHERE id=%s", (name, gid), fetch=None)
        else:
            query("INSERT INTO guests (name, phone) VALUES (%s,%s)", (name, phone), fetch=None)
            g = query("SELECT id FROM guests WHERE phone=%s", (phone,), fetch='one')
            gid = g['id']

        # Створити бронювання з total_amount
        nights_cnt = (co - ci).days
        room_total_amt = price * nights_cnt
        query("""INSERT INTO bookings
                  (guest_id, room_id, check_in, check_out, price_per_day,
                   adults, notes, status, total_amount, created_at)
                  VALUES (%s,%s,%s,%s,%s,%s,%s,'checkedin',%s,NOW())""",
              (gid, room['id'], ci, co, price,
               int(e_adults.get() or 1),
               (f"Паспорт: {passport_info}  " if passport_info.strip() else "") + e_note.get().strip(),
               room_total_amt),
              fetch=None)
        b_row = query("""SELECT id FROM bookings WHERE room_id=%s AND check_in=%s
                          ORDER BY id DESC LIMIT 1""", (room['id'], ci), fetch='one')
        bid = b_row['id']

        # Оплата повної суми
        query("""INSERT INTO payments (booking_id, amount, method, note, shift_id, created_at)
                  VALUES (%s,%s,%s,'Оплата при заселенні',%s,NOW())""",
              (bid, room_total_amt, meth_var.get(), get_current_shift_id()), fetch=None)

        # Залог
        if dep > 0:
            query("""INSERT INTO payments (booking_id,amount,method,note,shift_id,created_at)
                      VALUES (%s,%s,%s,'Залог при заселенні',%s,NOW())""",
                  (bid, dep, meth_var.get(), get_current_shift_id()), fetch=None)

        # Статус кімнати
        query("UPDATE rooms SET status='occupied' WHERE id=%s", (room['id'],), fetch=None)

        # Додаткові послуги — записати ДО формування чека
        _svcs_sel = _get_room_svcs()
        _svc_total = 0.0
        for _sv in _svcs_sel:
            try:
                query("""INSERT INTO service_orders(booking_id,room_id,service_id,quantity,price,total,note,created_at)
                    VALUES(%s,%s,%s,%s,%s,%s,%s,NOW())""",
                    (bid, room['id'], _sv['id'], _sv['qty'], _sv['price'], _sv['total'], _sv['name']), fetch=None)
                _svc_total += _sv['total']
            except Exception: pass

        # Якщо є послуги — додатковий платіж
        if _svc_total > 0:
            query("""INSERT INTO payments (booking_id,amount,method,note,shift_id,created_at)
                      VALUES (%s,%s,%s,'Додаткові послуги при заселенні',%s,NOW())""",
                  (bid, _svc_total, meth_var.get(), get_current_shift_id()), fetch=None)

        grand_total = total + _svc_total
        # Оновити total_amount в бронюванні з урахуванням послуг
        if _svc_total > 0:
            query("UPDATE bookings SET total_amount=%s WHERE id=%s", (grand_total, bid), fetch=None)

        # Штраф (якщо вказано)
        try:
            _fine_amt = float(e_fine_r.get() or 0)
        except: _fine_amt = 0.0
        if _fine_amt > 0:
            try:
                from app.utils.db import get_conn as _gcFR
                with _gcFR() as _cFR:
                    with _cFR.cursor() as _curFR:
                        _curFR.execute("INSERT INTO room_fines(room_id,room_number,reason,amount) VALUES(%s,%s,%s,%s)",
                            (room['id'], room['number'], fine_reason_var_r.get(), _fine_amt))
                    _cFR.commit()
            except Exception: pass

        # Чек з послугами
        lines = [
            f"  Готель: Готель Королівська Бочка",
            f"{'─'*52}",
            f"  ✅ ЧЕК ЗАСЕЛЕННЯ",
            f"{'─'*52}",
            f"  Гість   : {name}",
            f"  Телефон : {phone}",
        ]
        if passport_info.strip():
            lines.append(f"  Паспорт : {passport_info}")
        lines += [
            f"  Номер   : №{room['number']}  ({room.get('cat_name','—')})",
            f"  Заїзд   : {ci}",
            f"  Виїзд   : {co}",
            f"  Ночей   : {nights}",
            f"  Ціна/ніч: {price:.0f}₴",
            f"  Проживання: {total:.0f}₴",
        ]
        if _svcs_sel:
            lines.append(f"{'─'*52}")
            lines.append(f"  Додаткові послуги:")
            for _sv in _svcs_sel:
                lines.append(f"    {_sv['name'][:28]:<28} {float(_sv.get('qty',1)):.0f} × {float(_sv['price']):.0f}₴ = {float(_sv['total']):.0f}₴")
            lines.append(f"  Послуги  : {_svc_total:.0f}₴")
        lines += [
            f"{'─'*52}",
            f"  РАЗОМ   : {grand_total:.0f}₴",
            f"  Метод   : {meth_var.get()}",
        ]
        if dep > 0:
            lines += [
                f"{'─'*52}",
                f"  💛 Залог : {dep:.0f}₴  (повертається при виїзді)",
            ]
        lines += [
            f"{'─'*52}",
            f"  Час     : {_dt.datetime.now().strftime('%d.%m.%Y %H:%M')}",
            f"  Дякуємо за вибір нашого готелю!",
        ]
        cbx_ask_and_receipt(grand_total,
            "CARD" if meth_var.get()=="card" else "CASH",
            f"Заселення №{bid}",
            name, phone)
        print_text(f"Чек заселення №{bid}", lines)
        _invalidate_rooms_cache()   # примусово скидаємо кеш після заселення
        win.destroy()
        if on_save: on_save()

    # Кнопки внизу
    bf = tk.Frame(sc, bg=C['bg']); bf.pack(fill='x', padx=12, pady=10)
    btn(bf, "✅ Заселити та роздрукувати чек", do_checkin, C['green'], 330, height=46).pack(side='left',padx=(0,6))
    btn(bf, "✖ Скасувати", win.destroy, C['red'], 120, height=46).pack(side='left')


