# ЗАЇЗДИ СЬОГОДНІ
# ══════════════════════════════════════════════════════
class TodayArrivalsFrame(tk.Frame):
    def __init__(self, parent, user):
        super().__init__(parent, bg=C['bg'])
        self.user = user
        self._build()

    def _build(self):
        from datetime import date as _date
        tb = tk.Frame(self, bg=C['bg']); tb.pack(fill='x', padx=20, pady=(14,6))
        lbl(tb, "📥  Заїзди сьогодні", 20, True).pack(side='left')
        btn(tb, "🔄", self._load, C['accent'], 44, height=36).pack(side='right', padx=4)

        # Пошук
        sf = tk.Frame(self, bg=C['bg']); sf.pack(fill='x', padx=20, pady=(0,6))
        lbl(sf, "Пошук:", 12).pack(side='left')
        self._search_var = tk.StringVar()
        e = ctk.CTkEntry(sf, textvariable=self._search_var, width=240,
                         placeholder_text="Гість або номер кімнати",
                         font=('Segoe UI',12))
        e.pack(side='left', padx=8)
        self._search_var.trace_add('write', lambda *_: self._apply_filter())

        # Таблиця
        cols = ['room_number','guest_name','phone','check_in','check_out']
        hdrs = {'room_number':'Номер','guest_name':'Гість','phone':'Тел.','check_in':'Заїзд','check_out':'Виїзд'}
        cf = card(self); cf.pack(fill='both', expand=True, padx=20, pady=(0,14))
        ff, tree = mktree(cf, cols, 12, [90, 240, 150, 110, 110])
        for c in cols: tree.heading(c, text=hdrs[c])
        ff.pack(fill='both', expand=True, padx=8, pady=8)
        self._tree = tree
        self._rows = []
        tree.bind('<Double-1>', self._on_row_click)
        tree.bind('<Return>',   self._on_row_click)
        self.after(50, self._load)

    def _load(self):
        import threading
        threading.Thread(target=self._load_bg, daemon=True).start()

    def _load_bg(self):
        from datetime import date as _date
        from app.modules.logic import report_arrivals
        try:
            rows = report_arrivals(_date.today()) or []
            self._rows = rows
            self.after(0, self._apply_filter)
        except Exception as e:
            log_error("TodayArrivalsFrame._load_bg", e)

    def _apply_filter(self):
        q = self._search_var.get().lower().strip()
        self._tree.delete(*self._tree.get_children())
        for r in self._rows:
            if q and q not in (r.get('guest_name','') or '').lower() \
                  and q not in (r.get('room_number','') or '').lower():
                continue
            self._tree.insert('', 'end', values=[
                r.get('room_number',''),
                r.get('guest_name',''),
                r.get('phone',''),
                str(r.get('check_in',''))[:10],
                str(r.get('check_out',''))[:10],
            ])

    def _on_row_click(self, event=None):
        sel = self._tree.selection()
        if not sel: return
        idx = self._tree.index(sel[0])
        q = self._search_var.get().lower().strip()
        visible = [r for r in self._rows
                   if not q or q in (r.get('guest_name','') or '').lower()
                   or q in (r.get('room_number','') or '').lower()]
        if idx >= len(visible): return
        row = visible[idx]
        bid = row.get('id') or row.get('booking_id')
        if not bid:
            from app.utils.db import query as _qa
            _bk = _qa("""SELECT b.id FROM bookings b JOIN rooms r ON r.id=b.room_id
                          LEFT JOIN guests g ON g.id=b.guest_id
                          WHERE r.number=%s AND COALESCE(g.name,'')=%s
                          AND b.status IN ('confirmed','checkedin') LIMIT 1""",
                      (row.get('room_number'), row.get('guest_name','')), fetch='one')
            bid = (_bk[0] if isinstance(_bk,(tuple,list)) else _bk.get('id')) if _bk else None
        if not bid:
            messagebox.showwarning("", "Не вдалось знайти бронювання"); return
        bid = int(bid)
        menu = tk.Menu(self, tearoff=0, bg=C['card'], fg=C['text'],
                       activebackground=C['accent'], activeforeground='white',
                       font=('Segoe UI', 12))
        menu.add_command(label="🏨  Заселити",
                         command=lambda: _open_checkin_from_booking(self, bid, self._load))
        menu.add_command(label="💰  Оплата",
                         command=lambda: PaymentDlg(self, bid, self._load))
        try:
            menu.tk_popup(self.winfo_rootx() + 300, self.winfo_rooty() + 150)
        finally:
            menu.grab_release()

    def _load_data_async(self):
        self._load()


