# ВИЇЗДИ СЬОГОДНІ
# ══════════════════════════════════════════════════════
class TodayDeparturesFrame(tk.Frame):
    def __init__(self, parent, user):
        super().__init__(parent, bg=C['bg'])
        self.user = user
        self._build()

    def _build(self):
        from datetime import date as _date
        tb = tk.Frame(self, bg=C['bg']); tb.pack(fill='x', padx=20, pady=(14,6))
        lbl(tb, "📤  Виїзди сьогодні", 20, True).pack(side='left')
        btn(tb, "🔄", self._load, C['accent'], 44, height=36).pack(side='right', padx=4)

        # Пошук
        sf = tk.Frame(self, bg=C['bg']); sf.pack(fill='x', padx=20, pady=(0,6))
        lbl(sf, "Пошук:", 12).pack(side='left')
        self._search_var = tk.StringVar()
        e = ctk.CTkEntry(sf, textvariable=self._search_var, width=240,
                         placeholder_text="Гість або номер кімнати",
                         font=('Segoe UI',12))
        e.pack(side='left', padx=8)
        self._search_var.trace_add('write', lambda *_: self._apply_filter())

        # Таблиця
        cols = ['room_number','guest_name','phone','check_in','check_out','debt']
        hdrs = {'room_number':'Номер','guest_name':'Гість','phone':'Тел.','check_in':'Заїзд','check_out':'Виїзд','debt':'Борг'}
        cf = card(self); cf.pack(fill='both', expand=True, padx=20, pady=(0,14))
        ff, tree = mktree(cf, cols, 12, [90, 200, 140, 100, 100, 100])
        for c in cols: tree.heading(c, text=hdrs[c])
        # Виділити червоним рядки з боргом
        tree.tag_configure('debt', foreground='#ff6b6b')
        ff.pack(fill='both', expand=True, padx=8, pady=8)
        self._tree = tree
        self._rows = []
        tree.bind('<Double-1>', self._on_row_click)
        tree.bind('<Return>',   self._on_row_click)
        self.after(50, self._load)

    def _load(self):
        import threading
        threading.Thread(target=self._load_bg, daemon=True).start()

    def _load_bg(self):
        from datetime import date as _date
        from app.utils.db import query as _q
        try:
            rows = _q("""
                SELECT b.id, r.number as room_number, COALESCE(g.name,'') as guest_name,
                       g.phone, b.check_in, b.check_out,
                       GREATEST(b.total_amount - COALESCE((
                           SELECT SUM(p.amount) FROM payments p
                           WHERE p.booking_id = b.id AND p.amount > 0
                             AND (p.note IS NULL OR p.note NOT LIKE 'Залог%%')
                       ), 0), 0) AS debt
                FROM bookings b
                JOIN rooms r ON r.id = b.room_id
                LEFT JOIN guests g ON g.id = b.guest_id
                WHERE b.check_out::date = %s
                  AND b.status = 'checkedin'
                ORDER BY r.number
            """, (_date.today(),), fetch='all') or []
            # Normalize to dicts
            cols = ['id','room_number','guest_name','phone','check_in','check_out','debt']
            self._rows = [dict(zip(cols, r)) if isinstance(r,(tuple,list)) else r for r in rows]
            self.after(0, self._apply_filter)
        except Exception as e:
            log_error("TodayDeparturesFrame._load_bg", e)

    def _apply_filter(self):
        q = self._search_var.get().lower().strip()
        self._tree.delete(*self._tree.get_children())
        for r in self._rows:
            if q and q not in (r.get('guest_name','') or '').lower() \
                  and q not in (r.get('room_number','') or '').lower():
                continue
            debt = float(r.get('debt') or 0)
            tag = ('debt',) if debt > 0 else ()
            self._tree.insert('', 'end', tags=tag, values=[
                r.get('room_number',''),
                r.get('guest_name',''),
                r.get('phone',''),
                str(r.get('check_in',''))[:10],
                str(r.get('check_out',''))[:10],
                f"{debt:.0f}₴" if debt else '—',
            ])

    def _on_row_click(self, event=None):
        sel = self._tree.selection()
        if not sel: return
        idx = self._tree.index(sel[0])
        q = self._search_var.get().lower().strip()
        visible = [r for r in self._rows
                   if not q or q in (r.get('guest_name','') or '').lower()
                   or q in (r.get('room_number','') or '').lower()]
        if idx >= len(visible): return
        row = visible[idx]
        bid = row.get('id') or row.get('booking_id')
        if not bid:
            from app.utils.db import query as _qd
            _bk = _qd("""SELECT b.id FROM bookings b JOIN rooms r ON r.id=b.room_id
                          LEFT JOIN guests g ON g.id=b.guest_id
                          WHERE r.number=%s AND COALESCE(g.name,'')=%s AND b.status='checkedin' LIMIT 1""",
                      (row.get('room_number'), row.get('guest_name','')), fetch='one')
            bid = (_bk[0] if isinstance(_bk,(tuple,list)) else _bk.get('id')) if _bk else None
        if not bid:
            messagebox.showwarning("", "Не вдалось знайти бронювання"); return
        bid = int(bid)
        menu = tk.Menu(self, tearoff=0, bg=C['card'], fg=C['text'],
                       activebackground=C['accent'], activeforeground='white',
                       font=('Segoe UI', 12))
        menu.add_command(label="🚪  Виселити",
                         command=lambda: _open_checkout_dlg(self, bid, self._load))
        menu.add_command(label="📅  Продовжити",
                         command=lambda: self._do_extend(bid))
        menu.add_command(label="💰  Оплата",
                         command=lambda: PaymentDlg(self, bid, self._load))
        try:
            x = self.winfo_rootx() + 300
            y = self.winfo_rooty() + 150
            menu.tk_popup(x, y)
        finally:
            menu.grab_release()

    def _do_extend(self, bid):
        try:
            from app.modules.logic import get_booking as _gb
            _b = _gb(bid)
            _cn = (_b.get('cat_name') or '').lower() if _b else ''
            _nt = (_b.get('notes') or '').lower() if _b else ''
            _is_sauna = any(k in _cn for k in ['баня','бані','sauna']) or 'баня:' in _nt
        except Exception:
            _is_sauna = False
        if _is_sauna:
            from app.utils.db import query as _q2
            from app.modules.logic import get_booking as _gb2
            _bk = _gb2(bid)
            _rm = _q2("SELECT * FROM rooms WHERE id=%s", (_bk['room_id'],), fetch='one') if _bk else None
            _open_extend_sauna_dlg(self, bid, _rm or {}, self._load)
        else:
            _open_extend_room_dlg(self, bid, self._load)

    def _load_data_async(self):
        self._load()


class ChessFrame(tk.Frame):
    def __init__(self, parent, user):
        super().__init__(parent, bg=C['bg'])
        self.user=user; self.start=date.today(); self.days=14
        self._build_toolbar()
        # Завантаження даних у фоні — не блокуємо UI
        self.after(10, self._draw)

    def _load_data_async(self):
        """Викликається при повторному відкритті вкладки."""
        self._redraw()

    def _build_toolbar(self):
        tb=ctk.CTkFrame(self,fg_color=C['card'],height=52)
        tb.pack(fill='x',padx=15,pady=(15,5)); tb.pack_propagate(False)
        lbl(tb,"📅  Шахматка",18,True).pack(side='left',padx=15)
        btn(tb,"◀ -7",lambda:self._shift(-7),C['card2'],70).pack(side='left',padx=3,pady=8)
        btn(tb,"Сьогодні",self._today,C['card2'],90).pack(side='left',padx=3,pady=8)
        btn(tb,"▶ +7",lambda:self._shift(7),C['card2'],70).pack(side='left',padx=3,pady=8)
        lbl(tb,"Днів:",11,color=C['text2']).pack(side='left',padx=(10,3))
        self.days_var=ctk.StringVar(value="14")
        ctk.CTkOptionMenu(tb,values=["7","14","21","30","60","90","180","365"],
                          variable=self.days_var,
                          width=80,fg_color=C['card2'],button_color=C['accent'],
                          command=lambda v:(setattr(self,'days',int(v)),self._redraw())).pack(side='left',pady=8)
        # Кнопки швидкого вибору місяців
        for lbl_t, d in [("1М",30),("3М",90),("6М",180),("1Р",365)]:
            btn(tb, lbl_t, lambda d=d:(setattr(self,'days',d),self.days_var.set(str(d)),self._redraw()),
                C['card2'], 44).pack(side='left', padx=2, pady=8)
        self.tb = tb

    def _shift(self,d): self.start+=timedelta(days=d); self._redraw()
    def _today(self):   self.start=date.today();       self._redraw()

    def _redraw(self):
        # Знищуємо canvas_area і банер (якщо є) перед перемалюванням
        if hasattr(self, 'canvas_area'):
            try: self.canvas_area.destroy()
            except Exception: pass
        if hasattr(self, '_chess_overdue_banner'):
            try: self._chess_overdue_banner.destroy()
            except Exception: pass
        self._draw()

    def _draw(self):
        from app.modules.logic import get_chess
        from app.utils.db import get_conn as _gc

        self.canvas_area = tk.Frame(self, bg=C['bg'])
        self.canvas_area.pack(fill='both', expand=True, padx=15, pady=5)

        end=self.start+timedelta(days=self.days)
        self._rooms=_get_rooms_cached() or []
        try:
            self._chess=get_chess(self.start,end) or []
        except Exception:
            # Офлайн-fallback для шахматки: читаємо з SQLite
            try:
                self._chess = _sqlite_bookings(
                    status=['confirmed','checkedin'],
                    limit=1000)
            except Exception:
                self._chess = []

        # Оновлюємо статуси кімнат напряму з БД (кеш може бути застарілим)
        try:
            with _gc() as _dc:
                with _dc.cursor() as _dcur:
                    _dcur.execute("SELECT id, status FROM rooms")
                    _live = {row[0]: row[1] for row in _dcur.fetchall()}
            for r in self._rooms:
                _rid = int(r['id'])
                if _rid in _live:
                    r['status'] = _live[_rid]
        except Exception:
            # Офлайн-fallback: статуси з SQLite
            try:
                _sq_rooms = _sqlite_rooms_with_status()
                _live_sq = {int(r['id']): r.get('status','free') for r in _sq_rooms}
                for r in self._rooms:
                    _rid = int(r.get('id', 0))
                    if _rid in _live_sq:
                        r['status'] = _live_sq[_rid]
            except Exception:
                pass
        today=date.today()
        CW,CH,LW,LH=48,38,210,40
        self._CW=CW; self._CH=CH; self._LW=LW; self._LH=LH
        W=LW+self.days*CW+20; H=LH+len(self._rooms)*CH+20

        canvas=tk.Canvas(self.canvas_area,bg=C['bg'],highlightthickness=0)
        sx=tk.Scrollbar(self.canvas_area,orient='horizontal',command=canvas.xview)
        sy=tk.Scrollbar(self.canvas_area,orient='vertical',command=canvas.yview)
        canvas.configure(xscrollcommand=sx.set,yscrollcommand=sy.set,scrollregion=(0,0,W,H))
        sx.pack(side='bottom',fill='x'); sy.pack(side='right',fill='y')
        canvas.pack(side='left',fill='both',expand=True)
        self._canvas=canvas

        # ── Overlay прострочених виїздів поверх canvas шахматки ─────────────
        def _chess_overdue_overlay():
            try:
                today_chess = date.today()
                _overdue_chess = []
                try:
                    with _gc() as _oc:
                        with _oc.cursor() as _ocur:
                            _ocur.execute("""
                                SELECT b.id, r.number as room_number,
                                       COALESCE(g.name,'') as guest_name, b.check_out
                                FROM bookings b
                                JOIN rooms r ON r.id = b.room_id
                                LEFT JOIN guests g ON g.id = b.guest_id
                                WHERE b.status = 'checkedin'
                                  AND b.check_out <= %s
                                ORDER BY b.check_out ASC
                            """, (today_chess,))
                            _cols_c = [d[0] for d in _ocur.description]
                            _rows_c = [dict(zip(_cols_c, row)) for row in _ocur.fetchall()]
                            for _rc in _rows_c:
                                try:
                                    _co_c = _rc['check_out']
                                    if hasattr(_co_c, 'date'): _co_c = _co_c.date()
                                    elif isinstance(_co_c, str):
                                        import datetime as _dtp2
                                        _co_c = _dtp2.date.fromisoformat(_co_c[:10])
                                    _rc['days_late'] = (today_chess - _co_c).days
                                except Exception:
                                    _rc['days_late'] = 0
                            _overdue_chess = _rows_c
                except Exception as _ce:
                    log_error("Chess: overdue query", _ce)
                    # Офлайн-fallback
                    try:
                        _overdue_chess = _sqlite_select(
                            """SELECT b.id, r.number as room_number,
                               COALESCE(g.name,'') as guest_name, b.check_out
                               FROM bookings b JOIN rooms r ON r.id=b.room_id
                               LEFT JOIN guests g ON g.id=b.guest_id
                               WHERE b.status='checkedin' AND b.check_out <= ?
                               ORDER BY b.check_out ASC""", (str(today_chess),))
                        for _rc in _overdue_chess:
                            try:
                                _co_c = _rc['check_out']
                                if isinstance(_co_c, str):
                                    import datetime as _dtp3
                                    _co_c = _dtp3.date.fromisoformat(_co_c[:10])
                                _rc['days_late'] = (today_chess - _co_c).days
                            except Exception:
                                _rc['days_late'] = 0
                    except Exception:
                        _overdue_chess = []

                if not _overdue_chess: return
                _strictly = [b for b in _overdue_chess if b.get('days_late', 0) > 0]
                _today_co = [b for b in _overdue_chess if b.get('days_late', 0) == 0]
                _bg_c  = '#3d0000' if _strictly else '#3d2c00'
                _brd_c = '#ff4444' if _strictly else '#ffcc00'
                _icon_c = "🚨" if _strictly else "⚠️"
                _btitle = (f"{_icon_c}  {len(_strictly)} прострочених виїздів — Виселити або Продовжити"
                           if _strictly else
                           f"⚠️  Виїзд сьогодні: {len(_today_co)} номерів — Виселити або Продовжити")

                # Overlay прикріплюємо до canvas (вже намальованого)
                ov = tk.Frame(canvas, bg=_bg_c,
                              highlightbackground=_brd_c, highlightthickness=2)
                ov.place(relx=0.0, rely=0.0, anchor='nw', relwidth=1.0, y=0)

                hf = tk.Frame(ov, bg=_bg_c); hf.pack(fill='x', padx=10, pady=(6, 3))
                tk.Label(hf, text=_btitle, bg=_bg_c, fg=_brd_c,
                         font=('Segoe UI', 11, 'bold')).pack(side='left')
                tk.Button(hf, text='✕', bg=_bg_c, fg='#888888',
                          relief='flat', bd=0, cursor='hand2',
                          font=('Segoe UI', 10),
                          command=lambda: ov.place_forget()).pack(side='right')

                cf = tk.Frame(ov, bg=_bg_c); cf.pack(fill='x', padx=10, pady=(0, 6))
                for _b in _overdue_chess[:12]:
                    _dov = _b.get('days_late', 0)
                    _bc = '#cc0000' if _dov > 0 else '#cc8800'
                    _bt = f"+{_dov} дн." if _dov > 0 else "виїзд"
                    _nm = (_b.get('guest_name') or '—').split()[0]
                    _ch = tk.Frame(cf, bg=_bc, padx=5, pady=2)
                    _ch.pack(side='left', padx=2, pady=2)
                    tk.Label(_ch, text=f"№{_b.get('room_number','?')} {_nm} {_bt}",
                             bg=_bc, fg='white', font=('Segoe UI', 9, 'bold')).pack()
                if len(_overdue_chess) > 12:
                    tk.Label(cf, text=f"  +{len(_overdue_chess)-12} ще",
                             bg=_bg_c, fg='#888888', font=('Segoe UI', 9)).pack(side='left', padx=4)
                ov.lift()
            except Exception as _chess_err:
                log_error("Chess: overdue overlay", _chess_err)
        self.after(50, _chess_overdue_overlay)

        for i in range(self.days):
            d=self.start+timedelta(days=i); x=LW+i*CW
            bg=C['red'] if d==today else (C['card2'] if d.weekday()>=5 else C['card'])
            canvas.create_rectangle(x,0,x+CW,LH,fill=bg,outline=C['border'])
            canvas.create_text(x+CW//2,LH//2,
                text=f"{d.day}\n{['Пн','Вт','Ср','Чт','Пт','Сб','Нд'][d.weekday()]}",
                fill=C['text'],font=('Segoe UI',9,'bold'),justify='center')

        for ri,room in enumerate(self._rooms):
            y=LH+ri*CH
            canvas.create_rectangle(0,y,LW,y+CH,fill=C['card'],outline=C['border'])
            canvas.create_rectangle(2,y+2,7,y+CH-2,fill=STATUS_COLOR.get(room['status'],C['gray']),outline='')
            canvas.create_text(LW//2+5,y+CH//2,
                text=f"№{room['number']}  {(room.get('cat_name') or '')}",
                fill=C['text'],font=('Segoe UI',10,'bold'))
            for i in range(self.days):
                x=LW+i*CW
                bg='#141828' if (self.start+timedelta(days=i)).weekday()>=5 else C['bg']
                canvas.create_rectangle(x,y,x+CW,y+CH,fill=bg,outline=C['border'])

        # Малюємо статус прибирання/ремонту/блокування поверх порожніх клітинок
        _statuses_to_show = {'cleaning', 'repair', 'blocked', 'occupied'}
        _status_colors = {'cleaning': C['yellow'], 'repair': C['gray'],
                          'blocked': '#555', 'occupied': C['red']}
        for ri, room in enumerate(self._rooms):
            st = room.get('status', 'free')
            if st not in _statuses_to_show: continue
            _st_color = _status_colors.get(st, C['gray'])
            _st_text  = STATUS_UA.get(st, '')
            y = LH + ri * CH
            # Знаходимо дні які НЕ покриті бронюванням
            _booked_days = set()
            for b2 in self._chess:
                if int(b2['room_id']) == int(room['id']):
                    for di in range((min(b2['check_out'], end) - max(b2['check_in'], self.start)).days):
                        _booked_days.add((max(b2['check_in'], self.start) + timedelta(days=di)))
            # Статус відображаємо тільки на сьогодні (поточний стан номера)
            if today >= self.start and today < end and today not in _booked_days:
                i = (today - self.start).days
                x = LW + i * CW
                canvas.create_rectangle(x+1, y+1, x+CW-1, y+CH-1, fill=_st_color, outline='', stipple='gray25')
                if CW > 30:
                    canvas.create_text(x+CW//2, y+CH//2, text=_st_text[:5],
                                       fill='white', font=('Segoe UI', 7))

        for b in self._chess:
            _bid = int(b['room_id']) if b.get('room_id') is not None else None
            ri=next((i for i,r in enumerate(self._rooms) if int(r['id'])==_bid),None)
            if ri is None: continue
            ci=max(b['check_in'],self.start)
            # check_out — день виїзду: гість ще в номері вранці, тому малюємо ДО check_out включно
            co_raw=min(b['check_out'],end)
            # Якщо co == ci (виїзд сьогодні = перший видимий день) — показуємо 1 клітинку
            co=co_raw if co_raw > ci else ci+timedelta(days=1)
            x1=LW+(ci-self.start).days*CW+2; x2=LW+(co-self.start).days*CW-2
            # Гарантуємо мінімальну ширину 1 клітинки
            if x2 < x1+4: x2=x1+CW-4
            y1=LH+ri*CH+3;                   y2=LH+ri*CH+CH-3
            color=C['green'] if b['status']=='checkedin' else C['accent']
            canvas.create_rectangle(x1,y1,x2,y2,fill=color,outline='')
            if x2-x1>20:
                name=(b.get('guest_name') or '').split()[0]
                canvas.create_text((x1+x2)//2,(y1+y2)//2,text=name,fill='white',font=('Segoe UI',8),width=x2-x1-4)

        def _chess_scroll_v(e): self._canvas.yview_scroll(int(-1*(e.delta/120)), 'units')
        def _chess_scroll_h(e): self._canvas.xview_scroll(int(-1*(e.delta/120)), 'units')
        def _chess_enter(e):
            self._canvas.bind_all('<MouseWheel>', _chess_scroll_v)
            self._canvas.bind_all('<Shift-MouseWheel>', _chess_scroll_h)
        def _chess_leave(e):
            try: self._canvas.unbind_all('<MouseWheel>')
            except Exception: pass
            try: self._canvas.unbind_all('<Shift-MouseWheel>')
            except Exception: pass
        canvas.bind('<Enter>', _chess_enter)
        canvas.bind('<Leave>', _chess_leave)
        canvas.bind('<Button-1>', self._on_click)

    def _on_click(self, event):
        """Клік на шахматці — визначає що клікнули: номер чи клітинку."""
        cx = self._canvas.canvasx(event.x)
        cy = self._canvas.canvasy(event.y)
        CW,CH,LW,LH = self._CW,self._CH,self._LW,self._LH

        # Клік на назву номера (ліва колонка) — змінити статус номера
        if cx < LW and cy >= LH:
            ri = int((cy - LH) // CH)
            if ri < len(self._rooms):
                self._room_status_dlg(self._rooms[ri])
            return

        # Клік на клітинку сітки
        if cx >= LW and cy >= LH:
            col = int((cx - LW) // CW)
            ri  = int((cy - LH) // CH)
            if col >= self.days or ri >= len(self._rooms): return
            click_date = self.start + timedelta(days=col)
            room = self._rooms[ri]

            # Перевірити чи є бронювання на цей день
            existing = next((b for b in self._chess
                if int(b['room_id'])==int(room['id'])
                and b['check_in'] <= click_date < b['check_out']), None)

            if existing:
                self._booking_action_dlg(existing)
            else:
                self._new_booking_dlg(room, click_date)

    def _room_status_dlg(self, room):
        """Діалог зміни статусу номера."""
        from app.utils.db import query
        win = dlg_win(self, f"Статус номера №{room['number']}", "380x320")
        scroll = ctk.CTkScrollableFrame(win, fg_color=C['bg'])
        scroll.pack(fill='both', expand=True, padx=10, pady=10)
        f = card(scroll); f.pack(fill='x', pady=5)
        lbl(f, f"№{room['number']} — {room.get('cat_name','')}", 14, True, C['accent']).pack(pady=(12,5))
        lbl(f, f"Поточний: {STATUS_UA.get(room['status'],'')}", 12, color=C['text2']).pack(pady=(0,10))

        sv = ctk.StringVar(value=room['status'])
        for val, label_text, color in [
            ('free',     '✅ Вільний',      C['green']),
            ('repair',   '🔧 Ремонт',       C['gray']),
            ('cleaning', '🧹 Прибирання',   C['yellow']),
            ('blocked',  '🔒 Заблокований', C['gray']),
        ]:
            rb_frame = ctk.CTkFrame(f, fg_color=C['card2'], corner_radius=8)
            rb_frame.pack(fill='x', padx=12, pady=3)
            ctk.CTkRadioButton(rb_frame, text=label_text, variable=sv, value=val,
                               fg_color=color, text_color=C['text'],
                               font=('Segoe UI',12)).pack(anchor='w', padx=15, pady=8)

        bf = ctk.CTkFrame(scroll, fg_color='transparent'); bf.pack(fill='x', pady=8)
        # Прибиральниця (показується якщо вибрано "cleaning")
        cl_f = card(scroll); cl_f.pack(fill='x', pady=5)
        lbl(cl_f, "👤 Прибиральниця:", 11, True).pack(anchor='w', padx=12, pady=(8,3))
        cleaners2 = _get_cleaners_db()
        cleaner_opts2 = cleaners2 if cleaners2 else ['—']
        cleaner_var2 = ctk.StringVar(value=cleaner_opts2[0])
        ctk.CTkOptionMenu(cl_f, values=cleaner_opts2, variable=cleaner_var2,
                          width=320, fg_color=C['card2'],
                          button_color=C['accent']).pack(padx=12, pady=(0,6))
        lbl(cl_f, "або вручну:", 10, color=C['text2']).pack(anchor='w', padx=12)
        e_cl2 = ent(cl_f, "Ім'я", w=320); e_cl2.pack(padx=12, pady=(2,10))

        def save():
            new_st = sv.get()
            try:
                query("UPDATE rooms SET status=%s WHERE id=%s", (new_st, room['id']), fetch=None)
            except Exception as e:
                messagebox.showerror("Помилка", str(e)); return
            # Якщо поставлено "Прибирання" — писати в журнал
            if new_st == 'cleaning':
                import json as _jlog, datetime as _dtlog
                cleaner_name = e_cl2.get().strip()
                if not cleaner_name or cleaner_name == "Ім'я":
                    cleaner_name = cleaner_var2.get().strip()
                if cleaner_name == '—': cleaner_name = ''
                _now = _dtlog.datetime.now().strftime('%d.%m.%Y %H:%M')
                _cl_append({
                    'room':       str(room['number']),
                    'cleaner':    cleaner_name,
                    'started':    _now,
                    'finished':   '',
                    'new_status': 'cleaning',
                    'note':       '',
                    'logged_at':  _dtlog.datetime.now().strftime('%d.%m.%Y %H:%M:%S'),
                })
            win.destroy(); self._redraw()

        btn(bf, "💾 Зберегти", save, C['accent'], 180, height=38).pack(side='left', padx=5)
        btn(bf, "✖ Скасувати", win.destroy, C['red'], 130, height=38).pack(side='left', padx=5)

    def _booking_action_dlg(self, b):
        """Клік на існуюче бронювання — дії."""
        win = dlg_win(self, f"Бронювання #{b['id']}", "400x320")
        scroll = ctk.CTkScrollableFrame(win, fg_color=C['bg'])
        scroll.pack(fill='both', expand=True, padx=10, pady=10)
        f = card(scroll); f.pack(fill='x', pady=5)
        lbl(f, f"👤 {b.get('guest_name','')}", 15, True, C['accent']).pack(pady=(12,4))
        lbl(f, f"📅 {b['check_in']} → {b['check_out']}", 12, color=C['text2']).pack(pady=2)
        n = (b['check_out'] - b['check_in']).days
        lbl(f, f"🛏 Номер: {b.get('room_number','')}  |  {n} ночей", 12).pack(pady=2)
        status_color = STATUS_COLOR.get(b['status'], C['gray'])
        lbl(f, f"● {STATUS_UA.get(b['status'],b['status'])}", 12, color=status_color).pack(pady=(2,12))

        def action(s):
            try:
                from app.modules.logic import update_booking_status
                update_booking_status(b['id'], s)
            except Exception as e:
                messagebox.showerror("Помилка", str(e)); return
            win.destroy(); self._redraw()

        # Кнопка заселення — відкриває повноцінне вікно
        r0 = ctk.CTkFrame(scroll, fg_color='transparent'); r0.pack(fill='x', pady=2)
        def do_checkin_from_chess():
            room_ = _get_room_by_id(b['room_id'])
            if not room_: messagebox.showerror("","Номер не знайдено (id="+str(b.get('room_id'))+")"); return
            parent_ref = self  # зберегти до знищення вікна
            win.destroy()
            _open_checkin_existing(parent_ref, b, room_, self._redraw)
        btn(r0, "✅ Заселити", do_checkin_from_chess, C['green'], 360, height=40).pack(fill='x', padx=5)

        # Виселення — повноцінне вікно з поверненням залогу
        r_co = ctk.CTkFrame(scroll, fg_color='transparent'); r_co.pack(fill='x', pady=2)
        def do_checkout_from_chess():
            _open_checkout_dlg(self, b['id'], self._redraw)
            win.destroy()
        btn(r_co, "🚪 Виселити", do_checkout_from_chess,
            C['yellow'], 360, height=40).pack(fill='x', padx=5)
        # Скасувати — без залогу
        r_ca = ctk.CTkFrame(scroll, fg_color='transparent'); r_ca.pack(fill='x', pady=2)
        btn(r_ca, "❌ Скасувати", lambda: action('cancelled'), C['red'], 360, height=40).pack(fill='x', padx=5)

        r2 = ctk.CTkFrame(scroll, fg_color='transparent'); r2.pack(fill='x', pady=2)
        btn(r2, "📋 Відкрити деталі",
            lambda: (win.destroy(), BookingDetailDlg(self, b['id'], self._redraw)),
            C['accent'], 360, height=40).pack(fill='x', padx=5)
        btn(r2, "✖ Закрити", win.destroy, C['card2'], 360, height=36).pack(fill='x', padx=5, pady=(4,0))

    def _new_booking_dlg(self, room, click_date):
        """Клік на клітинку — нове бронювання або виселення якщо заселений."""
        st = room.get('status', '')

        # Якщо номер заселений — одразу відкриваємо діалог виселення
        if st == 'checkedin':
            try:
                from app.utils.db import get_conn as _gc_co
                with _gc_co() as _conn_co:
                    with _conn_co.cursor() as _cur_co:
                        _cur_co.execute(
                            "SELECT id FROM bookings WHERE room_id=%s AND status='checkedin' LIMIT 1",
                            (room['id'],))
                        _bid_row = _cur_co.fetchone()
                        if _bid_row:
                            _open_checkout_dlg(self, _bid_row[0], self._redraw)
                            return
            except Exception:
                pass
            messagebox.showinfo("ℹ️", f"Номер №{room['number']} заселений, але бронювання не знайдено.")
            return

        # Прибирання / ремонт — питаємо
        if st not in ('free', 'confirmed', None, ''):
            if not messagebox.askyesno(
                "Номер недоступний",
                f"Номер №{room['number']} має статус '{STATUS_UA.get(st, st)}'.\n"
                "Все одно створити бронювання?"):
                return

        win = dlg_win(self, f"Номер №{room['number']} — {click_date.strftime('%d.%m.%Y')}", "380x290")
        scroll = ctk.CTkScrollableFrame(win, fg_color=C['bg'])
        scroll.pack(fill='both', expand=True, padx=10, pady=10)
        f = card(scroll); f.pack(fill='x', pady=5)
        lbl(f, f"🛏 №{room['number']} — {room.get('cat_name','')}", 14, True, C['accent']).pack(pady=(12,3))
        lbl(f, f"📅 {click_date.strftime('%d.%m.%Y')}", 12, color=C['text2']).pack(pady=(0,12))

        # Перевірити чи є активне бронювання для виселення
        active_bid = None
        try:
            from app.utils.db import get_conn as _gc_ch
            with _gc_ch() as _conn_ch:
                with _conn_ch.cursor() as _cur_ch:
                    _cur_ch.execute(
                        "SELECT id FROM bookings WHERE room_id=%s AND status='checkedin' LIMIT 1",
                        (room['id'],)
                    )
                    _row_ch = _cur_ch.fetchone()
                    if _row_ch:
                        active_bid = _row_ch[0]
        except Exception:
            pass

        # Визначаємо тип об'єкта: баня/бесідка → годинний діалог; готель → нічний
        _cn = (room.get('cat_name') or '').lower()
        _cd = (room.get('cat_description') or room.get('description') or '').lower()
        _is_sauna   = any(k in _cn for k in ['баня','бані','sauna']) or '[tariff:hour]' in _cd
        _is_gazebo  = False  # бесідки — подобово, не погодинно
        _is_hourly  = _is_sauna or _is_gazebo

        if _is_hourly:
            actions = [
                ("📋 Забронювати",
                 lambda: (win.destroy(), _open_sauna_booking_dlg(self, room, self._redraw)),
                 C['accent']),
                ("✅ Одразу заселити",
                 lambda: (win.destroy(), _open_sauna_checkin_dlg(self, room, self._redraw)),
                 C['green']),
            ]
        else:
            actions = [
                ("📋 Забронювати",
                 lambda: (win.destroy(), _open_booking_dlg(self, room, click_date, self._redraw)),
                 C['accent']),
                ("✅ Одразу заселити",
                 lambda: (win.destroy(), _open_checkin_dlg(self, room, click_date, self._redraw)),
                 C['green']),
            ]
        if active_bid is not None:
            _bid_ref = active_bid
            actions.append((
                "🚪 Виселити",
                lambda: (win.destroy(), _open_checkout_dlg(self, _bid_ref, self._redraw)),
                C['yellow']
            ))
        actions.append(("✖ Скасувати", win.destroy, C['red']))

        for txt, cmd, color in actions:
            r = ctk.CTkFrame(scroll, fg_color='transparent'); r.pack(fill='x', pady=3)
            btn(r, txt, cmd, color, 340, height=42).pack(fill='x', padx=10)

# ══════════════════════════════════════════════════════
# БРОНЮВАННЯ
# ══════════════════════════════════════════════════════
class CheckedinFrame(tk.Frame):
    """Вкладка заселених гостей — тільки checkedin."""
    def __init__(self, parent, user):
        super().__init__(parent, bg=C['bg'])
        self.user=user
        lbl(self,'⏳ Завантаження...', 14, color=C['text2']).pack(pady=60)
        self.after(30, self._build)

    def _load_data_async(self):
        self.after(0, self._load)

    def _build(self):
        try:
            for w in self.winfo_children(): w.destroy()
        except Exception: pass
        tb=ctk.CTkFrame(self,fg_color=C['card']); tb.pack(fill='x',padx=15,pady=(15,5))
        lbl(tb,"🏨  Заселені гості",18,True).pack(side='left',padx=15,pady=12)
        refresh_btn(tb, self._load, side='left', padx=4, pady=10)

        flt=ctk.CTkFrame(self,fg_color=C['card']); flt.pack(fill='x',padx=15,pady=3)
        lbl(flt,"Пошук:",11,color=C['text2']).pack(side='left',padx=(10,4),pady=8)
        self.e_srch=ent(flt,"Гість або номер кімнати",w=240)
        self.e_srch.pack(side='left',pady=8)
        self.e_srch.bind('<Return>',lambda e:self._load())

        cols=('id','room','guest','phone','cin','cout','n','price','adv','dopla','dep','sплачено','debt')
        widths=[40,90,175,108,88,88,42,85,70,80,70,85,72]
        ff,self.tree=mktree(self,cols,16,widths)
        for c,h in zip(cols,['#','Кімн.','Гість','Тел.','Заїзд','Виїзд','Діб','Ціна/ніч','Аванс','Доплата','Залог','Сплачено','Борг']):
            self.tree.heading(c,text=h)
        ff.pack(fill='both',expand=True,padx=15,pady=5)
        self.tree.bind('<Double-1>',lambda e:self._open())

        bot=ctk.CTkFrame(self,fg_color=C['card']); bot.pack(fill='x',padx=15,pady=(0,10))
        for txt,cmd,color in [
            ("🚪 Виселити",    self._checkout,  C['yellow']),
            ("📅 Продовжити",  self._extend,    C['green']),
            ("💰 Оплата",      self._pay,        C['accent']),
            ("📋 Деталі",      self._open,       C['card2']),
        ]:
            btn(bot,txt,cmd,color,120).pack(side='left',padx=4,pady=8)
        self._load()

    def _load(self):
        import threading
        if getattr(self, '_loading_in_progress', False):
            return
        self._loading_in_progress = True
        threading.Thread(target=self._load_bg, daemon=True).start()

    def _load_bg(self):
        try:
            from app.modules.logic import get_bookings
            srch = self.e_srch.get().strip() if hasattr(self, 'e_srch') else None
            data = get_bookings(status='checkedin', search=srch or None) or []
            # Офлайн-fallback
            if not data:
                data = _sqlite_bookings(status='checkedin', search=srch or None)
            paid_map = {}
            dep_map  = {}
            adv_map  = {}
            if data:
                ids_int = tuple(int(b['id']) for b in data)
                ph = ','.join(['%s'] * len(ids_int))
                from app.utils.db import query as _qCI
                try:
                    for r in (_qCI(
                        f"SELECT booking_id,"
                        f" COALESCE(SUM(CASE WHEN amount>0 AND (note IS NULL"
                        f"  OR (note NOT LIKE 'Залог при заселенні%%%%' AND note NOT LIKE 'deposit%%%%'"
                        f"  AND note NOT LIKE 'Повернення залогу%%%%'"
                        f"  AND note NOT LIKE 'Аванс%%%%')) THEN amount END),0) AS paid,"
                        f" COALESCE(SUM(CASE WHEN amount>0 AND note LIKE 'Залог при заселенні%%%%'"
                        f"  THEN amount END),0) AS dep,"
                        f" COALESCE(SUM(CASE WHEN amount>0 AND note LIKE 'Аванс%%%%'"
                        f"  THEN amount END),0) AS adv"
                        f" FROM payments WHERE booking_id IN ({ph}) GROUP BY booking_id",
                        ids_int, fetch='all') or []):
                        k = int(r['booking_id'])
                        paid_map[k] = float(r['paid'])
                        dep_map[k]  = float(r['dep'])
                        adv_map[k]  = float(r['adv'])
                except Exception:
                    # SQLite fallback для платежів
                    pay_by_bid = _sqlite_payments_for_bookings(ids_int)
                    for bid_k, pays in pay_by_bid.items():
                        paid_map[bid_k] = sum(float(p['amount'] or 0) for p in pays
                            if float(p.get('amount',0)) > 0
                            and not any(tag in (p.get('note','') or '') for tag in ('Залог','deposit','Аванс')))
                        dep_map[bid_k]  = sum(float(p['amount'] or 0) for p in pays
                            if 'Залог' in (p.get('note','') or ''))
                        adv_map[bid_k]  = sum(float(p['amount'] or 0) for p in pays
                            if 'Аванс' in (p.get('note','') or ''))
            rows = []
            for b in data:
                bid_int = int(b['id'])
                n = (b['check_out'] - b['check_in']).days
                total = float(b['total_amount'] or 0)
                if total == 0:
                    total = float(b.get('price_per_day') or 0) * max(n, 1)
                paid_dopla = paid_map.get(bid_int, 0.0)   # доплата (без авансу і залогу)
                dep        = dep_map.get(bid_int, 0.0)   # залог
                adv        = adv_map.get(bid_int, 0.0)   # аванс
                nights     = max(n, 1)
                price_night = float(b.get('price_per_day') or 0)  # ціна за ніч
                # Сплачено = ціна×діб - аванс - доплата + залог
                # Сплачено = аванс + доплата + залог (всі реально отримані гроші від гостя)
                splacheno  = adv + paid_dopla + dep
                # Борг = те що ще не оплачено за проживання
                total_live = price_night * nights
                paid_live  = adv + paid_dopla
                debt       = max(total_live - paid_live, 0)
                adv_str    = f"{adv:.0f}₴"       if adv > 0       else "—"
                dopla_str  = f"{paid_dopla:.0f}₴" if paid_dopla > 0 else "—"
                dep_str    = f"{dep:.0f}₴"       if dep > 0       else "—"
                rows.append((b['id'], b['room_number'], b.get('guest_name', ''),
                             b.get('guest_phone', ''), b['check_in'], b['check_out'],
                             nights, f"{price_night:.0f}₴", adv_str, dopla_str, dep_str,
                             f"{splacheno:.0f}₴", f"{debt:.0f}₴",
                             'debt' if debt > 0 else ''))
            self.after(0, lambda: self._apply_checkedin_rows(rows))
        except Exception as e:
            log_error("CheckedinFrame._load_bg", e)
        finally:
            self._loading_in_progress = False

    def _apply_checkedin_rows(self, rows):
        self.tree.delete(*self.tree.get_children())
        for r in rows:
            self.tree.insert('', 'end', iid=r[0], tags=(r[-1],), values=r[:-1])
        self.tree.tag_configure('debt', foreground='#e74c3c')
        try: self.tree.after(10, lambda: self.tree.yview_moveto(0))
        except Exception: pass

    def _sel(self):
        s=self.tree.selection()
        if not s: messagebox.showwarning("","Оберіть гостя"); return None
        return int(s[0])

    def _checkout(self):
        bid=self._sel()
        if not bid: return
        _open_checkout_dlg(self, bid, self._load)
        return
        # --- legacy code below (kept for reference, unreachable) ---
        from app.modules.logic import get_booking, get_balance, update_booking_status
        from app.utils.db import query
        import datetime as _dt
        b=get_booking(bid)
        bal=get_balance(bid)

        dep_row = query("""SELECT COALESCE(SUM(amount),0) as dep
                           FROM payments WHERE booking_id=%s AND note LIKE 'Залог%%'""",
                        (bid,), fetch='one') or {}
        dep_amt = float(dep_row.get('dep') or 0)

        paid_total = float(bal.get('paid') or 0)
        total_amt  = float(b.get('total_amount') or 0)
        # Сума без залогу = те що реально за проживання
        living_total = total_amt - dep_amt if total_amt > 0 else 0
        debt = max(living_total - (paid_total - dep_amt), 0)

        # Вікно підтвердження виселення
        win = dlg_win(self, "🚪 Виселення", "420x400")
        main = tk.Frame(win, bg=C['bg']); main.pack(fill='both',expand=True,padx=15,pady=15)

        hdr = card(main); hdr.pack(fill='x', pady=(0,8))
        lbl(hdr,f"🚪  Виселення — №{b['room_number']}",15,True,C['yellow']).pack(anchor='w',padx=12,pady=(10,3))
        lbl(hdr,f"👤 {b.get('guest_name','')}   📞 {b.get('phone','')}",12).pack(anchor='w',padx=12,pady=(0,10))

        # Фінансовий підсумок
        fin = card(main); fin.pack(fill='x', pady=(0,8))
        lbl(fin,"💰  Фінансовий підсумок",13,True).pack(anchor='w',padx=12,pady=(10,5))
        ff = tk.Frame(fin,bg=C['card']); ff.pack(fill='x',padx=12,pady=(0,10))
        nights = (b['check_out']-b['check_in']).days
        price = float(b.get('price_per_day') or 0)
        for row_lbl,val,clr in [
            (f"Проживання ({nights}н × {price:.0f}₴)", f"{price*nights:.0f}₴",  C['accent']),
            ("Оплачено за проживання",  f"{paid_total - dep_amt:.0f}₴",           C['green']),
            ("Борг за проживання",      f"{debt:.0f}₴",    C['red'] if debt>0 else C['gray']),
        ]:
            rf=tk.Frame(ff,bg=C['card2']); rf.pack(fill='x',pady=2)
            lbl(rf,row_lbl,12).pack(side='left',padx=10,pady=6)
            lbl(rf,val,13,True,clr).pack(side='right',padx=12)

        # Залог
        if dep_amt > 0:
            dep_card = card(main); dep_card.pack(fill='x', pady=(0,8))
            lbl(dep_card,"💛  Залог",13,True).pack(anchor='w',padx=12,pady=(10,4))
            dep_row2 = tk.Frame(dep_card,bg=C['card']); dep_row2.pack(fill='x',padx=12,pady=(0,4))
            lbl(dep_row2,f"Залог при заселенні:",12).pack(side='left',padx=10,pady=6)
            lbl(dep_row2,f"{dep_amt:.0f}₴",13,True,C['yellow']).pack(side='right',padx=12)
            ret_row = tk.Frame(dep_card,bg=C['card']); ret_row.pack(fill='x',padx=12,pady=(0,10))
            lbl(ret_row,"Повернути гостю:",12,True).pack(side='left',padx=10,pady=6)
            lbl(ret_row,f"{dep_amt:.0f}₴",14,True,C['green']).pack(side='right',padx=12)

        def do_checkout():
            # Повернути залог (від'ємний платіж — зменшує отримане)
            if dep_amt > 0:
                query("""INSERT INTO payments (booking_id,amount,method,note,shift_id,created_at)
                          VALUES (%s,%s,'cash','Повернення залогу при виїзді',%s,NOW())""",
                      (bid, -dep_amt, get_current_shift_id()), fetch=None)
                # Оновити total_amount — прибрати залог
                query("UPDATE bookings SET total_amount=total_amount-%s WHERE id=%s",
                      (dep_amt, bid), fetch=None)

            update_booking_status(bid,'checkedout')
            query("UPDATE rooms SET status='cleaning' WHERE id=%s",(b['room_id'],),fetch=None)
            import datetime as _dt_cl
            _cl_append({'room': str(b.get('room_number', b['room_id'])), 'cleaner': '—', 'started': _dt_cl.datetime.now().strftime('%d.%m.%Y %H:%M'), 'finished': '', 'new_status': 'cleaning', 'note': 'Авто-запис при виселенні', 'logged_at': _dt_cl.datetime.now().strftime('%d.%m.%Y %H:%M:%S')})

            # Чек виселення
            lines=[
                f"  Готель: Готель Королівська Бочка",
                f"{'─'*52}",
                f"  🚪 ЧЕК ВИСЕЛЕННЯ",
                f"{'─'*52}",
                f"  Гість   : {b.get('guest_name','')}",
                f"  Номер   : №{b['room_number']}",
                f"  Заїзд   : {b['check_in']}",
                f"  Виїзд   : {b['check_out']}",
                f"  Ночей   : {nights}",
                f"{'─'*52}",
                f"  Проживання: {price*nights:.0f}₴",
                f"  Оплачено  : {paid_total - dep_amt:.0f}₴",
            ]
            if dep_amt > 0:
                lines += [
                    f"{'─'*52}",
                    f"  💛 Залог повернено: {dep_amt:.0f}₴",
                    f"  Разом отримано   : {paid_total - dep_amt:.0f}₴",
                ]
            lines += [
                f"{'─'*52}",
                f"  Час: {_dt.datetime.now().strftime('%d.%m.%Y %H:%M')}",
                f"  До побачення! Чекаємо знову!",
            ]
            print_text(f"Чек виселення #{bid}", lines)
            _invalidate_rooms_cache()
            win.destroy(); self._load()

        bf=tk.Frame(main,bg=C['bg']); bf.pack(fill='x',pady=(5,0))
        btn(bf,"🚪 Виселити та роздрукувати чек",do_checkout,C['yellow'],290,height=44).pack(side='left',padx=(0,6))
        btn(bf,"✖ Скасувати",win.destroy,C['red'],110,height=44).pack(side='left')

    def _extend(self):
        bid = self._sel()
        if not bid: return
        # Визначаємо тип об'єкта — баня → годинний діалог
        try:
            from app.utils.db import query as _q_ext
            from app.modules.logic import get_booking as _gb_chk
            _b_ext = _gb_chk(bid)
            # Перевіряємо cat_name + нотатку (нотатка "Баня: X год" = точно баня)
            _cn_ext = (_b_ext.get('cat_name') or '').lower() if _b_ext else ''
            _notes_ext = (_b_ext.get('notes') or '').lower() if _b_ext else ''
        except Exception:
            _cn_ext = ''; _notes_ext = ''
        _is_sauna_ext = (any(k in _cn_ext for k in ['баня','бані','sauna'])
                         or 'баня:' in _notes_ext or 'год (' in _notes_ext)
        if _is_sauna_ext:
            # Отримуємо room для передачі в діалог
            try:
                from app.utils.db import query as _q2
                from app.modules.logic import get_booking as _gb
                _bk = _gb(bid)
                _rm = _q2("SELECT * FROM rooms WHERE id=%s", (_bk['room_id'],), fetch='one') if _bk else None
            except Exception:
                _rm = None
            _open_extend_sauna_dlg(self, bid, _rm or {}, self._load)
        else:
            _open_extend_room_dlg(self, bid, self._load)

    def _pay(self):
        bid=self._sel()
        if bid: PaymentDlg(self,bid,self._load)

    def _open(self):
        bid=self._sel()
        if bid: BookingDetailDlg(self,bid,on_close=self._load)



class CheckedOutFrame(tk.Frame):
    """Вкладка виселених гостей — checkedout за поточну зміну або сьогодні."""
    def __init__(self, parent, user):
        super().__init__(parent, bg=C['bg'])
        self.user = user
        lbl(self,'⏳ Завантаження...', 14, color=C['text2']).pack(pady=60)
        self.after(30, self._build)

    def _load_data_async(self):
        self.after(0, self._load)

    def _build(self):
        try:
            for w in self.winfo_children(): w.destroy()
        except Exception: pass
        tb = ctk.CTkFrame(self, fg_color=C['card']); tb.pack(fill='x', padx=15, pady=(15,5))
        lbl(tb, "🚪  Виселені гості", 18, True).pack(side='left', padx=15, pady=12)
        refresh_btn(tb, self._load, side='left', padx=4, pady=10)

        flt = ctk.CTkFrame(self, fg_color=C['card']); flt.pack(fill='x', padx=15, pady=3)
        lbl(flt, "Пошук:", 11, color=C['text2']).pack(side='left', padx=(10,4), pady=8)
        self.e_srch = ent(flt, "Гість або номер кімнати", w=240)
        self.e_srch.pack(side='left', pady=8)
        self.e_srch.bind('<Return>', lambda e: self._load())

        # Фільтр по даті
        lbl(flt, "За:", 11, color=C['text2']).pack(side='left', padx=(15,4), pady=8)
        self.period_var = ctk.StringVar(value='all')
        for val, label_text in [('today','Сьогодні'), ('shift','Зміна'), ('week','Тиждень'), ('all','Всі')]:
            ctk.CTkRadioButton(flt, text=label_text, variable=self.period_var, value=val,
                               font=('Segoe UI', 11), text_color=C['text'],
                               fg_color=C['accent']).pack(side='left', padx=6, pady=8)
        self.period_var.trace_add('write', lambda *_: self._load())

        cols = ('id','room','guest','phone','cin','cout','n','total','adv','dep','paid','debt','checkout_time')
        widths = [40,68,165,108,88,88,38,75,65,65,75,72,110]
        ff, self.tree = mktree(self, cols, 16, widths)
        for c, h in zip(cols, ['#','Кімн.','Гість','Тел.','Заїзд','Виїзд','Н','Всього','Аванс','Залог','Оплач.','Борг','Час виселення']):
            self.tree.heading(c, text=h)
        ff.pack(fill='both', expand=True, padx=15, pady=5)
        self.tree.bind('<Double-1>', lambda e: self._open())

        bot = ctk.CTkFrame(self, fg_color=C['card']); bot.pack(fill='x', padx=15, pady=(0,10))
        btn(bot, "📋 Деталі", self._open, C['card2'], 120).pack(side='left', padx=4, pady=8)
        self._load()

    def _load(self):
        import threading
        if getattr(self, '_loading_in_progress', False):
            return
        self._loading_in_progress = True
        threading.Thread(target=self._load_bg, daemon=True).start()

    def _load_bg(self):
        try:
            import datetime as _dt
            from app.utils.db import query as _qco, get_conn as _gcc
            srch = self.e_srch.get().strip() if hasattr(self, 'e_srch') else ''
            period = self.period_var.get() if hasattr(self, 'period_var') else 'all'
            today = _dt.date.today()

            # Визначити фільтр по даті
            if period == 'today':
                date_filter = "AND b.check_out::date = %(today)s"
                params = {'today': today, 'srch': f'%{srch}%'}
            elif period == 'shift':
                from app.utils.db import query as _qs
                sid = get_current_shift_id()
                if sid:
                    sr = _qs("SELECT opened_at FROM shifts WHERE id=%s", (sid,), fetch='one')
                    opened = sr['opened_at'] if sr else None
                    date_filter = "AND b.check_out >= %(opened)s" if opened else "AND b.check_out::date = %(today)s"
                    params = {'today': today, 'srch': f'%{srch}%', 'opened': opened}
                else:
                    date_filter = "AND b.check_out::date = %(today)s"
                    params = {'today': today, 'srch': f'%{srch}%'}
            elif period == 'week':
                date_filter = "AND b.check_out::date >= %(week_start)s"
                params = {'today': today, 'srch': f'%{srch}%', 'week_start': today - _dt.timedelta(days=7)}
            else:  # 'all' — всі без фільтра по даті
                date_filter = ""
                params = {'today': today, 'srch': f'%{srch}%'}

            srch_filter = "AND (g.name ILIKE %(srch)s OR r.number ILIKE %(srch)s)" if srch else ""

            data = _qco(f"""
                SELECT b.id, r.number AS room_number, g.name AS guest_name,
                       g.phone AS guest_phone, b.check_in, b.check_out,
                       COALESCE(b.total_amount, 0) AS total_amount,
                       COALESCE(
                           (SELECT MAX(p.created_at) FROM payments p WHERE p.booking_id = b.id),
                           b.check_out::timestamp
                       ) AS updated_at
                FROM bookings b
                JOIN rooms r ON b.room_id = r.id
                JOIN guests g ON b.guest_id = g.id
                WHERE b.status = 'checkedout'
                {date_filter}
                {srch_filter}
                ORDER BY b.check_out DESC NULLS LAST
                LIMIT 500
            """, params, fetch='all') or []

            # Офлайн-fallback
            if not data:
                sq_data = _sqlite_bookings(status='checkedout', search=srch or None, limit=500)
                if sq_data:
                    # Фільтр по даті
                    from datetime import timedelta as _tdd
                    if period == 'today':
                        sq_data = [b for b in sq_data if str(b.get('check_out',''))[:10] == str(today)]
                    elif period == 'week':
                        week_start = str(today - _tdd(days=7))
                        sq_data = [b for b in sq_data if str(b.get('check_out',''))[:10] >= week_start]
                    for b in sq_data:
                        b['updated_at'] = b.get('check_out', '')
                    data = sq_data
                self.after(0, lambda: self._apply_rows([]))
                return

            ids = tuple(int(b['id']) for b in data)
            ph = ','.join(['%s']*len(ids))
            try:
                pay_rows = _qco(
                    f"SELECT booking_id,"
                    f" COALESCE(SUM(CASE WHEN amount>0 AND note NOT LIKE 'Залог%%%%' AND note NOT LIKE 'deposit%%%%' AND note NOT LIKE 'Повернення залогу%%%%' THEN amount END),0) AS paid,"
                    f" COALESCE(SUM(CASE WHEN amount>0 AND note LIKE 'Залог%%%%' THEN amount END),0) AS dep,"
                    f" COALESCE(SUM(CASE WHEN amount>0 AND note LIKE 'Аванс%%%%' THEN amount END),0) AS adv"
                    f" FROM payments WHERE booking_id IN ({ph}) GROUP BY booking_id",
                    ids, fetch='all') or []
                paid_map = {int(r['booking_id']): (float(r['paid']), float(r['dep']), float(r['adv'])) for r in pay_rows}
            except Exception:
                pay_by_bid = _sqlite_payments_for_bookings(ids)
                paid_map = {}
                for bid_k, pays in pay_by_bid.items():
                    _dep  = sum(float(p['amount']) for p in pays if 'Залог' in (p.get('note','') or ''))
                    _adv  = sum(float(p['amount']) for p in pays if 'Аванс' in (p.get('note','') or ''))
                    _paid = sum(float(p['amount']) for p in pays
                                if float(p.get('amount',0)) > 0
                                and 'Залог' not in (p.get('note','') or '')
                                and 'Аванс' not in (p.get('note','') or ''))
                    paid_map[bid_k] = (_paid, _dep, _adv)

            rows = []
            for b in data:
                bid = int(b['id'])
                from datetime import date as _date, datetime as _datetime
                def _to_date(v):
                    if isinstance(v, _date): return v
                    if isinstance(v, _datetime): return v.date()
                    try: return _datetime.strptime(str(v)[:10], '%Y-%m-%d').date()
                    except Exception: return _date.today()
                n = (_to_date(b['check_out']) - _to_date(b['check_in'])).days or 1
                total = float(b['total_amount'] or 0)
                paid, dep, adv = paid_map.get(bid, (0.0, 0.0, 0.0))
                paid_ttl = paid + dep + adv
                debt = max(total - paid_ttl, 0)
                checkout_time = str(b.get('updated_at',''))[:16]
                adv_str = f"{adv:.0f}₴" if adv > 0 else "—"
                dep_str = f"{dep:.0f}₴" if dep > 0 else "—"
                rows.append((
                    b['id'], b['room_number'], b.get('guest_name',''),
                    b.get('guest_phone',''), b['check_in'], b['check_out'],
                    n, f"{total:.0f}₴", adv_str, dep_str,
                    f"{paid_ttl:.0f}₴", f"{debt:.0f}₴", checkout_time,
                    'debt' if debt > 0 else ''
                ))

            self.after(0, lambda: self._apply_rows(rows))
        except Exception as e:
            log_error("CheckedOutFrame._load_bg", e)
        finally:
            self._loading_in_progress = False

    def _apply_rows(self, rows):
        self.tree.delete(*self.tree.get_children())
        total_sum = 0.0
        for r in rows:
            self.tree.insert('', 'end', iid=r[0], tags=(r[-1],), values=r[:-1])
            try: total_sum += float(str(r[7]).replace('₴',''))
            except: pass
        self.tree.tag_configure('debt', foreground='#e74c3c')
        try: self.tree.after(10, lambda: self.tree.yview_moveto(0))
        except: pass

    def _sel(self):
        s = self.tree.selection()
        if not s: messagebox.showwarning("", "Оберіть запис"); return None
        return int(s[0])

    def _open(self):
        bid = self._sel()
        if bid: BookingDetailDlg(self, bid)


class BookingsFrame(tk.Frame):
    def __init__(self, parent, user):
        super().__init__(parent, bg=C['bg'])
        self.user=user
        lbl(self, '⏳ Завантаження...', 14, color=C['text2']).pack(pady=60)
        self.after(30, self._build)

    def _load_data_async(self):
        self.after(0, self._load)

    def _build(self):
        try:
            for w in self.winfo_children(): w.destroy()
        except Exception: pass
        tb=ctk.CTkFrame(self,fg_color=C['card']); tb.pack(fill='x',padx=15,pady=(15,5))
        lbl(tb,"🛏  Бронювання",18,True).pack(side='left',padx=15,pady=12)
        btn(tb,"➕ Нове",self._new,width=120).pack(side='left',padx=4,pady=10)
        refresh_btn(tb, self._load, side='left', padx=4, pady=10)
        lbl(tb,"Тут тільки підтверджені бронювання",11,color=C['text2']).pack(side='left',padx=12)

        flt=ctk.CTkFrame(self,fg_color=C['card']); flt.pack(fill='x',padx=15,pady=3)
        lbl(flt,"Пошук:",11,color=C['text2']).pack(side='left',padx=(10,4),pady=8)
        self.e_srch=ent(flt,"Гість або номер кімнати",w=280)
        self.e_srch.pack(side='left',pady=8); self.e_srch.bind('<Return>',lambda e:self._load())

        cols=('id','room','guest','phone','cin','cout','n','total','paid','debt','status')
        widths=[40,70,180,120,90,90,55,85,85,85,120]
        ff,self.tree=mktree(self,cols,16,widths)
        for c,h in zip(cols,['#','Кімн.','Гість','Тел.','Заїзд','Виїзд','Н','Всього','Оплач.','Борг','Статус']):
            self.tree.heading(c,text=h)
        ff.pack(fill='both',expand=True,padx=15,pady=5)
        self.tree.bind('<Double-1>',lambda e:self._open())

        bot=ctk.CTkFrame(self,fg_color=C['card']); bot.pack(fill='x',padx=15,pady=(0,10))
        for txt,cmd,color in [
            ("✅ Заселити",  self._checkin_dlg,           C['green']),
            ("❌ Скасувати", lambda:self._st('cancelled'), C['red']),
            ("💰 Оплата",    self._pay,                   C['accent']),
            ("📋 Деталі",    self._open,                  C['card2']),
        ]:
            btn(bot,txt,cmd,color,130).pack(side='left',padx=5,pady=8)
        self._load()

    def _load(self):
        import threading
        if getattr(self, '_loading_in_progress', False):
            return
        self._loading_in_progress = True
        threading.Thread(target=self._load_bg, daemon=True).start()

    def _load_bg(self):
        try:
            from app.modules.logic import get_bookings
            from app.utils.db import query
            srch = self.e_srch.get().strip() if hasattr(self, 'e_srch') else None
            data = get_bookings(status='confirmed', search=srch or None) or []
            # Офлайн-fallback
            if not data:
                data = _sqlite_bookings(status='confirmed', search=srch or None)
            paid_map = {}
            if data:
                ids_int = tuple(int(b['id']) for b in data)
                ph = ','.join(['%s'] * len(ids_int))
                try:
                    for r in (query(
                    f"SELECT booking_id,"
                    f" COALESCE(SUM(CASE WHEN amount>0 AND (note IS NULL"
                    f"  OR (note NOT LIKE 'Залог%%%%' AND note NOT LIKE 'deposit%%%%'))"
                    f"  THEN amount END),0) AS paid,"
                    f" COALESCE(SUM(CASE WHEN amount>0 AND (note LIKE 'Залог%%%%'"
                    f"  OR note LIKE 'deposit%%%%') THEN amount END),0) AS dep"
                    f" FROM payments WHERE booking_id IN ({ph}) GROUP BY booking_id",
                    ids_int, fetch='all') or []):
                        k = int(r['booking_id'])
                        paid_map[k] = float(r['paid']) + float(r['dep'])
                except Exception:
                    # SQLite fallback для платежів
                    pay_by_bid = _sqlite_payments_for_bookings(ids_int)
                    for bid_k, pays in pay_by_bid.items():
                        paid_map[bid_k] = sum(float(p.get('amount',0)) for p in pays
                                              if float(p.get('amount',0)) > 0)
            rows = []
            for b in data:
                bid_int = int(b['id'])
                _cn = (b.get('cat_name') or '').lower()
                _is_hourly = any(k in _cn for k in ['баня','бані','sauna'])
                if _is_hourly:
                    # Погодинний об'єкт: показуємо години замість ночей, і кінець замість виїзду
                    import datetime as _dt_bk
                    _ci = b['check_in']; _co = b['check_out']
                    if isinstance(_ci, _dt_bk.datetime):
                        _diff_h = (_co - _ci).total_seconds() / 3600 if isinstance(_co, _dt_bk.datetime) else (b['check_out'] - b['check_in']).days * 24
                    else:
                        _diff_h = (b['check_out'] - b['check_in']).days * 24
                    n_disp = f"{_diff_h:.0f}г"
                    # Колонка "Виїзд" — показуємо час закінчення або дату якщо немає часу
                    if isinstance(_co, _dt_bk.datetime):
                        cout_disp = _co.strftime('%d.%m %H:%M')
                    else:
                        cout_disp = str(_co)
                    total = float(b['total_amount'] or 0)
                    if total == 0:
                        total = float(b.get('price_per_day') or 0) * max(_diff_h, 1)
                else:
                    n_disp = (b['check_out'] - b['check_in']).days
                    cout_disp = b['check_out']
                    total = float(b['total_amount'] or 0)
                    if total == 0:
                        total = float(b.get('price_per_day') or 0) * max(n_disp, 1)
                paid_ttl = paid_map.get(bid_int, 0.0)
                debt = max(total - paid_ttl, 0)
                rows.append((b['id'], b['room_number'], b.get('guest_name', ''),
                             b.get('guest_phone', ''), b['check_in'], cout_disp,
                             n_disp, f"{total:.0f}₴", f"{paid_ttl:.0f}₴", f"{debt:.0f}₴",
                             STATUS_UA.get(b['status'], b['status'])))
            self.after(0, lambda: self._apply_bookings_rows(rows))
        except Exception as e:
            log_error("BookingsFrame._load_bg", e)
        finally:
            self._loading_in_progress = False

    def _apply_bookings_rows(self, rows):
        self.tree.delete(*self.tree.get_children())
        for r in rows:
            self.tree.insert('', 'end', iid=r[0], values=r)
        try: self.tree.after(10, lambda: self.tree.yview_moveto(0))
        except Exception: pass

    def _sel(self):
        s=self.tree.selection()
        if not s: messagebox.showwarning("","Оберіть бронювання"); return None
        return int(s[0])

    def _st(self,s):
        bid=self._sel()
        if bid:
            from app.modules.logic import update_booking_status
            update_booking_status(bid,s); self._load()

    def _pay(self):
        bid=self._sel()
        if bid: PaymentDlg(self,bid,self._load)

    def _open(self):
        bid=self._sel()
        if bid: BookingDetailDlg(self,bid,on_close=self._load)

    def _checkin_dlg(self):
        """Вікно заселення з бронювань: паспорт + оплата + залог → чек → заселення."""
        from app.modules.logic import get_booking, get_balance, update_booking_status
        from app.utils.db import query
        import datetime as _dt
        bid = self._sel()
        if not bid: return
        b = get_booking(bid)
        if not b: return
        if b['status'] == 'checkedin':
            messagebox.showinfo("","Гість вже заселений."); return

        # Нормалізуємо поле phone (get_booking може повертати guest_phone)
        if not b.get('phone') and b.get('guest_phone'):
            b['phone'] = b['guest_phone']

        # Завантажуємо кімнату для deposit_amount
        try:
            room = query("SELECT * FROM rooms WHERE id=%s", (b['room_id'],), fetch='one') or {}
        except Exception:
            room = {}
        if not room:
            room = {'id': b['room_id'], 'number': b.get('room_number',''),
                    'cat_name': b.get('cat_name',''), 'base_price': b.get('price_per_day', 0)}

        # Маршрутизація: баня/бесідка → погодинний діалог заселення
        _cn = (b.get('cat_name') or '').lower()
        _is_hourly = any(k in _cn for k in ['баня','бані','sauna'])
        if _is_hourly:
            _open_sauna_checkin_from_booking(self, bid, room, self._load_data_async)
            return

        nights    = (b['check_out'] - b['check_in']).days
        price     = float(b.get('price_per_day') or 0)
        room_total= price * nights

        win = dlg_win(self, "✅ Заселення", "500x580")
        main = tk.Frame(win, bg=C['bg']); main.pack(fill='both',expand=True)
        cv = tk.Canvas(main, bg=C['bg'], highlightthickness=0)
        vsb= tk.Scrollbar(main, orient='vertical', command=cv.yview)
        cv.configure(yscrollcommand=vsb.set)
        vsb.pack(side='right',fill='y'); cv.pack(side='left',fill='both',expand=True)
        sc = tk.Frame(cv, bg=C['bg'])
        cw_= cv.create_window((0,0), window=sc, anchor='nw')
        cv.bind('<Configure>', lambda e: cv.itemconfig(cw_, width=e.width))
        sc.bind('<Configure>', lambda e: cv.configure(scrollregion=cv.bbox('all')))

        # Заголовок
        hdr = card(sc); hdr.pack(fill='x',padx=12,pady=(10,5))
        lbl(hdr,f"✅  Заселення — №{b['room_number']}",15,True,C['green']).pack(anchor='w',padx=12,pady=(10,3))
        lbl(hdr,f"👤 {b.get('guest_name','')}   📞 {b.get('phone','')}",12).pack(anchor='w',padx=12,pady=2)
        _cn_h = (b.get('cat_name') or '').lower()
        _is_h = any(k in _cn_h for k in ['баня','бані','sauna','альтанк','бесідк','gazebo'])
        if _is_h:
            import datetime as _dt_hdr
            _ci_h = b['check_in']; _co_h = b['check_out']
            if isinstance(_ci_h, _dt_hdr.datetime) and isinstance(_co_h, _dt_hdr.datetime):
                _hrs = (_co_h - _ci_h).total_seconds() / 3600
                _period_str = f"{_hrs:.0f} год × {price:.0f}₴"
            else:
                _period_str = f"{nights} ніч × {price:.0f}₴"
        else:
            _period_str = f"{nights} ніч × {price:.0f}₴"
        lbl(hdr,f"📅 {b['check_in']} → {b['check_out']}  ({_period_str})",11,color=C['text2']).pack(anchor='w',padx=12,pady=(0,10))

        # Паспорт
        pc = card(sc); pc.pack(fill='x',padx=12,pady=5)
        lbl(pc,"🪪  Документ гостя",13,True).pack(anchor='w',padx=12,pady=(10,5))
        pf = tk.Frame(pc, bg=C['card']); pf.pack(fill='x',padx=12,pady=(0,10))
        lbl(pf,"Серія:",11,color=C['text2']).grid(row=0,column=0,sticky='w',pady=3)
        e_series = ent(pf,"АА",w=90); e_series.grid(row=0,column=1,padx=8,pady=3,sticky='w')
        lbl(pf,"Номер:",11,color=C['text2']).grid(row=1,column=0,sticky='w',pady=3)
        e_pnum = ent(pf,"123456",w=140); e_pnum.grid(row=1,column=1,padx=8,pady=3,sticky='w')

        # Оплата
        oc = card(sc); oc.pack(fill='x',padx=12,pady=5)
        lbl(oc,"💰  Розрахунок",13,True).pack(anchor='w',padx=12,pady=(10,5))
        of = tk.Frame(oc, bg=C['card']); of.pack(fill='x',padx=12,pady=(0,6))
        rf1=tk.Frame(of,bg=C['card2']); rf1.pack(fill='x',pady=2)
        lbl(rf1,f"Проживання ({nights} × {price:.0f}₴)",12).pack(side='left',padx=10,pady=7)
        lbl(rf1,f"{room_total:.0f}₴",13,True,C['accent']).pack(side='right',padx=12)

        # Аванс при бронюванні (вже сплачений)
        _adv_paid = 0.0
        try:
            _ar = query("SELECT COALESCE(SUM(amount),0) AS adv FROM payments WHERE booking_id=%s AND note LIKE 'Аванс%%'", (bid,), fetch='one')
            _adv_paid = float(_ar['adv'] if _ar else 0)
        except Exception: pass

        if _adv_paid > 0:
            rf_adv = tk.Frame(of, bg=C['card2']); rf_adv.pack(fill='x', pady=2)
            lbl(rf_adv, "💰 Аванс (сплачено при бронюванні)", 12).pack(side='left', padx=10, pady=7)
            lbl(rf_adv, f"-{_adv_paid:.0f}₴", 13, True, C['yellow']).pack(side='right', padx=12)
            _to_pay = max(0.0, room_total - _adv_paid)
            rf_rest = tk.Frame(of, bg=C['card2']); rf_rest.pack(fill='x', pady=2)
            lbl(rf_rest, "💵 До доплати при заселенні", 12, True).pack(side='left', padx=10, pady=7)
            lbl(rf_rest, f"{_to_pay:.0f}₴", 13, True, C['green']).pack(side='right', padx=12)

        lbl(oc,"💛  Залог (повертається при виїзді):",13,True).pack(anchor='w',padx=12,pady=(8,3))
        dr = tk.Frame(oc,bg=C['card']); dr.pack(fill='x',padx=12,pady=(0,10))
        _dep_ci_default = 0
        try:
            _dep_ci_row = query("SELECT COALESCE(deposit_amount,0) as dep FROM rooms WHERE id=%s",
                                (b['room_id'],), fetch='one')
            if _dep_ci_row: _dep_ci_default = int(float(_dep_ci_row.get('dep') or 0))
        except Exception: pass
        e_dep = ent(dr, str(_dep_ci_default) if _dep_ci_default else "0", w=100)
        if _dep_ci_default:
            e_dep.delete(0,'end'); e_dep.insert(0, str(_dep_ci_default))
        e_dep.pack(side='left',padx=(0,6))
        lbl(dr,"₴ (введіть 0 якщо без залогу)",11,color=C['text2']).pack(side='left')

        # РАЗОМ сьогодні — доплата + залог
        _to_pay_bk = max(0.0, room_total - _adv_paid)
        razom_card = card(sc); razom_card.pack(fill='x',padx=12,pady=5)
        razom_row_bk = tk.Frame(razom_card, bg=C['card2']); razom_row_bk.pack(fill='x',padx=12,pady=8)
        lbl(razom_row_bk,"💳 РАЗОМ сьогодні:",13,True,C['accent']).pack(side='left',padx=10)
        lbl_razom_bk = lbl(razom_row_bk,"",14,True,C['accent']); lbl_razom_bk.pack(side='right',padx=12)

        def _upd_razom_bk(*_):
            try: _d = float(e_dep.get() or 0)
            except: _d = 0.0
            _r = _to_pay_bk + _d
            lbl_razom_bk.configure(text=f"{_r:.0f}₴  (доплата {_to_pay_bk:.0f}₴ + залог {_d:.0f}₴)")

        e_dep.bind('<KeyRelease>', _upd_razom_bk)
        _upd_razom_bk()

        # Метод
        mc = card(sc); mc.pack(fill='x',padx=12,pady=5)
        lbl(mc,"💳  Спосіб оплати",13,True).pack(anchor='w',padx=12,pady=(10,6))
        meth_var = ctk.StringVar(value='cash')
        mf = tk.Frame(mc, bg=C['card']); mf.pack(fill='x',padx=12,pady=(0,10))
        for val,label_text,clr in [('cash','💵 Готівка',C['green']),
                                    ('card','💳 Картка',C['accent']),
                                    ('transfer','🏦 Переказ','#9b59b6')]:
            ctk.CTkRadioButton(mf,text=label_text,variable=meth_var,value=val,
                               fg_color=clr,text_color=C['text'],
                               font=('Segoe UI',12)).pack(side='left',padx=8)

        def do_checkin():
            try: dep = float(e_dep.get() or 0)
            except: dep = 0.0
            passport_info = f"{e_series.get().strip()} {e_pnum.get().strip()}".strip()
            total_with_dep = room_total + dep

            # Зберегти паспорт у нотатки
            if passport_info.strip():
                notes = b.get('notes','') or ''
                query("UPDATE bookings SET notes=%s WHERE id=%s",
                      (f"Паспорт: {passport_info}  {notes}".strip(), bid), fetch=None)

            # Встановити total_amount = проживання + залог
            query("UPDATE bookings SET total_amount=%s WHERE id=%s",
                  (total_with_dep, bid), fetch=None)

            # Платіж — доплата при заселенні (проживання мінус вже сплачений аванс)
            _sid = get_current_shift_id()
            _adv_already = 0.0
            try:
                _ar2 = query("SELECT COALESCE(SUM(amount),0) AS adv FROM payments WHERE booking_id=%s AND note LIKE 'Аванс%%'", (bid,), fetch='one')
                _adv_already = float(_ar2['adv'] if _ar2 else 0)
            except Exception: pass
            _topay_now = max(0.0, room_total - _adv_already)
            if _topay_now > 0:
                query("""INSERT INTO payments(booking_id,amount,method,note,shift_id,created_at)
                          VALUES(%s,%s,%s,'Доплата при заселенні',%s,NOW())""",
                      (bid, _topay_now, meth_var.get(), _sid), fetch=None)

            # Платіж залогу
            if dep > 0:
                query("""INSERT INTO payments(booking_id,amount,method,note,shift_id,created_at)
                          VALUES(%s,%s,%s,'Залог при заселенні',%s,NOW())""",
                      (bid, dep, meth_var.get(), _sid), fetch=None)

            # Заселити + статус кімнати
            update_booking_status(bid, 'checkedin')
            query("UPDATE rooms SET status='occupied' WHERE id=%s",(b['room_id'],),fetch=None)

            # Чек
            lines=[
                f"  Готель: Готель Королівська Бочка",
                f"{'─'*52}",
                f"  ✅ ЧЕК ЗАСЕЛЕННЯ",
                f"{'─'*52}",
                f"  Гість   : {b.get('guest_name','')}",
                f"  Телефон : {b.get('phone','')}",
            ]
            if passport_info.strip():
                lines.append(f"  Паспорт : {passport_info}")
            lines += [
                f"  Номер   : №{b['room_number']}  ({b.get('cat_name','—')})",
                f"  Заїзд   : {b['check_in']}",
                f"  Виїзд   : {b['check_out']}",
                f"  Ночей   : {nights}",
                f"  Ціна/ніч: {price:.0f}₴",
                f"{'─'*52}",
                f"  Проживання : {room_total:.0f}₴",
            ]
            if _adv_already > 0:
                lines.append(f"  Аванс      : -{_adv_already:.0f}₴  (сплачено при бронюванні)")
            if dep > 0:
                lines += [
                    f"  Залог      : {dep:.0f}₴  (повертається при виїзді)",
                    f"  {'─'*46}",
                    f"  РАЗОМ      : {total_with_dep:.0f}₴",
                ]
            lines += [
                f"  Метод   : {meth_var.get()}",
                f"{'─'*52}",
                f"  ✅ Заселено о {_dt.datetime.now().strftime('%H:%M %d.%m.%Y')}",
                f"  Дякуємо за вибір нашого готелю!",
            ]
            print_text(f"Чек заселення №{bid}", lines)
            win.destroy(); self._load()

        bf = tk.Frame(sc, bg=C['bg']); bf.pack(fill='x',padx=12,pady=10)
        btn(bf,"✅ Заселити та роздрукувати чек",do_checkin,C['green'],320,height=46).pack(side='left',padx=(0,6))
        btn(bf,"✖ Скасувати",win.destroy,C['red'],120,height=46).pack(side='left')

    def _new(self): BookingDlg(self,on_save=self._load)

# ══════════════════════════════════════════════════════
class BookingDlg(ctk.CTkToplevel):
    def __init__(self, parent, on_save=None):
        super().__init__(parent)
        self.on_save=on_save; self.guest_id=None
        self.configure(fg_color=C['bg']); self.title("➕ Нове бронювання")
        self.lift(); self.focus_force()
        self.update_idletasks()
        _center_window(self, 640, 680, parent)
        # (grab вимкнено — Windows сумісність)
        self._build()

    def _build(self):
        from app.modules.logic import get_rooms
        scroll=ctk.CTkScrollableFrame(self,fg_color=C['bg'])
        scroll.pack(fill='both',expand=True,padx=15,pady=15)

        g=card(scroll); g.pack(fill='x',pady=5)
        lbl(g,"👤  Гість",13,True).pack(anchor='w',padx=12,pady=(10,5))
        sf=ctk.CTkFrame(g,fg_color='transparent'); sf.pack(fill='x',padx=12,pady=3)
        self.e_srch=ent(sf,"Пошук за ім'ям або телефоном",w=300)
        self.e_srch.pack(side='left',padx=(0,6))
        btn(sf,"🔍",self._search,C['card2'],50).pack(side='left')
        self.guest_info=lbl(g,"",11,color=C['green']); self.guest_info.pack(anchor='w',padx=12)

        self.fields={}
        for lt,key,ph in [("Ім'я та прізвище *",'name',"Іванов Іван"),("Телефон",'phone',"+380...")]:
            f=row_frm(g)
            ctk.CTkLabel(f,text=lt,font=('Segoe UI',11),text_color=C['text2'],width=160,anchor='w').pack(side='left')
            e=ent(f,ph,w=340); e.pack(side='left'); self.fields[key]=e
        ctk.CTkFrame(g,fg_color='transparent',height=6).pack()

        b2=card(scroll); b2.pack(fill='x',pady=5)
        lbl(b2,"🛏  Бронювання",13,True).pack(anchor='w',padx=12,pady=(10,5))
        rooms=get_rooms() or []
        self.room_map={}
        for r in rooms:
            k=f"№{r['number']} — {r.get('cat_name','') or ''} ({r.get('base_price') or 0}₴/ніч)"
            self.room_map[k]=r
        f=row_frm(b2)
        ctk.CTkLabel(f,text="Номер *",font=('Segoe UI',11),text_color=C['text2'],width=120,anchor='w').pack(side='left')
        self.room_var=ctk.StringVar(value=list(self.room_map.keys())[0] if self.room_map else '')
        ctk.CTkOptionMenu(f,values=list(self.room_map.keys()) or ['—'],variable=self.room_var,
                          width=360,fg_color=C['card2'],button_color=C['accent'],
                          command=self._fill_price).pack(side='left')

        for lt,key,ph,val in [
            ("Заїзд *",'cin',"РРРР-ММ-ДД",str(date.today())),
            ("Виїзд *",'cout',"РРРР-ММ-ДД",str(date.today()+timedelta(days=1))),
            ("Ціна/ніч *",'price',"₴",""),
            ("Дорослих",'adults',"","1"),("Дітей",'kids',"","0"),
        ]:
            f=row_frm(b2)
            ctk.CTkLabel(f,text=lt,font=('Segoe UI',11),text_color=C['text2'],width=120,anchor='w').pack(side='left')
            e=ent(f,ph,w=200); e.insert(0,val); e.pack(side='left'); self.fields[key]=e

        f=row_frm(b2)
        ctk.CTkLabel(f,text="Нотатки",font=('Segoe UI',11),text_color=C['text2'],width=120,anchor='w').pack(side='left')
        self.e_notes=ent(f,w=360); self.e_notes.pack(side='left')

        f=row_frm(b2)
        ctk.CTkLabel(f,text="💰 Аванс",font=('Segoe UI',11),text_color=C['text2'],width=120,anchor='w').pack(side='left')
        dep_f=tk.Frame(f,bg=C['card2']); dep_f.pack(side='left')
        self.e_deposit=ent(dep_f,"0",w=120); self.e_deposit.pack(side='left')
        ctk.CTkLabel(dep_f,text="₴",font=('Segoe UI',11),text_color=C['text2']).pack(side='left',padx=4)
        _adv_method_map = {"💵 Готівка": "cash", "💳 Картка": "card", "📲 Переказ": "transfer"}
        self._adv_method_map = _adv_method_map
        self._adv_method_var = ctk.StringVar(value="💵 Готівка")
        ctk.CTkComboBox(dep_f, variable=self._adv_method_var,
            values=list(_adv_method_map.keys()),
            width=130, font=('Segoe UI',11),
            fg_color=C['card2'], text_color=C['text'],
            button_color=C['accent'], border_color=C['border']
        ).pack(side='left', padx=(6,0))

        btn(scroll,"💾  Зберегти бронювання",self._save,height=44).pack(fill='x',pady=15)
        if self.room_map: self.after(150, lambda: self._fill_price(self.room_var.get()))

    def _fill_price(self,choice):
        if choice in self.room_map:
            p=self.room_map[choice].get('base_price',0)
            self.fields['price'].delete(0,'end'); self.fields['price'].insert(0,str(p or 0))
            # Автоматично підтягуємо аванс
            dep = 0
            try:
                dep = int(float(self.room_map[choice].get('deposit_amount') or 0))
            except Exception:
                pass
            if dep == 0:
                try:
                    from app.utils.db import query as _qd
                    _dr = _qd("SELECT COALESCE(deposit_amount,0) FROM rooms WHERE id=%s",
                               (self.room_map[choice]['id'],), fetch='one')
                    if _dr: dep = int(float(_dr[0]))
                except Exception:
                    pass
            if hasattr(self, 'e_deposit'):
                self.e_deposit.delete(0,'end')
                self.e_deposit.insert(0, str(dep) if dep else '0')

    def _search(self):
        from app.modules.logic import search_guests
        term=self.e_srch.get().strip()
        if not term: return
        results=search_guests(term)
        if not results: messagebox.showinfo("","Гостя не знайдено"); return
        win=dlg_win(self,"Оберіть гостя","460x300")
        ff,tree=mktree(win,('id','name','phone'),8,[50,260,140])
        for c,h in zip(('id','name','phone'),['ID','Гість','Телефон']): tree.heading(c,text=h)
        for g in results: tree.insert('','end',iid=g['id'],values=(g['id'],g.get('name',''),g.get('phone','')))
        ff.pack(fill='both',expand=True,padx=10,pady=10)
        def sel():
            s=tree.selection()
            if not s: return
            g=next(x for x in results if x['id']==int(s[0]))
            self.fields['name'].delete(0,'end'); self.fields['name'].insert(0,g.get('name',''))
            self.fields['phone'].delete(0,'end'); self.fields['phone'].insert(0,g.get('phone',''))
            self.guest_id=g['id']
            self.guest_info.configure(text=f"✓ {g.get('name','')}")
            win.destroy()
        btn(win,"✅ Обрати",sel,height=36).pack(pady=5)

    def _save(self):
        from app.modules.logic import save_guest, create_booking
        try:
            cin=date.fromisoformat(self.fields['cin'].get().strip())
            cout=date.fromisoformat(self.fields['cout'].get().strip())
        except: messagebox.showerror("","Невірна дата (РРРР-ММ-ДД)"); return
        if cout<=cin: messagebox.showerror("","Виїзд має бути пізніше заїзду"); return
        name=self.fields['name'].get().strip()
        if not name: messagebox.showerror("","Введіть ім'я гостя"); return
        gid=self.guest_id or save_guest({'name':name,'phone':self.fields['phone'].get().strip()})
        rc=self.room_var.get()
        rid=self.room_map[rc]['id']
        _adv_amount = float(getattr(self,'e_deposit',None) and self.e_deposit.get() or 0)
        _new_bid = create_booking({'room_id':rid,'guest_id':gid,'check_in':cin,'check_out':cout,
                        'price_per_day':float(self.fields['price'].get() or 0),
                        'adults':int(self.fields['adults'].get() or 1),
                        'children':int(self.fields['kids'].get() or 0),
                        'notes':self.e_notes.get(),
                        'deposit_amount':_adv_amount})
        # Записати аванс як платіж якщо > 0
        if _adv_amount > 0:
            try:
                from app.utils.db import query as _q2
                # Якщо create_booking повернув id — використовуємо, інакше шукаємо останнє бронювання
                _use_bid = _new_bid
                if not _use_bid:
                    _last = _q2("SELECT id FROM bookings WHERE room_id=%s AND guest_id=%s ORDER BY created_at DESC LIMIT 1",
                                (rid, gid), fetch='one')
                    _use_bid = _last['id'] if _last else None
                if _use_bid:
                    _sid2 = get_current_shift_id()
                    _adv_label = getattr(self, "_adv_method_var", None)
                    _adv_method_map = getattr(self, "_adv_method_map", {})
                    _adv_method = _adv_method_map.get(_adv_label.get() if _adv_label else "💵 Готівка", "cash")
                    _q2("INSERT INTO payments(booking_id,amount,method,note,shift_id,created_at) VALUES(%s,%s,%s,'Аванс при бронюванні',%s,NOW())",
                        (_use_bid, _adv_amount, _adv_method, _sid2), fetch=None)
            except Exception as _e2:
                log_error("BookingDlg: не вдалося записати аванс", _e2)
        # Оновити статус номера → Заброньований (явний commit)
        try:
            from app.utils.db import get_conn
            with get_conn() as _conn:
                with _conn.cursor() as _cur:
                    _cur.execute("UPDATE rooms SET status='confirmed' WHERE id=%s", (rid,))
                _conn.commit()
        except Exception as _e:
            log_error("BookingDlg: не вдалося оновити статус номера", _e)
            try:
                from app.utils.db import query as _q
                _q("UPDATE rooms SET status='confirmed' WHERE id=%s", (rid,), fetch=None)
            except Exception:
                pass
        messagebox.showinfo("✅","Бронювання створено!")
        if self.on_save: self.on_save()
        self.destroy()

# ══════════════════════════════════════════════════════
class BookingDetailDlg(ctk.CTkToplevel):
    def __init__(self, parent, bid, on_close=None):
        super().__init__(parent)
        self.bid=bid; self.on_close=on_close
        self.configure(fg_color=C['bg']); self.title(f"📋 Бронювання #{bid}")
        self.lift(); self.focus_force()
        self.update_idletasks()
        _center_window(self, 780, 700, parent)
        self.protocol("WM_DELETE_WINDOW",self._close); self._build()

    def _close(self):
        if self.on_close: self.on_close()
        self.destroy()

    def _build(self):
        from app.modules.logic import get_booking,get_balance,get_booking_services,get_payments,get_services
        from app.utils.db import query
        b=get_booking(self.bid)
        bal_raw=get_balance(self.bid)
        bal={k: float(v or 0) for k,v in (bal_raw or {}).items()} if bal_raw else {'total':0,'paid':0,'debt':0}
        svc=get_booking_services(self.bid) or []; pay=get_payments(self.bid) or []
        if not b: return

        # Залоги та штрафи зі service_orders
        deposits=query("SELECT * FROM service_orders WHERE booking_id=%s AND note LIKE 'deposit%%' ORDER BY created_at",
                       (self.bid,)) or []
        fines=query("SELECT * FROM service_orders WHERE booking_id=%s AND note LIKE 'fine%%' ORDER BY created_at",
                    (self.bid,)) or []
        dep_total=sum(float(d['total'] or 0) for d in deposits)
        dep_returned=sum(float(d['total'] or 0) for d in deposits if d.get('note','').startswith('deposit_returned'))
        dep_active=sum(float(d['total'] or 0) for d in deposits if d.get('note','').startswith('deposit:'))
        fine_total=sum(float(f['total'] or 0) for f in fines)

        scroll=ctk.CTkScrollableFrame(self,fg_color=C['bg'])
        scroll.pack(fill='both',expand=True,padx=15,pady=10)

        # ── Інфо ──────────────────────────────────────
        inf=card(scroll); inf.pack(fill='x',pady=5)
        lbl(inf,f"🛏  Номер {b['room_number']} — {b.get('cat_name','—')}",16,True,C['accent']).pack(anchor='w',padx=12,pady=(10,3))
        lbl(inf,f"👤  {b.get('guest_name','')}   📞  {b.get('phone','')}",13).pack(anchor='w',padx=12,pady=2)
        lbl(inf,f"📅  {b['check_in']} → {b['check_out']}   |   {STATUS_UA.get(b['status'],b['status'])}",12,color=C['text2']).pack(anchor='w',padx=12,pady=(2,10))

        # ── Фінансовий підсумок ───────────────────────
        bf=card(scroll); bf.pack(fill='x',pady=5)
        bf.columnconfigure((0,1,2,3),weight=1)
        for col,(lt,val,color) in enumerate([
            ("Всього",f"{bal['total']:.0f}₴",C['accent']),
            ("Оплачено",f"{bal['paid']:.0f}₴",C['green']),
            ("Борг",f"{bal['debt']:.0f}₴",C['red'] if bal['debt']>0 else C['gray']),
            ("Штрафи",f"{fine_total:.0f}₴",C['red'] if fine_total>0 else C['gray']),
        ]):
            ctk.CTkFrame(bf,fg_color=color,corner_radius=10).grid(row=0,column=col,padx=6,pady=8,sticky='ew',ipady=10)
            lbl(bf,val,22,True,color).grid(row=0,column=col,pady=(14,2))
            lbl(bf,lt,10,color=C['text2']).grid(row=1,column=col,pady=(0,10))

        # ── Залог ─────────────────────────────────────
        df=card(scroll); df.pack(fill='x',pady=5)
        dh=ctk.CTkFrame(df,fg_color='transparent'); dh.pack(fill='x',padx=12,pady=(10,5))
        dep_color=C['green'] if dep_active<=0 else C['yellow']
        lbl(dh,"🔐  Залог",13,True).pack(side='left')
        dep_status="✅ Повернено" if dep_returned>0 and dep_active<=0 else (f"💛 Утримується: {dep_active:.0f}₴" if dep_active>0 else "—")
        lbl(dh,dep_status,11,color=dep_color).pack(side='left',padx=12)
        if deposits:
            ff_d,dt=mktree(df,('type','amount','note','time'),3,[120,90,230,130])
            for c,h in zip(('type','amount','note','time'),['Тип','Сума','Нотатка','Час']): dt.heading(c,text=h)
            for d in deposits:
                note=d.get('note','')
                tp="💛 Залог" if note.startswith('deposit:') else "✅ Повернено"
                dt.insert('','end',values=(tp,f"{float(d['total'] or 0):.0f}₴",note.split(':',1)[-1].strip(),str(d['created_at'])[:16]))
            ff_d.pack(fill='x',padx=8,pady=(0,4))
        bf_d=ctk.CTkFrame(df,fg_color='transparent'); bf_d.pack(fill='x',padx=8,pady=(0,10))
        btn(bf_d,"💛 Взяти залог",lambda:self._deposit_dlg('take'),C['yellow'],150).pack(side='left',padx=4)
        if dep_active>0:
            btn(bf_d,"✅ Повернути залог",lambda:self._deposit_dlg('return'),C['green'],160).pack(side='left',padx=4)
            btn(bf_d,"❌ Утримати залог",lambda:self._deposit_dlg('keep'),C['red'],160).pack(side='left',padx=4)

        # ── Штрафи ────────────────────────────────────
        ff_card=card(scroll); ff_card.pack(fill='x',pady=5)
        lbl(ff_card,"⚠️  Штрафи",13,True).pack(anchor='w',padx=12,pady=(10,5))
        if fines:
            ff_f,ft=mktree(ff_card,('reason','amount','note','time'),3,[200,80,200,130])
            for c,h in zip(('reason','amount','note','time'),['Причина','Сума','Деталі','Час']): ft.heading(c,text=h)
            for f in fines:
                note=f.get('note','')
                parts=note.split(':',2)
                reason=parts[1].strip() if len(parts)>1 else note
