# КАСА
# ══════════════════════════════════════════════════════
class CashierFrame(tk.Frame):
    def __init__(self, parent, user):
        super().__init__(parent, bg=C['bg'])
        self.user = user
        # ── Посилання на label-и для оновлення без перебудови UI ──
        self._stat_lbls   = {}   # ключ → CTkLabel (великі картки вгорі)
        self._split_lbls  = {}   # cash/card/transfer → CTkLabel
        self._built       = False
        self._build()  # _build() вже відкладає важку частину через after(50,...)
        self._schedule_refresh()
        # Скрол колесом — через глобальний bind_mousewheel
        bind_mousewheel(self)

    def _schedule_refresh(self):
        try:
            if self.winfo_exists():
                self.after(30000, self._do_scheduled_refresh)
        except Exception:
            pass

    def _load_data_async(self):
        """Викликається при кожному переході на вкладку Каса — оновлює цифри."""
        self._refresh_data()

    def _do_scheduled_refresh(self):
        """Оновлення тільки цифр — без знищення/перестворення UI."""
        try:
            if not self.winfo_exists():
                return
            self._refresh_data()
            self.after(30000, self._do_scheduled_refresh)
        except Exception:
            pass

    def _refresh_data(self):
        """Отримує нові дані з БД у фоновому потоці, оновлює UI через after()."""
        import threading
        threading.Thread(target=self._refresh_data_bg, daemon=True).start()

    def _refresh_data_bg(self):
        """Один SQL-запит замість 8+ окремих — менше round-trips до PostgreSQL."""
        from app.utils.db import get_conn
        import datetime as _dt
        today = date.today()
        current_shift_id = get_current_shift_id()

        # ── ВИПРАВЛЕННЯ: перевірити shift напряму в БД (обходить SQLite-кеш) ──
        # Якщо get_current_shift_id() повернув None або застарілий id — беремо свіжий
        try:
            with get_conn() as _sc:
                with _sc.cursor() as _scc:
                    _scc.execute("SELECT id FROM shifts WHERE status='open' ORDER BY id DESC LIMIT 1")
                    _sr = _scc.fetchone()
                    if _sr and _sr[0]:
                        current_shift_id = _sr[0]
        except Exception:
            pass

        # Дефолти — перевизначаться у блоках if/else нижче
        bani_rev = besidky_rev = rooms_rev_only = 0.0
        rest_svc_total = paid_total = ret_total = dep_total_bg = 0.0
        cash_total = card_total = transfer_total = 0.0
        pay = []; pay_rows_all = []; bk_cnt = 0
        try:
            with get_conn() as conn:
                with conn.cursor() as cur:
                    if current_shift_id:
                        # ════════════════════════════════════════════════════════
                        # КАСА: вся логіка через таблицю payments (єдине джерело)
                        # Умовні позначки в note:
                        #   'Залог при заселенні%' — залог при заселенні
                        #   'Залог%' / 'deposit%'  — будь-який залог
                        #   'Повернення залогу%'    — повернення залогу при виселенні
                        #   'Аванс%'                — аванс (може бути з попередньої зміни)
                        #   'Ресторан #%'           — оплата ресторану
                        #   'Послуга:%'             — додаткові послуги
                        #   'Додаткові послуги%'    — послуги до бронювання
                        #   booking_id IS NULL      — ресторан / послуга без бронювання
                        # ════════════════════════════════════════════════════════
                        # Отримати opened_at для захоплення платежів з shift_id IS NULL
                        cur.execute("SELECT opened_at FROM shifts WHERE id=%s", (current_shift_id,))
                        _oat_row = cur.fetchone()
                        _oat = _oat_row[0] if _oat_row else None
                        if _oat:
                            _sf_bg      = "(shift_id = %s OR (shift_id IS NULL AND created_at >= %s))"
                            _sf_bg_p    = (current_shift_id, _oat)
                            _sf_bg_join = "(p.shift_id = %s OR (p.shift_id IS NULL AND p.created_at >= %s))"
                            _sf_bg_jp   = (current_shift_id, _oat)
                        else:
                            _sf_bg      = "shift_id = %s"
                            _sf_bg_p    = (current_shift_id,)
                            _sf_bg_join = "p.shift_id = %s"
                            _sf_bg_jp   = (current_shift_id,)

                        cur.execute(f"""
                            SELECT
                                -- [1] Залоги прийняті у цій зміні
                                COALESCE(SUM(CASE
                                    WHEN amount > 0
                                     AND (note LIKE 'Залог при заселенні%%%%' OR note LIKE 'Залог при бронюванні%%%%' OR note LIKE 'deposit:%%%%')
                                    THEN amount END), 0) AS dep_in,

                                -- [2] Повернення залогів — тільки з відповідним note
                                COALESCE(SUM(CASE
                                    WHEN note LIKE 'Повернення залогу%%%%' OR note LIKE 'deposit_returned%%%%'
                                    THEN ABS(amount) END), 0) AS dep_ret,

                                -- [3] Дохід номери: booking_id є, звичайний номер (не бані/бесідки),
                                --     не залог, не повернення, не послуги
                                --     АВАНС включається — дохід = аванс + доплата
                                COALESCE(SUM(CASE
                                    WHEN amount > 0 AND booking_id IS NOT NULL
                                     AND (note IS NULL OR (
                                          note NOT LIKE 'Залог%%%%' AND note NOT LIKE 'deposit%%%%'
                                          AND note NOT LIKE 'Повернення%%%%'
                                          AND note NOT LIKE 'Послуга:%%%%' AND note NOT LIKE 'Додаткові послуги%%%%'
                                     ))
                                    THEN amount END), 0) AS rooms_all,

                                -- [4] Ресторан/послуги: booking_id IS NULL (ресторан, послуги без броні)
                                --     + послуги до бронювань (note LIKE 'Послуга%'/'Додаткові послуги%')
                                COALESCE(SUM(CASE
                                    WHEN amount > 0
                                     AND (
                                         booking_id IS NULL
                                         AND note NOT LIKE 'Залог%%%%' AND note NOT LIKE 'deposit%%%%'
                                         AND note NOT LIKE 'Повернення%%%%'
                                     ) OR (
                                         amount > 0 AND booking_id IS NOT NULL
                                         AND (note LIKE 'Послуга:%%%%' OR note LIKE 'Додаткові послуги%%%%')
                                     )
                                    THEN amount END), 0) AS rest_svc,

                                -- [5] Готівка = дохід за готівку
                                -- Залог НЕ входить — він повертається при виселенні
                                COALESCE(SUM(CASE
                                    WHEN method = 'cash' AND amount > 0
                                     AND COALESCE(note,'') NOT LIKE 'Залог%%%%'
                                     AND COALESCE(note,'') NOT LIKE 'deposit%%%%'
                                     AND COALESCE(note,'') NOT LIKE 'Повернення%%%%'
                                    THEN amount END), 0) AS cash_total,

                                -- [6] Картка — залог не входить
                                COALESCE(SUM(CASE
                                    WHEN method = 'card' AND amount > 0
                                     AND COALESCE(note,'') NOT LIKE 'Залог%%%%'
                                     AND COALESCE(note,'') NOT LIKE 'deposit%%%%'
                                     AND COALESCE(note,'') NOT LIKE 'Повернення%%%%'
                                    THEN amount END), 0) AS card_total,

                                -- [7] Переказ — залог не входить
                                COALESCE(SUM(CASE
                                    WHEN method IN ('transfer','online') AND amount > 0
                                     AND COALESCE(note,'') NOT LIKE 'Залог%%%%'
                                     AND COALESCE(note,'') NOT LIKE 'deposit%%%%'
                                     AND COALESCE(note,'') NOT LIKE 'Повернення%%%%'
                                    THEN amount END), 0) AS transfer_total

                            FROM payments WHERE {_sf_bg}
                        """, _sf_bg_p)
                        _agg = cur.fetchone()
                        dep_total_bg, ret_total, rooms_all, rest_svc_total, cash_total, card_total, transfer_total = (
                            float(v or 0) for v in _agg)

                        # [8] Бані і бесідки — підмножина rooms_all через JOIN з категорією
                        cur.execute(f"""
                            SELECT
                                COALESCE(SUM(CASE
                                    WHEN (LOWER(COALESCE(rc.name,'')) LIKE '%%%%бан%%%%'
                                      OR LOWER(COALESCE(rc.name,'')) LIKE '%%%%saun%%%%'
                                      OR LOWER(COALESCE(rc.description,'')) LIKE '%%%%[tariff:hour]%%%%')
                                    THEN p.amount END), 0) AS bani,
                                COALESCE(SUM(CASE
                                    WHEN (LOWER(COALESCE(rc.name,'')) LIKE '%%%%бесід%%%%'
                                      OR LOWER(COALESCE(rc.name,'')) LIKE '%%%%альтанк%%%%')
                                    THEN p.amount END), 0) AS besidky
                            FROM payments p
                            JOIN bookings b ON p.booking_id = b.id
                            JOIN rooms r ON b.room_id = r.id
                            LEFT JOIN room_categories rc ON r.category_id = rc.id
                            WHERE {_sf_bg_join} AND p.amount > 0
                              AND (p.note IS NULL OR (
                                p.note NOT LIKE 'Залог%%%%' AND p.note NOT LIKE 'deposit%%%%'
                                AND p.note NOT LIKE 'Повернення%%%%'
                                AND p.note NOT LIKE 'Послуга:%%%%'
                                AND p.note NOT LIKE 'Додаткові послуги%%%%'
                              ))
                        """, _sf_bg_jp)
                        _cat = cur.fetchone()
                        bani_rev    = float(_cat[0] or 0) if _cat else 0.0
                        besidky_rev = float(_cat[1] or 0) if _cat else 0.0

                        # [9] Дохід номери = rooms_all мінус бані мінус бесідки
                        rooms_rev_only = max(rooms_all - bani_rev - besidky_rev, 0)

                        # [10] Всього отримано = готівка + картка + переказ
                        paid_total = cash_total + card_total + transfer_total

                        # [11] Розбивка по методах для таблиці
                        cur.execute(f"""
                            SELECT method,
                                   COUNT(CASE
                                       WHEN amount > 0
                                        AND COALESCE(note,'') NOT LIKE 'Залог%%%%'
                                        AND COALESCE(note,'') NOT LIKE 'deposit%%%%'
                                        AND COALESCE(note,'') NOT LIKE 'Повернення%%%%'
                                       THEN 1 END) as cnt,
                                   COALESCE(SUM(CASE
                                       WHEN amount > 0
                                        AND COALESCE(note,'') NOT LIKE 'Залог%%%%'
                                        AND COALESCE(note,'') NOT LIKE 'deposit%%%%'
                                        AND COALESCE(note,'') NOT LIKE 'Повернення%%%%'
                                       THEN amount END), 0) as total
                            FROM payments WHERE {_sf_bg}
                            GROUP BY method
                        """, _sf_bg_p)
                        pay = [dict(zip(['method','cnt','total'], r)) for r in cur.fetchall()]

                        # [12] Деталі платежів — ВСІ транзакції: платежі + ресторан + послуги
                        if _oat:
                            _rest_filter   = "ro.created_at >= %s"
                            _svc_filter    = "so.created_at >= %s"
                            _detail_params = _sf_bg_jp + (_oat, _oat)
                        else:
                            _rest_filter   = "(ro.created_at AT TIME ZONE 'UTC' AT TIME ZONE 'Europe/Kyiv')::date = CURRENT_DATE"
                            _svc_filter    = "(so.created_at AT TIME ZONE 'UTC' AT TIME ZONE 'Europe/Kyiv')::date = CURRENT_DATE"
                            _detail_params = _sf_bg_jp
                        cur.execute(f"""
                            -- Платежі (доходи, залоги, повернення)
                            SELECT p.amount, p.method, p.note,
                                   p.created_at AT TIME ZONE 'UTC' AT TIME ZONE 'Europe/Kyiv' as cat,
                                   COALESCE(g.name, '—') as guest_name,
                                   COALESCE(r.number, '—') as room_number
                            FROM payments p
                            LEFT JOIN bookings b ON p.booking_id=b.id
                            LEFT JOIN guests g ON g.id=b.guest_id
                            LEFT JOIN rooms r ON b.room_id=r.id
                            WHERE {_sf_bg_join}

                            UNION ALL

                            -- Ресторан
                            SELECT ro.total, COALESCE(ro.method,'cash'),
                                   CONCAT('Ресторан #', ro.id::text),
                                   ro.created_at AT TIME ZONE 'UTC' AT TIME ZONE 'Europe/Kyiv',
                                   'Ресторан', '—'
                            FROM restaurant_orders ro
                            WHERE ro.status = 'closed' AND ro.total > 0
                              AND {_rest_filter}

                            UNION ALL

                            -- Послуги
                            SELECT so.total, 'cash',
                                   CONCAT('Послуга: ', COALESCE(sv.name, so.note, '?')),
                                   so.created_at AT TIME ZONE 'UTC' AT TIME ZONE 'Europe/Kyiv',
                                   COALESCE(g2.name, '—'),
                                   COALESCE(r2.number, '—')
                            FROM service_orders so
                            LEFT JOIN bookings b2 ON so.booking_id=b2.id
                            LEFT JOIN guests g2 ON g2.id=b2.guest_id
                            LEFT JOIN rooms r2 ON so.room_id=r2.id
                            LEFT JOIN services sv ON so.service_id=sv.id
                            WHERE so.total > 0
                              AND so.note NOT LIKE 'deposit%%%%' AND so.note NOT LIKE 'fine%%%%'
                              AND {_svc_filter}

                            ORDER BY cat DESC
                        """, _detail_params)
                        cols = ['amount','method','note','created_at','guest_name','room_number']
                        pay_rows_all = [dict(zip(cols, r)) for r in cur.fetchall()]

                    else:
                        # ── Без зміни — агрегати за сьогодні (та ж логіка що з shift_id) ──
                        tz_cast = "(created_at AT TIME ZONE 'UTC' AT TIME ZONE 'Europe/Kyiv')::date"
                        cur.execute(f"""
                            SELECT
                                COALESCE(SUM(CASE
                                    WHEN amount > 0
                                     AND (note LIKE 'Залог при заселенні%%' OR note LIKE 'Залог при бронюванні%%' OR note LIKE 'deposit:%%')
                                    THEN amount END), 0) AS dep_in,
                                COALESCE(SUM(CASE
                                    WHEN note LIKE 'Повернення залогу%%' OR note LIKE 'deposit_returned%%'
                                    THEN ABS(amount) END), 0) AS dep_ret,
                                COALESCE(SUM(CASE
                                    WHEN amount > 0 AND booking_id IS NOT NULL
                                     AND (note IS NULL OR (
                                          note NOT LIKE 'Залог%%' AND note NOT LIKE 'deposit%%'
                                          AND note NOT LIKE 'Повернення%%'
                                          AND note NOT LIKE 'Послуга:%%' AND note NOT LIKE 'Додаткові послуги%%'
                                     ))
                                    THEN amount END), 0) AS rooms_all,
                                COALESCE(SUM(CASE
                                    WHEN amount > 0
                                     AND (
                                         (booking_id IS NULL
                                          AND note NOT LIKE 'Залог%%' AND note NOT LIKE 'deposit%%'
                                          AND note NOT LIKE 'Повернення%%')
                                         OR (booking_id IS NOT NULL AND amount > 0
                                             AND (note LIKE 'Послуга:%%' OR note LIKE 'Додаткові послуги%%'))
                                     )
                                    THEN amount END), 0) AS rest_svc,
                                COALESCE(SUM(CASE
                                    WHEN method = 'cash' AND amount > 0
                                     AND COALESCE(note,'') NOT LIKE 'Залог%%'
                                     AND COALESCE(note,'') NOT LIKE 'deposit%%'
                                     AND COALESCE(note,'') NOT LIKE 'Повернення%%'
                                    THEN amount END), 0) AS cash_total,
                                COALESCE(SUM(CASE
                                    WHEN method = 'card' AND amount > 0
                                     AND COALESCE(note,'') NOT LIKE 'Залог%%'
                                     AND COALESCE(note,'') NOT LIKE 'deposit%%'
                                     AND COALESCE(note,'') NOT LIKE 'Повернення%%'
                                    THEN amount END), 0) AS card_total,
                                COALESCE(SUM(CASE
                                    WHEN method IN ('transfer','online') AND amount > 0
                                     AND COALESCE(note,'') NOT LIKE 'Залог%%'
                                     AND COALESCE(note,'') NOT LIKE 'deposit%%'
                                     AND COALESCE(note,'') NOT LIKE 'Повернення%%'
                                    THEN amount END), 0) AS transfer_total
                            FROM payments WHERE {tz_cast} = %s
                        """, (today,))
                        _agg2 = cur.fetchone()
                        dep_total_bg, ret_total, rooms_all, rest_svc_total, cash_total, card_total, transfer_total = (
                            float(v or 0) for v in _agg2)

                        # Бані і бесідки через JOIN
                        cur.execute(f"""
                            SELECT
                                COALESCE(SUM(CASE
                                    WHEN (LOWER(COALESCE(rc.name,'')) LIKE '%%%%бан%%%%'
                                      OR LOWER(COALESCE(rc.name,'')) LIKE '%%%%saun%%%%'
                                      OR LOWER(COALESCE(rc.description,'')) LIKE '%%%%[tariff:hour]%%%%')
                                    THEN p.amount END), 0) AS bani,
                                COALESCE(SUM(CASE
                                    WHEN (LOWER(COALESCE(rc.name,'')) LIKE '%%%%бесід%%%%'
                                      OR LOWER(COALESCE(rc.name,'')) LIKE '%%%%альтанк%%%%')
                                    THEN p.amount END), 0) AS besidky
                            FROM payments p
                            JOIN bookings b ON p.booking_id = b.id
                            JOIN rooms r ON b.room_id = r.id
                            LEFT JOIN room_categories rc ON r.category_id = rc.id
                            WHERE {tz_cast} = %s AND p.amount > 0
                              AND (p.note IS NULL OR (
                                p.note NOT LIKE 'Залог%%%%' AND p.note NOT LIKE 'deposit%%%%'
                                AND p.note NOT LIKE 'Повернення%%%%'
                                AND p.note NOT LIKE 'Послуга:%%%%' AND p.note NOT LIKE 'Додаткові послуги%%%%'
                              ))
                        """, (today,))
                        _cat2 = cur.fetchone()
                        bani_rev    = float(_cat2[0] or 0) if _cat2 else 0.0
                        besidky_rev = float(_cat2[1] or 0) if _cat2 else 0.0
                        rooms_rev_only = max(rooms_all - bani_rev - besidky_rev, 0)
                        paid_total = cash_total + card_total + transfer_total

                        cur.execute(f"""
                            SELECT method,
                                   COUNT(CASE
                                       WHEN amount > 0
                                        AND COALESCE(note,'') NOT LIKE 'Залог%%%%'
                                        AND COALESCE(note,'') NOT LIKE 'deposit%%%%'
                                        AND COALESCE(note,'') NOT LIKE 'Повернення%%%%'
                                       THEN 1 END) as cnt,
                                   COALESCE(SUM(CASE
                                       WHEN amount > 0
                                        AND COALESCE(note,'') NOT LIKE 'Залог%%%%'
                                        AND COALESCE(note,'') NOT LIKE 'deposit%%%%'
                                        AND COALESCE(note,'') NOT LIKE 'Повернення%%%%'
                                       THEN amount END), 0) as total
                            FROM payments WHERE {tz_cast} = %s
                            GROUP BY method
                        """, (today,))
                        pay = [dict(zip(['method','cnt','total'], r)) for r in cur.fetchall()]

                        # pay_rows_all — ВСІ транзакції поточної зміни (платежі + ресторан + послуги)
                        _oat_bi = _opened_at_raw
                        cur.execute(f"""
                            SELECT p.amount, p.method, p.note,
                                   p.created_at AT TIME ZONE 'UTC' AT TIME ZONE 'Europe/Kyiv' as cat,
                                   COALESCE(g.name, b.guest_name, '—') as guest_name,
                                   COALESCE(r.number, '—') as room_number
                            FROM payments p
                            LEFT JOIN bookings b ON p.booking_id=b.id
                            LEFT JOIN guests g ON b.guest_id=g.id
                            LEFT JOIN rooms r ON b.room_id=r.id
                            WHERE {_sf}

                            UNION ALL

                            SELECT ro.total, 'cash',
                                   CONCAT('Ресторан #', ro.id::text),
                                   ro.created_at AT TIME ZONE 'UTC' AT TIME ZONE 'Europe/Kyiv',
                                   'Ресторан', '—'
                            FROM restaurant_orders ro
                            WHERE ro.status = 'closed' AND ro.total > 0
                              AND ro.created_at >= %s

                            UNION ALL

                            SELECT so.total, 'cash',
                                   CONCAT('Послуга: ', COALESCE(sv.name, so.note, '?')),
                                   so.created_at AT TIME ZONE 'UTC' AT TIME ZONE 'Europe/Kyiv',
                                   COALESCE(g2.name, b2.guest_name, '—'),
                                   COALESCE(r2.number, '—')
                            FROM service_orders so
                            LEFT JOIN bookings b2 ON so.booking_id=b2.id
                            LEFT JOIN guests g2 ON b2.guest_id=g2.id
                            LEFT JOIN rooms r2 ON so.room_id=r2.id
                            LEFT JOIN services sv ON so.service_id=sv.id
                            WHERE so.total > 0
                              AND so.note NOT LIKE 'deposit%%%%' AND so.note NOT LIKE 'fine%%%%'
                              AND so.created_at >= %s

                            ORDER BY cat DESC
                        """, _sfp + (_oat_bi, _oat_bi))
                        cols = ['amount','method','note','created_at','guest_name','room_number']
                        pay_rows_all = [dict(zip(cols, r)) for r in cur.fetchall()]

                    # Початковий залишок поточної зміни
                    cur.execute("SELECT COALESCE(opening_cash,0), COALESCE(opening_deposits,0) "
                                "FROM shifts WHERE id=%s", (current_shift_id,))
                    _op_row = cur.fetchone()
                    _op_cash = float(_op_row[0] if _op_row else 0)
                    _op_dep  = float(_op_row[1] if _op_row else 0)

                    # Кількість заселених — окремо (інша таблиця)
                    cur.execute("SELECT COUNT(DISTINCT id) as cnt FROM bookings WHERE status='checkedin'")
                    bk_cnt = int((cur.fetchone() or (0,))[0])

            # Переміщення коштів за поточну зміну (потрібно до визначення _update_ui)
            _tr_rows = []
            if current_shift_id:
                try:
                    with get_conn() as _conn2:
                        with _conn2.cursor() as _cur2:
                            _cur2.execute("""SELECT created_at, amount, reason, username
                                FROM cash_transfers WHERE shift_id=%s ORDER BY created_at DESC""",
                                (current_shift_id,))
                            _tr_rows = [dict(zip(['created_at','amount','reason','username'], r))
                                        for r in _cur2.fetchall()]
                except Exception: pass

            # ── UI-оновлення через after(0) ──
            def _update_ui(
                _op_cash_ui=_op_cash,
                _op_dep_ui=_op_dep,
                _new_stat={
                    'rooms':     f"{rooms_rev_only:.0f}₴",
                    'bani':      f"{bani_rev:.0f}₴",
                    'besidky':   f"{besidky_rev:.0f}₴",
                    'rest':      f"{rest_svc_total:.0f}₴",
                    'total':     f"{paid_total:.0f}₴",
                    'ret':       f"-{ret_total:.0f}₴" if ret_total > 0 else "0₴",
                    'dep':       f"{max(dep_total_bg + _op_dep - ret_total, 0):.0f}₴",
                    'rooms_cnt': str(bk_cnt),
                },
                _new_split={
                    'cash':      f"{cash_total:.0f}₴",
                    'card':      f"{card_total:.0f}₴",
                    'transfer':  f"{transfer_total:.0f}₴",
                    'dep_split': f"{max(dep_total_bg + _op_dep - ret_total, 0):.0f}₴",
                },
                _pay=pay, _pay_rows=pay_rows_all, _ret=ret_total,
                _transfers=_tr_rows
            ):
                METHOD_UA = {'cash':'готівка','card':'картка','transfer':'переказ','online':'онлайн'}
                for k, v in _new_stat.items():
                    if k in self._stat_lbls:
                        try: self._stat_lbls[k].configure(text=v)
                        except Exception: pass
                for k, v in _new_split.items():
                    if k in self._split_lbls:
                        try: self._split_lbls[k].configure(text=v)
                        except Exception: pass
                # Оновити банер "Готівка в касі"
                try:
                    if hasattr(self, '_cash_banner_lbl') and self._cash_banner_lbl.winfo_exists():
                        # Готівка в касі = відкриття зміни + готівка за зміну (дохід)
                        #                  - повернення готівкою - переміщення
                        _tr_total_ui = sum(float(r.get("amount",0)) for r in _transfers)
                        # Повернення залогів готівкою
                        _ret_cash_ui = sum(
                            abs(float(p["amount"])) for p in _pay_rows
                            if float(p.get("amount",0)) < 0 and p.get("method") == "cash"
                        )
                        # cash_total = готівка з доходів (вже без залогів і повернень)
                        _cash_in_ui = float(_new_split["cash"].replace("₴","").strip())
                        _real_cash_ui = _op_cash_ui + _cash_in_ui - _ret_cash_ui - _tr_total_ui
                        _clr = C["green"] if _real_cash_ui >= 0 else C["red"]
                        self._cash_banner_lbl.configure(text=f"{_real_cash_ui:.0f}₴", text_color=_clr)
                except Exception: pass
                # Оновити банер "Залогів в касі"
                try:
                    if hasattr(self, '_dep_banner_lbl') and self._dep_banner_lbl.winfo_exists():
                        _dep_ui = float(_new_stat["dep"].replace("₴","").replace("-","").strip())
                        self._dep_banner_lbl.configure(text=f"{_dep_ui:.0f}₴")
                except Exception: pass
                # Блок початкового залишку (якщо є)
                if _op_cash_ui > 0 or _op_dep_ui > 0:
                    try:
                        if not hasattr(self, '_op_card') or not self._op_card.winfo_exists():
                            self._op_card = card(self)
                            self._op_card.pack(fill='x', padx=15, pady=(0,5), before=self._pay_frame if hasattr(self,'_pay_frame') else None)
                            lbl(self._op_card, "🏁  Початок зміни", 12, True).pack(anchor='w', padx=12, pady=(8,4))
                            _op_f = tk.Frame(self._op_card, bg=C['card']); _op_f.pack(fill='x', padx=12, pady=(0,8))
                            if _op_cash_ui > 0:
                                _r1 = tk.Frame(_op_f, bg=C['card2']); _r1.pack(fill='x', pady=2)
                                lbl(_r1, "💵 Готівковий залишок", 11).pack(side='left', padx=8, pady=5)
                                lbl(_r1, f"{_op_cash_ui:.0f}₴", 12, True, C['green']).pack(side='right', padx=8)
                            if _op_dep_ui > 0:
                                _r2 = tk.Frame(_op_f, bg=C['card2']); _r2.pack(fill='x', pady=2)
                                lbl(_r2, "🔒 Залоги від попередньої зміни", 11).pack(side='left', padx=8, pady=5)
                                lbl(_r2, f"{_op_dep_ui:.0f}₴", 12, True, '#e67e22').pack(side='right', padx=8)
                    except Exception: pass

                # Таблиця транзакцій
                try:
                    self._pay_tree.delete(*self._pay_tree.get_children())
                    for p in _pay_rows:
                        try:
                            t = p.get('created_at')
                            if hasattr(t, 'strftime'):
                                ts = t.strftime('%d.%m %H:%M:%S')
                            else:
                                s = str(t)
                                ts = s[5:10].replace('-','.') + ' ' + s[11:19] if len(s) >= 19 else s[:19]
                            amt = float(p['amount'] or 0)
                            tag = 'ret' if amt < 0 else ('dep' if 'залог' in (p.get('note') or '').lower() else '')
                            self._pay_tree.insert('', 'end', tags=(tag,), values=(
                                ts,
                                p.get('room_number', '—'),
                                p.get('guest_name', ''),
                                f"{amt:+.0f}₴",
                                METHOD_UA.get(p.get('method', ''), p.get('method', '')),
                                p.get('note', '') or ''))
                        except Exception: pass
                except Exception: pass

            if current_shift_id:
                # Таблиця переміщень
                try:
                    METHOD_UA_loc = {'cash':'готівка','card':'картка','transfer':'переказ','online':'онлайн'}
                    self._transfer_tree.delete(*self._transfer_tree.get_children())
                    for r in _transfers:
                        t = r['created_at']
                        ts = t.strftime('%H:%M:%S') if hasattr(t,'strftime') else str(t)[:8]
                        self._transfer_tree.insert('', 'end', tags=('transfer',), values=(
                            ts, f"{float(r['amount']):.0f}₴", r['reason'], r['username'] or ''))
                except Exception: pass

            try: self.after(0, _update_ui)
            except Exception: pass

        except Exception as e:
            log_error("CashierFrame._refresh_data", e)

    def _build(self):
        # Показуємо рамку миттєво, данні підтягуємо через after() після рендеру
        self._load_lbl = ctk.CTkLabel(self, text="⏳ Завантаження каси...",
                                      font=('Segoe UI', 14), text_color=C['text2'])
        self._load_lbl.pack(pady=60)
        self.after(50, self._build_deferred)

    def _build_deferred(self):
        try:
            if not self.winfo_exists(): return
            try: self._load_lbl.destroy()
            except Exception: pass
            self._build_inner()
            self._built = True
        except Exception as _e:
            import traceback; traceback.print_exc()
            try:
                if self.winfo_exists():
                    lbl(self, f"⚠️ Помилка: {_e}", 12, color=C['red']).pack(pady=20)
            except Exception: pass

    def _build_inner(self):
        """Будує UI каси. Дані отримує через один SQL-запит у get_conn()."""
        from app.utils.db import get_conn
        import datetime as _dt
        today = date.today()
        current_shift_id = get_current_shift_id()
        # ── ВИПРАВЛЕННЯ: завжди брати свіжий shift_id напряму з БД ──
        try:
            with get_conn() as _sc2:
                with _sc2.cursor() as _scc2:
                    _scc2.execute("SELECT id FROM shifts WHERE status='open' ORDER BY id DESC LIMIT 1")
                    _sr2 = _scc2.fetchone()
                    if _sr2 and _sr2[0]:
                        current_shift_id = _sr2[0]
        except Exception:
            pass

        # Дефолти — на випадок будь-якого виключення
        paid_total = ret_total = dep_total = dep_total_bg = rooms_rev = 0.0
        bani_rev = besidky_rev = rooms_rev_only = rest_svc_total = 0.0
        svcs_rev = rest_total = cash_total = card_total = transfer_total = 0.0
        pay = []; pay_rows_all = []; bk_cnt = 0; shift_label = "—"
        _op_cash = _op_dep = 0.0

        # ── Отримати всі дані одним з'єднанням ──
        try:
            with get_conn() as conn:
                with conn.cursor() as cur:
                    if current_shift_id:
                        # Спочатку отримуємо дату відкриття зміни (для захоплення
                        # платежів з shift_id IS NULL, що могли потрапити в чергу синхронізації)
                        cur.execute("SELECT username, opened_at, COALESCE(opening_cash,0), COALESCE(opening_deposits,0) FROM shifts WHERE id=%s",
                                    (current_shift_id,))
                        shift_row = dict(zip(['username','opened_at','opening_cash','opening_deposits'], cur.fetchone() or ('','',0,0)))
                        _op_cash = float(shift_row.get('opening_cash') or 0)
                        _op_dep  = float(shift_row.get('opening_deposits') or 0)
                        _opened_at_raw = shift_row.get('opened_at')
                        # Якщо opened_at є — включаємо orphan-платежі (shift_id IS NULL, created >= opened)
                        # + fallback: будь-які платежі за сьогодні (на випадок якщо shift_id != current)
                        _today_cast = "(created_at AT TIME ZONE 'UTC' AT TIME ZONE 'Europe/Kyiv')::date = CURRENT_DATE"
                        if _opened_at_raw:
                            _sf = f"(shift_id = %s OR (shift_id IS NULL AND created_at >= %s) OR {_today_cast})"
                            _sfp = (current_shift_id, _opened_at_raw)   # 2 params
                            _sf_p = (current_shift_id, _opened_at_raw)  # для JOIN-запитів (p.shift_id)
                        else:
                            _sf = f"(shift_id = %s OR {_today_cast})"
                            _sfp = (current_shift_id,)
                            _sf_p = (current_shift_id,)

                        cur.execute(f"""
                            SELECT
                                COALESCE(SUM(CASE WHEN amount > 0
                                    AND COALESCE(note,'') NOT LIKE 'deposit%%%%'
                                    AND COALESCE(note,'') NOT LIKE 'Залог%%%%'
                                    AND COALESCE(note,'') NOT LIKE 'Повернення%%%%'
                                    THEN amount END), 0) AS paid,
                                COALESCE(ABS(SUM(CASE WHEN amount < 0
                                    AND COALESCE(note,'') NOT LIKE 'Повернення залогу%%%%'
                                    THEN amount END)), 0) AS ret,
                                COALESCE(SUM(CASE WHEN (note LIKE 'deposit%%%%' OR note LIKE 'Залог%%%%') AND amount > 0
                                    THEN amount END), 0) AS dep,
                                COALESCE(SUM(CASE WHEN booking_id IS NOT NULL AND amount > 0
                                    AND COALESCE(note,'') NOT LIKE 'deposit%%%%'
                                    AND COALESCE(note,'') NOT LIKE 'Залог%%%%'
                                    AND COALESCE(note,'') NOT LIKE 'Повернення%%%%'
                                    THEN amount END), 0) AS rooms
                            FROM payments WHERE {_sf}
                        """, _sfp)
                        paid_total, ret_total, dep_total, rooms_rev = (float(v or 0) for v in cur.fetchone())

                        # Бані і бесідки через JOIN
                        _today_p_cast = "(p.created_at AT TIME ZONE 'UTC' AT TIME ZONE 'Europe/Kyiv')::date = CURRENT_DATE"
                        if _opened_at_raw:
                            _sf_join = f"(p.shift_id = %s OR (p.shift_id IS NULL AND p.created_at >= %s) OR {_today_p_cast})"
                        else:
                            _sf_join = f"(p.shift_id = %s OR {_today_p_cast})"
                        cur.execute(f"""
                            SELECT
                                COALESCE(SUM(CASE WHEN (LOWER(COALESCE(rc.name,'')) LIKE '%%%%бан%%%%'
                                    OR LOWER(COALESCE(rc.name,'')) LIKE '%%%%saun%%%%'
                                    OR LOWER(COALESCE(rc.description,'')) LIKE '%%%%[tariff:hour]%%%%')
                                    THEN p.amount END), 0),
                                COALESCE(SUM(CASE WHEN (LOWER(COALESCE(rc.name,'')) LIKE '%%%%бесід%%%%'
                                    OR LOWER(COALESCE(rc.name,'')) LIKE '%%%%альтанк%%%%')
                                    THEN p.amount END), 0)
                            FROM payments p
                            JOIN bookings b ON p.booking_id = b.id
                            JOIN rooms r ON b.room_id = r.id
                            LEFT JOIN room_categories rc ON r.category_id = rc.id
                            WHERE {_sf_join} AND p.amount > 0
                              AND (p.note IS NULL OR (p.note NOT LIKE 'Залог%%%%'
                                AND p.note NOT LIKE 'deposit%%%%' AND p.note NOT LIKE 'Повернення%%%%'))
                        """, _sf_p)
                        _bi_cat = cur.fetchone()
                        bani_rev    = float(_bi_cat[0] or 0) if _bi_cat else 0.0
                        besidky_rev = float(_bi_cat[1] or 0) if _bi_cat else 0.0
                        rooms_rev_only = max(rooms_rev - bani_rev - besidky_rev, 0)

                        cur.execute(f"""
                            SELECT method,
                                   COUNT(CASE WHEN amount > 0
                                        AND COALESCE(note,'') NOT LIKE 'Залог%%%%'
                                        AND COALESCE(note,'') NOT LIKE 'deposit%%%%'
                                        AND COALESCE(note,'') NOT LIKE 'Повернення%%%%'
                                       THEN 1 END) as cnt,
                                   COALESCE(SUM(CASE WHEN amount > 0
                                        AND COALESCE(note,'') NOT LIKE 'Залог%%%%'
                                        AND COALESCE(note,'') NOT LIKE 'deposit%%%%'
                                        AND COALESCE(note,'') NOT LIKE 'Повернення%%%%'
                                       THEN amount END), 0) as total
                            FROM payments WHERE {_sf}
                            GROUP BY method
                        """, _sfp)
                        pay = [dict(zip(['method','cnt','total'], r)) for r in cur.fetchall()]

                        cur.execute(f"""
                            SELECT COALESCE(
                                (SELECT SUM(p2.amount) FROM payments p2
                                    WHERE ({_sf.replace('shift_id', 'p2.shift_id').replace('created_at', 'p2.created_at')}) AND p2.amount > 0
                                    AND (
                                        (p2.booking_id IS NULL
                                         AND p2.note NOT LIKE 'Залог%%%%' AND p2.note NOT LIKE 'deposit%%%%'
                                         AND p2.note NOT LIKE 'Повернення%%%%')
                                        OR
                                        (p2.booking_id IS NOT NULL
                                         AND (p2.note LIKE 'Послуга:%%%%' OR p2.note LIKE 'Додаткові послуги%%%%'))
                                    )
                                ), 0)
                        """, _sfp)
                        _rst = cur.fetchone()
                        svcs_rev = 0.0
                        rest_svc_total = float(_rst[0] or 0) if _rst else 0.0
                        # Правильний підрахунок залогів і повернень для блоків "Залишок залогів" і "Повернено"
                        cur.execute(f"""
                            SELECT
                                COALESCE(SUM(CASE WHEN amount > 0
                                    AND (note LIKE 'Залог при заселенні%%%%' OR note LIKE 'Залог при бронюванні%%%%' OR note LIKE 'deposit:%%%%')
                                    THEN amount END), 0) AS dep_in,
                                COALESCE(SUM(CASE WHEN (note LIKE 'Повернення залогу%%%%' OR note LIKE 'deposit_returned%%%%')
                                    THEN ABS(amount) END), 0) AS dep_ret
                            FROM payments WHERE {_sf}
                        """, _sfp)
                        _dep_row = cur.fetchone()
                        dep_total_bg = float(_dep_row[0] or 0) if _dep_row else dep_total
                        ret_total    = float(_dep_row[1] or 0) if _dep_row else 0.0
                        rest_total = rest_svc_total  # сумісність

                        ot = _opened_at_raw
                        if isinstance(ot, str):
                            try:
                                ot = _dt.datetime.fromisoformat(ot.replace(' ', 'T'))
                            except Exception: ot = None
                        if ot and hasattr(ot, 'tzinfo') and ot.tzinfo:
                            ot = ot.astimezone(_kyiv_tz()).replace(tzinfo=None)
                        shift_label = f'зміна #{current_shift_id}'
                        if ot:
                            shift_label = f"з {ot.strftime('%H:%M')} ({shift_row.get('username', '')})"

                        cur.execute(f"""
                            SELECT p.id, p.amount, p.method, p.note,
                                   p.created_at AT TIME ZONE 'UTC' AT TIME ZONE 'Europe/Kyiv' as created_at,
                                   COALESCE(g.name, 'Ресторан') as guest_name,
                                   COALESCE(r.number, '—') as room_number
                            FROM payments p
                            LEFT JOIN bookings b ON p.booking_id=b.id
                            LEFT JOIN guests g ON b.guest_id=g.id
                            LEFT JOIN rooms r ON b.room_id=r.id
                            WHERE {_sf_join}
                            ORDER BY p.created_at DESC
                        """, _sf_p)
                        cols = ['id', 'amount', 'method', 'note', 'created_at', 'guest_name', 'room_number']
                        pay_rows_all = [dict(zip(cols, r)) for r in cur.fetchall()]
                    else:
                        tz_cast = "(created_at AT TIME ZONE 'UTC' AT TIME ZONE 'Europe/Kyiv')::date"
                        cur.execute(f"""
                            SELECT
                                COALESCE(SUM(CASE WHEN amount > 0
                                    AND COALESCE(note,'') NOT LIKE 'Залог%%'
                                    AND COALESCE(note,'') NOT LIKE 'deposit%%'
                                    AND COALESCE(note,'') NOT LIKE 'Повернення%%'
                                    THEN amount END), 0) AS paid,
                                COALESCE(ABS(SUM(CASE WHEN note LIKE 'Повернення залогу%%' THEN amount END)), 0) AS ret,
                                COALESCE(SUM(CASE WHEN (note LIKE 'deposit%%' OR note LIKE 'Залог%%') AND amount > 0
                                    THEN amount END), 0) AS dep,
                                COALESCE(SUM(CASE WHEN booking_id IS NOT NULL
                                    AND COALESCE(note,'') NOT LIKE 'deposit%%'
                                    AND COALESCE(note,'') NOT LIKE 'Повернення залогу%%'
                                    AND COALESCE(note,'') NOT LIKE 'Залог%%'
                                    THEN amount END), 0) AS rooms
                            FROM payments WHERE {tz_cast} = %s
                        """, (today,))
                        paid_total, ret_total, dep_total, rooms_rev = (float(v or 0) for v in cur.fetchone())
                        # Derive bani/besidky/rooms_only from rooms_rev
                        bani_rev = 0.0; besidky_rev = 0.0
                        try:
                            cur.execute(f"""
                                SELECT
                                    COALESCE(SUM(CASE WHEN (LOWER(COALESCE(rc.name,'')) LIKE '%%бан%%'
                                        OR LOWER(COALESCE(rc.name,'')) LIKE '%%saun%%') THEN p.amount END), 0),
                                    COALESCE(SUM(CASE WHEN (LOWER(COALESCE(rc.name,'')) LIKE '%%бесід%%'
                                        OR LOWER(COALESCE(rc.name,'')) LIKE '%%альтанк%%') THEN p.amount END), 0)
                                FROM payments p JOIN bookings b ON p.booking_id=b.id
                                JOIN rooms r ON b.room_id=r.id LEFT JOIN room_categories rc ON r.category_id=rc.id
                                WHERE {tz_cast} = %s AND p.amount > 0
                                  AND (p.note IS NULL OR (p.note NOT LIKE 'Залог%%' AND p.note NOT LIKE 'deposit%%'
                                    AND p.note NOT LIKE 'Повернення%%'))
                            """, (today,))
                            _bc2 = cur.fetchone()
                            bani_rev = float(_bc2[0] or 0) if _bc2 else 0.0
                            besidky_rev = float(_bc2[1] or 0) if _bc2 else 0.0
                        except Exception: pass
                        rooms_rev_only = max(rooms_rev - bani_rev - besidky_rev, 0)
                        rest_svc_total = 0.0  # буде перераховано нижче
                        dep_total_bg = dep_total

                        cur.execute(f"""
                            SELECT method,
                                   COUNT(CASE WHEN amount > 0
                                        AND COALESCE(note,'') NOT LIKE 'Залог%%'
                                        AND COALESCE(note,'') NOT LIKE 'deposit%%'
                                        AND COALESCE(note,'') NOT LIKE 'Повернення%%'
                                       THEN 1 END) as cnt,
                                   COALESCE(SUM(CASE WHEN amount > 0
                                        AND COALESCE(note,'') NOT LIKE 'Залог%%'
                                        AND COALESCE(note,'') NOT LIKE 'deposit%%'
                                        AND COALESCE(note,'') NOT LIKE 'Повернення%%'
                                       THEN amount END), 0) as total
                            FROM payments WHERE {tz_cast} = %s
                            GROUP BY method
                        """, (today,))
                        pay = [dict(zip(['method','cnt','total'], r)) for r in cur.fetchall()]

                        cur.execute(f"""
                            SELECT
                                COALESCE((SELECT SUM(total) FROM service_orders
                                    WHERE {tz_cast} = %s
                                      AND (note IS NULL OR note NOT LIKE 'deposit%%')), 0),
                                COALESCE((SELECT SUM(total) FROM restaurant_orders
                                    WHERE status='closed' AND {tz_cast} = %s), 0)
                        """, (today, today))
                        svcs_rev, rest_total = (float(v or 0) for v in cur.fetchone())
                        rest_svc_total = svcs_rev + rest_total  # тепер обидві змінні визначені
                        shift_label = "за сьогодні"

                        # pay_rows_all: payments фільтруємо за shift_id (+ orphan + today),
                        # ресторан/послуги — за today (вони не мають shift_id)
                        _p_sf = _sf.replace("shift_id", "p.shift_id").replace("created_at", "p.created_at")
                        cur.execute(f"""
                            SELECT p.amount, p.method, p.note,
                                   p.created_at AT TIME ZONE 'UTC' AT TIME ZONE 'Europe/Kyiv' as cat,
                                   COALESCE(g.name, b.guest_name, '—') as guest_name,
                                   COALESCE(r.number, '—') as room_number
                            FROM payments p
                            LEFT JOIN bookings b ON p.booking_id=b.id
                            LEFT JOIN guests g ON b.guest_id=g.id
                            LEFT JOIN rooms r ON b.room_id=r.id
                            WHERE {_p_sf}

                            UNION ALL

                            SELECT ro.total, COALESCE(ro.method,'cash'),
                                   CONCAT('Ресторан #', ro.id::text),
                                   ro.created_at AT TIME ZONE 'UTC' AT TIME ZONE 'Europe/Kyiv',
                                   'Ресторан', '—'
                            FROM restaurant_orders ro
                            WHERE ro.status = 'closed' AND ro.total > 0
                              AND (ro.created_at AT TIME ZONE 'UTC' AT TIME ZONE 'Europe/Kyiv')::date = CURRENT_DATE

                            UNION ALL

                            SELECT so.total, 'cash',
                                   CONCAT('Послуга: ', COALESCE(sv.name, so.note, '?')),
                                   so.created_at AT TIME ZONE 'UTC' AT TIME ZONE 'Europe/Kyiv',
                                   COALESCE(g2.name, b2.guest_name, '—'),
                                   COALESCE(r2.number, '—')
                            FROM service_orders so
                            LEFT JOIN bookings b2 ON so.booking_id=b2.id
                            LEFT JOIN guests g2 ON b2.guest_id=g2.id
                            LEFT JOIN rooms r2 ON so.room_id=r2.id
                            LEFT JOIN services sv ON so.service_id=sv.id
                            WHERE so.total > 0
                              AND so.note NOT LIKE 'deposit%%' AND so.note NOT LIKE 'fine%%'
                              AND (so.created_at AT TIME ZONE 'UTC' AT TIME ZONE 'Europe/Kyiv')::date = CURRENT_DATE

                            ORDER BY cat DESC
                        """, _sfp)
                        cols = ['amount','method','note','created_at','guest_name','room_number']
                        pay_rows_all = [dict(zip(cols, r)) for r in cur.fetchall()]

                    cur.execute("SELECT COUNT(DISTINCT id) FROM bookings WHERE status='checkedin'")
                    bk_cnt = int((cur.fetchone() or (0,))[0])

        except Exception as _e:
            log_error("CashierFrame._build_inner DB", _e)
            paid_total = ret_total = dep_total = rooms_rev = svcs_rev = rest_total = dep_total_bg = 0.0
            bani_rev = besidky_rev = rooms_rev_only = rest_svc_total = 0.0
            bk_cnt = 0; pay = []; pay_rows_all = []; shift_label = "помилка БД"

        # Розбивка за методом оплати — тільки дохідні платежі (БЕЗ залогів)
        def _is_deposit(p):
            note = (p.get('note') or '').lower()
            return 'залог' in note or note.startswith('deposit')
        cash_total     = sum(float(p['amount'] or 0) for p in pay_rows_all if p.get('method') == 'cash'                        and float(p.get('amount') or 0) > 0 and not _is_deposit(p))
        card_total     = sum(float(p['amount'] or 0) for p in pay_rows_all if p.get('method') == 'card'                        and float(p.get('amount') or 0) > 0 and not _is_deposit(p))
        transfer_total = sum(float(p['amount'] or 0) for p in pay_rows_all if p.get('method') in ('transfer','online') and float(p.get('amount') or 0) > 0 and not _is_deposit(p))

        # ── Будуємо UI ──
        shift_start_dt = get_session_start()

        # ── Реальний залишок готівки в касі ──
        _opening_cash_bi = 0.0
        _transfers_out   = 0.0
        _ret_cash_bi     = 0.0
        if current_shift_id:
            try:
                from app.utils.db import query as _biq
                def _biq_val(row):
                    """Витягує перше числове значення з рядка (tuple або dict)."""
                    if row is None: return 0.0
                    if isinstance(row, (tuple, list)): return float(row[0] or 0)
                    return float(next(iter(row.values()), 0) or 0)
                _oc = _biq("SELECT COALESCE(opening_cash,0) AS opening_cash FROM shifts WHERE id=%s",
                           (current_shift_id,), fetch='one')
                _opening_cash_bi = _biq_val(_oc)
                _tr = _biq("SELECT COALESCE(SUM(amount),0) AS total FROM cash_transfers WHERE shift_id=%s",
                           (current_shift_id,), fetch='one')
                _transfers_out = _biq_val(_tr)
                _rc = _biq("""SELECT COALESCE(ABS(SUM(amount)),0) AS total FROM payments
                              WHERE shift_id=%s AND amount<0 AND method='cash'""",
                           (current_shift_id,), fetch='one')
                _ret_cash_bi = _biq_val(_rc)
            except Exception: pass
        # Готівка в касі = відкриття + дохід готівкою (БЕЗ залогів) - повернення - переміщення
        _cash_total_bi = sum(float(p['total'] or 0) for p in pay if p['method'] == 'cash')
        _real_cash = _opening_cash_bi + _cash_total_bi - _ret_cash_bi - _transfers_out

        hdr = tk.Frame(self, bg=C['bg']); hdr.pack(fill='x', padx=20, pady=(15,8))
        lbl(hdr, f"💰  Каса ({shift_label})", 22, True).pack(side='left')
        if shift_start_dt:
            lbl(hdr, f"Зміна відкрита: {shift_start_dt.strftime('%d.%m %H:%M')}",
                11, color=C['text2']).pack(side='left', padx=15)
        refresh_btn(hdr, self._rebuild, side='right', padx=8)
        btn(hdr, "💸 Переміщення", self._add_transfer, C['yellow'], 150, height=36).pack(side='right', padx=4)

        # ── Блок "Готівка в касі" зверху ──
        _cash_color = C['green'] if _real_cash >= 0 else C['red']
        _dep_balance = max(dep_total + _op_dep - ret_total, 0)
        cash_banner = ctk.CTkFrame(self, fg_color=C['card2'], corner_radius=12)
        cash_banner.pack(fill='x', padx=20, pady=(0, 8))
        _cb_inner = tk.Frame(cash_banner, bg=C['card2']); _cb_inner.pack(fill='x', padx=16, pady=10)

        # ── Ліва частина: Готівка ──
        lbl(_cb_inner, "💵  Готівка в касі:", 13, True, C['text']).pack(side='left')
        _cash_val_lbl = lbl(_cb_inner, f"{_real_cash:.0f}₴", 22, True, _cash_color)
        _cash_val_lbl.pack(side='left', padx=(8, 24))

        # ── Роздільник ──
        _sep = tk.Frame(_cb_inner, bg=C['text2'], width=1, height=36)
        _sep.pack(side='left', fill='y', padx=(0, 24))

        # ── Права частина: Залоги ──
        lbl(_cb_inner, "🔒  Залогів в касі:", 13, True, C['text']).pack(side='left')
        _dep_val_lbl = lbl(_cb_inner, f"{_dep_balance:.0f}₴", 22, True, '#e67e22')
        _dep_val_lbl.pack(side='left', padx=(8, 24))

        # деталі: відкриття + прийнято - повернено - переміщено
        _detail = f"Відкриття: {_opening_cash_bi:.0f}₴  +  Прийнято: {_cash_total_bi:.0f}₴"
