        def _show_revenue_details(title, cat_type, icon_color):
            """Popup з деталями платежів по категорії доходу."""
            from app.utils.db import query as _qr
            win2 = dlg_win(self, title, "750x560")
            top2 = tk.Frame(win2, bg=C['bg']); top2.pack(fill='both', expand=True)
            cv2 = tk.Canvas(top2, bg=C['bg'], highlightthickness=0)
