        def _show_bookings_popup(title, status_filter, cat_type, icon_color):
            """Popup з деталями бронювань по категорії."""
            from app.utils.db import query as _qp
            win = dlg_win(self, title, "700x520")
            top = tk.Frame(win, bg=C['bg']); top.pack(fill='both', expand=True)
            cv = tk.Canvas(top, bg=C['bg'], highlightthickness=0)
            sb = tk.Scrollbar(top, orient='vertical', command=cv.yview)
            cv.configure(yscrollcommand=sb.set)
            sb.pack(side='right', fill='y'); cv.pack(side='left', fill='both', expand=True)
            sc = tk.Frame(cv, bg=C['bg'])
            cw = cv.create_window((0,0), window=sc, anchor='nw')
            cv.bind('<Configure>', lambda e: cv.itemconfig(cw, width=e.width))
            sc.bind('<Configure>', lambda e: cv.configure(scrollregion=cv.bbox('all')))
            cv.bind_all('<MouseWheel>', lambda e: cv.yview_scroll(int(-1*(e.delta/120)),'units'))

            hdr2 = card(sc); hdr2.pack(fill='x', padx=10, pady=(10,5))
            lbl(hdr2, title, 14, True, icon_color).pack(anchor='w', padx=12, pady=(10,3))
            lbl(hdr2, f"Тип: {cat_type}", 11, color=C['text2']).pack(anchor='w', padx=12, pady=(0,8))

            # Умова фільтрації по категорії
            if cat_type == 'rooms':
                cat_cond = """lower(COALESCE(rc.name,'')) NOT LIKE '%%бан%%'
                    AND lower(COALESCE(rc.name,'')) NOT LIKE '%%saun%%'
                    AND lower(COALESCE(rc.name,'')) NOT LIKE '%%бесід%%'
                    AND lower(COALESCE(rc.name,'')) NOT LIKE '%%альтанк%%'
                    AND lower(COALESCE(rc.description,'')) NOT LIKE '%%[tariff:hour]%%'
                    AND CAST(COALESCE(r.number,'') AS text) NOT ILIKE '%%баня%%'
                    AND CAST(COALESCE(r.number,'') AS text) NOT ILIKE '%%бесід%%'
                    AND CAST(COALESCE(r.number,'') AS text) NOT ILIKE '%%альтанк%%'"""
            elif cat_type == 'bani':
                cat_cond = """(lower(COALESCE(rc.name,'')) LIKE '%%бан%%'
                    OR lower(COALESCE(rc.name,'')) LIKE '%%saun%%'
                    OR lower(COALESCE(rc.description,'')) LIKE '%%[tariff:hour]%%'
                    OR CAST(COALESCE(r.number,'') AS text) ILIKE '%%баня%%')"""
            else:  # besidky
                cat_cond = """(lower(COALESCE(rc.name,'')) LIKE '%%бесід%%'
                    OR lower(COALESCE(rc.name,'')) LIKE '%%альтанк%%'
                    OR CAST(COALESCE(r.number,'') AS text) ILIKE '%%бесід%%'
                    OR CAST(COALESCE(r.number,'') AS text) ILIKE '%%альтанк%%')"""

            # Отримати бронювання
            try:
                if shift_id:
                    rows = _qp(f"""
                        SELECT b.id, r.number AS room, g.name AS guest, g.phone,
                               b.check_in, b.check_out, b.status,
                               COALESCE(b.total_amount,0) AS total,
                               COALESCE((SELECT SUM(p2.amount) FROM payments p2
                                         WHERE p2.booking_id=b.id AND p2.amount>0
                                           AND p2.note NOT LIKE 'Залог%%'), 0) AS paid,
                               COALESCE((SELECT SUM(p3.amount) FROM payments p3
                                         WHERE p3.booking_id=b.id AND p3.amount>0
                                           AND p3.note LIKE 'Залог%%'), 0) AS dep
                        FROM bookings b
                        JOIN rooms r ON b.room_id=r.id
                        JOIN guests g ON b.guest_id=g.id
                        LEFT JOIN room_categories rc ON r.category_id=rc.id
                        WHERE b.status=%s
                          AND b.created_at >= (SELECT opened_at FROM shifts WHERE id=%s)
                          AND {cat_cond}
                        ORDER BY b.check_in DESC
                    """, (status_filter, shift_id)) or []
                else:
                    import datetime as _dtt2
                    _today_s = str(today)
                    rows = _qp(f"""
                        SELECT b.id, r.number AS room, g.name AS guest, g.phone,
                               b.check_in, b.check_out, b.status,
                               COALESCE(b.total_amount,0) AS total,
                               COALESCE((SELECT SUM(p2.amount) FROM payments p2
                                         WHERE p2.booking_id=b.id AND p2.amount>0
                                           AND p2.note NOT LIKE 'Залог%%'), 0) AS paid,
                               COALESCE((SELECT SUM(p3.amount) FROM payments p3
                                         WHERE p3.booking_id=b.id AND p3.amount>0
                                           AND p3.note LIKE 'Залог%%'), 0) AS dep
                        FROM bookings b
                        JOIN rooms r ON b.room_id=r.id
                        JOIN guests g ON b.guest_id=g.id
                        LEFT JOIN room_categories rc ON r.category_id=rc.id
                        WHERE b.status=%s AND DATE(b.created_at)=%s
                          AND {cat_cond}
                        ORDER BY b.check_in DESC
                    """, (status_filter, _today_s)) or []
            except Exception as _ex:
                rows = []
                lbl(sc, f"Помилка: {_ex}", 11, color=C['red']).pack(padx=15, pady=10)

            if not rows:
                lbl(sc, "Немає записів за цей період", 12, color=C['text2']).pack(padx=15, pady=20)
            else:
                # Підсумок
                sum_card = card(sc); sum_card.pack(fill='x', padx=10, pady=5)
                _tot_sum = sum(float(r.get('total') or 0) for r in rows)
                _paid_sum = sum(float(r.get('paid') or 0) for r in rows)
                _dep_sum = sum(float(r.get('dep') or 0) for r in rows)
                for lt, vl, cl in [
                    (f"Всього записів: {len(rows)}", "", C['text']),
                    (f"Сума проживання: {_tot_sum:.0f}₴", "", C['accent']),
                    (f"Оплачено: {_paid_sum:.0f}₴", "", C['green']),
                    (f"Залоги: {_dep_sum:.0f}₴", "", '#e67e22'),
                ]:
                    sf = tk.Frame(sum_card, bg=C['card2']); sf.pack(fill='x', padx=10, pady=2)
                    lbl(sf, lt, 12, color=cl).pack(side='left', padx=10, pady=6)

                # Рядки
                for row in rows:
                    rf2 = tk.Frame(sc, bg=C['card2']); rf2.pack(fill='x', padx=10, pady=2)
                    ci = str(row.get('check_in',''))[:10]
                    co = str(row.get('check_out',''))[:16]
                    tot = float(row.get('total') or 0)
                    paid = float(row.get('paid') or 0)
                    dep = float(row.get('dep') or 0)
                    debt = max(tot - paid - dep, 0)
                    status_ua = {'checkedin':'Заселений','confirmed':'Забронюваний',
                                 'checkedout':'Виселений','cancelled':'Скасований'}.get(
                                 str(row.get('status','')),'')
                    st_color = {'checkedin':C['green'],'confirmed':C['accent'],
                                'checkedout':C['text2'],'cancelled':C['red']}.get(
                                str(row.get('status','')),'')
                    # Рядок 1: кімната + гість
                    r1 = tk.Frame(rf2, bg=C['card2']); r1.pack(fill='x', padx=8, pady=(5,1))
                    lbl(r1, f"🛏 {row.get('room','')}",  12, True, icon_color).pack(side='left', padx=4)
                    lbl(r1, f"👤 {row.get('guest','')}",  12).pack(side='left', padx=8)
                    lbl(r1, f"📞 {row.get('phone','')}",  11, color=C['text2']).pack(side='left', padx=4)
                    lbl(r1, status_ua, 11, True, st_color).pack(side='right', padx=8)
