                    lbl(r2, f"📅 {ci} → {co}", 11, color=C['text2']).pack(side='left', padx=4)
                    lbl(r2, f"Всього: {tot:.0f}₴", 11, color=C['accent']).pack(side='left', padx=8)
                    lbl(r2, f"Оплач: {paid:.0f}₴", 11, color=C['green']).pack(side='left', padx=4)
                    if dep > 0:
                        lbl(r2, f"Залог: {dep:.0f}₴", 11, color='#e67e22').pack(side='left', padx=4)
