        # Прибирання за зміну
        import datetime as _dtclean
        _clog_all = _cl_load()
        # Фільтруємо по часу відкриття зміни (якщо є shift_id → беремо opened_at з БД)
        _shift_date_str = today.strftime('%d.%m.%Y')
        _shift_open_dt = None
        if shift_id:
            _sr2 = query("SELECT opened_at FROM shifts WHERE id=%s", (shift_id,), fetch='one') or {}
            _shift_open_dt = _sr2.get('opened_at')
        def _in_shift(e):
            _la = e.get('logged_at','') or e.get('started','')
            if not _la: return False
            if _shift_open_dt:
                _odt = _shift_open_dt if hasattr(_shift_open_dt,'strftime') else _dtclean.datetime.fromisoformat(str(_shift_open_dt))
                # Прибираємо timezone щоб уникнути порівняння aware vs naive
                if hasattr(_odt, 'tzinfo') and _odt.tzinfo is not None:
                    _odt = _odt.replace(tzinfo=None)
                _edt = None
                for _fmt, _ln in [('%d.%m.%Y %H:%M:%S', 19), ('%d.%m.%Y %H:%M', 16), ('%d.%m.%Y', 10)]:
                    try:
                        _edt = _dtclean.datetime.strptime(_la.strip()[:_ln], _fmt)
                        break
                    except Exception: pass
                if _edt:
                    return _edt >= _odt
                return _la.startswith(_shift_date_str)
            return _la.startswith(_shift_date_str)
        _clog_shift = [e for e in _clog_all if _in_shift(e)]
