        def do_export_excel():
            import os, datetime as _dte
            if not _OPENPYXL_OK:
                from tkinter import messagebox as _mb
                _mb.showerror("Помилка експорту",
                    "Бібліотека openpyxl не знайдена.\n\n"
                    "Зверніться до адміністратора та перезберіть програму з командою:\n"
                    "  pip install openpyxl\n"
                    "  pyinstaller HotelPMS.spec\n\n"
                    "Або додайте у spec-файл:\n"
                    "  hiddenimports=['openpyxl','openpyxl.styles','et_xmlfile']")
                return

            wb = openpyxl.Workbook()

            # ── Стилі ──
            def _hdr_fill(hex_color):
                return PatternFill('solid', fgColor=hex_color.lstrip('#'))
            def _font(bold=False, color='000000', size=11):
                return Font(bold=bold, color=color, size=size)
            def _border():
                s = Side(style='thin', color='CCCCCC')
                return Border(left=s, right=s, top=s, bottom=s)
            def _align(h='left'):
                return Alignment(horizontal=h, vertical='center', wrap_text=True)

            def _style_row(ws, row, fills=None, bold=False, font_color='000000'):
                for cell in ws[row]:
                    cell.border = _border()
                    cell.alignment = _align('right' if cell.column > 1 else 'left')
                    cell.font = _font(bold=bold, color=font_color)
                    if fills and cell.column - 1 < len(fills) and fills[cell.column-1]:
                        cell.fill = fills[cell.column-1]

            # ══ Аркуш 1: Зведений звіт ══
            ws1 = wb.active; ws1.title = "Зведений звіт"
            ws1.column_dimensions['A'].width = 36
            ws1.column_dimensions['B'].width = 18

            def _add(label, val, bold=False, color=None):
                r = ws1.max_row + 1
                ws1.cell(r, 1, label).font = _font(bold=bold)
                ws1.cell(r, 1).alignment = _align()
                v_cell = ws1.cell(r, 2, val)
                v_cell.font = _font(bold=bold, color=(color or '000000').lstrip('#'))
                v_cell.alignment = _align('right')
                ws1.cell(r, 1).border = _border()
                ws1.cell(r, 2).border = _border()
                return r

            ws1.append([f"{'Z-ЗВІТ' if is_z else 'X-ЗВІТ'} — {today.strftime('%d.%m.%Y')}"])
            ws1.cell(1,1).font = _font(bold=True, size=14)
            ws1.append([shift_info]); ws1.cell(2,1).font = _font(color='666666')
            ws1.append([f"Сформовано: {_dte.datetime.now().strftime('%d.%m.%Y %H:%M')}"])
            ws1.cell(3,1).font = _font(color='666666')
            ws1.append([])

            # ── КАСА ──
            ws1.append(["КАСА", "Сума"]); _style_row(ws1, ws1.max_row, bold=True,
                fills=[_hdr_fill('2C3E50'), _hdr_fill('2C3E50')], font_color='FFFFFF')
            _add("💵 Готівка",           f"{cash_total:.2f}₴",  color='27ae60')
            _add("💳 Картка",            f"{card_total:.2f}₴",  color='2980b9')
            _add("🏦 Переказ",           f"{transfer_total:.2f}₴", color='8e44ad')
            if adv_total > 0:
                _add("📋 Аванс при бронюванні", f"{adv_total:.2f}₴", color='f39c12')
            if xz_dep > 0:
                _add("🔒 Залоги прийнято", f"{xz_dep:.2f}₴",   color='e67e22')
            _add("✅ РАЗОМ ОТРИМАНО",    f"{grand_total:.2f}₴", bold=True, color='117A65')
            _add("🔢 Транзакцій",        str(tx_count))

            # ── ПОВЕРНЕННЯ ПРИ ВИЇЗДІ ──
            _ret_pay = sum(
                max(float(r.get('paid') or 0) - float(r.get('total') or 0), 0)
                for r in checkedout_detail)
            if _ret_pay > 0 or xz_ret > 0:
                ws1.append([])
                ws1.append(["ПОВЕРНЕННЯ ПРИ ВИЇЗДІ", "Сума"]); _style_row(ws1, ws1.max_row, bold=True,
                    fills=[_hdr_fill('922B21'), _hdr_fill('922B21')], font_color='FFFFFF')
                if _ret_pay > 0:
                    _add("↩️ Повернення оплати", f"{_ret_pay:.0f}", color='e74c3c')
                if xz_ret > 0:
                    _add("↩️ Повернено залогів", f"-{xz_ret:.2f}₴", color='e74c3c')
                _add("✅ РАЗОМ ПОВЕРНУТО", f"{_ret_pay + xz_ret:.2f}₴", bold=True, color='c0392b')
                _add("💸 Залишок залогів", f"{xz_dep_balance:.2f}₴", bold=True, color='e67e22')

            # ── ДОХІД ЗА КАТЕГОРІЯМИ ──
            ws1.append([])
            ws1.append(["ДОХІД ЗА КАТЕГОРІЯМИ", "Сума"]); _style_row(ws1, ws1.max_row, bold=True,
                fills=[_hdr_fill('1a252f'), _hdr_fill('1a252f')], font_color='FFFFFF')
            for _cat, _amt, _col in [
                ("🛏 Номери (готель)", _rooms_r,   '2980b9'),
                ("🛁 Бані",            _bani_r,    'e67e22'),
                ("⛺ Бесідки",         _besid_r,   '27ae60'),
                ("🍽 Послуги готелю",  svc_rev,    '1abc9c'),
                ("🍴 Ресторан",        rest_total, '8e44ad'),
            ]:
                _add(_cat, f"{_amt:.2f}₴", color=_col)
            _add("📊 РАЗОМ", f"{_rooms_r+_bani_r+_besid_r+svc_rev+rest_total:.2f}₴", bold=True, color='27ae60')

            # ── ОПЕРАЦІЙНА СТАТИСТИКА ──
            ws1.append([])
            ws1.append(["ОПЕРАЦІЙНА СТАТИСТИКА", "К-сть"]); _style_row(ws1, ws1.max_row, bold=True,
                fills=[_hdr_fill('1a252f'), _hdr_fill('1a252f')], font_color='FFFFFF')
            for _sl, _sv in [
                ("🛏 Номерів заселено",    ci_rooms),
                ("🔥 Бань заселено",       ci_bani),
                ("⛺ Бесідок заселено",     ci_besid),
                ("🛏 Номерів заброньовано", bk_rooms),
                ("🔥 Бань заброньовано",    bk_bani),
                ("⛺ Бесідок заброньовано", bk_besid),
                ("📋 Всього нових броней",  bk.get('cnt') or 0),
                ("🍴 Замовлень ресторану",  rest_cnt),
            ]:
                _add(_sl, str(_sv))

            # ══ Аркуш 2: Всі платежі зміни ══
            from app.utils.db import query as _qxl
            if shift_id:
                all_pays = _qxl("""
                    SELECT p.created_at, COALESCE(r.number,'—') AS room,
                           COALESCE(g.name,'—') AS guest, COALESCE(g.phone,'') AS phone,
                           p.amount, p.method, COALESCE(p.note,'') AS note
                    FROM payments p
                    LEFT JOIN bookings b ON p.booking_id=b.id
                    LEFT JOIN rooms r ON b.room_id=r.id
                    LEFT JOIN guests g ON b.guest_id=g.id
                    WHERE p.shift_id=%s ORDER BY p.created_at DESC
                """, (shift_id,)) or []
            else:
                all_pays = _qxl(f"""
                    SELECT p.created_at, COALESCE(r.number,'—') AS room,
                           COALESCE(g.name,'—') AS guest, COALESCE(g.phone,'') AS phone,
                           p.amount, p.method, COALESCE(p.note,'') AS note
                    FROM payments p
                    LEFT JOIN bookings b ON p.booking_id=b.id
                    LEFT JOIN rooms r ON b.room_id=r.id
                    LEFT JOIN guests g ON b.guest_id=g.id
                    WHERE DATE(p.created_at)=%s ORDER BY p.created_at DESC
                """, (str(today),)) or []

            ws2 = wb.create_sheet("Платежі зміни")
            hdrs2 = ["Час", "Кімната", "Гість", "Телефон", "Сума (₴)", "Метод", "Нотатка"]
            ws2.append(hdrs2)
            for i, h in enumerate(hdrs2, 1):
                c = ws2.cell(1, i)
                c.font = _font(bold=True, color='FFFFFF')
                c.fill = _hdr_fill('2C3E50')
                c.alignment = _align('center')
                c.border = _border()
            ws2.column_dimensions['A'].width = 18; ws2.column_dimensions['B'].width = 16
            ws2.column_dimensions['C'].width = 22; ws2.column_dimensions['D'].width = 15
            ws2.column_dimensions['E'].width = 12; ws2.column_dimensions['F'].width = 12
            ws2.column_dimensions['G'].width = 30
            METH_UA = {'cash':'Готівка','card':'Картка','transfer':'Переказ','online':'Онлайн'}
            for row in all_pays:
                amt_v = float(row.get('amount') or 0)
                ws2.append([
                    str(row.get('created_at',''))[:16],
                    row.get('room',''), row.get('guest',''), row.get('phone',''),
                    amt_v, METH_UA.get(str(row.get('method','')),''), row.get('note','')
                ])
                rn = ws2.max_row
                for ci2 in range(1, 8):
                    cell = ws2.cell(rn, ci2)
                    cell.border = _border()
                    cell.alignment = _align('right' if ci2 == 5 else 'left')
                    if ci2 == 5:
                        cell.font = _font(color='27AE60' if amt_v >= 0 else 'E74C3C')
                    if row.get('method') == 'z_report':
                        cell.fill = _hdr_fill('FFE0E0')

            # Збереження
            fname = f"{'Z' if is_z else 'X'}_zvit_{today.strftime('%Y%m%d_%H%M')}.xlsx"
            fpath = os.path.join(os.path.expanduser('~'), 'Desktop', fname)
            if not os.path.exists(os.path.dirname(fpath)):
                fpath = os.path.join(os.path.expanduser('~'), fname)
            try:
                wb.save(fpath)
                messagebox.showinfo("Excel", f"Збережено:\n{fpath}")
                try:
                    import subprocess
                    subprocess.Popen(['start', '', fpath], shell=True)
                except Exception:
                    pass
            except Exception as _es:
                messagebox.showerror("Помилка", str(_es))

        btn(act, "📊  Вигрузити Excel", do_export_excel, '#27ae60', 180).pack(side='left', padx=4)

        if is_z:
            # Перевірити чи вже закрита зміна сьогодні
            from app.utils.db import query as db_query
            already = db_query(
                "SELECT id FROM payments WHERE method='z_report' AND DATE(created_at)=%s",
                (today,), fetch='one')

            if already:
                warn = card(self.result); warn.pack(fill='x', padx=5, pady=5)
                lbl(warn, f"✅  Зміну {today.strftime('%d.%m.%Y')} вже закрито.",
                    13, color=C['green']).pack(padx=15, pady=12)
            else:
                def close_shift():
                    from app.utils.db import query as db_q, get_conn
                    if not messagebox.askyesno("Z-звіт",
                        f"Закрити зміну {today.strftime('%d.%m.%Y')}?\n\n"
                        f"Готівка: {cash_total:.2f}₴\n"
                        f"Картка: {card_total:.2f}₴\n"
                        f"Переказ: {transfer_total:.2f}₴\n"
                        f"Разом: {grand_total:.2f}₴\n\n"
                        "Після закриття каса обнуляється."):
                        return

                    # ── ОБОВ'ЯЗКОВА СИНХРОНІЗАЦІЯ перед закриттям зміни ──────
                    pending = _sync_mgr.pending_count()
                    if pending > 0 or not _sync_mgr.is_online():
                        sync_ok = _sync_mgr.on_shift_close(parent_widget=self)
                        if not sync_ok and _sync_mgr.pending_count() > 0:
                            if not messagebox.askyesno(
                                "⚠️  Синхронізація не завершена",
                                f"Не всі дані вивантажено на сервер.\n"
                                f"Залишилось операцій: {_sync_mgr.pending_count()}\n\n"
                                "Продовжити закриття зміни?"
                            ):
                                return
                        return
                    # Зберегти запис Z-звіту окремо (не в payments — там NOT NULL booking_id)
                    # Використаємо примітку в таблиці payments через фіктивне booking_id=1
                    # або через окрему логіку — зберігаємо у файл + позначаємо прапором
                    import os, json
                    zdir = os.path.join(os.path.dirname(os.path.abspath(__file__)), '..', '..', 'data')
                    os.makedirs(zdir, exist_ok=True)
                    zfile = os.path.join(zdir, 'z_reports.json')
                    try:
                        with open(zfile) as f_: zlog = json.load(f_)
                    except Exception:
                        zlog = []
                    import datetime as _dt
                    zlog.append({
                        'date': str(today),
                        'closed_at': _dt.datetime.now().strftime('%d.%m.%Y %H:%M:%S'),
                        'cash': cash_total,
                        'card': card_total,
                        'total': grand_total,
                        'tx': tx_count,
                    })
                    with open(zfile, 'w') as f_: json.dump(zlog, f_, ensure_ascii=False, indent=2)

                    # Закрити зміну в БД (статус → closed)
                    _shift_closed_ok = False
                    try:
                        from app.utils.db import get_conn as _gc_z
                        with _gc_z() as _conn_z:
                            with _conn_z.cursor() as _cur_z:
                                _cur_z.execute(
                                    "UPDATE shifts SET closed_at=NOW(), status='closed' "
                                    "WHERE status='open'"
                                )
                                _rows_updated = _cur_z.rowcount
                            _conn_z.commit()
                        _shift_closed_ok = True
                        print(f"[Z-звіт] Зміну закрито в БД, оновлено рядків: {_rows_updated}")
                    except Exception as _e:
                        print(f"[Z-звіт] Помилка закриття зміни в БД: {_e}")
                        messagebox.showerror(
                            "Помилка закриття зміни",
                            f"Не вдалося закрити зміну в БД:\n{_e}\n\n"
                            "Зверніться до адміністратора."
                        )
                        return

                    # Очистити shift_id в session.json — НЕ створювати нову зміну тут.
                    # Нова зміна відкриється автоматично коли наступний касир увійде в систему.
                    try:
                        import os as _os_z, json as _json_z
                        _sfile_z = _os_z.path.join(get_data_dir(), 'session.json')
                        try:
                            with open(_sfile_z, encoding='utf-8') as _f_z:
                                _sess_z = _json_z.load(_f_z)
                        except Exception:
                            _sess_z = {}
                        _sess_z.pop('shift_id', None)
                        _sess_z.pop('login_dt', None)
                        with open(_sfile_z, 'w', encoding='utf-8') as _f_z:
                            _json_z.dump(_sess_z, _f_z, ensure_ascii=False, indent=2)
                    except Exception as _se:
                        print(f"[Z-звіт] session clear error: {_se}")

                    do_print_report()

                    # Сховати головне вікно — обов'язковий релогін
                    try:
                        self.winfo_toplevel().withdraw()
                    except Exception:
                        pass

                    # Показати вікно підсумків зміни (блокує до релогіну)
                    ShiftClosedDlg(self, today, cash_total, card_total, transfer_total, grand_total, tx_count)

                btn(act, "🔴  Закрити зміну", close_shift, C['red'], 180).pack(side='left', padx=4)
                warn = card(self.result); warn.pack(fill='x', padx=5, pady=5)
                lbl(warn, "⚠️  Натисніть 'Закрити зміну' — каса обнулиться за цю зміну.",
                    12, color=C['yellow']).pack(padx=15, pady=12)

