# ДІАЛОГ ЗАКРИТТЯ ЗМІНИ
# ══════════════════════════════════════════════════════
class ShiftClosedDlg(ctk.CTkToplevel):
    """Показує підсумки закритої зміни і пропонує авторизуватись."""
    def __init__(self, parent, shift_date, cash, card_amt, transfer_amt, total, tx_count):
        super().__init__(parent)
        self.title("✅ Зміну закрито")
        self.configure(fg_color=C['bg'])
        self.lift(); self.focus_force()
        self.update_idletasks()
        _center_window(self, 480, 420, parent)
        # (grab вимкнено — Windows сумісність)
        # Блокуємо закриття хрестиком — тільки через кнопку "Авторизуватись"
        self.protocol("WM_DELETE_WINDOW", lambda: None)
        self._parent = parent
        self._build(shift_date, cash, card_amt, transfer_amt, total, tx_count)
        # Модальне вікно — захоплює фокус
        self.after(100, self._make_modal)

    def _make_modal(self):
        try:
            self.grab_set()
            self.lift()
            self.focus_force()
        except Exception:
            pass

    def _build(self, shift_date, cash, card_amt, transfer_amt, total, tx_count):
        scroll = ctk.CTkScrollableFrame(self, fg_color=C['bg'])
        scroll.pack(fill='both', expand=True, padx=15, pady=15)

        hdr = card(scroll); hdr.pack(fill='x', pady=5)
        lbl(hdr, "✅  Зміну закрито", 22, True, C['green']).pack(pady=(15,5))
        lbl(hdr, f"{shift_date.strftime('%d.%m.%Y')}", 14, color=C['text2']).pack(pady=(0,15))

        st = tk.Frame(scroll, bg=C['bg']); st.pack(fill='x', pady=8)
        st.columnconfigure((0,1,2), weight=1)
        for col, (lt, val, color) in enumerate([
            ("💵 Готівка",  f"{cash:.2f}₴",         C['green']),
            ("💳 Картка",   f"{card_amt:.2f}₴",      C['accent']),
            ("🏦 Переказ",  f"{transfer_amt:.2f}₴",  '#9b59b6'),
        ]):
            c = ctk.CTkFrame(st, fg_color=color, corner_radius=12)
            c.grid(row=0, column=col, padx=6, pady=4, sticky='ew', ipady=10)
            lbl(c, val, 26, True, 'white').pack(pady=(10,2))
            lbl(c, lt, 11, color='white').pack(pady=(0,10))

        tot = card(scroll); tot.pack(fill='x', pady=5)
        lbl(tot, f"✅  Разом за зміну: {total:.2f}₴", 20, True, '#9b59b6').pack(pady=12)
        lbl(tot, f"Транзакцій: {tx_count}", 12, color=C['text2']).pack(pady=(0,12))

        info = card(scroll); info.pack(fill='x', pady=5)
        lbl(info, "🔐  Каса обнулена. Для початку нової зміни\nнеобхідна авторизація.",
            13, color=C['yellow']).pack(padx=15, pady=12)

        btn(scroll, "🔐  Авторизуватись для нової зміни",
            self._do_relogin, C['accent'], 420, height=48).pack(pady=10)

    def _do_relogin(self):
        try:
            self.grab_release()
        except Exception:
            pass
        try:
            self.destroy()
        except Exception:
            pass
        try:
            _relogin(self._parent.winfo_toplevel())
        except Exception:
            pass


# ══════════════════════════════════════════════════════
# ВІДВІДУВАЧІ
# ══════════════════════════════════════════════════════
class VisitorsFrame(tk.Frame):
    def __init__(self, parent, user):
        super().__init__(parent, bg=C['bg'])
        self.user = user
        self._all_rows = []
        self._sort_col = None
        self._sort_rev = False
        self._loading_in_progress = False
        lbl(self, '⏳ Завантаження відвідувачів...', 14, color=C['text2']).pack(pady=60)
        self.after(30, self._build)

    def _build(self):
        try:
            for w in self.winfo_children(): w.destroy()
        except Exception: pass
        import datetime as _dt
        # ── Заголовок з refresh_btn ──
        tb = ctk.CTkFrame(self, fg_color=C['card']); tb.pack(fill='x', padx=15, pady=(15,5))
        lbl(tb, "👥  Відвідувачі", 18, True).pack(side='left', padx=15, pady=12)
        refresh_btn(tb, self._load, side='left', padx=4, pady=10)

        # ── Фільтр дат + пошук (як в інших вкладках) ──
        flt = ctk.CTkFrame(self, fg_color=C['card']); flt.pack(fill='x', padx=15, pady=3)
        lbl(flt, "Від:", 11, color=C['text2']).pack(side='left', padx=(10,4), pady=8)
        self._d_from = ent(flt, w=105); self._d_from.pack(side='left', pady=8)
        self._d_from.insert(0, _dt.date.today().replace(day=1).isoformat())
        lbl(flt, "До:", 11, color=C['text2']).pack(side='left', padx=(8,4), pady=8)
        self._d_to = ent(flt, w=105); self._d_to.pack(side='left', pady=8)
        self._d_to.insert(0, _dt.date.today().isoformat())
        btn(flt, "Застосувати", self._load, C['accent'], 110).pack(side='left', padx=8, pady=8)
        lbl(flt, "Пошук:", 11, color=C['text2']).pack(side='left', padx=(12,4), pady=8)
        self._search_entry = ent(flt, "Ім'я, телефон, паспорт, номер...", w=260)
        self._search_entry.pack(side='left', pady=8)
        self._search_entry.bind('<KeyRelease>', lambda e: self._filter())
        self._count_lbl = lbl(flt, "", 11, color=C['text2'])
        self._count_lbl.pack(side='left', padx=12)

        # ── Таблиця ──
        cols   = ('guest','passport','phone','room','check_in','check_out','nights','amount','status')
        heads  = ['ПІБ гостя','Паспорт','Телефон','Кімн.','Заїзд','Виїзд','Ночей','Сума','Статус']
        widths = [220, 130, 120, 65, 100, 100, 58, 90, 110]
        ff, self._tree = mktree(self, cols, 16, widths)
        for c, h in zip(cols, heads):
            self._tree.heading(c, text=h, command=lambda c=c: self._sort(c))
        for c in ('guest', 'passport'):
            self._tree.column(c, anchor='w')
        ff.pack(fill='both', expand=True, padx=15, pady=5)

        self._load()

    def _load_data_async(self):
        """Викликається _refresh_tab при повторному переході на вкладку."""
        self._load()

    def _load(self):
        if getattr(self, '_loading_in_progress', False):
            return
        self._loading_in_progress = True
        import threading
        threading.Thread(target=self._load_bg, daemon=True).start()

    def _load_bg(self):
        try:
            try:
                d_from = self._d_from.get().strip()
                d_to   = self._d_to.get().strip()
            except Exception:
                import datetime as _dt
                d_from = _dt.date.today().replace(day=1).isoformat()
                d_to   = _dt.date.today().isoformat()

            from app.utils.db import query
            rows = query("""
                SELECT
                    g.name  AS guest,
                    g.phone,
                    COALESCE(
                        (SELECT trim(regexp_replace(
                            substring(b2.notes FROM E'Паспорт: ([^\\n]+)'),
                            E'\\s+', ' ', 'g'))
                         FROM bookings b2
                         WHERE b2.guest_id = g.id
                           AND b2.notes LIKE '%%Паспорт%%'
                         ORDER BY b2.check_in DESC LIMIT 1),
                        '—'
                    ) AS passport,
                    r.number   AS room,
                    b.check_in,
                    b.check_out,
                    (b.check_out - b.check_in) AS nights,
                    COALESCE(b.total_amount, 0) AS amount,
                    b.status
                FROM bookings b
                JOIN guests g ON b.guest_id = g.id
                JOIN rooms  r ON b.room_id  = r.id
                WHERE b.check_in  BETWEEN %s AND %s
                   OR b.check_out BETWEEN %s AND %s
                ORDER BY b.check_in DESC
            """, (d_from, d_to, d_from, d_to)) or []

            parsed = []
            for r in rows:
                parsed.append({
                    'guest':    r['guest'] or '—',
                    'passport': r['passport'] or '—',
                    'phone':    r['phone'] or '—',
                    'room':     str(r['room']),
                    'check_in': str(r['check_in']),
                    'check_out':str(r['check_out']),
                    'nights':   str(r['nights'] or 0),
                    'amount':   f"{float(r['amount'] or 0):.0f}₴",
                    'status':   STATUS_UA.get(r['status'], r['status']),
                })
            self._all_rows = parsed
            try: self.after(0, self._filter)
            except Exception: pass
        except Exception as e:
            log_error("VisitorsFrame._load_bg", e)
        finally:
            self._loading_in_progress = False

    def _filter(self):
        try: q = self._search_entry.get().lower().strip()
        except Exception: q = ''
        filtered = [r for r in self._all_rows if not q or any(
            q in str(v).lower() for v in r.values())]
        self._tree.delete(*self._tree.get_children())
        for i, r in enumerate(filtered):
            tag = 'odd' if i % 2 else 'even'
            self._tree.insert('', 'end', values=[
                r['guest'], r['passport'], r['phone'],
                r['room'], r['check_in'], r['check_out'],
                r['nights'], r['amount'], r['status']
            ], tags=(tag,))
        self._tree.tag_configure('even', background=C['card'])
        self._tree.tag_configure('odd',  background=C['card2'])
        try: self._count_lbl.configure(text=f"Знайдено: {len(filtered)}")
        except Exception: pass

    def _sort(self, col):
        if self._sort_col == col:
            self._sort_rev = not self._sort_rev
        else:
            self._sort_col = col; self._sort_rev = False
        self._all_rows.sort(key=lambda r: r.get(col, ''), reverse=self._sort_rev)
        self._filter()


# ══════════════════════════════════════════════════════
# ТЕСТОВИЙ РЕЖИМ — очистка (викликається з SettingsFrame)
# ══════════════════════════════════════════════════════
def _run_test_mode_cleanup(on_done=None, on_error=None):
    """Видаляє всі дані створені після мітки тест-режиму.
    on_done(deleted_bids) — callback у головному потоці.
    on_error(str)         — callback у головному потоці при помилці.
    Завжди вимикає test_mode_active незалежно від результату.
    """
    import threading as _tmthr
    s = _load_app_settings()
    started_at_str = s.get('test_mode_started_at', '')
    if not started_at_str:
        _save_app_settings({'test_mode_active': False, 'test_mode_started_at': None})
        if on_done: on_done(0)
        return

    def _bg():
        _deleted_bids = 0
        _err_msg = None
        try:
            import psycopg2 as _pg2, os as _osT, json as _jsonT
            _db_json = None
            for _cp in [
                _osT.path.join(_osT.path.dirname(_osT.path.abspath(__file__)), '..', '..', 'config', 'db.json'),
                _osT.path.join(_osT.path.dirname(_osT.path.abspath(__file__)), '..', 'config', 'db.json'),
                _osT.path.join(_osT.path.dirname(_osT.path.abspath(__file__)), 'config', 'db.json'),
            ]:
                if _osT.path.exists(_cp): _db_json = _cp; break
            if not _db_json:
                raise RuntimeError("config/db.json не знайдено")
            with open(_db_json) as _tf:
                _tcfg = _jsonT.load(_tf)
            _conn = _pg2.connect(
                host=_tcfg.get('host','localhost'), port=int(_tcfg.get('port',5432)),
                dbname=_tcfg.get('database','hotel'), user=_tcfg.get('user','hotel'),
                password=_tcfg.get('password',''), connect_timeout=15,
                options="-c statement_timeout=60000")  # 60с максимум на запит
            _conn.autocommit = False
            ts = started_at_str
            try:
                with _conn.cursor() as _cur:
                    # 1. Бронювання та залежності
                    _cur.execute("SELECT id FROM bookings WHERE created_at >= %s", (ts,))
                    _bids = [r[0] for r in _cur.fetchall()]
                    _deleted_bids = len(_bids)
                    if _bids:
                        _cur.execute("DELETE FROM payments WHERE booking_id = ANY(%s)", (_bids,))
                        _cur.execute("DELETE FROM service_orders WHERE booking_id = ANY(%s)", (_bids,))
                        _cur.execute("""DELETE FROM restaurant_order_items WHERE order_id IN (
                            SELECT id FROM restaurant_orders WHERE booking_id = ANY(%s))""", (_bids,))
                        _cur.execute("DELETE FROM restaurant_orders WHERE booking_id = ANY(%s)", (_bids,))
                        _cur.execute("DELETE FROM bookings WHERE id = ANY(%s)", (_bids,))
                    # 2. Касові платежі без бронювань після ts
                    _cur.execute("DELETE FROM payments WHERE created_at >= %s AND booking_id IS NULL", (ts,))
                    # 3. Гості без бронювань (guests не має created_at — видаляємо по зв'язку)
                    if _bids:
                        _cur.execute("""DELETE FROM guests WHERE id IN (
                            SELECT DISTINCT guest_id FROM bookings
                            WHERE id = ANY(%s) AND guest_id IS NOT NULL
                        ) AND id NOT IN (
                            SELECT guest_id FROM bookings WHERE guest_id IS NOT NULL
                        )""", (_bids,))
                    # 4. Ресторанні замовлення без бронювань після ts
                    _cur.execute("""DELETE FROM restaurant_order_items WHERE order_id IN (
                        SELECT id FROM restaurant_orders
                        WHERE created_at >= %s AND booking_id IS NULL)""", (ts,))
                    _cur.execute("""DELETE FROM restaurant_orders
                        WHERE created_at >= %s AND booking_id IS NULL""", (ts,))
                _conn.commit()
                log_info(f"[TEST MODE] Очищено: {_deleted_bids} бронювань, мітка={ts}")
            except Exception as _ce:
                _conn.rollback(); raise _ce
            finally:
                _conn.close()
            # Оновити SQLite-кеш
            try:
                from app.utils.db_cache import _cache_instance as _ci
                if _ci: _tmthr.Thread(target=_ci.full_sync, daemon=True).start()
            except Exception: pass
        except Exception as _e:
            log_error("_run_test_mode_cleanup", _e)
            _err_msg = str(_e)
        finally:
            _save_app_settings({'test_mode_active': False, 'test_mode_started_at': None})
        if _err_msg:
            if on_error: on_error(_err_msg)
        else:
            if on_done: on_done(_deleted_bids)

    _tmthr.Thread(target=_bg, daemon=True).start()


# ══════════════════════════════════════════════════════
# НАЛАШТУВАННЯ
# ══════════════════════════════════════════════════════

class GuestDatabaseFrame(tk.Frame):
    def __init__(self, parent, user):
        super().__init__(parent, bg=C['bg'])
        self.user = user
        self._all_rows = []; self._filtered = []
        self._sort_col = 'last_visit'; self._sort_rev = True
        self._loading = False; self._expanded = None; self._child_iids = []; self._checks = {}
        lbl(self, '⏳ Завантаження...', 14, color=C['text2']).pack(pady=60)
        self.after(30, self._build)

    def _build(self):
        try:
            for w in self.winfo_children(): w.destroy()
        except Exception: pass
        tb = ctk.CTkFrame(self, fg_color=C['card']); tb.pack(fill='x', padx=15, pady=(15,4))
        lbl(tb, '📋  База гостей', 18, True).pack(side='left', padx=15, pady=10)
        refresh_btn(tb, self._load, side='left', padx=4, pady=8)
        self._total_lbl = lbl(tb, '', 11, color=C['text2']); self._total_lbl.pack(side='right', padx=15)
        sf = ctk.CTkFrame(self, fg_color=C['card']); sf.pack(fill='x', padx=15, pady=3)
        lbl(sf, '🔍', 13).pack(side='left', padx=(10,2), pady=8)
        self._search = ent(sf, "Пошук за ПІБ, телефоном...", w=280); self._search.pack(side='left', pady=8)
        self._search.bind('<KeyRelease>', lambda e: self._filter())
        lbl(sf, 'Візитів:', 11, color=C['text2']).pack(side='left', padx=(14,4))
        self._vis_var = tk.StringVar(value='всі')
        for lv, vv in [('всі','всі'),('1','1'),('2+','2+'),('5+','5+')]:
            ctk.CTkRadioButton(sf, text=lv, variable=self._vis_var, value=vv,
                               font=('Segoe UI',11), text_color=C['text'], fg_color=C['accent']).pack(side='left', padx=3)
        self._vis_var.trace_add('write', lambda *a: self._filter())
        btn(sf, '📊 Excel', self._export_excel, C['green'], 100, height=32).pack(side='right', padx=(4,12), pady=8)
        btn(sf, '☑ Всі',  self._select_all,   C['card2'],  80, height=32).pack(side='right', padx=4, pady=8)
        btn(sf, '☐ Зняти', self._deselect_all, C['card2'],  80, height=32).pack(side='right', padx=4, pady=8)
        self._count_lbl = lbl(sf, '', 11, color=C['text2']); self._count_lbl.pack(side='right', padx=8)
        cols = ('check','num','name','visits')
        ff, self._tree = mktree(self, cols, 16, [30,45,400,80])
        for c in ('check','num'): self._tree.column(c, anchor='center', stretch=False)
        self._tree.column('name', anchor='w')
        self._tree.heading('check', text='✓'); self._tree.heading('num', text='#')
        self._tree.heading('name', text='ПІБ гостя', command=lambda: self._sort('name'))
        self._tree.heading('visits', text='Візитів', command=lambda: self._sort('visits'))
        ff.pack(fill='both', expand=True, padx=15, pady=(3,8))
        self._tree.bind('<ButtonRelease-1>', self._on_click)
        self._tree.bind('<<TreeviewSelect>>', self._guard_select)
        self._load()

    def _load_data_async(self): self._load()

    def _load(self):
        if self._loading: return
        self._loading = True
        import threading
        threading.Thread(target=self._load_bg, daemon=True).start()

    def _load_bg(self):
        try:
            from app.utils.db import query
            rows = query("""
                SELECT g.id AS guest_id, g.name,
                    COALESCE(NULLIF(trim(g.phone),''),'—') AS phone,
                    COALESCE(NULLIF(trim(g.phone),''),'')  AS phone_key,
                    COALESCE(
                        (SELECT trim(regexp_replace(substring(b2.notes FROM E'Паспорт: ([^\\n]+)'),E'\\s+',' ','g'))
                         FROM bookings b2 WHERE b2.guest_id=g.id AND b2.notes LIKE '%%Паспорт%%'
                         ORDER BY b2.check_in DESC LIMIT 1),'—') AS passport,
                    COUNT(b.id) AS visits,
                    MIN(b.check_in) AS first_visit, MAX(b.check_in) AS last_visit,
                    COALESCE(SUM(b.check_out-b.check_in),0) AS total_nights,
                    COALESCE(SUM(b.total_amount),0) AS total_paid,
                    STRING_AGG(DISTINCT r.number::text,', ' ORDER BY r.number::text) AS rooms_list
                FROM guests g
                LEFT JOIN bookings b ON b.guest_id=g.id
                LEFT JOIN rooms r ON b.room_id=r.id
                GROUP BY g.id,g.name,g.phone ORDER BY MAX(b.check_in) DESC NULLS LAST,g.id
            """) or []
            from collections import defaultdict
            import re as _re_merge

            def _normalize_name(n):
                """Нормалізує ім'я: нижній регістр, тільки літери і пробіли."""
                return _re_merge.sub(r'\s+', ' ', str(n or '').strip().lower())

            # Ключ: якщо є телефон → телефон; інакше нормалізоване ім'я
            groups = defaultdict(list); no_key = []
            for r in rows:
                pk = str(r['phone_key'] or '').strip()
                name_key = _normalize_name(r['name'])
                if pk:
                    groups[pk].append(r)
                elif name_key and len(name_key) > 2:
                    groups['name:' + name_key].append(r)
                else:
                    no_key.append(r)
            # Додатково об'єднуємо по імені в рамках тієї самої phone-групи
            # (якщо в різних phone-групах однакові нормалізовані імена → злити)
            # Об'єднуємо групи з однаковим нормалізованим іменем
            name_to_key = {}
            final_groups = defaultdict(list)
            for pk, grp in groups.items():
                # Берем нормалізоване ім'я найкращого запису
                best_nk = _normalize_name(max(grp, key=lambda x: len(str(x['name'] or '')))['name'])
                if not pk.startswith('name:') and best_nk and best_nk in name_to_key:
                    # Є вже група з таким іменем — зливаємо
                    final_groups[name_to_key[best_nk]].extend(grp)
                else:
                    if best_nk and not pk.startswith('name:'):
                        name_to_key[best_nk] = pk
                    # Також кожне ім'я з групи реєструємо
                    for r in grp:
                        nk = _normalize_name(r['name'])
                        if nk and nk not in name_to_key:
                            name_to_key[nk] = pk
                    final_groups[pk].extend(grp)
            merged = []
            for pk, grp in final_groups.items():
                best = max(grp, key=lambda x: len(str(x['name'] or '')))
                all_ids = [int(x['guest_id']) for x in grp]
                passport = next((str(x['passport']) for x in grp if x['passport'] and str(x['passport'])!='—'),'—')
                tv = sum(int(x['visits'] or 0) for x in grp)
                tn = sum(int(x['total_nights'] or 0) for x in grp)
                tp = sum(float(x['total_paid'] or 0) for x in grp)
                firsts = [str(x['first_visit']) for x in grp if x['first_visit'] and str(x['first_visit']) not in ('—','None','')]
                lasts  = [str(x['last_visit'])  for x in grp if x['last_visit']  and str(x['last_visit'])  not in ('—','None','')]
                rooms = ', '.join(sorted({rm.strip() for x in grp for rm in str(x['rooms_list'] or '').split(',') if rm.strip() and rm.strip()!='—'})) or '—'
                merged.append({'guest_id':int(best['guest_id']),'all_ids':all_ids,'name':str(best['name'] or '—'),
                    'phone':str(best['phone'] or '—'),'passport':passport,'visits':str(tv),
                    'first_visit':min(firsts) if firsts else '—','last_visit':max(lasts) if lasts else '—',
                    'total_nights':str(tn),'total_paid':f"{tp:.0f}₴",'rooms_list':rooms})
            for r in no_key:
                merged.append({'guest_id':int(r['guest_id']),'all_ids':[int(r['guest_id'])],
                    'name':str(r['name'] or '—'),'phone':'—','passport':str(r['passport'] or '—'),
                    'visits':str(r['visits'] or 0),'first_visit':str(r['first_visit'] or '—'),
                    'last_visit':str(r['last_visit'] or '—'),'total_nights':str(r['total_nights'] or 0),
                    'total_paid':f"{float(r['total_paid'] or 0):.0f}₴",'rooms_list':str(r['rooms_list'] or '—')})
            def _ms(x):
                lv = x['last_visit']
                if lv and lv != '—':
                    try:
                        import datetime as _dt2
                        return (0, str(_dt2.date.fromisoformat(lv)))
                    except Exception: return (0, str(lv))
                return (1, '')
            merged.sort(key=_ms, reverse=True)
            self._all_rows = merged
            try: self.after(0, self._filter)
            except Exception: pass
        except Exception as e:
            log_error('GuestDatabaseFrame._load_bg', e)
        finally:
            self._loading = False

    def _filter(self):
        self._collapse()
        try: q = self._search.get().lower().strip()
        except Exception: q = ''
        try: vf = self._vis_var.get()
        except Exception: vf = 'всі'
        def _vis_ok(r):
            v = int(r['visits'] or 0)
            return (vf=='всі' or (vf=='1' and v==1) or (vf=='2+' and v>=2) or (vf=='5+' and v>=5))
        self._filtered = [r for r in self._all_rows if
                         (not q or any(q in str(r[k]).lower() for k in ('name','phone','passport','rooms_list')))
                         and _vis_ok(r)]
        def _sk(r):
            v = r.get(self._sort_col,'')
            try: return (0, float(str(v).replace('₴','')))
            except Exception: pass
            try:
                import datetime as _dtf
                return (0, str(_dtf.date.fromisoformat(str(v))))
            except Exception: pass
            return (1, str(v).lower())
        self._filtered.sort(key=_sk, reverse=self._sort_rev)
        self._tree.delete(*self._tree.get_children())
        self._checks = {}
        for i, r in enumerate(self._filtered):
            gid = r['guest_id']; v = int(r['visits'] or 0)
            tag = 'vip' if v>=5 else ('repeat' if v>=2 else ('odd' if i%2 else 'even'))
            self._tree.insert('','end',iid=f'g{gid}',tags=(tag,),values=[
                '☑' if self._checks.get(gid) else '☐', i+1, r['name'], r['visits']])
        self._tree.tag_configure('even',   background=C['card'])
        self._tree.tag_configure('odd',    background=C['card2'])
        self._tree.tag_configure('repeat', background='#1a3a1a')
        self._tree.tag_configure('vip',    background='#1a2a3a')
        self._tree.tag_configure('det_hdr',background='#222233')
        self._tree.tag_configure('det',    background=C['bg'])
        try: self._count_lbl.configure(text=f"Знайдено: {len(self._filtered)}")
        except Exception: pass
        try:
            rep = sum(1 for r in self._all_rows if int(r['visits'] or 0) >= 2)
            self._total_lbl.configure(text=f"Всього: {len(self._all_rows)} | Постійних: {rep}")
        except Exception: pass

    def _sort(self, col):
        if self._sort_col == col: self._sort_rev = not self._sort_rev
        else: self._sort_col = col; self._sort_rev = False
        self._filter()

    def _guard_select(self, event=None):
        sel = self._tree.selection()
        bad = [s for s in sel if s.startswith('d_')]
        if bad: self._tree.selection_remove(bad)

    def _on_click(self, event):
        col = self._tree.identify_column(event.x)
        iid = self._tree.identify_row(event.y)
        if not iid or iid.startswith('d_'): return
        gid_str = iid[1:]
        if not gid_str.isdigit(): return
        gid = int(gid_str)
        if col == '#1':
            self._checks[gid] = not self._checks.get(gid, False)
            vals = list(self._tree.item(iid,'values'))
            vals[0] = '☑' if self._checks[gid] else '☐'
            self._tree.item(iid, values=vals)
        else:
            if iid == self._expanded: self._collapse()
            else: self._expand(iid)

    def _collapse(self):
        if self._expanded:
            for c in self._child_iids:
                try: self._tree.delete(c)
                except Exception: pass
            self._child_iids = []; self._expanded = None

    def _expand(self, iid):
        """Відкриває повну картку гостя у окремому вікні."""
        self._collapse()
        gid = int(iid[1:])
        row = next((r for r in self._all_rows if r['guest_id']==gid), None)
        if not row: return
        self._open_guest_card(gid, row)

    def _open_guest_card(self, gid, row):
        import threading
        win = ctk.CTkToplevel(self)
        win.title(f"Гість: {row['name']}")
        win.geometry('1000x640')
        win.configure(fg_color=C['bg'])
        win.grab_set()
        win.lift()

        # ── Шапка ──
        hdr_f = ctk.CTkFrame(win, fg_color=C['card'], corner_radius=10)
        hdr_f.pack(fill='x', padx=14, pady=(14,6))
        lbl(hdr_f, f"👤  {row['name']}", 20, True, C['accent']).pack(anchor='w', padx=16, pady=(12,4))
        info_row = tk.Frame(hdr_f, bg=C['card']); info_row.pack(fill='x', padx=16, pady=(0,12))
        for i, (ico, label, val) in enumerate([
            ('📞','Телефон',   row['phone']),
            ('🪪','Паспорт',   row['passport']),
            ('📅','Перший візит', row['first_visit']),
            ('📅','Останній',  row['last_visit']),
        ]):
            info_row.columnconfigure(i, weight=1)
            cf = tk.Frame(info_row, bg=C['card2'], relief='flat')
            cf.grid(row=0, column=i, padx=4, pady=2, sticky='ew', ipady=4)
            lbl(cf, f"{ico} {label}", 9, color=C['text2']).pack(anchor='w', padx=8, pady=(4,1))
            lbl(cf, val, 12, True).pack(anchor='w', padx=8, pady=(0,4))

        # ── Статистика ──
        st_row = tk.Frame(win, bg=C['bg']); st_row.pack(fill='x', padx=14, pady=4)
        for i, (title, val, clr) in enumerate([
            ('Візитів',       row['visits'],       C['accent']),
            ('Ночей всього',  row['total_nights'],  C['green']),
            ('Сплачено',      row['total_paid'],    '#9b59b6'),
        ]):
            st_row.columnconfigure(i, weight=1)
            cf = ctk.CTkFrame(st_row, fg_color=C['card'], corner_radius=10)
            cf.grid(row=0, column=i, padx=5, pady=4, sticky='ew', ipady=8)
            lbl(cf, val, 22, True, clr).pack(pady=(8,2))
            lbl(cf, title, 10, color=C['text2']).pack(pady=(0,8))

        # ── Таблиця бронювань ──
        lbl(win, '📋  Всі бронювання', 13, True).pack(anchor='w', padx=18, pady=(6,3))

        tbl_frame = tk.Frame(win, bg=C['bg']); tbl_frame.pack(fill='both', expand=True, padx=14, pady=(0,10))
        tbl_frame.rowconfigure(0, weight=1); tbl_frame.columnconfigure(0, weight=1)

        import tkinter.ttk as _ttb
        _vsb = tk.Scrollbar(tbl_frame, orient='vertical')
        _hsb = tk.Scrollbar(tbl_frame, orient='horizontal')
        _sty = _ttb.Style()
        _sty.configure('Guest.Treeview', background=C['card'], foreground=C['text'],
            fieldbackground=C['card'], rowheight=26, font=('Segoe UI', 11))
        _sty.configure('Guest.Treeview.Heading', background=C['card2'],
            foreground=C['accent'], font=('Segoe UI', 11, 'bold'))
        _sty.map('Guest.Treeview', background=[('selected', C['accent'])])

        _cols = ('room','check_in','check_out','nights','amount','paid','debt','status')
        _tv = _ttb.Treeview(tbl_frame, columns=_cols, show='headings',
            style='Guest.Treeview', yscrollcommand=_vsb.set, xscrollcommand=_hsb.set)
        _vsb.config(command=_tv.yview); _hsb.config(command=_tv.xview)
        _tv.grid(row=0, column=0, sticky='nsew')
        _vsb.grid(row=0, column=1, sticky='ns')
        _hsb.grid(row=1, column=0, sticky='ew')

        for c, h, w in zip(_cols,
            ['Кімната','Заїзд','Виїзд','Ночей','Сума','Сплачено','Борг','Статус'],
            [110, 110, 110, 70, 100, 100, 90, 120]):
            _tv.heading(c, text=h); _tv.column(c, width=w, minwidth=60, anchor='center')
        _tv.column('room', anchor='w')

        _tv.tag_configure('even', background=C['card'])
        _tv.tag_configure('odd',  background=C['card2'])
        _tv.tag_configure('debt', background='#2a1010')
        _tv.tag_configure('active', background='#0a2a0a')

        _loading_lbl = lbl(win, '⏳ Завантаження бронювань...', 11, color=C['text2'])
        _loading_lbl.place(relx=0.5, rely=0.85, anchor='center')

        def _load_brows():
            try:
                from app.utils.db import get_conn as _gc_card
                ids_t = tuple(int(x) for x in row['all_ids'])
                placeholders = ','.join(['%s']*len(ids_t))
                with _gc_card() as _c2:
                    with _c2.cursor() as _cur2:
                        _cur2.execute(f"""
                            SELECT r.number AS room, b.check_in, b.check_out,
                                (b.check_out-b.check_in) AS nights,
                                COALESCE(b.total_amount,0) AS amount,
                                COALESCE((SELECT SUM(p.amount) FROM payments p
                                    WHERE p.booking_id=b.id AND p.amount>0
                                    AND COALESCE(p.note,'') NOT LIKE 'Залог%%'),0) AS paid,
                                b.status
                            FROM bookings b
                            JOIN rooms r ON b.room_id=r.id
                            WHERE b.guest_id IN ({placeholders})
                            ORDER BY b.check_in DESC
                        """, ids_t)
                        rc2 = [d[0] for d in _cur2.description]
                        brows = [dict(zip(rc2, r)) for r in _cur2.fetchall()]
            except Exception as _be:
                log_error('guest_card._load_brows', _be); brows = []

            def _fill():
                try: _loading_lbl.place_forget()
                except Exception: pass
                if not brows:
                    lbl(win, '— немає бронювань —', 11, color=C['text2']).pack()
                    return
                total_n = 0; total_p = 0; total_d = 0
                for i, br in enumerate(brows):
                    amt   = float(br['amount'] or 0)
                    paid  = float(br['paid'] or 0)
                    debt  = max(amt - paid, 0)
                    nights = int(br['nights'] or 0)
                    total_n += nights; total_p += paid; total_d += debt
                    status = STATUS_UA.get(br['status'], br['status'] or '—')
                    tag = 'active' if br['status']=='checked_in' else ('debt' if debt>0 else ('odd' if i%2 else 'even'))
                    _tv.insert('','end',tags=(tag,),values=[
                        str(br['room'] or '—'),
                        str(br['check_in'] or '—'),
                        str(br['check_out'] or '—'),
                        str(nights),
                        f"{amt:.0f}₴",
                        f"{paid:.0f}₴",
                        f"{debt:.0f}₴" if debt>0 else '—',
                        status,
                    ])
                # Підсумок
                _tv.insert('','end',tags=('even',),values=[
                    '━━ Разом', '', '', str(total_n),
                    '', f"{total_p:.0f}₴",
                    f"{total_d:.0f}₴" if total_d>0 else '—', f"{len(brows)} бронювань"
                ])
            try: win.after(0, _fill)
            except Exception: pass

        threading.Thread(target=_load_brows, daemon=True).start()
        btn(win, '✕  Закрити', win.destroy, C['card2'], 140, height=36).pack(pady=(0,10))

    def _load_bookings_bg(self, gid, all_ids, load_iid, parent_iid):
        brows = []
        try:
            from app.utils.db import get_conn as _gc_gb
            ids_t = tuple(int(x) for x in all_ids)
            placeholders = ','.join(['%s'] * len(ids_t))
            with _gc_gb() as _c_gb:
                with _c_gb.cursor() as _cur_gb:
                    _cur_gb.execute(f"""
                        SELECT r.number AS room, b.status, b.check_in, b.check_out,
                            (b.check_out - b.check_in) AS nights,
                            COALESCE(b.total_amount, 0) AS amount,
                            COALESCE((SELECT SUM(p.amount) FROM payments p
                                      WHERE p.booking_id=b.id AND p.amount>0
                                      AND COALESCE(p.note,'') NOT LIKE 'Залог%%'), 0) AS paid_total,
                            COALESCE(NULLIF(trim(b.guest_name),''), '—') AS note,
                            g.name AS guest_name
                        FROM bookings b
                        JOIN rooms r ON b.room_id = r.id
                        LEFT JOIN guests g ON b.guest_id = g.id
                        WHERE b.guest_id IN ({placeholders})
                        ORDER BY b.check_in DESC
                    """, ids_t)
                    _rc = [d[0] for d in _cur_gb.description]
                    brows = [dict(zip(_rc, r)) for r in _cur_gb.fetchall()]
        except Exception as _e:
            log_error('GuestDatabaseFrame._load_bookings_bg', _e)

        def _fill():
            try:
                try: self._tree.delete(load_iid)
                except Exception: pass
                if load_iid in self._child_iids: self._child_iids.remove(load_iid)
                if not brows:
                    ei = f'd_empty_{gid}'
                    self._tree.insert(parent_iid,'end',iid=ei,tags=('det',),values=['','','    — немає бронювань —',''])
                    self._child_iids.append(ei); return
                for i, br in enumerate(brows):
                    bi = f'd_{gid}_{i}'
                    left = f"    {br['room'] or '—'}   {br['check_in'] or '—'} \u2192 {br['check_out'] or '—'}   {br['nights'] or 0} ніч   {float(br['amount'] or 0):.0f}\u20b4 / {float(br['paid_total'] or 0):.0f}\u20b4"
                    right = f"  {STATUS_UA.get(br['status'], br['status'] or '—')}"
                    self._tree.insert(parent_iid,'end',iid=bi,tags=('det',),values=['','',left,right])
                    self._child_iids.append(bi)
                tn = sum(int(br['nights'] or 0) for br in brows)
                tp = sum(float(br['paid_total'] or 0) for br in brows)
                si = f'd_sum_{gid}'
                self._tree.insert(parent_iid,'end',iid=si,tags=('det_hdr',),
                    values=['','',f"    📊 {len(brows)} бронювань  |  {tn} ніч  |  {tp:.0f}₴",''])
                self._child_iids.append(si)
            except Exception: pass
        try: self.after(0, _fill)
        except Exception: pass

    def _select_all(self):
        for r in self._filtered: self._checks[r['guest_id']] = True
        self._redraw_checks()

    def _deselect_all(self):
        self._checks.clear(); self._redraw_checks()

    def _redraw_checks(self):
        for r in self._filtered:
            gid = r['guest_id']
            try:
                vals = list(self._tree.item(f'g{gid}','values'))
                vals[0] = '☑' if self._checks.get(gid) else '☐'
                self._tree.item(f'g{gid}', values=vals)
            except Exception: pass

    def _export_excel(self):
        selected = [r for r in self._filtered if self._checks.get(r['guest_id'])]
        data = selected if selected else self._filtered
        if not data:
            import tkinter.messagebox as _mb; _mb.showinfo('Експорт','Немає даних'); return
        import tkinter.filedialog as _fd, datetime as _dte, os as _os2
        fname = f'guests_{_dte.date.today().isoformat()}.xlsx'
        desktop = _os2.path.join(_os2.path.expanduser('~'),'Desktop')
        if not _os2.path.isdir(desktop): desktop = _os2.path.expanduser('~')
        fpath = _fd.asksaveasfilename(title='Зберегти базу гостей',initialdir=desktop,
            initialfile=fname,defaultextension='.xlsx',filetypes=[('Excel','*.xlsx'),('Всі','*.*')])
        if not fpath: return
        import threading
        threading.Thread(target=self._do_export, args=(data,fpath), daemon=True).start()

    def _do_export(self, data, fname):
        try:
            headers = ['#','ПІБ гостя','Телефон','Паспорт','Візитів','Перший','Останній','Ночей','Сплачено','Кімнати']
            col_w = [5,28,16,16,8,13,13,7,12,28]
            rows = [[i+1,r['name'],r['phone'],r['passport'],int(r['visits'] or 0),
                     r['first_visit'],r['last_visit'],int(r['total_nights'] or 0),
                     r['total_paid'],r['rooms_list']] for i,r in enumerate(data)]
            SettingsFrame._make_xlsx(rows, headers, fname, col_widths=col_w)
            self.after(0, lambda f=fname: __import__('tkinter.messagebox',fromlist=['showinfo']).showinfo('✅ Готово',f'Збережено {len(data)} записів:\n{f}'))
        except Exception as _e:
            log_error('GuestDatabaseFrame._do_export', _e)
            self.after(0, lambda e=_e: __import__('tkinter.messagebox',fromlist=['showerror']).showerror('Помилка',str(e)))



class SettingsFrame(tk.Frame):
    def __init__(self, parent, user):
        super().__init__(parent, bg=C['bg'])
        self.user=user
        self._ui_built = False
        # Показуємо заглушку, важкий UI будуємо після рендеру
        lbl(self, "⏳ Завантаження налаштувань...", 14, color=C['text2']).pack(pady=60)
        self.after(50, self._build)

    def _load_data_async(self):
        """Викликається при кожному переході на вкладку.
        Якщо CTkTabview ще не добудований або виник race condition — перебудовуємо.
        """
        if not self._ui_built:
            self._build()
        else:
            # Примусово оновлюємо розміри CTkTabview — він міг бути побудований прихованим
            try:
                self.update_idletasks()
            except Exception:
                pass

    def _build(self):
        # Якщо виклик прийшов поки фрейм прихований (pre-render) — відкладаємо
        # до моменту коли він стане видимим, щоб CTkTabview правильно розрахував розміри
        try:
            if not self.winfo_viewable():
                self.after(100, self._build)
                return
        except Exception:
            pass
        self._ui_built = True
        try:
            for w in self.winfo_children():
                try: w.destroy()
                except Exception: pass
        except Exception:
            pass
        # Заголовок — фіксований зверху
        hdr = tk.Frame(self, bg=C['bg'])
        hdr.pack(fill='x', padx=20, pady=(15,4))
        lbl(hdr,"⚙️  Налаштування",22,True).pack(side='left')

        # Tabview — займає весь простір що залишився
        # ── Список вкладок (назва, метод) ──
        _TAB_LIST = [
            ("🛏 Номери",         "_rooms_tab"),
            ("🏷 Категорії",      "_cats_tab"),
            ("🍽 Меню",           "_menu_tab"),
            ("🪑 Столики",        "_tables_tab"),
            ("👥 Користувачі",    "_users_tab"),
            ("🧹 Прибиральниці",  "_cleaners_tab"),
            ("💛 Залоги",         "_deposits_tab"),
            ("⚙️ База даних",     "_db_tab"),
            ("💾 Резерв/Експорт", "_backup_tab"),
            ("🖨 Принтер",        "_printer_tab"),
            ("🧾 Checkbox РРО",   "_checkbox_tab"),
            ("📋 Лог",            "_log_tab"),
            ("🔄 Оновлення",      "_update_tab"),
            ("🧠 Логіка",         "_logic_tab"),
        ]
        _tab_map = {name: meth for name, meth in _TAB_LIST}

        # ── Дворядкова навігація (кнопки) ──────────────────────────────────
        ROW1 = _TAB_LIST[:7]   # Номери…Залоги
        ROW2 = _TAB_LIST[7:]   # База даних…Логіка

        nav_outer = tk.Frame(self, bg=C['bg'])
        nav_outer.pack(fill='x', padx=20, pady=(0, 4))

        self._settings_nav_btns = {}
        self._active_settings_tab = None

        for row_items in (ROW1, ROW2):
            row_f = tk.Frame(nav_outer, bg=C['bg'])
            row_f.pack(fill='x', pady=1)
            for name, _ in row_items:
                b = ctk.CTkButton(
                    row_f, text=name, width=0, height=30,
                    fg_color=C['card2'], hover_color=C['border'],
                    text_color=C['text2'], font=('Segoe UI', 11),
                    corner_radius=6,
                    command=lambda n=name: _switch_settings_tab(n)
                )
                b.pack(side='left', padx=2, pady=0)
                self._settings_nav_btns[name] = b

        # ── Контейнер вмісту ────────────────────────────────────────────────
        self._settings_content = tk.Frame(self, bg=C['card'])
        self._settings_content.pack(fill='both', expand=True, padx=20, pady=(0, 10))

        _tab_built = set()
        _tab_frames = {}

        def _switch_settings_tab(name):
            # Підсвітка активної кнопки
            for n, b in self._settings_nav_btns.items():
                b.configure(
                    fg_color=C['accent'] if n == name else C['card2'],
                    text_color='white' if n == name else C['text2']
                )
            self._active_settings_tab = name
            # Сховати всі фрейми
            for f in _tab_frames.values():
                f.pack_forget()
            # Створити або показати фрейм
            if name not in _tab_frames:
                frame = tk.Frame(self._settings_content, bg=C['bg'])
                _tab_frames[name] = frame
                frame.pack(fill='both', expand=True)
                if name not in _tab_built:
                    _tab_built.add(name)
                    try:
                        getattr(self, _tab_map[name])(frame)
                    except Exception as e:
                        log_error(f"SettingsFrame tab '{name}'", e)
            else:
                _tab_frames[name].pack(fill='both', expand=True)

        # Перша вкладка
        _switch_settings_tab("🛏 Номери")

        # Зберігаємо посилання для зовнішнього доступу (наприклад _log_tab)
        self._switch_settings_tab = _switch_settings_tab

    # ── НОМЕРИ ────────────────────────────────────────
    def _rooms_tab(self,p):
        tb=tk.Frame(p,bg=C['bg']); tb.pack(fill='x',pady=5)
        btn(tb,"➕ Додати",lambda:self._room_dlg(p),width=130).pack(side='left',padx=4)
        btn(tb,"✏️ Ред.",lambda:self._room_edit(p),C['card2'],100).pack(side='left',padx=4)
        btn(tb,"🗑 Видалити",lambda:self._room_del(p),C['red'],120).pack(side='left',padx=4)
        btn(tb,"🧹 Прибирання",lambda:self._cleaning_dlg(p),C['yellow'],140).pack(side='left',padx=4)
        refresh_btn(tb, lambda:self._load_rooms(), side='left', padx=4, pady=6)
        ff,self.rooms_t=mktree(p,('id','number','cat','floor','status','price'),14,[50,80,160,60,120,100])
        for c,h in zip(('id','number','cat','floor','status','price'),['ID','Кімн.','Категорія','Пов.','Статус','Ціна/ніч']):
            self.rooms_t.heading(c,text=h)
        ff.pack(fill='both',expand=True)

        # Журнал прибирань
        lbl(p,'📋  Журнал прибирань',12,True).pack(anchor='w',padx=4,pady=(8,2))
        ff2,self.clean_t=mktree(p,('room','cleaner','started','finished','note'),5,[70,160,130,130,200])
        for c,h in zip(('room','cleaner','started','finished','note'),['Кімн.','Прибиральник','Початок','Кінець','Нотатка']):
            self.clean_t.heading(c,text=h)
        ff2.pack(fill='x')
        # Дані завантажуємо після рендеру UI через after()
        self.after(50, lambda: (self._load_rooms(), self._load_cleaning_log()))

    def _load_rooms(self):
        from app.modules.logic import get_rooms
        self.rooms_t.delete(*self.rooms_t.get_children())
        for r in (get_rooms() or []):
            self.rooms_t.insert('','end',iid=r['id'],
                values=(r['id'],r['number'],r.get('cat_name','—'),r.get('floor',1),
                        STATUS_UA.get(r.get('status',''),''),f"{float(r.get('base_price') or 0):.0f}₴"))

    def _room_dlg(self,p,room=None):
        from app.modules.logic import get_categories,save_room
        cats=get_categories() or []
        cat_map={c['name']:c['id'] for c in cats}
        win=dlg_win(self,"Номер кімнати","460x420")
        f=card(win); f.pack(fill='both',expand=True,padx=15,pady=15)
        flds={}
        for lt,key,val in [("Номер кімнати *",'number',room['number'] if room else ''),
                            ("Поверх",'floor',str(room.get('floor',1) if room else 1)),
                            ("Нотатки",'notes',room.get('notes','') if room else '')]:
            r=row_frm(f)
            ctk.CTkLabel(r,text=lt,font=('Segoe UI',11),text_color=C['text2'],width=140,anchor='w').pack(side='left')
            e=ent(r,w=240); e.insert(0,val); e.pack(side='left'); flds[key]=e
        r=row_frm(f)
        ctk.CTkLabel(r,text="Категорія *",font=('Segoe UI',11),text_color=C['text2'],width=140,anchor='w').pack(side='left')
        cv=ctk.StringVar(value=list(cat_map.keys())[0] if cat_map else '')
        if room:
            cur=next((c['name'] for c in cats if c['id']==room.get('category_id')),cv.get())
            cv.set(cur)
        ctk.CTkOptionMenu(r,values=list(cat_map.keys()) or ['—'],variable=cv,width=240,fg_color=C['card2'],button_color=C['accent']).pack(side='left')

        # Статус номера
        r2=row_frm(f)
        ctk.CTkLabel(r2,text="Статус",font=('Segoe UI',11),text_color=C['text2'],width=140,anchor='w').pack(side='left')
        status_opts=[('free','✅ Вільний'),('cleaning','🧹 Прибирання'),
                     ('repair','🔧 Ремонт'),('blocked','🔒 Заблокований')]
        status_labels=[s[1] for s in status_opts]
        status_vals  =[s[0] for s in status_opts]
        cur_status = room.get('status','free') if room else 'free'
        cur_label  = next((s[1] for s in status_opts if s[0]==cur_status), status_labels[0])
        stv=ctk.StringVar(value=cur_label)
        ctk.CTkOptionMenu(r2,values=status_labels,variable=stv,width=240,
                          fg_color=C['card2'],button_color=C['accent']).pack(side='left')

        def save():
            if not flds['number'].get().strip(): messagebox.showerror("","Введіть номер"); return
            chosen_status=status_vals[status_labels.index(stv.get())] if stv.get() in status_labels else 'free'
            save_room({'number':flds['number'].get().strip(),'floor':int(flds['floor'].get() or 1),
                       'notes':flds['notes'].get(),'category_id':cat_map.get(cv.get()),
                       'status':chosen_status},
                      room['id'] if room else None)
            self._load_rooms(); win.destroy()
        btn(f,"💾 Зберегти",save,height=40).pack(fill='x',padx=10,pady=15)

    def _room_edit(self,p):
        from app.modules.logic import get_room
        s=self.rooms_t.selection()
        if not s: messagebox.showwarning("","Оберіть номер"); return
        r=get_room(int(s[0]))
        if r: self._room_dlg(p,r)

    def _room_del(self,p):
        from app.modules.logic import delete_room
        s=self.rooms_t.selection()
        if not s: messagebox.showwarning("","Оберіть номер"); return
        if messagebox.askyesno("Видалити?","Видалити цей номер?"):
            try: delete_room(int(s[0])); self._load_rooms()
            except Exception as e: messagebox.showerror("Помилка",str(e))

    def _load_cleaning_log(self):
        if not hasattr(self,'clean_t'): return
        self.clean_t.delete(*self.clean_t.get_children())
        log = _cl_load()
        for e in reversed(log[-50:]):  # останні 50
            self.clean_t.insert('','end',values=(
                e.get('room',''), e.get('cleaner',''),
                e.get('started',''), e.get('finished',''),
                e.get('note','')))

