    # ── вбудований xlsx-writer/reader (без зовнішніх бібліотек) ─────────
    @staticmethod
    def _make_xlsx(rows, headers, path, col_widths=None):
        import zipfile, io
        col_letters = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ'
        all_str, str_idx = [], {}
        def si(s):
            s = str(s) if s is not None else ''
            if s not in str_idx:
                str_idx[s] = len(all_str); all_str.append(s)
            return str_idx[s]
        for h in headers: si(h)
        for row in rows:
            for c in row:
                try: float(str(c).replace(',','.')) if c not in ('',None) else None
                except: si(str(c) if c is not None else '')
        def cxml(ref, val, sid):
            try:
                n = float(str(val).replace(',','.')) if val not in ('',None) else None
                if n is not None: return '<c r="{}\" s="{}"><v>{}</v></c>'.format(ref,sid,n)
            except: pass
            return '<c r="{}" t="s" s="{}"><v>{}</v></c>'.format(ref,sid,si(str(val) if val is not None else ''))
        def rxml(ri, cells, sids):
            p = ['<row r="{}">'.format(ri)]
            for ci,(v,s) in enumerate(zip(cells,sids)): p.append(cxml('{}{}'.format(col_letters[ci],ri),v,s))
            p.append('</row>'); return ''.join(p)
        default_widths = [50, 14, 14, 16, 8, 12, 6]
        widths = col_widths if col_widths else default_widths
        col_els = ''.join(
            '<col min="{0}" max="{0}" width="{1}" customWidth="1"/>'.format(i+1, w)
            for i, w in enumerate(widths[:max(len(headers), 4)])
        )
        ws = ['<?xml version="1.0" encoding="UTF-8" standalone="yes"?>',
              '<worksheet xmlns="http://schemas.openxmlformats.org/spreadsheetml/2006/main">',
              '<cols>{}</cols>'.format(col_els),
              '<sheetData>']
        ws.append(rxml(1, headers, [1]*len(headers)))
        for i,row in enumerate(rows,2):
            sids=([2,3,4]+[2]*max(0,len(row)-3))[:len(row)]
            ws.append(rxml(i,row,sids))
        ws += ['</sheetData>','</worksheet>']
        styles = (
            '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>'
            '<styleSheet xmlns="http://schemas.openxmlformats.org/spreadsheetml/2006/main">'
            '<fonts><font><sz val="11"/><name val="Calibri"/></font>'
            '<font><sz val="11"/><b/><color rgb="FFFFFFFF"/><name val="Calibri"/></font>'
            '<font><sz val="11"/><name val="Calibri"/></font></fonts>'
            '<fills><fill><patternFill patternType="none"/></fill>'
            '<fill><patternFill patternType="gray125"/></fill>'
            '<fill><patternFill patternType="solid"><fgColor rgb="FF1F4E79"/></patternFill></fill>'
            '<fill><patternFill patternType="solid"><fgColor rgb="FFEBF3FB"/></patternFill></fill>'
            '<fill><patternFill patternType="none"/></fill></fills>'
            '<borders><border><left/><right/><top/><bottom/><diagonal/></border></borders>'
            '<cellStyleXfs count="1"><xf numFmtId="0" fontId="0" fillId="0" borderId="0"/></cellStyleXfs>'
            '<cellXfs>'
            '<xf numFmtId="0" fontId="0" fillId="0" borderId="0" xfId="0"/>'
            '<xf numFmtId="0" fontId="1" fillId="2" borderId="0" xfId="0" applyFont="1" applyFill="1"><alignment horizontal="center" vertical="center"/></xf>'
            '<xf numFmtId="0" fontId="0" fillId="0" borderId="0" xfId="0"/>'
            '<xf numFmtId="0" fontId="0" fillId="0" borderId="0" xfId="0"><alignment horizontal="center"/></xf>'
            '<xf numFmtId="2" fontId="0" fillId="0" borderId="0" xfId="0"><alignment horizontal="center"/></xf>'
            '</cellXfs></styleSheet>')
        ss = ['<?xml version="1.0" encoding="UTF-8" standalone="yes"?>',
              '<sst xmlns="http://schemas.openxmlformats.org/spreadsheetml/2006/main" count="{}" uniqueCount="{}">'.format(len(all_str),len(all_str))]
        for s in all_str:
            e=s.replace('&','&amp;').replace('<','&lt;').replace('>','&gt;').replace('"','&quot;')
            ss.append('<si><t xml:space="preserve">{}</t></si>'.format(e))
        ss.append('</sst>')
        ct=('<?xml version="1.0" encoding="UTF-8" standalone="yes"?>'
            '<Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types">'
            '<Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/>'
            '<Default Extension="xml" ContentType="application/xml"/>'
            '<Override PartName="/xl/workbook.xml" ContentType="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet.main+xml"/>'
            '<Override PartName="/xl/worksheets/sheet1.xml" ContentType="application/vnd.openxmlformats-officedocument.spreadsheetml.worksheet+xml"/>'
            '<Override PartName="/xl/sharedStrings.xml" ContentType="application/vnd.openxmlformats-officedocument.spreadsheetml.sharedStrings+xml"/>'
            '<Override PartName="/xl/styles.xml" ContentType="application/vnd.openxmlformats-officedocument.spreadsheetml.styles+xml"/>'
            '</Types>')
        wb=('<?xml version="1.0" encoding="UTF-8" standalone="yes"?>'
            '<workbook xmlns="http://schemas.openxmlformats.org/spreadsheetml/2006/main"'
            ' xmlns:r="http://schemas.openxmlformats.org/officeDocument/2006/relationships">'
            '<sheets><sheet name="Прайс-лист" sheetId="1" r:id="rId1"/></sheets></workbook>')
        rels=('<?xml version="1.0" encoding="UTF-8" standalone="yes"?>'
              '<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">'
              '<Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="xl/workbook.xml"/>'
              '</Relationships>')
        wb_rels=('<?xml version="1.0" encoding="UTF-8" standalone="yes"?>'
                 '<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">'
                 '<Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/worksheet" Target="worksheets/sheet1.xml"/>'
                 '<Relationship Id="rId2" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/sharedStrings" Target="sharedStrings.xml"/>'
                 '<Relationship Id="rId3" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/styles" Target="styles.xml"/>'
                 '</Relationships>')
        buf=io.BytesIO()
        with zipfile.ZipFile(buf,'w',zipfile.ZIP_DEFLATED) as zf:
            zf.writestr('[Content_Types].xml',ct); zf.writestr('_rels/.rels',rels)
            zf.writestr('xl/workbook.xml',wb); zf.writestr('xl/_rels/workbook.xml.rels',wb_rels)
            zf.writestr('xl/worksheets/sheet1.xml','\n'.join(ws))
            zf.writestr('xl/sharedStrings.xml','\n'.join(ss)); zf.writestr('xl/styles.xml',styles)
        with open(path,'wb') as f_: f_.write(buf.getvalue())

    @staticmethod
    def _read_xlsx(path):
        import zipfile, xml.etree.ElementTree as ET, re as _re
        ns='http://schemas.openxmlformats.org/spreadsheetml/2006/main'

        def _col_to_idx(col):
            """'A'→0, 'B'→1, 'D'→3, 'AA'→26 …"""
            idx=0
            for ch in col.upper():
                idx=idx*26+(ord(ch)-64)
            return idx-1

        with zipfile.ZipFile(path,'r') as zf:
            names=zf.namelist(); sst=[]
            if 'xl/sharedStrings.xml' in names:
                root=ET.fromstring(zf.read('xl/sharedStrings.xml'))
                for si in root.findall('{'+ns+'}si'):
                    t=si.find('.//{'+ns+'}t')
                    sst.append(t.text or '' if t is not None else '')
            ws_name=next((n for n in names if n.startswith('xl/worksheets/sheet') and n.endswith('.xml')),None)
            if not ws_name: return []
            root=ET.fromstring(zf.read(ws_name)); rows=[]
            for row_el in root.findall('.//{'+ns+'}row'):
                row_dict={}
                for c in row_el.findall('{'+ns+'}c'):
                    ref=c.get('r','')
                    col_str=_re.sub(r'\d','',ref)
                    col_idx=_col_to_idx(col_str) if col_str else len(row_dict)
                    t=c.get('t',''); v_el=c.find('{'+ns+'}v')
                    val=v_el.text if v_el is not None else ''
                    if t=='s': val=sst[int(val)] if val and int(val)<len(sst) else ''
                    row_dict[col_idx]=val or ''
                if row_dict:
                    max_col=max(row_dict.keys())
                    rows.append([row_dict.get(i,'') for i in range(max_col+1)])
        return rows

    def _menu_export_xls(self):
        from app.modules.logic import get_services
        import tkinter.filedialog as fd
        svcs=get_services(active_only=False) or []
        if not svcs: messagebox.showinfo("","Меню порожнє"); return
        path=fd.asksaveasfilename(title="Зберегти прайс-лист",defaultextension=".xlsx",
            filetypes=[("Excel файл","*.xlsx"),("Всі файли","*.*")],initialfile="прайс_готель.xlsx")
        if not path: return
        try:
            rows=[]
            for s in svcs:
                qty = s.get('quantity') or s.get('stock') or s.get('qty') or ''
                unit = s.get('unit') or 'шт'
                active = '✓' if s.get('active', True) else '✗'
                rows.append([
                    s['name'],
                    s['id'],
                    float(s['price']),
                    s.get('category',''),
                    unit,
                    qty if qty != '' else '',
                    active,
                ])
            headers=['Найменування','Код (КТ)','Сума (грн)','Категорія','Од.','Кількість','Акт.']
            self._make_xlsx(rows, headers, path,
                col_widths=[50, 12, 14, 16, 8, 12, 6])
            messagebox.showinfo("✅",f"Збережено {len(svcs)} позицій\n{path}")
        except Exception as e: messagebox.showerror("Помилка",str(e))

    def _menu_import_xls(self):
        from app.modules.logic import save_service
        import tkinter.filedialog as fd
        path=fd.askopenfilename(title="Відкрити прайс-лист",
            filetypes=[("Excel/CSV","*.xlsx *.xls *.csv *.txt"),("Всі файли","*.*")])
        if not path: return
        rows=[]
        try:
            import zipfile
            if zipfile.is_zipfile(path): rows=self._read_xlsx(path)
        except Exception: rows=[]
        if not rows:
            import csv
            for enc in ('utf-8-sig','utf-8','cp1251','latin-1'):
                for delim in ('\t',';',','):
                    try:
                        with open(path,'r',encoding=enc,newline='') as fh:
                            rows=[r for r in csv.reader(fh,delimiter=delim) if r]
                        if rows and len(rows[0])>=2: break
                    except Exception: rows=[]
                if rows and len(rows[0])>=2: break
        if not rows: messagebox.showerror("Помилка","Не вдалося прочитати файл"); return
        sr=1 if rows and rows[0] and any(str(rows[0][0]).strip().lower().startswith(x)
            for x in ['найменування','назва','name','наименование']) else 0
        data_rows=[r for r in rows[sr:] if r and str(r[0]).strip()]
        if not data_rows: messagebox.showerror("","Дані не знайдено"); return
        win=dlg_win(self,"📥 Імпорт меню","540x560")
        f=tk.Frame(win,bg=C['bg']); f.pack(fill='both',expand=True,padx=15,pady=12)
        # Фільтруємо __cat_placeholder_* рядки (заголовки категорій) — не імпортуємо їх як позиції
        real_rows=[r for r in data_rows if not str(r[0]).strip().startswith('__cat_placeholder')]
        lbl(f,f"Знайдено {len(real_rows)} позицій (з {len(data_rows)} рядків, категорії зчитуються з файлу):",12).pack(anchor='w',pady=(0,6))
        cat_var=ctk.StringVar(value='other')
        cf=tk.Frame(f,bg=C['bg']); cf.pack(fill='x',pady=(0,6))
        lbl(cf,"Категорія (запасна):",11,color=C['text2']).pack(side='left',padx=(0,8))
        ctk.CTkOptionMenu(cf,values=['restaurant','bar','minibar','laundry','transfer','other','бані','бесідки','до_кави','до_пива','кава-чай'],
            variable=cat_var,width=200,fg_color=C['card2'],button_color=C['accent']).pack(side='left')
        lbl(cf,"← якщо у файлі порожньо",10,color=C['text2']).pack(side='left',padx=(8,0))
        unit_var=ctk.StringVar(value='шт')
        uf=tk.Frame(f,bg=C['bg']); uf.pack(fill='x',pady=(0,6))
        lbl(uf,"Одиниця (запасна):",11,color=C['text2']).pack(side='left',padx=(0,8))
        ctk.CTkOptionMenu(uf,values=['шт','чашка','стакан','келих','пляшка','порція','кг','г','л','мл'],
            variable=unit_var,width=160,fg_color=C['card2'],button_color=C['accent']).pack(side='left')
        lbl(uf,"← якщо у файлі порожньо",10,color=C['text2']).pack(side='left',padx=(8,0))
        lbl(f,"Превью:",11,color=C['text2']).pack(anchor='w',pady=(4,2))
        pf,pt=mktree(f,('name','code','price','cat','unit'),7,[200,60,60,90,60])
        pt.heading('name',text='Найменування'); pt.heading('code',text='Код'); pt.heading('price',text='Сума'); pt.heading('cat',text='Категорія'); pt.heading('unit',text='Од.')
        for r in real_rows[:7]:
            _cat=r[3] if len(r)>3 and r[3] else cat_var.get()
            _unit=r[4] if len(r)>4 and r[4] and r[4] not in ('0','✓','✗') else unit_var.get()
            pt.insert('','end',values=(r[0],r[1] if len(r)>1 else '—',r[2] if len(r)>2 else '0',_cat,_unit))
        pf.pack(fill='both',expand=True,pady=(0,6))
        mode_var=ctk.StringVar(value='upsert')
        mf=tk.Frame(f,bg=C['bg']); mf.pack(fill='x',pady=(0,4))
        ctk.CTkRadioButton(mf,text="Оновити існуючі + додати нові",variable=mode_var,value='upsert',
            fg_color=C['accent'],text_color=C['text']).pack(side='left',padx=(0,10))
        ctk.CTkRadioButton(mf,text="Тільки нові",variable=mode_var,value='add',
            fg_color=C['accent'],text_color=C['text']).pack(side='left',padx=(0,10))
        ctk.CTkRadioButton(mf,text="Замінити все меню",variable=mode_var,value='replace',
            fg_color=C['red'],text_color=C['text']).pack(side='left')
        def do_import():
            from app.utils.db import get_conn as _gc_imp
            imported=updated=skipped=0
            mode=mode_var.get()
            if mode=='replace':
                if not messagebox.askyesno("Підтвердження","ЗАМІНИТИ ВСЕ МЕНЮ?\nВсі поточні позиції будуть видалені!"): return
                try:
                    with _gc_imp() as _c:
                        with _c.cursor() as _cur:
                            _cur.execute("DELETE FROM restaurant_order_items WHERE service_id IN (SELECT id FROM services)")
                            _cur.execute("DELETE FROM service_orders")
                            _cur.execute("DELETE FROM services")
                        _c.commit()
                except Exception as e: messagebox.showerror("Помилка очищення",str(e)); return
            try:
                with _gc_imp() as _c:
                    with _c.cursor() as _cur:
                        for r in real_rows:
                            name=str(r[0]).strip() if r else ''
                            if not name: skipped+=1; continue
                            try:
                                raw=str(r[2]).replace(',','.').replace('₴','').strip() if len(r)>2 else '0'
                                price=float(raw) if raw else 0.0
                            except Exception: price=0.0
                            cat_val=str(r[3]).strip() if len(r)>3 and str(r[3]).strip() else cat_var.get()
                            unit_val=str(r[4]).strip() if len(r)>4 and str(r[4]).strip() and str(r[4]).strip() not in ('0','✓','✗') else unit_var.get()
                            # Кількість з колонки F (індекс 5)
                            try:
                                _qraw=str(r[5]).replace(',','.').strip() if len(r)>5 else ''
                                qty_val=float(_qraw) if _qraw and _qraw not in ('✓','✗','') else None
                            except Exception: qty_val=None
                            # Пошук існуючого запису — тільки за назвою (ціна може змінитись)
                            if mode in ('upsert','add'):
                                _cur.execute("SELECT id FROM services WHERE LOWER(TRIM(name))=LOWER(TRIM(%s)) LIMIT 1",(name,))
                                _row=_cur.fetchone()
                                existing_id=_row[0] if _row else None
                            else:
                                existing_id=None
                            if mode=='upsert':
                                if existing_id:
                                    if qty_val is not None:
                                        _cur.execute("""UPDATE services SET name=%s,price=%s,unit=%s,category=%s,quantity=%s,active=TRUE
                                            WHERE id=%s""",(name,price,unit_val,cat_val,qty_val,existing_id))
                                    else:
                                        _cur.execute("""UPDATE services SET name=%s,price=%s,unit=%s,category=%s,active=TRUE
                                            WHERE id=%s""",(name,price,unit_val,cat_val,existing_id))
                                    updated+=1
                                else:
                                    if qty_val is not None:
                                        _cur.execute("""INSERT INTO services(name,price,unit,category,quantity,active)
                                            VALUES(%s,%s,%s,%s,%s,TRUE)""",(name,price,unit_val,cat_val,qty_val))
                                    else:
                                        _cur.execute("""INSERT INTO services(name,price,unit,category,active)
                                            VALUES(%s,%s,%s,%s,TRUE)""",(name,price,unit_val,cat_val))
                                    imported+=1
                            elif mode=='add':
                                if existing_id: skipped+=1; continue
                                if qty_val is not None:
                                    _cur.execute("""INSERT INTO services(name,price,unit,category,quantity,active)
                                        VALUES(%s,%s,%s,%s,%s,TRUE)""",(name,price,unit_val,cat_val,qty_val))
                                else:
                                    _cur.execute("""INSERT INTO services(name,price,unit,category,active)
                                        VALUES(%s,%s,%s,%s,TRUE)""",(name,price,unit_val,cat_val))
                                imported+=1
                            else:  # replace
                                if qty_val is not None:
                                    _cur.execute("""INSERT INTO services(name,price,unit,category,quantity,active)
                                        VALUES(%s,%s,%s,%s,%s,TRUE)""",(name,price,unit_val,cat_val,qty_val))
                                else:
                                    _cur.execute("""INSERT INTO services(name,price,unit,category,active)
                                        VALUES(%s,%s,%s,%s,TRUE)""",(name,price,unit_val,cat_val))
                                imported+=1
                    _c.commit()
            except Exception as e: messagebox.showerror("Помилка імпорту",str(e)); return
            win.destroy(); self._load_svcs()
            parts=[f"Оновлено: {updated}"] if updated else []
            parts.append(f"Додано: {imported}")
            if skipped: parts.append(f"Пропущено: {skipped}")
            messagebox.showinfo("✅ Імпорт завершено","\n".join(parts))
        bf=tk.Frame(f,bg=C['bg']); bf.pack(fill='x',pady=(6,0))
        btn(bf,f"✅ Імпортувати {len(real_rows)} позицій",do_import,C['green'],270,height=40).pack(side='left',padx=(0,8))
        btn(bf,"🧹 Видалити дублікати",lambda:self._dedup_services(win),C['yellow'] if 'yellow' in C else '#b8860b',160,height=40).pack(side='left',padx=(0,8))
        btn(bf,"✖ Скасувати",win.destroy,C['red'],120,height=40).pack(side='left')


    def _dedup_services(self, parent_win=None):
        """Видалити дублікати послуг — залишити запис з меншим ID для кожної назви+ціна."""
        try:
            from app.utils.db import get_conn as _gc_dd
            with _gc_dd() as _c:
                with _c.cursor() as _cur:
                    _cur.execute("""
                        SELECT LOWER(TRIM(name)), price, COUNT(*) as cnt, MIN(id) as keep_id
                        FROM services
                        GROUP BY LOWER(TRIM(name)), price
                        HAVING COUNT(*) > 1
                    """)
                    dupes=_cur.fetchall()
                    if not dupes:
                        messagebox.showinfo("\u2705","\u0414\u0443\u0431\u043b\u0456\u043a\u0430\u0442\u0456\u0432 \u043d\u0435 \u0437\u043d\u0430\u0439\u0434\u0435\u043d\u043e"); return
                    total_del=0
                    for name_low,price,cnt,keep_id in dupes:
                        _cur.execute("""DELETE FROM restaurant_order_items
                            WHERE service_id IN (
                                SELECT id FROM services
                                WHERE LOWER(TRIM(name))=%s AND price=%s AND id<>%s
                            )""",(name_low,price,keep_id))
                        _cur.execute("""DELETE FROM services
                            WHERE LOWER(TRIM(name))=%s AND price=%s AND id<>%s
                        """,(name_low,price,keep_id))
                        total_del+=cnt-1
                _c.commit()
            self._load_svcs()
            messagebox.showinfo("\U0001f9f9 \u0413\u043e\u0442\u043e\u0432\u043e",f"\u0412\u0438\u0434\u0430\u043b\u0435\u043d\u043e {total_del} \u0434\u0443\u0431\u043b\u0456\u043a\u0430\u0442\u0456\u0432")
        except Exception as e:
            messagebox.showerror("\u041f\u043e\u043c\u0438\u043b\u043a\u0430",str(e))

    def _load_svcs(self):
        self.svcs_t.delete(*self.svcs_t.get_children())
        try:
            from app.utils.db import get_conn as _gc_ls
            with _gc_ls() as _c:
                with _c.cursor() as _cur:
                    # Ensure columns exist and initialize stock
                    try:
                        _cur.execute("ALTER TABLE services ADD COLUMN IF NOT EXISTS quantity NUMERIC DEFAULT 0")
                        _cur.execute("ALTER TABLE services ADD COLUMN IF NOT EXISTS stock NUMERIC DEFAULT 0")
                        _c.commit()
                    except Exception:
                        pass
                    try:
                        _cur.execute("""
                            UPDATE services SET stock = quantity
                            WHERE (stock IS NULL OR stock = 0) AND quantity IS NOT NULL AND quantity > 0
                        """)
                        _c.commit()
                    except Exception:
                        pass
                    _cur.execute("""
                        SELECT s.id, s.name, s.category, s.price, s.unit, s.active,
                               COALESCE(s.quantity, 0) as quantity,
                               COALESCE(s.stock, COALESCE(s.quantity, 0)) as stock
                        FROM services s
                        ORDER BY s.category, s.name
                    """)
                    _rows=[dict(zip([d[0] for d in _cur.description],r)) for r in _cur.fetchall()]
        except Exception: _rows=[]
        for s in _rows:
            qty = int(s.get('quantity') or 0)
            stock = int(s.get('stock') or 0) if s.get('quantity') else '—'
            stock_display = stock if isinstance(stock, str) else (f"⚠️ {stock}" if isinstance(stock, int) and stock < 5 else str(stock))
            self.svcs_t.insert('','end', iid=s['id'],
                values=(s['id'], s['name'], s.get('category',''),
                        f"{float(s.get('price') or 0):.0f}₴",
                        s.get('unit','шт'),
                        qty if qty > 0 else '—',
                        stock_display,
                        '✓' if s.get('active') else '✗'))

