    def _cleaners_tab(self, p):
        # Скидаємо кеш щоб завжди читати свіжий список з БД
        global _cleaners_cache, _cleaners_cache_ts
        _cleaners_cache = None
        _cleaners_cache_ts = 0.0
        def _get():
            return _get_cleaners_db()
        def _save(lst):
            global _cleaners_cache, _cleaners_cache_ts
            _cleaners_cache = None  # Скинути кеш після збереження
            _cleaners_cache_ts = 0.0
            _save_cleaners_db(lst)

        hdr=card(p); hdr.pack(fill='x',padx=5,pady=(8,4))
        lbl(hdr,"👤  Список прибиральниць",14,True).pack(anchor='w',padx=12,pady=(10,4))
        lbl(hdr,"Ці імена доступні при реєстрації прибирання",10,color=C['text2']).pack(anchor='w',padx=12,pady=(0,8))

        list_f=card(p); list_f.pack(fill='both',expand=True,padx=5,pady=4)
        lb=tk.Listbox(list_f,bg=C['card2'],fg=C['text'],font=('Segoe UI',13),
                      selectbackground=C['accent'],relief='flat',
                      highlightthickness=0,bd=0,activestyle='none')
        sb=tk.Scrollbar(list_f,command=lb.yview); sb.pack(side='right',fill='y')
        lb.configure(yscrollcommand=sb.set)
        lb.pack(fill='both',expand=True,padx=8,pady=8)

        def _reload():
            lb.delete(0,'end')
            for c in _get(): lb.insert('end','  '+c)
        _reload()

        add_f=tk.Frame(p,bg=C['bg']); add_f.pack(fill='x',padx=5,pady=6)
        e_new=ent(add_f,"Ім'я нової прибиральниці",w=280); e_new.pack(side='left',padx=(0,6))

        def add():
            name=e_new.get().strip()
            if not name or name=="Ім'я нової прибиральниці": return
            lst=_get()
            if name not in lst:
                lst.append(name); _save(lst)
            e_new.delete(0,'end'); _reload()

        def remove():
            sel=lb.curselection()
            if not sel: return
            name=lb.get(sel[0]).strip()
            lst=_get()
            if name in lst: lst.remove(name); _save(lst)
            _reload()

        def move_up():
            sel=lb.curselection()
            if not sel or sel[0]==0: return
            lst=_get(); i=sel[0]-1
            # find real index (strip spaces)
            names=[x.strip() for x in [lb.get(j) for j in range(lb.size())]]
            name=names[sel[0]]
            idx=lst.index(name) if name in lst else -1
            if idx>0: lst[idx-1],lst[idx]=lst[idx],lst[idx-1]; _save(lst); _reload(); lb.selection_set(sel[0]-1)

        def move_down():
            sel=lb.curselection()
            if not sel: return
            names=[x.strip() for x in [lb.get(j) for j in range(lb.size())]]
            if sel[0]>=len(names)-1: return
            name=names[sel[0]]; lst=_get()
            idx=lst.index(name) if name in lst else -1
            if idx>=0 and idx<len(lst)-1: lst[idx],lst[idx+1]=lst[idx+1],lst[idx]; _save(lst); _reload(); lb.selection_set(sel[0]+1)

        def sync_now():
            """Примусова синхронізація з БД — скидає кеш і перечитує."""
            global _cleaners_cache, _cleaners_cache_ts
            _cleaners_cache = None
            _cleaners_cache_ts = 0.0
            _reload()
            messagebox.showinfo("🔄 Синхронізовано", f"Завантажено {lb.size()} прибиральниць з бази даних.")

        btn_f=tk.Frame(add_f,bg=C['bg']); btn_f.pack(side='left')
        btn(btn_f,"➕ Додати",add,C['green'],110,height=34).pack(side='left',padx=3)
        btn(btn_f,"🗑 Видалити",remove,C['red'],110,height=34).pack(side='left',padx=3)
        btn(btn_f,"⬆",move_up,C['card2'],44,height=34).pack(side='left',padx=2)
        btn(btn_f,"⬇",move_down,C['card2'],44,height=34).pack(side='left',padx=2)
        btn(btn_f,"🔄 Синхр.",sync_now,C['accent'],100,height=34).pack(side='left',padx=(8,2))

        # Підпис внизу
        info_f=tk.Frame(p,bg=C['bg']); info_f.pack(fill='x',padx=5,pady=(0,4))
        lbl(info_f,"💡 Натисніть 🔄 Синхр. щоб оновити список з сервера",10,color=C['text2']).pack(anchor='w',padx=8)


