    # ── БАЗА ДАНИХ ────────────────────────────────────
    def _db_tab(self,p):
        import datetime as _dtdb
        scroll = ctk.CTkScrollableFrame(p, fg_color=C['bg'])
        scroll.pack(fill='both', expand=True, padx=0, pady=0)

        # ── PostgreSQL ────────────────────────────────────────────────────
        f=card(scroll); f.pack(fill='x',padx=10,pady=10)
        lbl(f,"⚙️  Підключення до PostgreSQL",14,True).pack(anchor='w',padx=12,pady=(12,8))
        cfg=self._load_cfg(); self.db_flds={}
        for lt,key in [("Host",'host'),("Port",'port'),("Database",'dbname'),("User",'user'),("Password",'password')]:
            r=row_frm(f)
            ctk.CTkLabel(r,text=lt,font=('Segoe UI',11),text_color=C['text2'],width=100,anchor='w').pack(side='left')
            e=ent(r,w=300,show='*' if key=='password' else None); e.insert(0,str(cfg.get(key,''))); e.pack(side='left')
            self.db_flds[key]=e
        bf=ctk.CTkFrame(f,fg_color='transparent'); bf.pack(fill='x',padx=12,pady=(8,15))
        btn(bf,"💾 Зберегти",self._save_db,width=130).pack(side='left',padx=4)
        btn(bf,"🔗 Тест",self._test_db,C['green'],100).pack(side='left',padx=4)
        btn(bf,"📦 Ініціалізувати БД",self._init_db,C['yellow'],190).pack(side='left',padx=4)
        self.db_info=lbl(f,"",11,color=C['green']); self.db_info.pack(anchor='w',padx=12,pady=(0,10))

        # ── Локальна SQLite база (кеш) ────────────────────────────────────
        lc = card(scroll); lc.pack(fill='x', padx=10, pady=(0,10))
        lbl(lc, "💾  Локальна база даних (SQLite кеш)", 14, True).pack(anchor='w', padx=12, pady=(12,6))
        lbl(lc, "Програма зберігає копію даних на цьому комп'ютері для швидкої роботи та офлайн-режиму.",
            11, color=C['text2']).pack(anchor='w', padx=12, pady=(0,8))

        # Шлях до SQLite файлу
        def _get_sqlite_path():
            try:
                from app.utils.db_cache import _cache_instance as _ci
                p = getattr(_ci, '_db_path', None) or getattr(_ci, 'db_path', None)
                if p: return str(p)
            except Exception: pass
            return os.path.join(get_data_dir(), 'hotel_local_cache.db')

        sqlite_path = _get_sqlite_path()
        sqlite_exists = os.path.exists(sqlite_path)

        path_row = row_frm(lc)
        ctk.CTkLabel(path_row, text="Шлях:", font=('Segoe UI',11), text_color=C['text2'], width=100, anchor='w').pack(side='left')
        path_e = ent(path_row, w=400)
        path_e.insert(0, sqlite_path)
        path_e.configure(state='readonly')
        path_e.pack(side='left')
        clr = C['green'] if sqlite_exists else C['red']
        lbl(path_row, "✅ існує" if sqlite_exists else "❌ не знайдено", 11, color=clr).pack(side='left', padx=8)

        # Розмір файлу
        if sqlite_exists:
            try:
                size_kb = os.path.getsize(sqlite_path) // 1024
                size_str = f"{size_kb} КБ" if size_kb < 1024 else f"{size_kb//1024} МБ"
            except Exception:
                size_str = "—"
            size_row = row_frm(lc)
            ctk.CTkLabel(size_row, text="Розмір:", font=('Segoe UI',11), text_color=C['text2'], width=100, anchor='w').pack(side='left')
            lbl(size_row, size_str, 11, color=C['text']).pack(side='left')

        # Час останньої синхронізації
        sync_row = row_frm(lc)
        ctk.CTkLabel(sync_row, text="Синхронізація:", font=('Segoe UI',11), text_color=C['text2'], width=100, anchor='w').pack(side='left')
        self._db_sync_lbl = lbl(sync_row, "⏳ визначається...", 11, color=C['text2'])
        self._db_sync_lbl.pack(side='left', padx=4)

        def _refresh_sync_time():
            try:
                # Час з лога синхронізації — шукаємо будь-яку успішну подію
                log_entries = _sync_mgr.get_sync_log(limit=50)
                last_ok = next((e for e in log_entries
                                if e['event'] in ('flush_ok','pull_ok','full_sync')), None)
                if last_ok:
                    ts = last_ok['ts']
                    evt_ua = {'flush_ok':'вивантаження','pull_ok':'завантаження','full_sync':'синхронізація'}
                    evt_name = evt_ua.get(last_ok['event'], last_ok['event'])
                    self._db_sync_lbl.configure(
                        text=f"✅ {evt_name}: {ts}", text_color=C['green'])
                    return
                # Якщо немає записів — перевірити mtime файлу
                sqlite_path_now = _get_sqlite_path()
                if os.path.exists(sqlite_path_now):
                    mtime = os.path.getmtime(sqlite_path_now)
                    dt = _dtdb.datetime.fromtimestamp(mtime).strftime('%d.%m.%Y %H:%M:%S')
                    self._db_sync_lbl.configure(text=f"📁 файл оновлено: {dt}", text_color=C['text2'])
                else:
                    self._db_sync_lbl.configure(text="⏳ очікування першої синхронізації...", text_color=C['yellow'])
            except Exception as _e:
                self._db_sync_lbl.configure(text=f"— ({_e})", text_color=C['text2'])

        _refresh_sync_time()

        # Кнопки дій з локальним кешем
        lc_bf = ctk.CTkFrame(lc, fg_color='transparent'); lc_bf.pack(fill='x', padx=12, pady=(8,15))
        def _open_sqlite_folder():
            import subprocess
            folder = os.path.dirname(sqlite_path)
            try:
                subprocess.Popen(['explorer', folder] if os.name == 'nt' else ['xdg-open', folder])
            except Exception: pass
        def _force_sync():
            import threading
            self._db_sync_lbl.configure(text="⏳ синхронізація...", text_color=C['yellow'])
            def _do():
                try:
                    from app.utils.db_cache import _cache_instance as _ci
                    if _ci and hasattr(_ci, 'full_sync'):
                        _ci.full_sync()
                except Exception: pass
                try: p.after(0, _refresh_sync_time)
                except Exception: pass
            threading.Thread(target=_do, daemon=True).start()

        btn(lc_bf, "📂 Відкрити папку", _open_sqlite_folder, C['card2'], 160).pack(side='left', padx=4)
        btn(lc_bf, "🔄 Синхронізувати зараз", _force_sync, C['accent'], 200).pack(side='left', padx=4)
        btn(lc_bf, "🔃 Оновити інфо", _refresh_sync_time, C['card2'], 150).pack(side='left', padx=4)

    def _load_cfg(self):
        try:
            p=os.path.normpath(os.path.join(os.path.dirname(os.path.abspath(__file__)),'..','..','config','db.json'))
            with open(p) as f: return json.load(f)
        except: return {'host':'localhost','port':5432,'dbname':'hotel','user':'hotel','password':'hotel'}

    def _save_db(self):
        cfg={k:(int(v.get()) if k=='port' else v.get()) for k,v in self.db_flds.items()}
        p=os.path.normpath(os.path.join(os.path.dirname(os.path.abspath(__file__)),'..','..','config','db.json'))
        with open(p,'w') as f: json.dump(cfg,f,indent=4)
        self.db_info.configure(text="✓ Збережено",text_color=C['green'])

    def _test_db(self):
        self._save_db()
        from app.utils.db import test_connection
        ok,msg=test_connection()
        self.db_info.configure(text="✓ Підключено!" if ok else f"✗ {msg[:50]}",text_color=C['green'] if ok else C['red'])

    def _init_db(self):
        self._save_db()
        if not messagebox.askyesno("Ініціалізація","Створити таблиці (якщо не існують)?"):return
        try:
            schema=os.path.normpath(os.path.join(os.path.dirname(os.path.abspath(__file__)),'..','..','db','schema.sql'))
            from app.utils.db import get_conn
            with get_conn() as conn:
                with conn.cursor() as cur:
                    with open(schema) as sf: cur.execute(sf.read())
                conn.commit()
            self.db_info.configure(text="✓ БД ініціалізовано!",text_color=C['green'])
            messagebox.showinfo("✅","Готово!")
        except Exception as e:
            messagebox.showerror("Помилка",str(e))

