        self._exp_clear = ctk.BooleanVar(value=False)
        clr_f = tk.Frame(ec, bg=C['card']); clr_f.pack(fill='x', padx=12, pady=4)
        ctk.CTkCheckBox(clr_f,
                        text="🗑 Очистити дані після експорту (платежі + завершені бронювання)",
                        variable=self._exp_clear,
                        fg_color=C['red'], text_color=C['text'], font=('Segoe UI',12)).pack(side='left', padx=8)

        bf3 = tk.Frame(ec, bg=C['card']); bf3.pack(fill='x', padx=12, pady=(4,12))
        self._exp_btn = btn(bf3, "📤 Експортувати в Excel", self._do_export, C['accent'], 220)
        self._exp_btn.pack(side='left', padx=4)

        # ── Очищення каси ─────────────────────────────────
        cc = card(scroll); cc.pack(fill='x', padx=10, pady=5)
