    def _update_tab(self, p):
        """Вкладка оновлення програми — замінити main_window.py новим файлом."""
        import shutil, os as _os, sys as _sys

        def _get_real_dst():
            """Повертає реальний шлях до main_window.py поруч з .exe або в папці проекту."""
            # Якщо запущено як .exe (PyInstaller) — шукаємо поруч з exe
            if getattr(_sys, 'frozen', False):
                exe_dir = _os.path.dirname(_sys.executable)
                # Шукаємо в папці app/ui/ поруч з exe
                for candidate in [
                    _os.path.join(exe_dir, 'app', 'ui', 'main_window.py'),
                    _os.path.join(exe_dir, 'main_window.py'),
                    _os.path.join(exe_dir, '..', 'app', 'ui', 'main_window.py'),
                ]:
                    if _os.path.exists(candidate):
                        return _os.path.normpath(candidate)
                # Якщо не знайшли — повертаємо app/ui/ поруч з exe як місце запису
                dst = _os.path.join(exe_dir, 'app', 'ui', 'main_window.py')
                _os.makedirs(_os.path.dirname(dst), exist_ok=True)
                return dst
            else:
                return _os.path.abspath(__file__)

        real_dst = _get_real_dst()

        _sc = ctk.CTkScrollableFrame(p, fg_color=C['bg']); _sc.pack(fill='both', expand=True)
        f = tk.Frame(_sc, bg=C['bg']); f.pack(fill='both', expand=True, padx=15, pady=10)
        lbl(f, "🔄  Оновлення програми", 15, True).pack(anchor='w', pady=(0,4))
        try:
            _cur_ver_str = APP_VERSION
        except NameError:
            _cur_ver_str = '—'
        lbl(f, f"Поточна версія: {_cur_ver_str}", 11, color=C['text2']).pack(anchor='w', pady=(0,6))

        # ── Посилання на оновлення — читаємо/зберігаємо в конфіг ──
        _UPD_CFG_KEY = 'update_url'
        _DEFAULT_URL = "https://mega.nz/file/hg8nQQrD#sSav2kaJjhuQH6un01zrtWoqjyGq6L-vBrVRTbq7jH0"

        def _load_upd_url():
            try:
                _s = _load_app_settings()
                return _s.get(_UPD_CFG_KEY, '') or _DEFAULT_URL
            except Exception:
                return _DEFAULT_URL

        def _save_upd_url(url):
            try: _save_app_settings({_UPD_CFG_KEY: url.strip()})
            except Exception: pass

        def _to_direct_url(url):
            """Конвертує посилання у пряме для завантаження."""
            import re as _reu
            url = url.strip()
            # GitHub blob → raw (найнадійніший)
            if 'github.com' in url and '/blob/' in url:
                return url.replace('github.com', 'raw.githubusercontent.com').replace('/blob/', '/')
            # Pastebin: /p/id → /raw/id
            if 'pastebin.com' in url and '/raw/' not in url:
                return url.replace('pastebin.com/', 'pastebin.com/raw/')
            # Google Drive: /file/d/{ID}/view → /uc?export=download&id={ID}
            m = _reu.search(r'drive\.google\.com/file/d/([a-zA-Z0-9_-]+)', url)
            if m:
                return f"https://drive.google.com/uc?export=download&id={m.group(1)}"
            # Google Drive: id= в параметрі
            m = _reu.search(r'drive\.google\.com.*[?&]id=([a-zA-Z0-9_-]+)', url)
            if m:
                return f"https://drive.google.com/uc?export=download&id={m.group(1)}"
            # Dropbox: ?dl=0 → ?dl=1
            if 'dropbox.com' in url:
                return _reu.sub(r'[?&]dl=0', '', url).rstrip('?') + ('&' if '?' in url else '?') + 'dl=1'
            # OneDrive: embed → download
            if '1drv.ms' in url or 'onedrive.live.com' in url:
                return url.replace('redir?', 'download?').replace('embed?', 'download?')
            # MEGA — повертаємо як є (завантаження через браузер)
            # Інші — повертаємо як є
            return url

        # ── Блок онлайн оновлення ────────────────────────────────────────────
        mc = card(f); mc.pack(fill='x', pady=(0,6))
        mh = tk.Frame(mc, bg=C['card']); mh.pack(fill='x', padx=12, pady=(10,6))
        lbl(mh, "☁️  Онлайн оновлення", 13, True).pack(side='left')
        _ms_lbl = lbl(mh, "", 11, color=C['text2']); _ms_lbl.pack(side='right', padx=8)

        # ── Поле посилання (tk.Entry — підтримує Ctrl+V і правий клік) ──
        url_row = tk.Frame(mc, bg=C['card']); url_row.pack(fill='x', padx=12, pady=(0,4))
        lbl(url_row, "Посилання:", 11, color=C['text2']).pack(side='left', padx=(0,8))
        _url_var = tk.StringVar(value=_load_upd_url())
        _url_ent = tk.Entry(url_row, textvariable=_url_var,
                            font=('Segoe UI', 11), bg=C['card2'], fg=C['text'],
                            insertbackground=C['text'], relief='flat',
                            highlightthickness=1, highlightbackground=C['border'],
                            highlightcolor=C['accent'], width=55)
        _url_ent.pack(side='left', padx=(0,6), ipady=5)
        # Контекстне меню з Вставити / Копіювати / Вирізати
        _url_menu = tk.Menu(_url_ent, tearoff=0, bg=C['card2'], fg=C['text'],
                            activebackground=C['accent'], activeforeground='white')
        _url_menu.add_command(label="✂️  Вирізати",  command=lambda: _url_ent.event_generate("<<Cut>>"))
        _url_menu.add_command(label="📋  Копіювати", command=lambda: _url_ent.event_generate("<<Copy>>"))
        _url_menu.add_command(label="📌  Вставити",  command=lambda: _url_ent.event_generate("<<Paste>>"))
        _url_menu.add_separator()
        _url_menu.add_command(label="🗑  Очистити",  command=lambda: (_url_var.set(''), _url_ent.focus_set()))
        def _url_popup(e): _url_menu.tk_popup(e.x_root, e.y_root)
        _url_ent.bind('<Button-3>', _url_popup)
        _url_ent.bind('<Control-a>', lambda e: (_url_ent.select_range(0,'end'), 'break'))

        def _save_url_click():
            url = _url_ent.get().strip()
            if not url:
                _ms_lbl.configure(text="Посилання порожнє", text_color=C['yellow']); return
            _save_upd_url(url)
            _ms_lbl.configure(text="Збережено", text_color=C['green'])
        btn(url_row, "Зберегти", _save_url_click, C['accent'], 90, height=32).pack(side='left')

        lbl(mc, "  ✅ Працює: GitHub Raw, власний сервер, Pastebin (raw), Dropbox (dl=1)",
            10, color=C['green']).pack(anchor='w', padx=12, pady=(0,2))
        lbl(mc, "  ⚠️ Google Drive блокує .py файли — використайте GitHub або власний сервер",
            10, color=C['yellow']).pack(anchor='w', padx=12, pady=(0,4))

        mb = tk.Frame(mc, bg=C['card']); mb.pack(fill='x', padx=12, pady=(0,4))
        _mi_lbl = lbl(mb, "Натисніть «Перевірити» щоб порівняти версії", 11, color=C['text2'])
        _mi_lbl.pack(anchor='w', pady=(0,4))

        mbr = tk.Frame(mc, bg=C['card']); mbr.pack(fill='x', padx=12, pady=(0,12))
        _mb_check = btn(mbr, "Перевірити", None, C['accent'], 140, height=34)
        _mb_check.pack(side='left', padx=(0,6))
        _mb_open = btn(mbr, "Відкрити в браузері",
            lambda: __import__('subprocess').Popen(['start', _url_ent.get().strip()], shell=True),
            C['card2'], 180, height=34)
        _mb_open.pack(side='left', padx=4)

        def _do_mega_check():
            url = _url_ent.get().strip()
            if not url:
                _ms_lbl.configure(text="Вкажіть посилання", text_color=C['yellow']); return
            _save_upd_url(url)
            _ms_lbl.configure(text="Перевірка...", text_color=C['yellow'])
            _mi_lbl.configure(text="Підключаємось...", text_color=C['text2'])
            _mb_check.configure(state='disabled')
            import threading as _tmc
            def _bg():
                try:
                    import urllib.request as _ur3, re as _re3, os as _os3
                    direct_url = _to_direct_url(url)
                    import urllib.request as _ur3b, urllib.parse as _up3

                    def _gdrive_download(dl_url, timeout=30):
                        """Завантажує файл з Google Drive, обходячи підтвердження вірусу."""
                        opener = _ur3b.build_opener(_ur3b.HTTPCookieProcessor())
                        req = _ur3b.Request(dl_url, headers={"User-Agent": "Mozilla/5.0"})
                        resp = opener.open(req, timeout=timeout)
                        raw = resp.read()
                        # Якщо Google повернув HTML з підтвердженням — витягаємо confirm токен
                        if b'confirm=' in raw or b'uc-error-subcaption' in raw or b'Google Drive' in raw[:200]:
                            import re as _rer
                            # Шукаємо confirm токен
                            m = _rer.search(rb'confirm=([0-9A-Za-z_-]+)', raw)
                            if not m:
                                m = _rer.search(rb'href="([^"]*confirm=[^"]+)"', raw)
                            if m:
                                tok = m.group(1).decode('utf-8', errors='ignore')
                                # Формуємо новий URL з токеном
                                if tok.startswith('http'):
                                    confirm_url = tok
                                else:
                                    # Додаємо confirm до оригінального URL
                                    sep = '&' if '?' in dl_url else '?'
                                    confirm_url = dl_url + sep + 'confirm=' + tok
                                req2 = _ur3b.Request(confirm_url, headers={"User-Agent": "Mozilla/5.0"})
                                resp2 = opener.open(req2, timeout=timeout)
                                raw = resp2.read()
                        return raw

                    try:
                        data = _gdrive_download(direct_url)
                    except Exception as _dle:
                        # Fallback: спробуємо через requests якщо доступний
                        try:
                            import requests as _rq
                            s = _rq.Session()
                            r1 = s.get(direct_url, timeout=20, stream=True)
                            # Перевіряємо на підтвердження
                            import re as _rer2
                            m2 = _rer2.search(r'confirm=([0-9A-Za-z_\-]+)', r1.text or '')
                            if m2:
                                sep = '&' if '?' in direct_url else '?'
                                r2 = s.get(direct_url + sep + 'confirm=' + m2.group(1), timeout=30, stream=True)
                                data = r2.content
                            else:
                                data = r1.content
                        except ImportError:
                            raise _dle
                    cs = _os3.path.getsize(_get_real_dst()) if _os3.path.exists(_get_real_dst()) else 0
                    # Якщо це прямий py-файл — одразу зберігаємо
                    if b'def ' in data[:3000] or b'import ' in data[:3000] or b'class ' in data[:3000]:
                        import tempfile as _tmp2, os as _os4
                        _tmp_path = _os4.path.join(_tmp2.gettempdir(), 'main_window_update.py')
                        with open(_tmp_path, 'wb') as _tf: _tf.write(data)
                        rs = len(data)
                        rn = 'main_window.py'
                        _dl = _tmp_path
                    else:
                        html = data.decode('utf-8', errors='ignore')
                        import re as _re4
                        sm = _re4.search(r'"s"\s*:\s*(\d+)', html)
                        nm = _re4.search(r'"n"\s*:\s*"([^"]+)"', html)
                        rs = int(sm.group(1)) if sm else 0
                        rn = nm.group(1) if nm else 'main_window.py'
                        _dl = None

                    def _ui():
                        _mb_check.configure(state='normal', text="Перевірити ще раз")
                        if _dl:
                            _ms_lbl.configure(text="Готовий до встановлення!", text_color=C['green'])
                            _mi_lbl.configure(text="Завантажено " + str(rs//1024) + " КБ. Натисніть «Оновити» нижче.", text_color=C['green'])
                            try:
                                self._upd_selected = _dl
                                self._upd_path_lbl.configure(text="main_window_update.py  (" + str(rs//1024) + " КБ)", text_color=C['green'])
                                do_btn.configure(state='normal')
                            except Exception: pass
                        elif rs > 0 and rs != cs:
                            diff = rs - cs; sign = "+" if diff > 0 else ""
                            _ms_lbl.configure(text="Є оновлення!", text_color=C['green'])
                            _mi_lbl.configure(
                                text="Сервер: " + rn + " (" + str(rs//1024) + " КБ)  |  Поточний: " + str(cs//1024) + " КБ  |  " + sign + str(diff//1024) + " КБ\nЗавантажте файл через «Відкрити в браузері», потім «Вибрати файл»",
                                text_color=C['green'])
                        elif rs == cs and rs > 0:
                            _ms_lbl.configure(text="Версія актуальна v" + APP_VERSION, text_color=C['green'])
                            _mi_lbl.configure(text="Файл на сервері (" + str(rs//1024) + " КБ) збігається з поточним.", text_color=C['text2'])
                        else:
                            _ms_lbl.configure(text="Не вдалось перевірити", text_color=C['yellow'])
                            _mi_lbl.configure(text="Не вдалось отримати дані. Спробуйте завантажити файл вручну.", text_color=C['yellow'])
                    try: f.after(0, _ui)
                    except Exception: pass
                except Exception as _eu:
                    _eu_str = str(_eu)
                    def _err(e=_eu_str):
                        _ms_lbl.configure(text="Помилка з'єднання", text_color=C['red'])
                        # Підказка залежно від типу помилки
                        if '403' in e:
                            _hint = ("❌ 403 Forbidden — файл заблоковано хостингом (Google Drive блокує .py)\n"
                                     "\n📋 Альтернативи:\n"
                                     "  1. GitHub: завантажте файл → Settings → Raw посилання\n"
                                     "  2. Власний сервер: будь-який URL що віддає .py\n"
                                     "  3. Pastebin: вставте код → отримайте raw.pastebin.com посилання")
                        elif '404' in e:
                            _hint = "❌ 404 — файл не знайдено. Перевірте посилання."
                        elif 'timeout' in e.lower():
                            _hint = "❌ Таймаут — немає з'єднання або сервер не відповідає."
                        else:
                            _hint = "❌ Помилка: " + e
                        _mi_lbl.configure(text=_hint, text_color=C['red'])
                        _mb_check.configure(state='normal')
                    try: f.after(0, _err)
                    except Exception: pass
            _tmc.Thread(target=_bg, daemon=True).start()

        _mb_check.configure(command=_do_mega_check)
        import threading as _tauto
        _tauto.Thread(target=lambda: (
            __import__('time').sleep(0.5),
            f.after(0, _do_mega_check) if f.winfo_exists() else None
        ), daemon=True).start()

        tk.Frame(f, bg=C['text2'], height=1).pack(fill='x', pady=6)
        lbl(f, "── або вручне оновлення ──", 10, color=C['text2']).pack(anchor='w', pady=(0,4))


        info = card(f); info.pack(fill='x', pady=5)
        lbl(info, "📁  Цільові файли для оновлення:", 12, True).pack(anchor='w', padx=12, pady=(10,3))
        _target_paths = [
            r'C:\hotel2\app\ui\main_window.py',
            r'C:\hotel2\dist\HotelPMS\app\ui\main_window.py',
        ]
        for _tp in _target_paths:
            _exists = _os.path.exists(_tp)
            _clr = C['green'] if _exists else C['yellow']
            _icon = "✅" if _exists else "⚠️"
            lbl(info, f"{_icon} {_tp}", 10, color=_clr).pack(anchor='w', padx=12, pady=1)
        if _os.path.normpath(real_dst) not in [_os.path.normpath(p) for p in _target_paths]:
            _exists = _os.path.exists(real_dst)
            _clr = C['green'] if _exists else C['text2']
            lbl(info, f"  + {real_dst}", 10, color=_clr).pack(anchor='w', padx=12, pady=1)
        tk.Frame(info, bg=C['card'], height=6).pack()

        upd = card(f); upd.pack(fill='x', pady=8)
        lbl(upd, "📂  Вибрати новий main_window.py", 13, True).pack(anchor='w', padx=12, pady=(10,5))
        lbl(upd, "Програма замінить файл і перезапуститься автоматично. Збірка EXE НЕ потрібна.",
            11, color=C['text2']).pack(anchor='w', padx=12, pady=(0,8))

        sel_row = tk.Frame(upd, bg=C['card']); sel_row.pack(fill='x', padx=12, pady=(0,10))
        self._upd_path_lbl = lbl(sel_row, "Файл не вибрано", 11, color=C['text2'])
        self._upd_path_lbl.pack(side='left', expand=True, fill='x')
        self._upd_selected = None

        # 🔧 ВИПРАВЛЕННЯ: Додати кнопки оновлення та статус ЛЬ ПЕРЕД pick_file()
        btn_row = ctk.CTkFrame(upd, fg_color='transparent')
        btn_row.pack(fill='x', padx=12, pady=(0, 10))
        
        # Заповнювачі для do_update та do_btn, будуть визначені пізніше
        do_update_fn = None
        do_btn = btn(btn_row, "💾 Оновити", lambda: do_update_fn() if do_update_fn else None, C['green'], 150)
        do_btn.pack(side='left', padx=(0, 6))
        do_btn.configure(state='disabled')  # Неактивна поки файл не вибраний
        
        status_lbl = lbl(btn_row, "Готово до оновлення", 11, color=C['text2'])
        status_lbl.pack(side='left', expand=True, fill='x')

        def pick_file():
            from tkinter import filedialog
            path = filedialog.askopenfilename(
                title="Виберіть новий main_window.py",
                filetypes=[("Python файли", "*.py"), ("Всі файли", "*.*")])
            if path:
                self._upd_selected = path
                self._upd_path_lbl.configure(
                    text=_os.path.basename(path) + f"  ({_os.path.getsize(path)//1024} КБ)",
                    text_color=C['green'])
                do_btn.configure(state='normal')

        # 🔧 ВИПРАВЛЕННЯ: Додати кнопку вибору файлу
        pick_btn = btn(sel_row, "🔍 Вибрати", pick_file, C['accent'], 110)
        pick_btn.pack(side='left', padx=(5, 0))

        def _get_all_targets(primary_dst):
            """Повертає список всіх шляхів де треба замінити main_window.py.
            Завжди включає обидва фіксованих шляхи Windows + primary_dst."""
            targets = []

            # ── Фіксовані шляхи Windows ────────────────────────────────
            FIXED_WIN = [
                r'C:\hotel2\app\ui\main_window.py',
                r'C:\hotel2\dist\HotelPMS\app\ui\main_window.py',
            ]
            for fw in FIXED_WIN:
                norm = _os.path.normpath(fw)
                if norm not in targets:
                    # Завжди додаємо — навіть якщо файлу нема (буде створено)
                    targets.append(norm)

            # ── Primary dst (поточний __file__ або exe-папка) ───────────
            norm_primary = _os.path.normpath(primary_dst)
            if norm_primary not in targets:
                targets.append(norm_primary)

            # ── Автошук dist/HotelPMS поруч з проектом (будь-який диск) ─
            base = primary_dst
            for _ in range(6):
                base = _os.path.dirname(base)
                for extra in [
                    _os.path.join(base, 'dist', 'HotelPMS', 'app', 'ui', 'main_window.py'),
                    _os.path.join(base, 'dist', 'HotelPMS', '_internal', 'app', 'ui', 'main_window.py'),
                ]:
                    norm = _os.path.normpath(extra)
                    if norm not in targets and _os.path.exists(norm):
                        targets.append(norm)

            return targets

        def do_update():
            if not self._upd_selected:
                messagebox.showwarning("", "Спочатку виберіть файл"); return
            src = self._upd_selected
            if not src.endswith('.py'):
                messagebox.showerror("❌", "Потрібен файл .py"); return

            all_targets = _get_all_targets(real_dst)
            targets_str = "\n".join(f"  • {t}" for t in all_targets)

            msg = ("Замінити файл програми?\n\n"
                   f"Звідки: {_os.path.basename(src)}  ({_os.path.getsize(src)//1024} КБ)\n\n"
                   f"Куди:\n{targets_str}\n\n"
                   "Файл буде замінено і програма перезапуститься автоматично.\n"
                   "Збірка EXE НЕ потрібна — просто перезапуск.")

            if not messagebox.askyesno("🔄 Оновлення", msg):
                return

            try:
                # ── 1. Копіюємо файл у всі цілі ────────────────────────────
                replaced = []
                for target in all_targets:
                    _os.makedirs(_os.path.dirname(target), exist_ok=True)
                    if _os.path.exists(target):
                        try: shutil.copy2(target, target + '.bak')
                        except Exception: pass
                    shutil.copy2(src, target)
                    replaced.append(_os.path.basename(target))

                status_lbl.configure(
                    text="✅ " + ", ".join(replaced) + " — перезапуск...",
                    text_color=C['green'])
                f.update()

                import subprocess, time as _t
                _t.sleep(0.8)

                # ── 2. Перезапуск ───────────────────────────────────────────
                if getattr(_sys, 'frozen', False):
                    # EXE-режим: запускаємо bat який чекає 2с і стартує EXE знову
                    exe_path     = _sys.executable
                    exe_dir      = _os.path.dirname(exe_path)
                    launcher_bat = _os.path.join(exe_dir, '_restart_hotel.bat')
                    bat_content  = (
                        "@echo off\n"
                        "timeout /t 2 /nobreak >nul\n"
                        f"start \"\" \"{exe_path}\"\n"
                        "del \"%~f0\" >nul 2>&1\n"
                    )
                    with open(launcher_bat, 'w', encoding='cp1251') as _bf:
                        _bf.write(bat_content)
                    # CREATE_NO_WINDOW — без чорного вікна консолі
                    subprocess.Popen(
                        ['cmd.exe', '/c', launcher_bat],
                        creationflags=0x08000000  # CREATE_NO_WINDOW
                    )
                else:
                    # Режим Python — перезапускаємо python main.py
                    import platform
                    project_root = _os.path.dirname(real_dst)
                    for _ in range(5):
                        if _os.path.exists(_os.path.join(project_root, 'main.py')):
                            break
                        project_root = _os.path.dirname(project_root)

                    if platform.system() == 'Windows':
                        subprocess.Popen(
                            [_sys.executable, _os.path.join(project_root, 'main.py')],
                            creationflags=0x00000010  # CREATE_NEW_CONSOLE
                        )
                    else:
                        launcher_sh = _os.path.join(project_root, '_restart_hotel.sh')
                        with open(launcher_sh, 'w') as _sh:
                            _sh.write(
                                "#!/bin/bash\n"
                                f"cd \"{project_root}\"\n"
                                "source ~/venv/bin/activate 2>/dev/null "
                                "|| source venv/bin/activate 2>/dev/null || :\n"
                                "python3 main.py\n"
                            )
                        _os.chmod(launcher_sh, 0o755)
                        for term in ['gnome-terminal', 'xterm', 'konsole']:
                            try:
                                subprocess.Popen([term, '--' if term != 'konsole' else '-e', launcher_sh])
                                break
                            except Exception:
                                continue

                _os._exit(0)

            except Exception as e:
                messagebox.showerror("❌ Помилка", f"Не вдалося оновити:\n{e}")
        
        # 🔧 ВИПРАВЛЕННЯ: Встановити функцію для кнопки
        do_update_fn = do_update
        do_btn.configure(command=do_update)


    # ══════════════════════════════════════════════════════
    # 🧠 ВКЛАДКА ЛОГІКИ — редагування розрахунків без коду
    # ══════════════════════════════════════════════════════
    def _logic_tab(self, p):
        import json as _jl, os as _osl

        def _cfg_path():
            base = _osl.path.normpath(_osl.path.join(
                _osl.path.dirname(_osl.path.abspath(__file__)), '..', '..', 'data'))
            _osl.makedirs(base, exist_ok=True)
            return _osl.path.join(base, 'logic_config.json')

        DEFAULT_CFG = {
            "cash": {
                "_comment": "Каса: ключові слова у полі note таблиці payments",
                "deposit_notes":    ["Залог при заселенні", "Залог при бронюванні", "deposit:"],
                "refund_notes":     ["Повернення залогу"],
                "deposit_any":      ["Залог", "deposit"],
                "advance_notes":    ["Аванс"],
                "service_notes":    ["Послуга:", "Додаткові послуги"],
                "exclude_from_total": ["Залог", "deposit", "Повернення"]
            },
            "categories": {
                "_comment": "Ключові слова в назві категорії номера для групування у касі",
                "bani":     ["бан", "saun", "[tariff:hour]"],
                "besidky":  ["бесід", "альтанк"]
            },
            "restaurant": {
                "_comment": "Категорії які НЕ показуються у Ресторан/Бар",
                "excluded_categories": ["штрафи", "бані", "бесідки"],
                "_comment2": "Категорії без перевірки залишку (необмежені)",
                "unlimited_categories": ["до_кави", "кава-чай", "кава_чай", "кава", "чай", "coffee", "tea"]
            },
            "reports": {
                "_comment": "Звідки беруться дані для звітів",
                "rooms_income_source":   "payments WHERE booking_id IS NOT NULL (not deposit/refund)",
                "restaurant_source":     "payments WHERE booking_id IS NULL (not deposit/refund)",
                "deposit_source":        "payments WHERE note LIKE deposit_notes",
                "refund_source":         "payments WHERE note LIKE refund_notes",
                "cash_balance_formula":  "opening_cash + cash_income - refunds_cash - transfers_out"
            }
        }

        def _load_cfg():
            try:
                p2 = _cfg_path()
                if _osl.path.exists(p2):
                    with open(p2, 'r', encoding='utf-8') as f2:
                        saved = _jl.load(f2)
                    # Merge with defaults (add missing keys)
                    for section, vals in DEFAULT_CFG.items():
                        if section not in saved:
                            saved[section] = vals
                        elif isinstance(vals, dict):
                            for k, v in vals.items():
                                if k not in saved[section]:
                                    saved[section][k] = v
                    return saved
            except Exception:
                pass
            return _jl.loads(_jl.dumps(DEFAULT_CFG))

        def _save_cfg(cfg):
            try:
                with open(_cfg_path(), 'w', encoding='utf-8') as f2:
                    _jl.dump(cfg, f2, ensure_ascii=False, indent=2)
                return True
            except Exception as e:
                messagebox.showerror("Помилка збереження", str(e))
                return False

        cfg = _load_cfg()

        # ── Scrollable container ──
        outer = tk.Frame(p, bg=C['bg']); outer.pack(fill='both', expand=True)
        canvas2 = tk.Canvas(outer, bg=C['bg'], highlightthickness=0)
        vsb2 = tk.Scrollbar(outer, orient='vertical', command=canvas2.yview)
        canvas2.configure(yscrollcommand=vsb2.set)
        vsb2.pack(side='right', fill='y')
        canvas2.pack(side='left', fill='both', expand=True)
        inner = tk.Frame(canvas2, bg=C['bg'])
        _cid = canvas2.create_window((0,0), window=inner, anchor='nw')
        canvas2.bind('<Configure>', lambda e: canvas2.itemconfig(_cid, width=e.width))
        inner.bind('<Configure>', lambda e: canvas2.configure(scrollregion=canvas2.bbox('all')))
        canvas2.bind('<MouseWheel>', lambda e: canvas2.yview_scroll(int(-1*(e.delta/120)),'units'))

        # ── Entry widgets dict for saving ──
        _entries = {}

        def _section(parent, title, icon=""):
            sf = card(parent); sf.pack(fill='x', padx=12, pady=6)
            lbl(sf, f"{icon}  {title}", 13, True).pack(anchor='w', padx=12, pady=(10,4))
            sep = tk.Frame(sf, bg=C['border'], height=1); sep.pack(fill='x', padx=12, pady=(0,8))
            return sf

        def _list_field(parent, label_text, cfg_section, cfg_key, hint="через кому"):
            row = tk.Frame(parent, bg=C['card']); row.pack(fill='x', padx=12, pady=3)
            lbl(row, label_text, 11, color=C['text2']).pack(side='left', padx=(0,8))
            lbl(row, f"({hint})", 10, color=C['text2']).pack(side='left', padx=(0,12))
            var = tk.StringVar(value=", ".join(cfg.get(cfg_section,{}).get(cfg_key,[])))
            e = ctk.CTkEntry(row, textvariable=var, width=400, fg_color=C['card2'],
                             border_color=C['border'], text_color=C['text'])
            e.pack(side='right', padx=(0,4), pady=2)
            _entries[(cfg_section, cfg_key)] = ('list', var)

        def _text_field(parent, label_text, cfg_section, cfg_key):
            row = tk.Frame(parent, bg=C['card']); row.pack(fill='x', padx=12, pady=3)
            lbl(row, label_text, 11, color=C['text2']).pack(side='left', padx=(0,8))
            var = tk.StringVar(value=cfg.get(cfg_section,{}).get(cfg_key,''))
            e = ctk.CTkEntry(row, textvariable=var, width=460, fg_color=C['card2'],
                             border_color=C['border'], text_color=C['text'])
            e.pack(side='right', padx=(0,4), pady=2)
            _entries[(cfg_section, cfg_key)] = ('str', var)

        # ═══ КАСА ═══
        s1 = _section(inner, "Каса — розрахунки по note у таблиці payments", "💰")
        _list_field(s1, "Залог при заселенні (note містить):", "cash", "deposit_notes")
        _list_field(s1, "Повернення залогу (note містить):", "cash", "refund_notes")
        _list_field(s1, "Будь-який залог (виключається з доходів):", "cash", "deposit_any")
        _list_field(s1, "Аванс (note містить):", "cash", "advance_notes")
        _list_field(s1, "Послуги/сервіс (note містить):", "cash", "service_notes")
        _list_field(s1, "Виключити з 'Всього отримано':", "cash", "exclude_from_total")

        tk.Frame(s1, bg=C['card'], height=4).pack()

        info1 = tk.Frame(s1, bg=C['card2']); info1.pack(fill='x', padx=12, pady=(0,10))
        lbl(info1, "ℹ️  Каса рахує:", 10, color=C['text2']).pack(anchor='w', padx=8, pady=2)
        for line in [
            "• Дохід номери = аванс + доплата (payments з booking_id, без залогів/повернень/послуг), мінус бані/бесідки",
            "• Бані/Бесідки = payments з booking_id, де категорія кімнати збігається з ключовими словами нижче",
            "• Ресторан/Послуги = payments без booking_id (+ послуги з note)",
            "• Всього отримано = готівка + картка + переказ (без залогів і повернень)",
            "• Залишок залогів = залоги цієї зміни + залоги при відкритті − повернено",
        ]:
            lbl(info1, line, 10, color=C['text2']).pack(anchor='w', padx=16, pady=1)
        tk.Frame(info1, height=4, bg=C['card2']).pack()

        # ═══ КАТЕГОРІЇ КІМНАТ ═══
        s2 = _section(inner, "Категорії кімнат — групування у касі", "🏠")
        _list_field(s2, "Ключові слова для 'Бані' (в назві категорії):", "categories", "bani")
        _list_field(s2, "Ключові слова для 'Бесідки' (в назві категорії):", "categories", "besidky")

        info2 = tk.Frame(s2, bg=C['card2']); info2.pack(fill='x', padx=12, pady=(4,10))
        lbl(info2, "ℹ️  Категорія шукається в room_categories.name і room_categories.description (LOWER)", 
            10, color=C['text2']).pack(anchor='w', padx=8, pady=4)

        # ═══ РЕСТОРАН ═══
        s3 = _section(inner, "Ресторан / Бар", "🍽")
        _list_field(s3, "Категорії НЕ видно в ресторані:", "restaurant", "excluded_categories")
        _list_field(s3, "Категорії без обмеження залишку:", "restaurant", "unlimited_categories")

        # ═══ ЗВІТИ ═══
        s4 = _section(inner, "Звіти — джерела даних (довідково)", "📊")
        for k, label in [
            ("rooms_income_source",   "Дохід номери — джерело:"),
            ("restaurant_source",     "Ресторан/послуги — джерело:"),
            ("deposit_source",        "Залоги — джерело:"),
            ("refund_source",         "Повернення — джерело:"),
            ("cash_balance_formula",  "Формула 'Готівка в касі':"),
        ]:
            _text_field(s4, label, "reports", k)

        tk.Frame(s4, bg=C['card'], height=4).pack()

        # ═══ КНОПКИ ═══
        bf = tk.Frame(inner, bg=C['bg']); bf.pack(fill='x', padx=12, pady=12)

        def _do_save():
            new_cfg = _jl.loads(_jl.dumps(cfg))  # deep copy
            for (section, key), (ftype, var) in _entries.items():
                val = var.get().strip()
                if ftype == 'list':
                    new_cfg.setdefault(section, {})[key] = [
                        x.strip() for x in val.split(',') if x.strip()]
                else:
                    new_cfg.setdefault(section, {})[key] = val
            if _save_cfg(new_cfg):
                cfg.update(new_cfg)
                messagebox.showinfo("✅ Збережено",
                    "Налаштування логіки збережено!\n\n"
                    "Зміни застосуються при наступному оновленні каси/ресторану.")

        def _do_reset():
            if not messagebox.askyesno("Скинути", "Скинути всі налаштування логіки до стандартних?"): return
            if _save_cfg(DEFAULT_CFG):
                # Update entry fields
                for (section, key), (ftype, var) in _entries.items():
                    dval = DEFAULT_CFG.get(section, {}).get(key, [] if ftype=='list' else '')
                    var.set(", ".join(dval) if ftype=='list' else dval)
                messagebox.showinfo("✅","Скинуто до стандартних значень")

        def _do_export():
            from tkinter import filedialog
            path = filedialog.asksaveasfilename(
                defaultextension=".json", filetypes=[("JSON","*.json")],
                initialfile="logic_config.json")
            if path:
                import shutil
                try: shutil.copy2(_cfg_path(), path); messagebox.showinfo("✅","Експортовано")
                except Exception as e: messagebox.showerror("Помилка", str(e))

        def _do_import():
            from tkinter import filedialog
            path = filedialog.askopenfilename(filetypes=[("JSON","*.json")])
            if not path: return
            try:
                with open(path, 'r', encoding='utf-8') as f2:
                    imported = _jl.load(f2)
                if _save_cfg(imported):
                    # Reload entries
                    for (section, key), (ftype, var) in _entries.items():
                        dval = imported.get(section, {}).get(key, [] if ftype=='list' else '')
                        var.set(", ".join(dval) if isinstance(dval, list) else str(dval))
                    messagebox.showinfo("✅","Імпортовано та застосовано")
            except Exception as e: messagebox.showerror("Помилка імпорту", str(e))

        btn(bf,"💾 Зберегти",_do_save,C['green'],160,height=38).pack(side='left',padx=(0,8))
        btn(bf,"🔄 Скинути до стандарту",_do_reset,'#e67e22',200,height=38).pack(side='left',padx=(0,8))
        btn(bf,"📤 Експорт JSON",_do_export,C['accent'],160,height=38).pack(side='left',padx=(0,8))
        btn(bf,"📥 Імпорт JSON",_do_import,C['card2'],140,height=38).pack(side='left')

